// ─── AI Cost Limit ───────────────────────────────────────────────────────────
// Set AI_COST_LIMIT_PER_USER=0.50 in env to cap each user at $0.50 lifetime.
// Set to 0 or leave unset to disable the limit.
const AI_COST_LIMIT_PER_USER = parseFloat(process.env.AI_COST_LIMIT_PER_USER || "0") || 0;
// Fixed cost estimate per analysis call (GPT-4o vision ~$0.01 per request).
// Replace with real token-based calculation when needed.
const AI_ESTIMATED_COST_PER_CALL = parseFloat(process.env.AI_ESTIMATED_COST_PER_CALL || "0.01");
// Developer bypass (temporary): AI_DEV_BYPASS_LIMIT=1 skips limit + cost recording for this process.
// Optional: client sends developerMode:true only if AI_ALLOW_DEV_CLIENT_BYPASS=1 (e.g. staging; never in prod).

// ─── AI Rate Limiter ─────────────────────────────────────────────────────────
// Per-patient: max 10 AI requests / 60 s window (configurable via env)
const AI_RATE_LIMIT_MAX    = parseInt(process.env.AI_RATE_LIMIT_MAX    || "10",    10);
const AI_RATE_LIMIT_WINDOW = parseInt(process.env.AI_RATE_LIMIT_WINDOW || "60000", 10); // ms

const _aiRateBuckets = new Map(); // patientId → [timestamp, …]

function aiRateLimitMiddleware(req, res, next) {
  const pid = String(req.patientId || req.body?.patientId || "").trim();
  if (!pid) return next();

  const now  = Date.now();
  const hits = (_aiRateBuckets.get(pid) || []).filter(t => now - t < AI_RATE_LIMIT_WINDOW);

  if (hits.length >= AI_RATE_LIMIT_MAX) {
    const retryAfterSec = Math.ceil((hits[0] + AI_RATE_LIMIT_WINDOW - now) / 1000);
    res.set("Retry-After", String(retryAfterSec));
    return res.status(429).json({
      ok: false,
      error: "rate_limit_exceeded",
      message: `Çok fazla istek. ${retryAfterSec} saniye sonra tekrar deneyin.`,
      retryAfter: retryAfterSec,
    });
  }

  hits.push(now);
  _aiRateBuckets.set(pid, hits);

  // Prune stale buckets every ~500 requests
  if (_aiRateBuckets.size > 500) {
    for (const [key, times] of _aiRateBuckets) {
      if (times.every(t => now - t >= AI_RATE_LIMIT_WINDOW)) _aiRateBuckets.delete(key);
    }
  }
  next();
}

// ─── AI Cost Tracking ────────────────────────────────────────────────────────
// Reads and writes to the `ai_usage` table in Supabase.
// Table DDL (run scripts/add-ai-usage.sql once):
//   CREATE TABLE ai_usage (
//     id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
//     user_id text NOT NULL UNIQUE,
//     total_cost float NOT NULL DEFAULT 0,
//     updated_at timestamptz NOT NULL DEFAULT now()
//   );

/** Returns { totalCost, limited } for the given userId.
 *  If AI_COST_LIMIT_PER_USER === 0 the limit is disabled → limited always false. */
async function aiCostCheck(userId) {
  if (!AI_COST_LIMIT_PER_USER || !isSupabaseEnabled()) {
    return { totalCost: 0, limited: false };
  }
  try {
    const { data, error } = await supabase
      .from('ai_usage')
      .select('total_cost')
      .eq('user_id', userId)
      .maybeSingle();

    if (error) {
      console.warn('[AI COST] Check failed (allowing request):', error.message);
      return { totalCost: 0, limited: false };
    }

    const totalCost = data?.total_cost ?? 0;
    const limited   = totalCost >= AI_COST_LIMIT_PER_USER;
    console.log('[AI COST]:', { userId, totalCost: totalCost.toFixed(4), limit: AI_COST_LIMIT_PER_USER, limited });
    return { totalCost, limited };
  } catch (e) {
    console.warn('[AI COST] Exception during check (allowing request):', e?.message);
    return { totalCost: 0, limited: false };
  }
}

/** When true, skip ai_cost limit check and aiCostRecord (dev / staging only). */
function shouldBypassAiCostLimit(req) {
  if (String(process.env.AI_DEV_BYPASS_LIMIT || "").trim() === "1") return true;
  const body = req.body || {};
  if (
    body.developerMode === true &&
    String(process.env.AI_ALLOW_DEV_CLIENT_BYPASS || "").trim() === "1"
  ) {
    return true;
  }
  return false;
}

/** Increments the user's accumulated cost by AI_ESTIMATED_COST_PER_CALL.
 *  Creates the row if it doesn't exist (upsert). Only called after a successful AI response. */
async function aiCostRecord(userId) {
  if (!isSupabaseEnabled()) return;
  try {
    // Fetch current value first so we can log the running total
    const { data: existing } = await supabase
      .from('ai_usage')
      .select('total_cost')
      .eq('user_id', userId)
      .maybeSingle();

    const prev = existing?.total_cost ?? 0;
    const next = parseFloat((prev + AI_ESTIMATED_COST_PER_CALL).toFixed(6));

    await supabase
      .from('ai_usage')
      .upsert(
        { user_id: userId, total_cost: next, updated_at: new Date().toISOString() },
        { onConflict: 'user_id' }
      );

    console.log('[AI COST] Recorded:', { userId, prev: prev.toFixed(4), added: AI_ESTIMATED_COST_PER_CALL, next: next.toFixed(4) });
  } catch (e) {
    console.warn('[AI COST] Record failed (non-fatal):', e?.message);
  }
}

// ─── Image Magic-Bytes Validator ─────────────────────────────────────────────
/** Returns true only if the buffer starts with a known image signature. */
function isValidImageBuffer(buf) {
  if (!buf || buf.length < 4) return false;
  const b = buf;
  // JPEG: FF D8 FF
  if (b[0] === 0xFF && b[1] === 0xD8 && b[2] === 0xFF) return true;
  // PNG:  89 50 4E 47
  if (b[0] === 0x89 && b[1] === 0x50 && b[2] === 0x4E && b[3] === 0x47) return true;
  // GIF:  47 49 46 38
  if (b[0] === 0x47 && b[1] === 0x49 && b[2] === 0x46 && b[3] === 0x38) return true;
  // WebP: 52 49 46 46 … 57 45 42 50
  if (b[0] === 0x52 && b[1] === 0x49 && b[2] === 0x46 && b[3] === 0x46 &&
      b.length >= 12 && b[8] === 0x57 && b[9] === 0x45 && b[10] === 0x42 && b[11] === 0x50) return true;
  // HEIC/HEIF: ftyp box at offset 4 (4 bytes), value 'ftyp' = 66 74 79 70
  if (b.length >= 12 && b[4] === 0x66 && b[5] === 0x74 && b[6] === 0x79 && b[7] === 0x70) return true;
  return false;
}

// ─── Structured AI Logger ─────────────────────────────────────────────────────
const AI_LOG_FILE = process.env.AI_LOG_FILE || null; // e.g. "/var/log/clinifly/ai.log"

function logAI(level, event, data = {}) {
  const entry = {
    ts:    new Date().toISOString(),
    level,
    event,
    ...data,
  };
  const line = JSON.stringify(entry);

  if (level === "error") {
    console.error(`[AI] ${line}`);
  } else if (level === "warn") {
    console.warn(`[AI] ${line}`);
  } else {
    console.log(`[AI] ${line}`);
  }

  if (AI_LOG_FILE) {
    try {
      fs.appendFileSync(AI_LOG_FILE, line + "\n");
    } catch (_) { /* non-fatal – disk write failure shouldn't crash the server */ }
  }
}

