function maskEmailForLog(email) {
  const e = String(email || "").trim().toLowerCase();
  if (!e) return "(empty)";
  const at = e.indexOf("@");
  if (at < 1) return "***";
  return `${e.slice(0, 2)}***${e.slice(at)}`;
}

