function normalizeOtpRowFromStore(raw) {
  if (raw == null) return null;
  if (Array.isArray(raw)) return raw.length > 0 ? raw[0] : null;
  return raw;
}

/** Normalize otp.registration_data (flat or nested) for verify + OTP resend merge. */
function flattenRegistrationPayload(raw) {
  if (!raw || typeof raw !== "object") return {};
  const inner = raw.registration_data && typeof raw.registration_data === "object" ? raw.registration_data : {};
  return {
    ...inner,
    name: raw.name ?? inner.name,
    phone: raw.phone ?? inner.phone ?? "",
    address: raw.address ?? inner.address ?? "",
    website: raw.website ?? inner.website ?? "",
    email: raw.email ?? inner.email ?? "",
    password_hash: raw.password_hash ?? inner.password_hash,
    password: raw.password ?? inner.password,
    clinic_code: raw.clinic_code ?? inner.clinic_code ?? raw.clinicCode ?? inner.clinicCode,
    plan: raw.plan ?? inner.plan,
    max_patients: raw.max_patients ?? inner.max_patients,
  };
}
const ALLOW_FILE_FALLBACK = String(process.env.ALLOW_FILE_FALLBACK || "").toLowerCase() === "true";
// ────────────────────────────────────────────────────────────────────────────

function getMissingColumnName(error) {
  const msg = String(error?.message || "");
  const match = msg.match(/'([^']+)'/);
  return match?.[1] || null;
}

async function insertWithColumnPruning(payload) {
  let current = { ...(payload || {}) };
  let lastError = null;

  for (let attempt = 0; attempt < 14; attempt += 1) {
    const { data, error } = await supabase
      .from("messages")
      .insert(current)
      .select("*")
      .single();

    if (!error) return { data, error };
    lastError = error;
    if (!isMissingColumnError(error)) return { data: null, error };

    const missingColumn = getMissingColumnName(error);
    if (!missingColumn || !(missingColumn in current)) {
      return { data: null, error };
    }
    delete current[missingColumn];
  }

  return { data: null, error: lastError };
}

function deriveMessageType(explicitType, attachment) {
  if (explicitType) return String(explicitType);
  if (!attachment) return "text";
  const fileType = String(attachment?.fileType || "").toLowerCase();
  const mime = String(attachment?.mimeType || attachment?.mime || "").toLowerCase();
  if (fileType === "image" || mime.startsWith("image/")) return "image";
  if (fileType === "pdf" || mime.includes("pdf")) return "pdf";
  return "text";
}

/** True when inbound patient message carries a file/photo — must use full messages insert (attachments). */
function hasInboundAttachments(attachments) {
  if (attachments == null) return false;
  if (typeof attachments !== "object") return true;
  const u = attachments.url ?? attachments.attachment_url;
  if (u != null && String(u).trim()) return true;
  return Object.keys(attachments).length > 0;
}

