// ── UUID param sanitization ──────────────────────────────────────────────────
const _paramUuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
function _assertUuidParam(paramName) {
  return (req, res, next, value) => {
    const v = String(value || "").trim();
    if (_paramUuidRe.test(v) || /^[a-zA-Z][a-zA-Z0-9]*_/.test(v)) return next();
    return res.status(400).json({ ok: false, error: "invalid_uuid", param: paramName, received: v });
  };
}
app.param("encounterId", _assertUuidParam("encounterId"));
// Invalid JSON body → always JSON (never HTML), so mobile clients don't get JSON.parse errors on "<"
app.use((err, req, res, next) => {
  const isBodyParse =
    err &&
    (err instanceof SyntaxError ||
      String(err.type || "") === "entity.parse.failed" ||
      /JSON|body/i.test(String(err.message || "")));
  if (isBodyParse && !res.headersSent) {
    return res.status(400).json({
      ok: false,
      error: "invalid_json",
      message: "Geçersiz istek gövdesi (JSON bekleniyor).",
    });
  }
  next(err);
});
app.use((req, res, next) => {
  // Structured request logger — always active for /api/ paths
  if (String(req.path || "").startsWith("/api/")) {
    const t0 = Date.now();
    res.on("finish", () => {
      const ms = Date.now() - t0;
      const lvl = res.statusCode >= 500 ? "[API][ERROR]" : res.statusCode >= 400 ? "[API][WARN]" : "[API]";
      console.log("RESPONSE TYPE:", req.path);
      console.log(`${lvl} ${req.method} ${req.path} → ${res.statusCode} (${ms}ms)`);
    });
  }
  if (!PERF_LOGS_ENABLED || !String(req.path || "").startsWith("/api/")) {
    next();
    return;
  }

  const startedAt = Date.now();
  logPerfLine(`[API CALL] ${req.method} ${req.originalUrl}`);

  res.on("finish", () => {
    const duration = Date.now() - startedAt;
    logPerfLine(`[API PERF] ${req.method} ${req.originalUrl} ${res.statusCode} ${duration}ms`);
  });

  next();
});

