/**
 * Kayıtta klinik isteğe bağlı: hastalar klinik kodu olmadan da kayıt olabilir; boş bırakılabilir.
 * İsteğe bağlı çözümleme: clinicCode | clinic_code | clinic_id (UUID), sonra DEFAULT_CLINIC_CODE / DEFAULT_CLINIC_ID.
 */
async function augmentRegisterClinicFromBody(body) {
  const b = body || {};
  let code = String(b.clinicCode ?? b.clinic_code ?? "").trim();
  const idHint = String(b.clinicId ?? b.clinic_id ?? "").trim();
  if (!code && idHint && UUID_RE.test(idHint) && isSupabaseEnabled()) {
    try {
      const c = await getClinicById(idHint);
      if (c?.clinic_code) code = String(c.clinic_code).trim().toUpperCase();
    } catch (_e) {
      /* ignore */
    }
  }
  if (!code) {
    const defCode = String(process.env.DEFAULT_CLINIC_CODE || "").trim();
    if (defCode) code = defCode.toUpperCase();
  }
  if (!code && isSupabaseEnabled()) {
    const defId = String(process.env.DEFAULT_CLINIC_ID || "").trim();
    if (UUID_RE.test(defId)) {
      try {
        const c = await getClinicById(defId);
        if (c?.clinic_code) code = String(c.clinic_code).trim().toUpperCase();
      } catch (_e) {
        /* ignore */
      }
    }
  }
  return code;
}

// ================== REGISTER ==================
app.post("/api/register", async (req, res) => {
  try {
  const body = req.body || {};
  const {
    name = "",
    patientName: bodyPatientName = "",
    fullName = "",
    phone = "",
    email = "",
    language = "",
  } = body;
  const referralCode = String(body.referralCode || body.inviterReferralCode || "").trim();
  const displayName = String(bodyPatientName || fullName || name || "").trim();

  let clinicCode = "";
  try {
    clinicCode = await augmentRegisterClinicFromBody(body);
  } catch (augErr) {
    console.warn("[REGISTER] augmentRegisterClinicFromBody:", augErr?.message || augErr);
  }

  console.log(`[REGISTER] Request received:`, { 
    name: displayName ? "***" : "", 
    phone: phone ? "***" : "", 
    email: email ? "***" : "",
    clinicCode: clinicCode || "(empty)",
    hasClinicCode: !!clinicCode 
  });
  console.log("[REGISTER] REGISTER_START", { route: "/api/register" });

  // Email is required for registration
  if (!email || !String(email).trim()) {
    return res.status(400).json({
      ok: false,
      error: "email_required",
      message: REGISTER_USER_MSG.emailRequired,
    });
  }

  // Validate email format
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailNormalized = String(email).trim().toLowerCase();
  if (!emailRegex.test(emailNormalized)) {
    return res.status(400).json({
      ok: false,
      error: "invalid_email",
      message: REGISTER_USER_MSG.invalidEmail,
    });
  }

  const patientLanguage = normalizePatientLanguage(language);

  // Phone is OPTIONAL (email-only OTP). If present, validate and normalize.
  const phoneTrimmed = String(phone || "").trim();
  const phoneNormalized = phoneTrimmed ? normalizePhone(phoneTrimmed) : "";
  if (phoneTrimmed && (!phoneNormalized || phoneNormalized.length < 10)) {
    return res.status(400).json({
      ok: false,
      error: "invalid_phone",
      message: REGISTER_USER_MSG.invalidPhone,
    });
  }

  // Klinik kodu isteğe bağlı — yalnızca gönderilmiş ve boş değilse doğrulanır
  let validatedClinicCode = null;
  let foundClinicId = null;
  if (clinicCode && String(clinicCode).trim()) {
    const code = String(clinicCode).trim().toUpperCase();
    let foundClinic = null;

    // SUPABASE: Primary lookup
    if (isSupabaseEnabled()) {
      foundClinic = await getClinicByCode(code);
      if (foundClinic) {
        foundClinicId = foundClinic.id;

      }
    }
    
    // FILE FALLBACK: First check CLINIC_FILE (single clinic object)
    if (!foundClinic) {
      const singleClinic = readJson(CLINIC_FILE, {});
      if (singleClinic && singleClinic.clinicCode) {
        const singleClinicCode = String(singleClinic.clinicCode).toUpperCase();

        if (singleClinicCode === code) {
          foundClinic = singleClinic;

        }
      }
    }
    
    // FILE FALLBACK: Then check CLINICS_FILE (multiple clinics object)
    if (!foundClinic) {
      const clinics = readJson(CLINICS_FILE, {});

      
      // Search for clinic by clinicCode or code field
      for (const clinicId in clinics) {
        const clinic = clinics[clinicId];
        if (clinic) {
          // Check both clinicCode and code fields
          const clinicCodeToCheck = clinic.clinicCode || clinic.code;
          if (clinicCodeToCheck) {
            const clinicCodeUpper = String(clinicCodeToCheck).toUpperCase();

            if (clinicCodeUpper === code) {
              foundClinic = clinic;
              foundClinicId = clinicId;

              break;
            }
          }
        }
      }
    }
    
    if (foundClinic) {
      validatedClinicCode = code;

    } else {
      // Clinic not found - return error

      return res.status(404).json({
        ok: false,
        error: "clinic_not_found",
        message: REGISTER_USER_MSG.clinicNotFound(code),
      });
    }
  } else {

  }
  


  // EMAIL is the identity: if a patient already exists for this email, reuse its patientId.
  let patientId = null;
  if (isSupabaseEnabled()) {
    try {
      const { data: existing, error: e } = await supabase
        .from("patients")
        .select("id, patient_id, email")
        .eq("email", emailNormalized)
        .single();
      if (!e && existing) {
        patientId = existing.patient_id || existing.id;
      } else if (e && String(e.code || "") !== "PGRST116") {
        console.error("[REGISTER] Supabase patient lookup by email failed", {
          message: e.message,
          code: e.code,
          details: e.details,
        });
      }
    } catch (err) {

    }
  }
  if (!patientId) {
    const patientsByFile = readJson(PAT_FILE, {});
    for (const pid in patientsByFile) {
      const em = String(patientsByFile[pid]?.email || "").trim().toLowerCase();
      if (em && em === emailNormalized) {
        patientId = pid;
        break;
      }
    }
  }
  if (!patientId) patientId = rid("p");
  const requestId = rid("req");
  const token = makeToken();

  // SUPABASE: Insert patient (PRIMARY - production source of truth)
  let supabaseClinicId = null;
  let supabasePatientRow = null;
  if (isSupabaseEnabled() && validatedClinicCode) {
    try {
      const clinic = await getClinicByCode(validatedClinicCode);
      if (clinic) {
        supabaseClinicId = clinic.id;

      } else {

      }
    } catch (err) {

    }
  }

  if (isSupabaseEnabled() && !supabaseClinicId) {
    console.log(
      "[REGISTER] open signup — no clinic (clinic_id null). Optional: DEFAULT_CLINIC_* or clinicCode later.",
    );
  }

  logRegisterTrace("/api/register", "STEP_BEFORE_DB_UPSERT", {
    supabase: isSupabaseEnabled(),
  });

  // === SUPABASE PATIENT UPSERT (ZORUNLU) ===
  if (isSupabaseEnabled()) {
    const payload = {
      patient_id: patientId, // legacy app id (p_xxx)
      email: emailNormalized,
      name: displayName,
      full_name: displayName,
      first_name: "",
      last_name: "",
      clinic_id: supabaseClinicId,
      status: "PENDING",
      language: patientLanguage,
      role: (req.body?.role || "PATIENT").toUpperCase(), // 🔥 NORMALIZE ROLE TO UPPERCASE
      ...(phoneNormalized ? { phone: phoneNormalized } : {}),
    };
    let { data: patientUpsertRow, error: patientUpsertErr } = await supabase
      .from("patients")
      .upsert(
        payload,
        {
          onConflict: "email",
        }
      )
      .select()
      .single();

    if (patientUpsertErr) {
      console.error("[SUPABASE] PATIENT UPSERT FAILED", {
        message: patientUpsertErr.message,
        code: patientUpsertErr.code,
        details: patientUpsertErr.details,
        hint: patientUpsertErr.hint,
      });
      const detailBlob = `${patientUpsertErr.details || ""} ${patientUpsertErr.message || ""}`.toLowerCase();
      const code23505 = String(patientUpsertErr.code || "") === "23505";
      const isPhoneConstraint =
        /patients_phone_unique|key \(phone\)/.test(detailBlob) ||
        String(patientUpsertErr.message || "").toLowerCase().includes("patients_phone_unique");
      const isEmailConstraint =
        /patients_email_unique|key \(email\)/.test(detailBlob) ||
        String(patientUpsertErr.message || "").toLowerCase().includes("patients_email_unique");
      const isDup =
        code23505 ||
        detailBlob.includes("duplicate key");

      const reusePatientRow = async (existing) => {
        patientId = existing.patient_id || existing.id;
        if (patientLanguage && existing.language !== patientLanguage) {
          await supabase.from("patients").update({ language: patientLanguage }).eq("id", existing.id);
        }
        try {
          const { data: fullRow } = await supabase
            .from("patients")
            .select("id, patient_id, clinic_id, name, referral_code, email")
            .eq("id", existing.id)
            .limit(1)
            .maybeSingle();
          supabasePatientRow = fullRow || existing;
        } catch {
          supabasePatientRow = existing;
        }
        patientUpsertRow = supabasePatientRow;
        patientUpsertErr = null;
      };

      let resolved = false;

      if (isDup) {
        if (isPhoneConstraint && phoneNormalized) {
          const { data: byPhone, error: ePhone } = await supabase
            .from("patients")
            .select("id, patient_id, email, language")
            .eq("phone", phoneNormalized)
            .limit(1)
            .maybeSingle();
          if (!ePhone && byPhone) {
            const em = String(byPhone.email || "").trim().toLowerCase();
            if (em !== emailNormalized) {
              return res.status(409).json({
                ok: false,
                error: "phone_already_registered",
                message: REGISTER_USER_MSG.phoneAlreadyRegistered,
              });
            }
            await reusePatientRow(byPhone);
            console.log("[REGISTER] PHONE_CONFLICT_HANDLED", {
              route: "/api/register",
              idempotent: true,
            });
            resolved = true;
          }
        }

        if (!resolved && patientUpsertErr && (isEmailConstraint || (code23505 && !isPhoneConstraint))) {
          try {
            const { data: existing, error: e2 } = await supabase
              .from("patients")
              .select("id, patient_id, email, language")
              .eq("email", emailNormalized)
              .limit(1)
              .maybeSingle();
            if (!e2 && existing) {
              await reusePatientRow(existing);
              resolved = true;
            } else {
              console.error("[REGISTER] Unique email but failed to fetch existing patient", {
                message: e2?.message,
                code: e2?.code,
                details: e2?.details,
              });
              return res.status(500).json({
                ok: false,
                error: "register_failed",
                message: REGISTER_USER_MSG.registerFailedLookup,
              });
            }
          } catch (e3) {
            return res.status(500).json({
              ok: false,
              error: "register_failed",
              message: REGISTER_USER_MSG.registerFailed,
            });
          }
        }

        if (!resolved && patientUpsertErr && phoneNormalized && !isPhoneConstraint) {
          const { data: byPhone, error: ePhone } = await supabase
            .from("patients")
            .select("id, patient_id, email, language")
            .eq("phone", phoneNormalized)
            .limit(1)
            .maybeSingle();
          if (!ePhone && byPhone) {
            const em = String(byPhone.email || "").trim().toLowerCase();
            if (em !== emailNormalized) {
              return res.status(409).json({
                ok: false,
                error: "phone_already_registered",
                message: REGISTER_USER_MSG.phoneAlreadyRegistered,
              });
            }
            await reusePatientRow(byPhone);
            console.log("[REGISTER] PHONE_CONFLICT_HANDLED", {
              route: "/api/register",
              idempotent: true,
            });
            resolved = true;
          }
        }
      }

      if (patientUpsertErr) {
        const hintNull =
          !supabaseClinicId &&
          String(patientUpsertErr.message || "")
            .toLowerCase()
            .includes("clinic_id");
        return res.status(500).json({
          ok: false,
          error: "register_failed",
          message: REGISTER_USER_MSG.registerFailed,
          ...(hintNull ? { hint: REGISTER_USER_MSG.clinicIdNullableHint } : {}),
        });
      }
    }

    if (patientUpsertRow?.id) console.log("[SUPABASE] ✅ patient upserted:", patientUpsertRow.id);
    if (patientUpsertRow) supabasePatientRow = patientUpsertRow;
    logRegisterTrace("/api/register", "STEP_AFTER_DB_UPSERT", {
      patientRowId: patientUpsertRow?.id || supabasePatientRow?.id || null,
    });
  }

  // FILE-BASED: Fallback storage (for backward compatibility)
  const patients = readJson(PAT_FILE, {});
  const existingFile = patients[patientId] || null;
  patients[patientId] = {
    patientId,
    name: displayName,
    ...(phoneNormalized ? { phone: phoneNormalized } : {}),
    email: emailNormalized,
    language: patientLanguage,
    status: "PENDING",
    clinicCode: validatedClinicCode,
    createdAt: existingFile?.createdAt || now(),
    updatedAt: now(),
  };
  writeJson(PAT_FILE, patients);

  // registrations (array/object safe)
  const regs = readJson(REG_FILE, {});
  const row = {
    requestId,
    patientId,
    name: displayName,
    phone: phoneNormalized, // Use normalized phone
    email: emailNormalized,
    status: "PENDING",
    clinicCode: validatedClinicCode, // Add clinicCode to registration
    createdAt: now(),
    updatedAt: now(),
  };
  if (Array.isArray(regs)) {
    regs.push(row);
    writeJson(REG_FILE, regs);
  } else {
    regs[requestId] = row;
    writeJson(REG_FILE, regs);
  }

  // Handle referral code if provided
  if (referralCode && String(referralCode).trim()) {
    try {
      const refCodeRaw = String(referralCode).trim();
      const refCode = refCodeRaw;

      // ================== SUPABASE PATH (source of truth) ==================
      if (isSupabaseEnabled() && supabaseClinicId) {
        const variants = Array.from(
          new Set([refCode, refCode.toUpperCase(), refCode.toLowerCase()].filter(Boolean))
        );

        let inviter = null;
        let lastInviterErr = null;
        for (const v of variants) {
          // 1) referral_code match (if column exists)
          try {
            const q1 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("referral_code", v)
              .limit(1)
              .maybeSingle();
            if (!q1.error && q1.data) {
              inviter = q1.data;
              break;
            }
            if (q1.error && !isMissingColumnError(q1.error, "referral_code") && String(q1.error.code || "") !== "PGRST116") {
              lastInviterErr = q1.error;
            }
          } catch (e) {
            // ignore
          }

          // 2) patient_id match (if column exists)
          try {
            const q2 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("patient_id", v)
              .limit(1)
              .maybeSingle();
            if (!q2.error && q2.data) {
              inviter = q2.data;
              break;
            }
            if (q2.error && !isMissingColumnError(q2.error, "patient_id") && String(q2.error.code || "") !== "PGRST116") {
              lastInviterErr = q2.error;
            }
          } catch (e) {
            // ignore
          }

          // 3) id match (covers schemas where patient id is stored in `id`)
          try {
            const q3 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("id", v)
              .limit(1)
              .maybeSingle();
            if (!q3.error && q3.data) {
              inviter = q3.data;
              break;
            }
            if (q3.error && String(q3.error.code || "") !== "PGRST116") {
              lastInviterErr = q3.error;
            }
          } catch (e) {
            // ignore
          }
        }

        if (!inviter) {

          return res.status(400).json({
            ok: false,
            error: "invalid_referral_code",
            message: REGISTER_USER_MSG.invalidReferralCode(refCodeRaw),
            supabase: lastInviterErr ? supabaseErrorPublic(lastInviterErr) : null,
          });
        }

        // Prevent cross-clinic referrals (must match clinic being registered)
        const inviterClinicId = inviter.clinic_id || null;
        if (inviterClinicId && String(inviterClinicId) !== String(supabaseClinicId)) {
          console.log("[REGISTER] Referral clinic mismatch:", {
            refCode: refCodeRaw,
            inviterClinicId,
            targetClinicId: supabaseClinicId,
          });
          return res.status(400).json({
            ok: false,
            error: "invalid_referral_code",
            message: REGISTER_USER_MSG.invalidReferralCode(refCodeRaw),
          });
        }

        const uuidLike = (s) =>
          /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(s || ""));

        let inviterCandidates = Array.from(
          new Set([inviter.id, inviter.patient_id].filter(Boolean))
        );

        let invitedCandidates = Array.from(
          new Set([supabasePatientRow?.id, supabasePatientRow?.patient_id, patientId].filter(Boolean))
        );

        // Some production schemas store referrals.*_patient_id as UUID.
        // Ensure we try UUID ids first by resolving from patient_id (p_xxx) when needed.
        const resolvedInviterUuids = (await Promise.all(inviterCandidates.map(resolvePatientUuidForReferral))).filter(Boolean);
        inviterCandidates = Array.from(new Set([...inviterCandidates, ...resolvedInviterUuids]));
        inviterCandidates = [
          ...inviterCandidates.filter((x) => uuidLike(x)),
          ...inviterCandidates.filter((x) => !uuidLike(x)),
        ];

        const resolvedInvitedUuids = (await Promise.all(invitedCandidates.map(resolvePatientUuidForReferral))).filter(Boolean);
        invitedCandidates = Array.from(new Set([...invitedCandidates, ...resolvedInvitedUuids]));
        invitedCandidates = [
          ...invitedCandidates.filter((x) => uuidLike(x)),
          ...invitedCandidates.filter((x) => !uuidLike(x)),
        ];

        // Self-referral guard (compare any representation)
        const inviterSet = new Set(inviterCandidates.map((x) => String(x)));
        const invitedSet = new Set(invitedCandidates.map((x) => String(x)));
        for (const x of inviterSet) {
          if (invitedSet.has(x)) {
            return res.status(400).json({
              ok: false,
              error: "invalid_referral_code",
              message: REGISTER_USER_MSG.selfReferralNotAllowed,
            });
          }
        }

        let created = null;
        let lastCreateErr = null;
        for (const invId of inviterCandidates) {
          for (const invitedId of invitedCandidates) {
            try {
              const referralData = {
                clinic_id: supabaseClinicId,
                inviter_patient_id: invId,
                invited_patient_id: invitedId,
                referral_code: generateReferralCodeV2(),
                status: "PENDING",
                inviter_discount_percent: null,
                invited_discount_percent: null,
                discount_percent: null,
                inviter_patient_name: inviter?.name || null,
                invited_patient_name: displayName || null,
              };
              created = await createReferralInDBFlexible(referralData);
              break;
            } catch (e) {
              lastCreateErr = e;
              // Unique violation (inviter+invited) -> treat as success
              if (String(e?.code || "") === "23505") {
                created = { id: null, duplicate: true };
                break;
              }
              // UUID mismatch -> try next candidate combo
              if (isInvalidUuidError(e)) {
                continue;
              }
            }
          }
          if (created) break;
        }

        if (!created) {
          console.error("[REGISTER] ❌ Failed to create referral in Supabase", supabaseErrorPublic(lastCreateErr));
          return res.status(500).json({
            ok: false,
            error: "referral_create_failed",
            message: REGISTER_USER_MSG.referralCreateFailed,
            supabase: supabaseErrorPublic(lastCreateErr),
          });
        }

        console.log("[REGISTER] ✅ Referral linked on register", {
          inviter: inviterCandidates[0],
          invited: invitedCandidates[0],
        });
      } else {
        // ================== FILE FALLBACK ==================
        const allPatients = readJson(PAT_FILE, {});
        let inviterPatientId = null;
        let inviterPatientName = null;

        for (const pid in allPatients) {
          const p = allPatients[pid];
          const code = String(p?.referralCode || p?.referral_code || "").trim();
          if (code && code === refCode) {
            inviterPatientId = pid;
            inviterPatientName = p?.name || "Unknown";
            break;
          }
          if (pid === refCode) {
            inviterPatientId = pid;
            inviterPatientName = p?.name || "Unknown";
            break;
          }
        }

        if (!inviterPatientId) {

        } else if (inviterPatientId === patientId) {

        } else if (canUseFileFallback()) {
          const referrals = readJson(REF_FILE, []);
          const referralList = Array.isArray(referrals) ? referrals : Object.values(referrals);
          referralList.push({
            id: rid("ref"),
            inviterPatientId,
            inviterPatientName,
            invitedPatientId: patientId,
            invitedPatientName: displayName,
            status: "PENDING",
            createdAt: now(),
            inviterDiscountPercent: null,
            invitedDiscountPercent: null,
            discountPercent: null,
            checkInAt: null,
            approvedAt: null,
            clinicCode: validatedClinicCode,
          });
          writeJson(REF_FILE, referralList);
        }
      }
    } catch (err) {

      // Don't fail registration if referral creation fails
    }
  }

  // Send OTP for email verification instead of returning token immediately
  try {
    // Review Mode Bypass: Skip OTP generation and saving for test@clinifly.net
    if (REVIEW_MODE && emailNormalized === "test@clinifly.net") {
      let reviewClinic = null;
      if (validatedClinicCode && isSupabaseEnabled()) {
        try {
          reviewClinic = await getClinicByCode(validatedClinicCode);
        } catch (_e) {
          /* ignore */
        }
      }
      return res.status(201).json({
        ok: true,
        clinicId: reviewClinic?.id || supabaseClinicId || null,
        clinicCode: reviewClinic?.clinic_code || validatedClinicCode || null,
        hasClinic: Boolean(reviewClinic?.id || supabaseClinicId),
        message: REGISTER_USER_MSG.reviewModeClinic,
        reviewMode: true,
        requires_verification: true,
        requiresOTP: true,
        email_sent: false,
      });
    }

    logRegisterTrace("/api/register", "STEP_OTP_BLOCK_ENTER", {
      email: maskEmailForLog(emailNormalized),
    });
    console.log("[REGISTER] register_otp_start", { route: "/api/register", email: maskEmailForLog(emailNormalized) });
    cleanupExpiredOTPs();

    logRegisterTrace("/api/register", "STEP_1_GENERATE_CODE", {});
    const otpCode = String(generateOTP()).trim();
    console.log("[REGISTER] register_otp_code_generated", {
      digits: otpCode.length,
      ...(OTP_DEBUG_LOG ? { code: otpCode } : {}),
    });

    logRegisterTrace("/api/register", "STEP_2_STORE_OTP_FILE", {});
    await saveOTP(emailNormalized, otpCode, 0);
    console.log("[REGISTER] register_otp_stored", { email: maskEmailForLog(emailNormalized) });

    if (!isTransactionalEmailConfigured()) {
      logRegisterTrace("/api/register", "STEP_OTP_EMAIL_NOT_CONFIGURED", {
        email: maskEmailForLog(emailNormalized),
      });
      console.error("[REGISTER] email transport missing → 503", {
        route: "/api/register",
        email: maskEmailForLog(emailNormalized),
        ...getTransactionalEmailDiagnostic(),
      });
      return res.status(503).json({
        ok: false,
        error: "email_not_configured",
        message: REGISTER_USER_MSG.otpEmailNotConfigured,
        hint: REGISTER_USER_MSG.otpEmailNotConfiguredHint,
      });
    }

    logRegisterTrace("/api/register", "STEP_3_BEFORE_SEND_EMAIL", {});
    console.log("[REGISTER] register_otp_before_send_email");

    let emailSent = false;
    try {
      await sendOTPEmail(emailNormalized, otpCode, patientLanguage);
      emailSent = true;
      console.log("[REGISTER] OTP_EMAIL_SENT", {
        route: "/api/register",
        email: maskEmailForLog(emailNormalized),
        patientId,
      });
      logRegisterTrace("/api/register", "STEP_4_AFTER_SEND_EMAIL", {});
      console.log("[REGISTER] register_otp_after_send_email", { email: maskEmailForLog(emailNormalized) });
    } catch (err) {
      console.error("[REGISTER] OTP_EMAIL_FAILED", {
        route: "/api/register",
        message: err?.message || err,
      });
    }

    return res.json(
      buildRegisterOtpSuccessJson({
        patientId,
        emailNormalized,
        patientLanguage,
        requestId,
        supabaseClinicId,
        validatedClinicCode,
        emailSent,
      }),
    );
  } catch (otpError) {
    if (res.headersSent) return;
    console.error("[REGISTER] register_otp_unexpected", otpError?.stack || otpError?.message || otpError);
    return res.status(500).json({
      ok: false,
      error: "internal_error",
      message: IS_PROD ? "Sunucu hatası. Lütfen tekrar deneyin." : String(otpError?.message || otpError),
    });
  }
  } catch (regErr) {
    console.error("[REGISTER] unhandled:", regErr?.stack || regErr?.message || regErr);
    if (!res.headersSent) {
      res.status(500).json({
        ok: false,
        error: "internal_error",
        message: IS_PROD ? "Sunucu hatası. Lütfen tekrar deneyin." : String(regErr?.message || regErr),
      });
    }
  }
});

// POST /api/lead-contact — non-registered visitor message (creates lead patient + unassigned thread; not visible to doctors until admin assigns)
app.post("/api/lead-contact", async (req, res) => {
  try {
    const body = req.body || {};
    const clinicCode = String(body.clinicCode || body.clinic_code || "").trim();
    const name = String(body.name || body.patientName || "").trim();
    const email = String(body.email || "").trim();
    const phone = String(body.phone || "").trim();
    const text = String(body.text || body.message || body.content || "").trim();
    const result = await createLeadFromPublicContact({ clinicCode, name, email, phone, text });
    if (!result.ok) {
      const code = result.status || 400;
      return res.status(code).json({
        ok: false,
        error: result.error || "lead_contact_failed",
        ...(result.details ? { details: result.details } : {}),
      });
    }
    return res.status(201).json({
      ok: true,
      patientId: result.patientId,
      legacyPatientId: result.legacyPatientId,
      message: result.message,
      status: "unassigned",
      assignedDoctorId: null,
    });
  } catch (e) {
    console.error("[POST /api/lead-contact]", e?.message || e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// ================== PATIENT LOGIN ==================
// Removed duplicate endpoint - using the one at line 509

// ================== PATIENT REGISTER (alias) ==================
// Same as /api/register/patient — some clients use the swapped path
app.post(["/api/patient/register", "/api/register/patient"], async (req, res) => {
  try {
  const body = req.body || {};
  const {
    name = "",
    patientName: bodyPatientName = "",
    fullName = "",
    phone = "",
    email = "",
    language = "",
  } = body;
  const referralCode = String(body.referralCode || body.inviterReferralCode || "").trim();
  /** Full display name: mobile often sends patientName; keep single field in DB (name/full_name), leave first/last empty */
  const displayName = String(bodyPatientName || fullName || name || "").trim();

  let clinicCode = "";
  try {
    clinicCode = await augmentRegisterClinicFromBody(body);
  } catch (augErr) {
    console.warn("[REGISTER /api/patient/register] augmentRegisterClinicFromBody:", augErr?.message || augErr);
  }

  console.log(`[REGISTER /api/patient/register] Request received:`, { 
    name: displayName ? "***" : "", 
    phone: phone ? "***" : "", 
    email: email ? "***" : "",
    clinicCode: clinicCode || "(empty)",
    hasClinicCode: !!clinicCode 
  });
  console.log("[REGISTER] REGISTER_START", { route: "/api/register/patient" });

  // Email is required for registration
  if (!email || !String(email).trim()) {
    return res.status(400).json({
      ok: false,
      error: "email_required",
      message: REGISTER_USER_MSG.emailRequired,
    });
  }

  // Validate email format
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailNormalized = String(email).trim().toLowerCase();
  if (!emailRegex.test(emailNormalized)) {
    return res.status(400).json({
      ok: false,
      error: "invalid_email",
      message: REGISTER_USER_MSG.invalidEmail,
    });
  }

  const patientLanguage = normalizePatientLanguage(language);

  // Phone is OPTIONAL (email-only OTP). If present, validate and normalize.
  const phoneTrimmed = String(phone || "").trim();
  const phoneNormalized = phoneTrimmed ? normalizePhone(phoneTrimmed) : "";
  if (phoneTrimmed && (!phoneNormalized || phoneNormalized.length < 10)) {
    return res.status(400).json({
      ok: false,
      error: "invalid_phone",
      message: REGISTER_USER_MSG.invalidPhone,
    });
  }

  logRegisterTrace("/api/register/patient", "REGISTER_START", {
    email: maskEmailForLog(emailNormalized),
  });

  // Klinik kodu isteğe bağlı — yalnızca gönderilmiş ve boş değilse doğrulanır
  let validatedClinicCode = null;
  let foundClinicId = null;
  if (clinicCode && String(clinicCode).trim()) {
    const code = String(clinicCode).trim().toUpperCase();
    let foundClinic = null;

    // SUPABASE: Primary lookup (source of truth)
    if (isSupabaseEnabled()) {
      try {
        foundClinic = await getClinicByCode(code);
        if (foundClinic) {
          foundClinicId = foundClinic.id;

        }
      } catch (e) {

      }
    }
    
    // First check CLINIC_FILE (single clinic object)
    if (!foundClinic) {
      const singleClinic = readJson(CLINIC_FILE, {});
      if (singleClinic && singleClinic.clinicCode) {
        const singleClinicCode = String(singleClinic.clinicCode).toUpperCase();

        if (singleClinicCode === code) {
          foundClinic = singleClinic;

        }
      }
    }
    
    // Then check CLINICS_FILE (multiple clinics object)
    if (!foundClinic) {
      const clinics = readJson(CLINICS_FILE, {});

      
      // Search for clinic by clinicCode or code field
      for (const clinicId in clinics) {
        const clinic = clinics[clinicId];
        if (clinic) {
          // Check both clinicCode and code fields
          const clinicCodeToCheck = clinic.clinicCode || clinic.code;
          if (clinicCodeToCheck) {
            const clinicCodeUpper = String(clinicCodeToCheck).toUpperCase();

            if (clinicCodeUpper === code) {
              foundClinic = clinic;
              foundClinicId = foundClinicId || clinicId;

              break;
            }
          }
        }
      }
    }
    
    if (foundClinic) {
      validatedClinicCode = code;

    } else {
      // Clinic not found - return error

      return res.status(404).json({
        ok: false,
        error: "clinic_not_found",
        message: REGISTER_USER_MSG.clinicNotFound(code),
      });
    }
  } else {

  }
  


  // EMAIL is the identity: if a patient already exists for this email, reuse its patientId.
  let patientId = null;
  if (isSupabaseEnabled()) {
    try {
      const { data: existing, error: e } = await supabase
        .from("patients")
        .select("id, patient_id, email")
        .eq("email", emailNormalized)
        .single();
      if (!e && existing) {
        patientId = existing.patient_id || existing.id;
      } else if (e && String(e.code || "") !== "PGRST116") {
        console.error("[REGISTER /api/patient/register] Supabase patient lookup by email failed", {
          message: e.message,
          code: e.code,
          details: e.details,
        });
      }
    } catch (err) {

    }
  }
  if (!patientId) {
    const patientsByFile = readJson(PAT_FILE, {});
    for (const pid in patientsByFile) {
      const em = String(patientsByFile[pid]?.email || "").trim().toLowerCase();
      if (em && em === emailNormalized) {
        patientId = pid;
        break;
      }
    }
  }
  if (!patientId) patientId = rid("p");
  const requestId = rid("req");
  const token = makeToken();

  // SUPABASE: Insert patient (PRIMARY - production source of truth)
  let supabaseClinicId = null;
  let supabasePatientRow = null;
  if (isSupabaseEnabled() && validatedClinicCode) {
    try {
      const clinic = await getClinicByCode(validatedClinicCode);
      if (clinic) {
        supabaseClinicId = clinic.id;

      } else {

      }
    } catch (err) {

    }
  }

  if (isSupabaseEnabled() && !supabaseClinicId) {
    console.log(
      "[REGISTER /api/patient/register] open signup — no clinic (clinic_id null). Optional: DEFAULT_CLINIC_* or clinicCode later.",
    );
  }

  logRegisterTrace("/api/register/patient", "STEP_BEFORE_DB_UPSERT", {
    supabase: isSupabaseEnabled(),
  });

  // === SUPABASE PATIENT UPSERT (ZORUNLU) ===
  if (isSupabaseEnabled()) {
    const payload = {
      patient_id: patientId, // legacy app id (p_xxx)
      email: emailNormalized,
      name: displayName,
      full_name: displayName,
      first_name: "",
      last_name: "",
      clinic_id: supabaseClinicId,
      status: "PENDING",
      language: patientLanguage,
      role: (req.body?.role || "PATIENT").toUpperCase(), // 🔥 NORMALIZE ROLE TO UPPERCASE
      ...(phoneNormalized ? { phone: phoneNormalized } : {}),
    };
    let { data: patientUpsertRow, error: patientUpsertErr } = await supabase
      .from("patients")
      .upsert(
        payload,
        {
          onConflict: "email",
        }
      )
      .select()
      .single();

    if (patientUpsertErr) {
      console.error("[SUPABASE] PATIENT UPSERT FAILED", {
        message: patientUpsertErr.message,
        code: patientUpsertErr.code,
        details: patientUpsertErr.details,
        hint: patientUpsertErr.hint,
      });
      const detailBlob = `${patientUpsertErr.details || ""} ${patientUpsertErr.message || ""}`.toLowerCase();
      const code23505 = String(patientUpsertErr.code || "") === "23505";
      const isPhoneConstraint =
        /patients_phone_unique|key \(phone\)/.test(detailBlob) ||
        String(patientUpsertErr.message || "").toLowerCase().includes("patients_phone_unique");
      const isEmailConstraint =
        /patients_email_unique|key \(email\)/.test(detailBlob) ||
        String(patientUpsertErr.message || "").toLowerCase().includes("patients_email_unique");
      const isDup =
        code23505 ||
        detailBlob.includes("duplicate key");

      const reusePatientRow = async (existing) => {
        patientId = existing.patient_id || existing.id;
        if (patientLanguage && existing.language !== patientLanguage) {
          await supabase.from("patients").update({ language: patientLanguage }).eq("id", existing.id);
        }
        try {
          const { data: fullRow } = await supabase
            .from("patients")
            .select("id, patient_id, clinic_id, name, referral_code, email")
            .eq("id", existing.id)
            .limit(1)
            .maybeSingle();
          supabasePatientRow = fullRow || existing;
        } catch {
          supabasePatientRow = existing;
        }
        patientUpsertRow = supabasePatientRow;
        patientUpsertErr = null;
      };

      let resolved = false;

      if (isDup) {
        if (isPhoneConstraint && phoneNormalized) {
          const { data: byPhone, error: ePhone } = await supabase
            .from("patients")
            .select("id, patient_id, email, language")
            .eq("phone", phoneNormalized)
            .limit(1)
            .maybeSingle();
          if (!ePhone && byPhone) {
            const em = String(byPhone.email || "").trim().toLowerCase();
            if (em !== emailNormalized) {
              return res.status(409).json({
                ok: false,
                error: "phone_already_registered",
                message: REGISTER_USER_MSG.phoneAlreadyRegistered,
              });
            }
            await reusePatientRow(byPhone);
            console.log("[REGISTER] PHONE_CONFLICT_HANDLED", {
              route: "/api/register/patient",
              idempotent: true,
            });
            resolved = true;
          }
        }

        if (!resolved && patientUpsertErr && (isEmailConstraint || (code23505 && !isPhoneConstraint))) {
          try {
            const { data: existing, error: e2 } = await supabase
              .from("patients")
              .select("id, patient_id, email, language")
              .eq("email", emailNormalized)
              .limit(1)
              .maybeSingle();
            if (!e2 && existing) {
              await reusePatientRow(existing);
              resolved = true;
            } else {
              console.error("[REGISTER /api/patient/register] Unique email but failed to fetch existing patient", {
                message: e2?.message,
                code: e2?.code,
                details: e2?.details,
              });
              return res.status(500).json({
                ok: false,
                error: "register_failed",
                message: REGISTER_USER_MSG.registerFailedLookup,
              });
            }
          } catch (e3) {
            return res.status(500).json({
              ok: false,
              error: "register_failed",
              message: REGISTER_USER_MSG.registerFailed,
            });
          }
        }

        if (!resolved && patientUpsertErr && phoneNormalized && !isPhoneConstraint) {
          const { data: byPhone, error: ePhone } = await supabase
            .from("patients")
            .select("id, patient_id, email, language")
            .eq("phone", phoneNormalized)
            .limit(1)
            .maybeSingle();
          if (!ePhone && byPhone) {
            const em = String(byPhone.email || "").trim().toLowerCase();
            if (em !== emailNormalized) {
              return res.status(409).json({
                ok: false,
                error: "phone_already_registered",
                message: REGISTER_USER_MSG.phoneAlreadyRegistered,
              });
            }
            await reusePatientRow(byPhone);
            console.log("[REGISTER] PHONE_CONFLICT_HANDLED", {
              route: "/api/register/patient",
              idempotent: true,
            });
            resolved = true;
          }
        }
      }

      if (patientUpsertErr) {
        const hintNull =
          !supabaseClinicId &&
          String(patientUpsertErr.message || "")
            .toLowerCase()
            .includes("clinic_id");
        return res.status(500).json({
          ok: false,
          error: "register_failed",
          message: REGISTER_USER_MSG.registerFailed,
          ...(hintNull ? { hint: REGISTER_USER_MSG.clinicIdNullableHint } : {}),
        });
      }
    }

    if (patientUpsertRow?.id) console.log("[SUPABASE] ✅ patient upserted:", patientUpsertRow.id);
    if (patientUpsertRow) supabasePatientRow = patientUpsertRow;
    logRegisterTrace("/api/register/patient", "STEP_AFTER_DB_UPSERT", {
      patientRowId: patientUpsertRow?.id || supabasePatientRow?.id || null,
    });
  }

  // FILE-BASED: Fallback storage (for backward compatibility)
  const patients = readJson(PAT_FILE, {});
  const existingFile = patients[patientId] || null;
  patients[patientId] = {
    patientId,
    name: displayName,
    ...(phoneNormalized ? { phone: phoneNormalized } : {}),
    email: emailNormalized,
    language: patientLanguage,
    status: "PENDING",
    clinicCode: validatedClinicCode,
    createdAt: existingFile?.createdAt || now(),
    updatedAt: now(),
  };
  writeJson(PAT_FILE, patients);

  // tokens
  const tokens = readJson(TOK_FILE, {});
  tokens[token] = { patientId, role: "PENDING", createdAt: now() };
  writeJson(TOK_FILE, tokens);

  // registrations (array/object safe)
  const regs = readJson(REG_FILE, {});
  const row = {
    requestId,
    patientId,
    name: displayName,
    phone: phoneNormalized, // Use normalized phone
    email: emailNormalized,
    status: "PENDING",
    clinicCode: validatedClinicCode, // Keep parity with /api/register
    createdAt: now(),
    updatedAt: now(),
  };
  if (Array.isArray(regs)) {
    regs.push(row);
    writeJson(REG_FILE, regs);
  } else {
    regs[requestId] = row;
    writeJson(REG_FILE, regs);
  }

  logRegisterTrace("/api/register/patient", "STEP_BEFORE_REFERRAL_AND_OTP", {});

  // Handle referral code if provided (Supabase-first; file fallback only when enabled)
  if (referralCode && String(referralCode).trim()) {
    try {
      const refCodeRaw = String(referralCode).trim();
      const refCode = refCodeRaw;

      // ================== SUPABASE PATH (source of truth) ==================
      if (isSupabaseEnabled() && supabaseClinicId) {
        const variants = Array.from(
          new Set([refCode, refCode.toUpperCase(), refCode.toLowerCase()].filter(Boolean))
        );

        let inviter = null;
        let lastInviterErr = null;
        for (const v of variants) {
          // 1) referral_code match (if column exists)
          try {
            const q1 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("referral_code", v)
              .limit(1)
              .maybeSingle();
            if (!q1.error && q1.data) {
              inviter = q1.data;
              break;
            }
            if (q1.error && !isMissingColumnError(q1.error, "referral_code") && String(q1.error.code || "") !== "PGRST116") {
              lastInviterErr = q1.error;
            }
          } catch {}

          // 2) patient_id match (if column exists)
          try {
            const q2 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("patient_id", v)
              .limit(1)
              .maybeSingle();
            if (!q2.error && q2.data) {
              inviter = q2.data;
              break;
            }
            if (q2.error && !isMissingColumnError(q2.error, "patient_id") && String(q2.error.code || "") !== "PGRST116") {
              lastInviterErr = q2.error;
            }
          } catch {}

          // 3) id match (covers schemas where patient id is stored in `id`)
          try {
            const q3 = await supabase
              .from("patients")
              .select("id, patient_id, clinic_id, name, referral_code")
              .eq("id", v)
              .limit(1)
              .maybeSingle();
            if (!q3.error && q3.data) {
              inviter = q3.data;
              break;
            }
            if (q3.error && String(q3.error.code || "") !== "PGRST116") {
              lastInviterErr = q3.error;
            }
          } catch {}
        }

        if (!inviter) {

          return res.status(400).json({
            ok: false,
            error: "invalid_referral_code",
            message: REGISTER_USER_MSG.invalidReferralCode(refCodeRaw),
            supabase: lastInviterErr ? supabaseErrorPublic(lastInviterErr) : null,
          });
        }

        // Prevent cross-clinic referrals (must match clinic being registered)
        const inviterClinicId = inviter.clinic_id || null;
        if (inviterClinicId && String(inviterClinicId) !== String(supabaseClinicId)) {
          return res.status(400).json({
            ok: false,
            error: "invalid_referral_code",
            message: REGISTER_USER_MSG.invalidReferralCode(refCodeRaw),
          });
        }

        const uuidLike = (s) =>
          /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(s || ""));

        let inviterCandidates = Array.from(
          new Set([inviter.id, inviter.patient_id].filter(Boolean))
        );

        let invitedCandidates = Array.from(
          new Set([supabasePatientRow?.id, supabasePatientRow?.patient_id, patientId].filter(Boolean))
        );

        // Some production schemas store referrals.*_patient_id as UUID.
        // Ensure we try UUID ids first by resolving from patient_id (p_xxx) when needed.
        const resolvedInviterUuids = (await Promise.all(inviterCandidates.map(resolvePatientUuidForReferral))).filter(Boolean);
        inviterCandidates = Array.from(new Set([...inviterCandidates, ...resolvedInviterUuids]));
        inviterCandidates = [
          ...inviterCandidates.filter((x) => uuidLike(x)),
          ...inviterCandidates.filter((x) => !uuidLike(x)),
        ];

        const resolvedInvitedUuids = (await Promise.all(invitedCandidates.map(resolvePatientUuidForReferral))).filter(Boolean);
        invitedCandidates = Array.from(new Set([...invitedCandidates, ...resolvedInvitedUuids]));
        invitedCandidates = [
          ...invitedCandidates.filter((x) => uuidLike(x)),
          ...invitedCandidates.filter((x) => !uuidLike(x)),
        ];

        // Self-referral guard (compare any representation)
        const inviterSet = new Set(inviterCandidates.map((x) => String(x)));
        const invitedSet = new Set(invitedCandidates.map((x) => String(x)));
        for (const x of inviterSet) {
          if (invitedSet.has(x)) {
            return res.status(400).json({
              ok: false,
              error: "invalid_referral_code",
              message: REGISTER_USER_MSG.selfReferralNotAllowed,
            });
          }
        }

        let created = null;
        let lastCreateErr = null;
        for (const invId of inviterCandidates) {
          for (const invitedId of invitedCandidates) {
            try {
              const referralData = {
                clinic_id: supabaseClinicId,
                inviter_patient_id: invId,
                invited_patient_id: invitedId,
                referral_code: generateReferralCodeV2(),
                status: "PENDING",
                inviter_discount_percent: null,
                invited_discount_percent: null,
                discount_percent: null,
                inviter_patient_name: inviter?.name || null,
                invited_patient_name: displayName || null,
              };
              created = await createReferralInDBFlexible(referralData);
              break;
            } catch (e) {
              lastCreateErr = e;
              if (String(e?.code || "") === "23505") {
                created = { id: null, duplicate: true };
                break;
              }
              if (isInvalidUuidError(e)) {
                continue;
              }
            }
          }
          if (created) break;
        }

        if (!created) {
          console.error("[PATIENT/REGISTER] ❌ Failed to create referral in Supabase", supabaseErrorPublic(lastCreateErr));
          return res.status(500).json({
            ok: false,
            error: "referral_create_failed",
            message: REGISTER_USER_MSG.referralCreateFailed,
            supabase: supabaseErrorPublic(lastCreateErr),
          });
        }
      } else {
        // ================== FILE FALLBACK ==================
        const allPatients = readJson(PAT_FILE, {});
        let inviterPatientId = null;
        let inviterPatientName = null;

        for (const pid in allPatients) {
          const p = allPatients[pid];
          const code = String(p?.referralCode || p?.referral_code || "").trim();
          if (code && code === refCode) {
            inviterPatientId = pid;
            inviterPatientName = p?.name || "Unknown";
            break;
          }
          if (pid === refCode) {
            inviterPatientId = pid;
            inviterPatientName = p?.name || "Unknown";
            break;
          }
        }

        if (inviterPatientId && inviterPatientId !== patientId && canUseFileFallback()) {
          const referrals = readJson(REF_FILE, []);
          const referralList = Array.isArray(referrals) ? referrals : Object.values(referrals);
          referralList.push({
            id: rid("ref"),
            inviterPatientId,
            inviterPatientName,
            invitedPatientId: patientId,
            invitedPatientName: displayName,
            status: "PENDING",
            createdAt: now(),
            inviterDiscountPercent: null,
            invitedDiscountPercent: null,
            discountPercent: null,
            checkInAt: null,
            approvedAt: null,
            clinicCode: validatedClinicCode,
          });
          writeJson(REF_FILE, referralList);
        }
      }
    } catch (err) {

    }
  }

  // Send OTP for email verification: 503 only if email transport not configured; send errors → 200 + email_sent: false
  try {
    logRegisterTrace("/api/register/patient", "STEP_OTP_BLOCK_ENTER", {
      email: maskEmailForLog(emailNormalized),
    });
    console.log("[REGISTER] register_otp_start", {
      route: "/api/register/patient",
      email: maskEmailForLog(emailNormalized),
    });
    cleanupExpiredOTPs();

    logRegisterTrace("/api/register/patient", "STEP_1_GENERATE_CODE", {});
    const otpCode = String(generateOTP()).trim();
    console.log("[REGISTER] register_otp_code_generated", {
      digits: otpCode.length,
      ...(OTP_DEBUG_LOG ? { code: otpCode } : {}),
    });
    const otpHash = await bcrypt.hash(otpCode, 10);

    logRegisterTrace("/api/register/patient", "STEP_2_STORE_OTP_HASH", {});
    await storeOTPForEmail(emailNormalized, otpHash, null, {
      type: "patient_registration",
      phone: phone || "",
      name: name || "",
      language: language || "en",
    });
    console.log("[REGISTER] register_otp_stored", { email: maskEmailForLog(emailNormalized) });

    if (!isTransactionalEmailConfigured()) {
      logRegisterTrace("/api/register/patient", "STEP_OTP_EMAIL_NOT_CONFIGURED", {
        email: maskEmailForLog(emailNormalized),
      });
      console.error("[REGISTER] email transport missing → 503", {
        route: "/api/register/patient",
        email: maskEmailForLog(emailNormalized),
        ...getTransactionalEmailDiagnostic(),
      });
      return res.status(503).json({
        ok: false,
        error: "email_not_configured",
        message: REGISTER_USER_MSG.otpEmailNotConfigured,
        hint: REGISTER_USER_MSG.otpEmailNotConfiguredHint,
      });
    }

    logRegisterTrace("/api/register/patient", "STEP_3_BEFORE_SEND_EMAIL", {});
    console.log("[REGISTER] register_otp_before_send_email");

    let emailSent = false;
    try {
      await sendOTPEmail(emailNormalized, otpCode, patientLanguage);
      emailSent = true;
      console.log("[REGISTER] OTP_EMAIL_SENT", {
        route: "/api/register/patient",
        email: maskEmailForLog(emailNormalized),
        patientId,
      });
      logRegisterTrace("/api/register/patient", "STEP_4_AFTER_SEND_EMAIL", {});
      console.log("[REGISTER] register_otp_after_send_email", { email: maskEmailForLog(emailNormalized) });
    } catch (err) {
      console.error("[REGISTER] OTP_EMAIL_FAILED", {
        route: "/api/register/patient",
        message: err?.message || err,
      });
    }

    return res.json(
      buildRegisterOtpSuccessJson({
        patientId,
        emailNormalized,
        patientLanguage,
        requestId,
        supabaseClinicId,
        validatedClinicCode,
        emailSent,
      }),
    );
  } catch (otpError) {
    if (res.headersSent) return;
    console.error("[REGISTER] register_otp_unexpected", otpError?.stack || otpError?.message || otpError);
    return res.status(500).json({
      ok: false,
      error: "internal_error",
      message: IS_PROD ? "Sunucu hatası. Lütfen tekrar deneyin." : String(otpError?.message || otpError),
    });
  }
  } catch (regErr) {
    console.error("[REGISTER /api/patient/register] unhandled:", regErr?.stack || regErr?.message || regErr);
    if (!res.headersSent) {
      res.status(500).json({
        ok: false,
        error: "internal_error",
        message: IS_PROD ? "Sunucu hatası. Lütfen tekrar deneyin." : String(regErr?.message || regErr),
      });
    }
  }
});

// ================== AUTH ==================
function requireToken(req, res, next) {
  const auth = req.headers.authorization || "";
  const token = auth.startsWith("Bearer ") ? auth.slice(7) : "";
  // Also check x-patient-token header (for compatibility)
  const altToken = req.headers["x-patient-token"] || "";
  const finalToken = token || altToken;
  
  if (!finalToken) {
    return res.status(401).json({ ok: false, error: "Unauthorized", code: "missing_token" });
  }

  const tokens = readJson(TOK_FILE, {});
  const t = tokens[finalToken];
  if (!t?.patientId) {
    // New mobile flow uses JWT patient tokens (from /auth/verify-otp)
    if (finalToken.startsWith("eyJ")) {
      try {
        const decoded = jwt.verify(finalToken, JWT_SECRET);
        const pid = decoded?.patientId;
        if (pid) {
          req.patientId = pid;
          req.role = (decoded?.role || decoded?.status || "PENDING").toUpperCase(); // 🔥 NORMALIZE ROLE TO UPPERCASE
          req.tokenType = "jwt_patient";
          return next();
        }
      } catch (e) {

      }
    }



    return res.status(401).json({
      ok: false,
      error: "Unauthorized",
      code: "bad_token",
    });
  }

  req.patientId = t.patientId;
  req.role = (t.role || "PENDING").toUpperCase(); // 🔥 NORMALIZE ROLE TO UPPERCASE
  req.tokenType = "legacy_patient";
  next();
}

// POST /api/leads — AI ekranından “teklif al” (patient intent → clinics)
// Body: { userId, treatments, country, imageUrl } — userId must match token patient.
app.post("/api/leads", requireToken, async (req, res) => {
  try {
    const patientId = String(req.patientId || "").trim();
    const body = req.body || {};
    const userId = String(body.userId || "").trim();
    if (userId && userId !== patientId) {
      return res.status(403).json({ ok: false, error: "user_mismatch", message: "Token ile kullanıcı uyuşmuyor." });
    }
    const treatments = Array.isArray(body.treatments) ? body.treatments.map((t) => String(t).trim()).filter(Boolean) : [];
    const country = String(body.country || "").trim() || null;
    const imageUrl = String(body.imageUrl || "").trim() || null;

    const lead = {
      id: crypto.randomUUID(),
      created_at: new Date().toISOString(),
      patient_id: patientId,
      user_id: patientId,
      treatments,
      country,
      image_url: imageUrl,
      source: "ai_result_offer",
    };

    const list = readJson(AI_LEADS_FILE, []);
    list.push(lead);
    writeJson(AI_LEADS_FILE, list);

    if (isSupabaseEnabled()) {
      try {
        const resolvedPid = await resolveMessagesPatientDbId(patientId);
        if (resolvedPid) {
          const row = {
            id: lead.id,
            patient_id: resolvedPid,
            treatments,
            country,
            image_url: imageUrl,
            created_at: lead.created_at,
            source: "ai_result_offer",
          };
          const r1 = await supabase.from("ai_leads").insert(row);
          if (r1.error) {
            const r2 = await supabase.from("leads").insert(row);
            if (r2.error) {
              console.warn("[LEADS] Supabase insert skipped (file OK):", r1.error.message, "|", r2.error.message);
            }
          }
        }
      } catch (e) {
        console.warn("[LEADS] Supabase optional insert failed:", e?.message);
      }
    }

    console.log("[LEADS] saved offer request", lead.id, "| patient:", patientId.slice(0, 8), "| nTreat:", treatments.length);
    return res.json({ ok: true, leadId: lead.id, message: "Talebiniz kliniklere gönderildi" });
  } catch (e) {
    console.error("[LEADS]", e?.message);
    return res.status(500).json({ ok: false, error: "lead_save_failed", message: e?.message || "Kayıt başarısız" });
  }
});

// ================== ME ==================
app.get("/api/me", requireToken, (req, res) => {
  const patients = readJson(PAT_FILE, {});
  const p = patients[req.patientId] || null;

  res.json({
    ok: true,
    patientId: req.patientId,
    role: req.role,
    status: p?.status || req.role,
    name: p?.name || "",
    phone: p?.phone || "",
  });
});

// ================== DOCTOR-ONLY OTP AUTHENTICATION ==================
async function resolveDoctorForOtp({ email, phone }) {
  const emailNormalized = email ? String(email).trim().toLowerCase() : "";
  const phoneTrimmed = phone ? String(phone).trim() : "";
  const phoneNormalized = phoneTrimmed ? normalizePhone(phoneTrimmed) : "";

  console.log("[DOCTOR OTP] Looking up doctor with:", {
    email: emailNormalized || '(none)',
    phone: phoneNormalized || '(none)',
    originalPhone: phone || '(none)'
  });



  let foundDoctor = null;
  let foundDoctorId = null;
  let foundPhone = phoneNormalized || null;
  let foundLanguage = "en";
  let resolvedEmail = emailNormalized || "";

  const selectColumns = "id, doctor_id, email, phone, status, name, language, clinic_id"; // 🔥 DOCTOR TABLE FIELDS

  if (isSupabaseEnabled()) {
    try {
      // 🔥 FIX: Query DOCTORS table only
      if (emailNormalized) {
        const { data: row, error: pErr } = await supabase
          .from("doctors") // 🔥 DOCTORS TABLE
          .select(selectColumns)
          .eq("email", emailNormalized)
          .single();
        if (!pErr && row) {
          foundDoctor = row;

        } else if (pErr && String(pErr.code || "") !== "PGRST116") {
          console.error("[DOCTOR OTP] Supabase doctor lookup (email) failed:", {
            message: pErr.message,
            code: pErr.code,
            details: pErr.details,
          });
        }
      }

      if (!foundDoctor && phoneNormalized) {
        const { data: row, error: pErr } = await supabase
          .from("doctors") // 🔥 DOCTORS TABLE
          .select(selectColumns)
          .eq("phone", phoneNormalized)
          .single();
        if (!pErr && row) {
          foundDoctor = row;

        } else if (pErr && String(pErr.code || "") !== "PGRST116") {
          console.error("[DOCTOR OTP] Supabase doctor lookup (phone) failed:", {
            message: pErr.message,
            code: pErr.code,
            details: pErr.details,
          });
        }
      }
    } catch (e) {

    }
  }

  // File-based fallback (if needed)
  if (!foundDoctor) {
    // Add file-based lookup logic here if needed

  }

  if (foundDoctor) {
    foundDoctorId = foundDoctor.doctor_id || foundDoctor.id; // 🔥 DOCTOR: use doctor_id
    foundPhone = foundDoctor.phone || phoneNormalized;
    foundLanguage = foundDoctor.language || "en";
    resolvedEmail = foundDoctor.email || emailNormalized;
  }

  return {
    doctor: foundDoctor,
    doctorId: foundDoctorId,
    email: resolvedEmail,
    phone: foundPhone,
    language: foundLanguage,
  };
}

async function resolvePatientForOtp({ email, phone }) {
  const emailNormalized = email ? String(email).trim().toLowerCase() : "";
  const phoneTrimmed = phone ? String(phone).trim() : "";
  const phoneNormalized = phoneTrimmed ? normalizePhone(phoneTrimmed) : "";

  console.log("LOGIN PHONE:", phone);
  console.log("SUPABASE URL:", process.env.SUPABASE_URL);

  let foundPatient = null;
  let foundPatientId = null;
  let foundPhone = phoneNormalized || null;
  let foundLanguage = "en";
  let resolvedEmail = emailNormalized || "";

  // Initialize foundPatientId to prevent undefined errors
  foundPatientId = null;

  const selectColumns = "id, patient_id, email, phone, status, name, language, role"; // 🔥 ADD ROLE COLUMN

  if (isSupabaseEnabled()) {
    try {
      // Use .limit(1) instead of .single() to avoid PGRST116 failures when
      // multiple clinics share the same email (or duplicate rows exist).
      if (emailNormalized) {
        const { data: rows, error: pErr } = await supabase
          .from("patients")
          .select(selectColumns)
          .eq("email", emailNormalized)
          .limit(1);
        if (!pErr && rows && rows.length > 0) {
          foundPatient = rows[0];
        } else if (pErr) {
          console.error("[OTP] Supabase patient lookup (email) failed:", {
            message: pErr.message,
            code: pErr.code,
            details: pErr.details,
          });
        }
      }

      if (!foundPatient && phoneNormalized) {
        const { data: rows, error: pErr } = await supabase
          .from("patients")
          .select(selectColumns)
          .eq("phone", phoneNormalized)
          .limit(1);
        if (!pErr && rows && rows.length > 0) {
          foundPatient = rows[0];
        } else if (pErr) {
          console.error("[OTP] Supabase patient lookup (phone) failed:", {
            message: pErr.message,
            code: pErr.code,
            details: pErr.details,
          });
        }
      }
    } catch (e) {
      console.error("[OTP] resolvePatientForOtp unexpected error:", e?.message || e);
    }
  }

  if (!foundPatient) {
    console.log("[PATIENT OTP] No patient found in Supabase, checking file...");
    const patients = readJson(PAT_FILE, {});
    console.log("[PATIENT OTP] File patients count:", Object.keys(patients).length);
    for (const pid in patients) {
      const p = patients[pid];
      const em = String(p?.email || "").trim().toLowerCase();
      const ph = normalizePhone(String(p?.phone || ""));
      if ((emailNormalized && em === emailNormalized) || (phoneNormalized && ph === phoneNormalized)) {
        console.log("[PATIENT OTP] Found patient in file:", pid);
        foundPatient = p;
        foundPatientId = pid;
        foundPhone = p?.phone || foundPhone;
        foundLanguage = normalizePatientLanguage(p?.language);
        resolvedEmail = em || resolvedEmail;
        break;
      }
    }
  }

  if (foundPatient) {
    // Önce Supabase UUID (id) — API / token ile uyum; yoksa legacy patient_id / patientId (p_…)
    foundPatientId =
      foundPatientId ||
      foundPatient.id ||
      foundPatient.patient_id ||
      foundPatient.patientId;
    foundPhone = foundPatient.phone || foundPhone;
    foundLanguage = normalizePatientLanguage(foundPatient.language);
    resolvedEmail = String(foundPatient.email || resolvedEmail || "").trim().toLowerCase();

  }

  console.log("USER QUERY RESULT:", foundPatient);

  const result = {
    patient: foundPatient,
    patientId: foundPatientId,
    email: resolvedEmail,
    phone: foundPhone,
    language: foundLanguage,
    phoneNormalized,
  };
  

  return result;
}

// POST /auth/request-otp
// Request OTP: takes email, phone, role, finds user by role, sends OTP
app.post("/auth/request-otp", async (req, res) => {
  console.log("[AUTH REQUEST-OTP] 🔥 ENDPOINT HIT");
  try {
    console.log("[AUTH REQUEST-OTP] FULL BODY:", JSON.stringify(req.body, null, 2));
    
    const { email, phone, role } = req.body || {};
    
    console.log("[AUTH REQUEST-OTP] ROLE:", role);
    console.log("[AUTH REQUEST-OTP] PHONE:", phone);
    console.log("[AUTH REQUEST-OTP] EMAIL:", email);
    
    if (role === "DOCTOR") {
      console.log("[AUTH REQUEST-OTP] 🔥 DOCTOR LOOKUP PATH");
    } else {
      console.log("[AUTH REQUEST-OTP] 🔥 PATIENT LOOKUP PATH");
    }
    
    // 🔥 CRITICAL: Role is REQUIRED
    if (!role || (role !== "DOCTOR" && role !== "PATIENT")) {
      return res.status(400).json({ 
        ok: false, 
        error: "role_required", 
        message: "Role parameter is required (DOCTOR or PATIENT)." 
      });
    }
    
    if ((!email || !String(email).trim()) && (!phone || !String(phone).trim())) {
      return res.status(400).json({ ok: false, error: "email_or_phone_required", message: "Email veya telefon gereklidir." });
    }

    const emailNormalized = email ? String(email).trim().toLowerCase() : "";
    const phoneNormalized = phone ? normalizePhone(String(phone)) : "";
    
    // Check rate limit (email-based)
    if (!checkRateLimit(emailNormalized)) {
      return res.status(429).json({ 
        ok: false, 
        error: "rate_limit_exceeded", 
        message: "Çok fazla OTP isteği. Lütfen daha sonra tekrar deneyin." 
      });
    }

    let resolved;
    let foundUserId;
    let foundLanguage;
    let foundPhone;
    let resolvedEmail;
    let errorMessage;

    if (role === "DOCTOR") {
      // 🔥 DOCTOR LOOKUP
      resolved = await resolveDoctorForOtp({ email: emailNormalized, phone: phoneNormalized });
      foundUserId = resolved.doctorId;
      foundLanguage = resolved.language;
      foundPhone = resolved.phone;
      resolvedEmail = resolved.email;
      errorMessage = "Bu telefon numarası ile kayıtlı doktor bulunamadı. Lütfen kayıt olun.";
    } else {
      // 🔥 PATIENT LOOKUP
      resolved = await resolvePatientForOtp({ email: emailNormalized, phone: phoneNormalized });
      foundUserId = resolved.patientId;
      foundLanguage = resolved.language;
      foundPhone = resolved.phone;
      resolvedEmail = resolved.email;
      errorMessage = "Bu telefon numarası ile kayıtlı hasta bulunamadı. Lütfen kayıt olun.";
    }

    if (!foundUserId) {
      return res.status(404).json({
        ok: false,
        error: role === "DOCTOR" ? "doctor_not_found" : "patient_not_found",
        message: errorMessage,
      });
    }

    if (!resolvedEmail) {
      return res.status(400).json({
        ok: false,
        error: "email_not_found",
        message: "Bu hastanın email adresi kayıtlı değil. Lütfen admin ile iletişime geçin.",
      });
    }
    
    if (!isTransactionalEmailConfigured()) {
      console.error("[AUTH REQUEST-OTP] email transport missing → 503", {
        role,
        email: maskEmailForLog(resolvedEmail),
        ...getTransactionalEmailDiagnostic(),
      });
      return res.status(503).json({
        ok: false,
        error: "email_not_configured",
        message: REGISTER_USER_MSG.otpEmailNotConfigured,
        hint: REGISTER_USER_MSG.otpEmailNotConfiguredHint,
      });
    }

    cleanupExpiredOTPs();

    const otpCode = generateOTP();
    await saveOTP(resolvedEmail, otpCode, 0);

    let emailSent = false;
    try {
      await sendOTPEmail(resolvedEmail, otpCode, foundLanguage);
      emailSent = true;
      console.log("[OTP] request-otp send OK", {
        role,
        email: maskEmailForLog(resolvedEmail),
      });
    } catch (emailErr) {
      console.error("[OTP] request-otp sendOTPEmail failed", {
        role,
        email: maskEmailForLog(resolvedEmail),
        message: String(emailErr?.message || emailErr),
        ...getTransactionalEmailDiagnostic(),
      });
    }

    return res.json({
      ok: true,
      message: emailSent
        ? "OTP email adresinize gönderildi."
        : REGISTER_USER_MSG.otpStoredEmailSendFailed,
      email_sent: emailSent,
      email: resolvedEmail,
      ...(role === "DOCTOR" ? {
        doctorId: String(foundUserId || ""),
      } : {
        patientId: String(foundUserId || ""),
      }),
      language: foundLanguage,
      ...(foundPhone ? { phone: foundPhone } : {}),
    });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// POST /api/admin/request-otp
// Request OTP for admin login: takes clinic code + email, sends OTP
app.post("/api/admin/request-otp", async (req, res) => {
  try {
    const { clinicCode, email } = req.body || {};
    
    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required", message: "Klinik kodu gereklidir." });
    }
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required", message: "Email adresi gereklidir." });
    }

    const code = String(clinicCode).trim().toUpperCase();
    const emailNormalized = String(email).trim().toLowerCase();
    
    // Basic email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(emailNormalized)) {
      return res.status(400).json({ ok: false, error: "invalid_email", message: "Geçersiz email formatı." });
    }
    
    // Check rate limit
    if (!checkRateLimit(emailNormalized)) {
      return res.status(429).json({ 
        ok: false, 
        error: "rate_limit_exceeded", 
        message: "Çok fazla istek. Lütfen bir süre sonra tekrar deneyin." 
      });
    }

    // Find clinic
    let clinic = null;
    if (isSupabaseEnabled()) {
      clinic = await getClinicByCode(code);
    } else {
      // Fallback to file-based
      const clinics = readJson(CLINICS_FILE, {});
      clinic = Object.values(clinics).find(c => 
        String(c.clinicCode || "").toUpperCase() === code
      );
    }

    if (!clinic) {
      return res.status(404).json({ ok: false, error: "clinic_not_found", message: "Klinik bulunamadı." });
    }

    // Review Mode Bypass: Skip OTP generation and email for test@clinifly.net
    if (REVIEW_MODE && emailNormalized === "test@clinifly.net") {


      
      return res.json({
        ok: true,
        message: "OTP kodu hazırlandı (Review Mode). OTP 123456 kullanabilirsiniz.",
        clinicCode: code,
        email: emailNormalized,
        reviewMode: true,
        staticOTP: "123456"
      });
    }

    // Generate and save OTP
    const otpCode = generateOTP();
    await saveOTP(emailNormalized, otpCode);
    
    // Send OTP email
    try {
      await sendOTPEmail(emailNormalized, otpCode, clinic.language || "en");

    } catch (emailError) {

      return res.status(500).json({ 
        ok: false, 
        error: "email_send_failed", 
        message: "OTP gönderilemedi. Lütfen daha sonra tekrar deneyin." 
      });
    }

    res.json({
      ok: true,
      message: "OTP kodu email adresinize gönderildi.",
      clinicCode: code,
      email: emailNormalized
    });

  } catch (error) {

    res.status(500).json({ ok: false, error: "internal_error", message: "Sunucu hatası." });
  }
});

// POST /api/admin/verify-otp
// Verify OTP for admin login: takes clinic code + email + OTP, generates JWT token
app.post("/api/admin/verify-otp", async (req, res) => {
  try {
    const { clinicCode, email, otp } = req.body || {};

    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required", message: "Klinik kodu gereklidir." });
    }
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required", message: "Email adresi gereklidir." });
    }
    
    if (!otp || !String(otp).trim()) {
      return res.status(400).json({ ok: false, error: "otp_required", message: "OTP kodu gereklidir." });
    }

    const code = String(clinicCode).trim().toUpperCase();
    const emailNormalized = String(email).trim().toLowerCase();
    const otpCode = String(otp).trim();

    // Find clinic
    let clinic = null;
    if (isSupabaseEnabled()) {
      clinic = await getClinicByCode(code);
    } else {
      // Fallback to file-based
      const clinics = readJson(CLINICS_FILE, {});
      clinic = Object.values(clinics).find(c => 
        String(c.clinicCode || "").toUpperCase() === code
      );
    }

    if (!clinic) {
      return res.status(404).json({ ok: false, error: "clinic_not_found", message: "Klinik bulunamadı." });
    }

    // Review Mode Bypass: Accept static OTP for test@clinifly.net
    if (REVIEW_MODE && emailNormalized === "test@clinifly.net" && otp === "123456") {

      
      // Generate JWT token
      const token = jwt.sign(
        { 
          type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
          clinicId: clinic.id, // 🔥 REQUIRED: clinicId (UUID)
          clinicCode: clinic.clinic_code,
          email: emailNormalized,
          role: "ADMIN", // 🔥 REQUIRED: role
          otpVerified: true,
          reviewMode: true
        },
        JWT_SECRET,
        { expiresIn: JWT_EXPIRES_IN }
      );



      return res.json({
        ok: true,
        token,
        clinicCode: clinic.clinic_code,
        email: emailNormalized,
        message: "Giriş başarılı (Review Mode).",
        reviewMode: true
      });
    }

    // Verify OTP
    const otpData = await getOTPsForEmail(emailNormalized);
    if (!otpData) {
      return res.status(400).json({ ok: false, error: "otp_not_found", message: "OTP bulunamadı veya süresi dolmuş." });
    }

    if (otpData.verified || otpData.expiresAt < now()) {
      return res.status(400).json({ ok: false, error: "otp_expired", message: "OTP süresi dolmuş." });
    }

    if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
      return res.status(400).json({ ok: false, error: "otp_max_attempts", message: "Maksimum deneme sayısına ulaşıldı." });
    }

    const isValidOTP = await verifyOTP(otpCode, otpData.otp_hash || otpData.hashedOTP);
    if (!isValidOTP) {
      await incrementOTPAttempt(emailNormalized);
      const remainingAttempts = OTP_MAX_ATTEMPTS - (otpData.attempts + 1);
      return res.status(400).json({ 
        ok: false, 
        error: "invalid_otp", 
        message: `Geçersiz OTP kodu. Kalan deneme: ${remainingAttempts}` 
      });
    }

    // Mark OTP as verified
    await markOTPVerified(emailNormalized);

    // Generate JWT token
    const token = jwt.sign(
      { 
        type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
        clinicId: clinic.id, // 🔥 REQUIRED: clinicId (UUID)
        clinicCode: clinic.clinic_code,
        email: emailNormalized,
        role: "ADMIN", // 🔥 REQUIRED: role
        otpVerified: true
      },
      JWT_SECRET,
      { expiresIn: JWT_EXPIRES_IN }
    );



    res.json({
      ok: true,
      token,
      clinicCode: clinic.clinic_code,
      email: emailNormalized,
      message: "Giriş başarılı."
    });

  } catch (error) {

    res.status(500).json({ ok: false, error: "internal_error", message: "Sunucu hatası." });
  }
});

// POST /api/doctor/verify-otp
// Doctor-specific OTP verification endpoint
app.post("/api/doctor/verify-otp", async (req, res) => {
  try {
    const { email, phone, otp, sessionId } = req.body || {};

    // Strict parameter validation
    if (!otp || typeof otp !== 'string' || !otp.trim()) {
      return res.status(400).json({ ok: false, error: "otp_required", message: "OTP kodu gereklidir." });
    }

    if ((!email || !String(email).trim()) && (!phone || !String(phone).trim())) {
      return res.status(400).json({ ok: false, error: "email_or_phone_required", message: "Email veya telefon gereklidir." });
    }

    const emailNormalized = email ? String(email).trim().toLowerCase() : "";
    const otpCode = String(otp).trim();

    // Validate OTP format (should be 6 digits)
    if (otpCode.length !== 6 || !/^\d{6}$/.test(otpCode)) {
      return res.status(400).json({ ok: false, error: "invalid_otp_format", message: "OTP kodu 6 haneli olmalıdır." });
    }


    
    // 🔥 FIX: Resolve doctor from patients table with role="DOCTOR"
    const resolved = await resolveDoctorForOtp({ email: emailNormalized, phone });

    const resolvedEmail = resolved.email || emailNormalized;

    
    if (!resolvedEmail) {
      return res.status(400).json({
        ok: false,
        error: "email_not_found",
        message: "Bu doktorun email adresi kayıtlı değil. Lütfen admin ile iletişime geçin.",
      });
    }

    // Get OTP data for this email
    const otpData = await getOTPsForEmail(resolvedEmail);

    
    if (!otpData) {
      return res.status(404).json({ 
        ok: false, 
        error: "otp_not_found", 
        message: "OTP kodu bulunamadı veya süresi dolmuş. Lütfen önce OTP isteyin." 
      });
    }
    
    // Check if already verified
    if (otpData.verified) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_already_used", 
        message: "Bu OTP zaten kullanılmış. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Check if expired
    const expiresAt = otpData.expires_at || otpData.created_at || (now() + OTP_EXPIRY_MS);
    if (expiresAt < now()) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_expired", 
        message: "OTP süresi dolmuş. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Check attempts
    if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_max_attempts", 
        message: "Maksimum doğrulama denemesi aşıldı. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Verify OTP
    let isValid = false;
    try {
      const hashToUse = otpData.otp_hash;
      if (!hashToUse) {
        return res.status(500).json({ 
          ok: false, 
          error: "hash_missing", 
          message: "OTP hash bulunamadı. Lütfen yeni bir OTP isteyin." 
        });
      }
      
      isValid = await verifyOTP(String(otpCode).trim(), hashToUse);

    } catch (verifyError) {

      return res.status(500).json({ 
        ok: false, 
        error: "verification_failed", 
        message: "OTP doğrulanamadı. Lütfen tekrar deneyin." 
      });
    }
    
    if (!isValid) {
      incrementOTPAttempt(emailNormalized);
      return res.status(401).json({ 
        ok: false, 
        error: "invalid_otp", 
        message: "Geçersiz OTP kodu. Lütfen tekrar deneyin." 
      });
    }
    
    // OTP is valid - resolve doctor by email
    const foundDoctor = resolved.patient;
    const foundDoctorId = resolved.patientId;
    const foundLanguage = resolved.language;
    
    if (!foundDoctorId) {
      return res.status(404).json({
        ok: false,
        error: "doctor_not_found",
        message: "Bu email ile kayıtlı doktor bulunamadı.",
      });
    }
    
    // Mark OTP as verified
    markOTPVerified(emailNormalized);

    const foundPhone = String(foundDoctor?.phone || "").trim();
    
    // 🔥 FIX: Generate DOCTOR JWT token
    const tokenExpiry = Math.floor(Date.now() / 1000) + (TOKEN_EXPIRY_DAYS * 24 * 60 * 60);
    const token = jwt.sign(
      { 
        patientId: foundDoctorId,
        email: emailNormalized || "",
        language: foundLanguage,
        ...(foundPhone ? { phone: foundPhone } : {}),
        role: "DOCTOR", // 🔥 FIX: Hardcode DOCTOR role
        type: "doctor", // 🔥 FIX: Set type to doctor
      },
      JWT_SECRET,
      { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
    );
    
    // Save token in legacy tokens.json
    const tokens = readJson(TOK_FILE, {});
    tokens[token] = {
      patientId: foundDoctorId,
      role: "DOCTOR", // 🔥 FIX: Use DOCTOR role
      createdAt: now(),
      email: emailNormalized || "",
      language: foundLanguage,
      ...(foundPhone ? { phone: foundPhone } : {}),
    };
    writeJson(TOK_FILE, tokens);
    

    
    res.json({
      ok: true,
      token,
      patientId: foundDoctorId,
      role: "DOCTOR", // 🔥 FIX: Include DOCTOR role in response
      status: foundDoctor.status || "PENDING",
      name: foundDoctor.name || "",
      ...(foundPhone ? { phone: foundPhone } : {}),
      email: emailNormalized || "",
      language: foundLanguage,
      expiresIn: TOKEN_EXPIRY_DAYS * 24 * 60 * 60, // seconds
    });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// POST /api/doctor/login
// Frontend login endpoint for doctors (email + clinic code) - for Expo app
app.post("/api/doctor/login", async (req, res) => {
  try {
    const { email, clinicCode } = req.body || {};

    // Validate inputs
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required", message: "Email is required" });
    }

    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required", message: "Clinic code is required" });
    }

    const emailNormalized = String(email).trim().toLowerCase();
    const code = String(clinicCode).trim().toUpperCase();

    console.log("[DOCTOR LOGIN] Request:", { email: emailNormalized, clinicCode: code });

    // Lookup doctor by email in doctors table
    let foundDoctor = null;
    let supabaseClinicId = null;
    let singleEmailFallbackUsed = false;

    if (isSupabaseEnabled()) {
      try {
        const normalizeClinicCode = (value) => String(value || "").trim().toUpperCase();

        const doctorSelectCandidates = [
          "id, doctor_id, email, phone, name, full_name, first_name, last_name, clinic_id, clinic_code, status",
          "id, doctor_id, email, phone, name, full_name, clinic_id, clinic_code, status",
          "id, doctor_id, email, phone, name, clinic_id, clinic_code, status",
          "id, doctor_id, email, clinic_id, clinic_code, status",
        ];

        const runDoctorLookup = async (filterKind, filterValue, limitValue = 50) => {
          let lastError = null;
          for (const selectClause of doctorSelectCandidates) {
            let query = supabase
              .from("doctors")
              .select(selectClause)
              .limit(limitValue);

            if (filterKind === "email") {
              query = query.ilike("email", filterValue);
            } else {
              query = query.ilike("clinic_code", filterValue);
            }

            const result = await query;
            if (!result.error) {
              return { data: Array.isArray(result.data) ? result.data : [], error: null };
            }

            lastError = result.error;
            const code = String(result.error?.code || "");
            if (!["42703", "PGRST204", "PGRST205"].includes(code)) {
              break;
            }
          }

          return { data: [], error: lastError };
        };

        const broadLookup = await runDoctorLookup("email", emailNormalized, 50);

        if (broadLookup.error) {
          console.error("[DOCTOR LOGIN] Doctor lookup failed:", {
            message: broadLookup.error.message,
            code: broadLookup.error.code,
          });
        } else {
          const rows = Array.isArray(broadLookup.data) ? broadLookup.data : [];
          const clinicMatched = rows.filter((row) => normalizeClinicCode(row?.clinic_code) === code);

          if (clinicMatched.length === 1) {
            foundDoctor = clinicMatched[0];
            supabaseClinicId = clinicMatched[0]?.clinic_id || null;
          } else if (clinicMatched.length > 1) {
            const approved = clinicMatched.find((row) => {
              const status = String(row?.status || "").trim().toUpperCase();
              return status === "APPROVED" || status === "ACTIVE";
            });
            foundDoctor = approved || clinicMatched[0];
            supabaseClinicId = foundDoctor?.clinic_id || null;
          } else if (rows.length === 1) {
            foundDoctor = rows[0];
            supabaseClinicId = rows[0]?.clinic_id || null;
            singleEmailFallbackUsed = true;
            console.warn("[DOCTOR LOGIN] Using single-email fallback (clinic_code mismatch or empty)", {
              email: emailNormalized,
              providedClinicCode: code,
              storedClinicCode: normalizeClinicCode(rows[0]?.clinic_code),
            });
          }

          if (foundDoctor) {
            console.log("[DOCTOR LOGIN] Found doctor in Supabase:", {
              id: foundDoctor.id,
              email: foundDoctor.email,
              name: foundDoctor.name || foundDoctor.full_name || null,
              clinic_code: foundDoctor.clinic_code,
            });
          } else {
            const clinicLookup = await runDoctorLookup("clinic", code, 20);

            if (!clinicLookup.error) {
              const clinicRows = Array.isArray(clinicLookup.data) ? clinicLookup.data : [];
              const activeRows = clinicRows.filter((row) => {
                const status = String(row?.status || "").trim().toUpperCase();
                return status === "APPROVED" || status === "ACTIVE" || status === "PENDING";
              });

              if (activeRows.length === 1) {
                foundDoctor = activeRows[0];
                supabaseClinicId = activeRows[0]?.clinic_id || null;
                singleEmailFallbackUsed = true;
                console.warn("[DOCTOR LOGIN] Using clinic-scoped fallback (single active doctor in clinic)", {
                  email: emailNormalized,
                  clinicCode: code,
                  resolvedDoctorId: foundDoctor?.doctor_id || foundDoctor?.id,
                  resolvedDoctorEmail: foundDoctor?.email || null,
                });
              }
            }
          }
        }
      } catch (err) {
        console.error("[DOCTOR LOGIN] Supabase error:", err.message);
      }
    }

    if (!foundDoctor) {
      console.log("[DOCTOR LOGIN] Doctor not found:", { email: emailNormalized });
      return res.status(404).json({ ok: false, error: "doctor_not_found", message: "Doctor not found with this email" });
    }

    // Verify clinic code matches
    const doctorClinicCode = String(foundDoctor.clinic_code || "").toUpperCase();
    if (!singleEmailFallbackUsed && doctorClinicCode && doctorClinicCode !== code) {
      console.log("[DOCTOR LOGIN] Clinic code mismatch:", { provided: code, stored: doctorClinicCode });
      return res.status(403).json({ ok: false, error: "invalid_clinic_code", message: "Clinic code does not match" });
    }

    const effectiveClinicCode = doctorClinicCode || code;

    // Generate JWT token
    const tokenExpiry = Math.floor(Date.now() / 1000) + (TOKEN_EXPIRY_DAYS * 24 * 60 * 60);
    const token = jwt.sign(
      {
        doctorId: foundDoctor.doctor_id || foundDoctor.id,
        email: emailNormalized,
        clinicId: supabaseClinicId || foundDoctor.clinic_id,
        clinicCode: effectiveClinicCode,
        role: "DOCTOR",
        type: "doctor"
      },
      JWT_SECRET,
      { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
    );

    console.log("[DOCTOR LOGIN] ✅ Login successful:", { 
      doctorId: foundDoctor.doctor_id || foundDoctor.id,
      email: emailNormalized,
      name: foundDoctor.name || foundDoctor.full_name || `${foundDoctor.first_name || ""} ${foundDoctor.last_name || ""}`.trim() || null
    });

    const doctorName =
      String(foundDoctor.name || "").trim() ||
      String(foundDoctor.full_name || "").trim() ||
      String(`${foundDoctor.first_name || ""} ${foundDoctor.last_name || ""}`).trim() ||
      null;

    // Return doctor info with token - format matches what frontend expects
    res.json({
      ok: true,
      token,
      doctor: {
        id: foundDoctor.doctor_id || foundDoctor.id,
        email: emailNormalized,
        name: doctorName,
        clinicId: supabaseClinicId || foundDoctor.clinic_id,
        clinicCode: effectiveClinicCode,
        role: "DOCTOR",
        type: "doctor",
        status: foundDoctor.status || "ACTIVE"
      },
      expiresIn: TOKEN_EXPIRY_DAYS * 24 * 60 * 60
    });
  } catch (error) {
    console.error("[DOCTOR LOGIN] Error:", error.message);
    res.status(500).json({ ok: false, error: "internal_error", message: error.message });
  }
});

// POST /api/register/doctor
// Real doctor registration endpoint - INSERTS INTO DOCTORS TABLE
app.post("/api/register/doctor", async (req, res) => {
  try {
    const { 
      name, 
      email, 
      phone, 
      clinicCode, 
      licenseNumber, 
      department, 
      specialties, 
      title, 
      experienceYears,
      languages 
    } = req.body || {};

    console.log(`[DOCTOR REGISTER] Request received:`, { 
      name: name ? "***" : "", 
      email: email ? "***" : "",
      phone: phone ? "***" : "",
      clinicCode,
      licenseNumber: licenseNumber ? "***" : "",
      department,
      specialties,
      title,
      experienceYears,
      languages
    });

    // Validation
    if (!name || !email || !phone || !clinicCode || !licenseNumber) {
      return res.status(400).json({ 
        ok: false, 
        error: "missing_required_fields",
        message: "Name, email, phone, clinic code, and license number are required" 
      });
    }

    // Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ 
        ok: false, 
        error: "invalid_email", 
        message: "Geçerli bir e-posta adresi girin" 
      });
    }

    // Phone validation
    const phoneNormalized = normalizePhone(phone);
    if (phoneNormalized.length < 10) {
      return res.status(400).json({ 
        ok: false, 
        error: "invalid_phone", 
        message: "Telefon numarası en az 10 haneli olmalıdır" 
      });
    }

    const emailNormalized = String(email).trim().toLowerCase();

    // Validate clinic code
    const code = String(clinicCode).trim().toUpperCase();
    let foundClinic = null;
    let supabaseClinicId = null;

    if (isSupabaseEnabled()) {
      try {
        const clinic = await getClinicByCode(code);
        if (clinic) {
          foundClinic = clinic;
          supabaseClinicId = clinic.id;

        } else {

        }
      } catch (err) {

      }
    }

    if (!foundClinic) {
      return res.status(400).json({ 
        ok: false, 
        error: "clinic_not_found", 
        message: "Klinik kodu bulunamadı. Lütfen geçerli bir klinik kodu girin." 
      });
    }

    if (isSupabaseEnabled() && !supabaseClinicId) {

      return res.status(400).json({ ok: false, error: "clinic_not_found", message: "Klinik kodu bulunamadı. Lütfen geçerli bir klinik kodu girin." });
    }

    // 🔥 FIX: Check if doctor already exists in DOCTORS table
    let existingDoctorId = null;
    if (isSupabaseEnabled()) {
      try {
        const { data: existing, error: e } = await supabase
          .from("doctors")
          .select("id, doctor_id, email")
          .eq("email", emailNormalized)
          .limit(1)
          .maybeSingle();
        
        if (!e && existing) {
          existingDoctorId = existing.doctor_id || existing.id;

        }
      } catch (err) {

      }
    }

    if (existingDoctorId) {
      return res.status(409).json({ 
        ok: false, 
        error: "doctor_already_exists", 
        message: "Bu e-posta ile kayıtlı bir doktor zaten mevcut." 
      });
    }

    // Generate doctor ID
    const doctorId = 'd_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

    // 🔥 FIX: Insert doctor into DOCTORS table (not patients)
    if (isSupabaseEnabled()) {
      try {
        const doctorPayload = {
          doctor_id: doctorId,
          clinic_id: supabaseClinicId,
          clinic_code: code,
          full_name: String(name || ""),
          email: emailNormalized,
          phone: phoneNormalized,
          license_number: licenseNumber,
          status: "PENDING",
          role: "DOCTOR"
        };

        console.log("[DOCTOR REGISTER] Inserting doctor into DOCTORS table:", {
          doctor_id: doctorPayload.doctor_id,
          email: doctorPayload.email,
          clinic_code: doctorPayload.clinic_code,
          status: doctorPayload.status,
        });

        console.log(
          "🔥 FINAL DOCTOR PAYLOAD",
          JSON.stringify(doctorPayload, null, 2)
        );

        const { data, error } = await supabase
          .from("doctors")
          .insert(doctorPayload)
          .select()
          .single();

        if (error) {

          return res.status(500).json({ 
            ok: false, 
            error: "registration_failed", 
            message: "Doktor kaydı başarısız oldu." 
          });
        }


        
        res.json({
          ok: true,
          message: "Doktor kaydı başarıyla oluşturuldu. Admin onayı bekleniyor.",
          doctorId: doctorId,
          email: emailNormalized,
          status: "PENDING",
          clinicCode: code,
        });

      } catch (error) {

        return res.status(500).json({ 
          ok: false, 
          error: "registration_failed", 
          message: "Doktor kaydı başarısız oldu." 
        });
      }
    } else {
      return res.status(500).json({ 
        ok: false, 
        error: "supabase_disabled", 
        message: "Kayıt sistemi şu anda kullanılamıyor." 
      });
    }

  } catch (error) {

    res.status(500).json({ 
      ok: false, 
      error: "internal_error", 
      message: "Sunucu hatası." 
    });
  }
});

// POST /auth/verify-otp-patient
// PATIENTS ONLY - Clean separation
app.post("/auth/verify-otp-patient", async (req, res) => {
  try {
    const { email, phone, otp, sessionId } = req.body || {};

    // Strict parameter validation
    if (!otp || typeof otp !== 'string' || !otp.trim()) {
      return res.status(400).json({ ok: false, error: "otp_required", message: "OTP kodu gereklidir." });
    }

    if ((!email || !String(email).trim()) && (!phone || !String(phone).trim())) {
      return res.status(400).json({ ok: false, error: "email_or_phone_required", message: "Email veya telefon gereklidir." });
    }

    const emailNormalized = email ? String(email).trim().toLowerCase() : "";
    const otpCode = String(otp).trim();

    // Validate OTP format (should be 6 digits)
    if (otpCode.length !== 6 || !/^\d{6}$/.test(otpCode)) {
      return res.status(400).json({ ok: false, error: "invalid_otp_format", message: "OTP kodu 6 haneli olmalıdır." });
    }


    
    // 🔥 CLEAN SEPARATION: Resolve patient from PATIENTS table only
    const resolved = await resolvePatientForOtp({ email: emailNormalized, phone });

    const resolvedEmail = resolved.email || emailNormalized;

    
    if (!resolvedEmail || !resolved.patientId) {
      return res.status(404).json({
        ok: false,
        error: "patient_not_found",
        message: "Bu email veya telefon ile kayıtlı hasta bulunamadı.",
      });
    }

    // Get OTP data for this email
    const otpData = await getOTPsForEmail(resolvedEmail);

    
    if (!otpData) {
      return res.status(404).json({ 
        ok: false, 
        error: "otp_not_found", 
        message: "OTP kodu bulunamadı veya süresi dolmuş. Lütfen önce OTP isteyin." 
      });
    }
    
    // Check if already verified
    if (otpData.verified) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_already_used", 
        message: "Bu OTP zaten kullanılmış. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Check if expired
    const expiresAt = otpData.expires_at || otpData.created_at || (now() + OTP_EXPIRY_MS);
    if (expiresAt < now()) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_expired", 
        message: "OTP süresi dolmuş. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Check attempts
    if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
      return res.status(400).json({ 
        ok: false, 
        error: "otp_max_attempts", 
        message: "Maksimum doğrulama denemesi aşıldı. Lütfen yeni bir OTP isteyin." 
      });
    }
    
    // Verify OTP
    let isValid = false;
    try {
      const hashToUse = otpData.otp_hash;
      if (!hashToUse) {
        return res.status(500).json({ 
          ok: false, 
          error: "hash_missing", 
          message: "OTP hash bulunamadı. Lütfen yeni bir OTP isteyin." 
        });
      }
      
      isValid = await verifyOTP(String(otpCode).trim(), hashToUse);

    } catch (verifyError) {

      return res.status(500).json({ 
        ok: false, 
        error: "verification_failed", 
        message: "OTP doğrulanamadı. Lütfen tekrar deneyin." 
      });
    }
    
    if (!isValid) {
      incrementOTPAttempt(emailNormalized);
      return res.status(401).json({ 
        ok: false, 
        error: "invalid_otp", 
        message: "Geçersiz OTP kodu. Lütfen tekrar deneyin." 
      });
    }
    
    // OTP is valid - get patient data
    const foundPatient = resolved.patient;
    const resolvedPid = resolved.patientId;
    const foundLanguage = resolved.language;
    const canonicalPatientId =
      (foundPatient &&
        (foundPatient.id || foundPatient.patient_id || foundPatient.patientId)) ||
      resolvedPid;
    
    if (!canonicalPatientId) {
      return res.status(404).json({
        ok: false,
        error: "patient_not_found",
        message: "Bu email ile kayıtlı hasta bulunamadı.",
      });
    }
    
    // Mark OTP as verified
    markOTPVerified(emailNormalized);

    const foundPhone = String(foundPatient?.phone || "").trim();
    const patientStatus = String(foundPatient?.status || "PENDING").toUpperCase();
    
    // 🔥 CLEAN SEPARATION: Generate PATIENT JWT token with REQUIRED payload
    const tokenExpiry = Math.floor(Date.now() / 1000) + (TOKEN_EXPIRY_DAYS * 24 * 60 * 60);
    const token = jwt.sign(
      { 
        type: "patient", // 🔥 REQUIRED: type is PRIMARY routing key
        patientId: canonicalPatientId, // UUID veya legacy p_…
        role: "PATIENT", // 🔥 REQUIRED: role
        status: patientStatus,
        email: emailNormalized || "",
        language: foundLanguage,
        ...(foundPhone ? { phone: foundPhone } : {}),
      },
      JWT_SECRET,
      { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
    );
    
    // Save token in legacy tokens.json
    const tokens = readJson(TOK_FILE, {});
    tokens[token] = {
      type: "patient",
      patientId: canonicalPatientId,
      role: "PATIENT",
      createdAt: now(),
      email: emailNormalized || "",
      language: foundLanguage,
      ...(foundPhone ? { phone: foundPhone } : {}),
    };
    writeJson(TOK_FILE, tokens);
    

    
    res.json({
      ok: true,
      type: "patient", // 🔥 REQUIRED: type for frontend routing
      token,
      patientId: canonicalPatientId,
      role: "PATIENT",
      status: patientStatus,
      name: foundPatient.name || "",
      ...(foundPhone ? { phone: foundPhone } : {}),
      email: emailNormalized || "",
      language: foundLanguage,
      expiresIn: TOKEN_EXPIRY_DAYS * 24 * 60 * 60, // seconds
    });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

