// POST /api/admin/verify-otp
// ADMIN ONLY - Clean separation
app.post("/api/admin/verify-otp", async (req, res) => {
  try {
    const { clinicCode, email, otp } = req.body || {};

    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required", message: "Klinik kodu gereklidir." });
    }
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required", message: "Email adresi gereklidir." });
    }
    
    if (!otp || !String(otp).trim()) {
      return res.status(400).json({ ok: false, error: "otp_required", message: "OTP kodu gereklidir." });
    }

    const code = String(clinicCode).trim().toUpperCase();
    const emailNormalized = String(email).trim().toLowerCase();
    const otpCode = String(otp).trim();

    // Find clinic
    let clinic = null;
    if (isSupabaseEnabled()) {
      clinic = await getClinicByCode(code);
    } else {
      clinic = readJson(CLINIC_FILE, []).find(c => String(c.clinicCode || "").toUpperCase() === code);
    }

    if (!clinic) {
      return res.status(404).json({ ok: false, error: "clinic_not_found", message: "Klinik bulunamadı." });
    }

    // Review Mode Bypass: Accept static OTP for test@clinifly.net
    if (REVIEW_MODE && emailNormalized === "test@clinifly.net" && otp === "123456") {

      
      // 🔥 CLEAN SEPARATION: Generate ADMIN JWT token with REQUIRED payload
      const token = jwt.sign(
        { 
          type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
          clinicId: clinic.id, // 🔥 REQUIRED: clinicId
          clinicCode: clinic.clinic_code,
          email: emailNormalized,
          role: "ADMIN", // 🔥 REQUIRED: role
          otpVerified: true,
          reviewMode: true
        },
        JWT_SECRET,
        { expiresIn: JWT_EXPIRES_IN }
      );



      return res.json({
        ok: true,
        type: "admin", // 🔥 REQUIRED: type for frontend routing
        token,
        clinicId: clinic.id,
        clinicCode: clinic.clinic_code,
        email: emailNormalized,
        message: "Giriş başarılı (Review Mode).",
        reviewMode: true
      });
    }

    // Verify OTP
    const otpData = await getOTPsForEmail(emailNormalized);
    if (!otpData) {
      return res.status(400).json({ ok: false, error: "otp_not_found", message: "OTP bulunamadı veya süresi dolmuş." });
    }

    if (otpData.verified || otpData.expiresAt < now()) {
      return res.status(400).json({ ok: false, error: "otp_expired", message: "OTP süresi dolmuş." });
    }

    if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
      return res.status(400).json({ ok: false, error: "otp_max_attempts", message: "Maksimum deneme sayısına ulaşıldı." });
    }

    const isValidOTP = await verifyOTP(otpCode, otpData.otp_hash || otpData.hashedOTP);
    if (!isValidOTP) {
      await incrementOTPAttempt(emailNormalized);
      const remainingAttempts = OTP_MAX_ATTEMPTS - (otpData.attempts + 1);
      return res.status(400).json({ 
        ok: false, 
        error: "invalid_otp", 
        message: `Geçersiz OTP kodu. Kalan deneme: ${remainingAttempts}` 
      });
    }

    // Mark OTP as verified
    await markOTPVerified(emailNormalized);

    // 🔥 CLEAN SEPARATION: Generate ADMIN JWT token with REQUIRED payload
    const token = jwt.sign(
      { 
        type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
        clinicId: clinic.id, // 🔥 REQUIRED: clinicId
        clinicCode: clinic.clinic_code,
        email: emailNormalized,
        role: "ADMIN", // 🔥 REQUIRED: role
        otpVerified: true
      },
      JWT_SECRET,
      { expiresIn: JWT_EXPIRES_IN }
    );



    res.json({
      ok: true,
      type: "admin", // 🔥 REQUIRED: type for frontend routing
      token,
      clinicId: clinic.id,
      clinicCode: clinic.clinic_code,
      email: emailNormalized,
      message: "Giriş başarılı."
    });

  } catch (error) {

    res.status(500).json({ ok: false, error: "internal_error", message: "Sunucu hatası." });
  }
});

// POST /auth/verify-otp | /api/auth/verify-otp
// UNIFIED OTP ENDPOINT - Single server, type-based separation
app.post(["/auth/verify-otp", "/api/auth/verify-otp"], async (req, res) => {
  try {
    const { otp, email, phone, sessionId } = req.body || {};
    let role = req.body?.role;
    if (!role && req.body?.type != null) {
      const t = String(req.body.type).toLowerCase();
      if (t === "patient") role = "PATIENT";
      else if (t === "doctor") role = "DOCTOR";
      else if (t === "admin") role = "ADMIN";
    }

    // 🔥 CRITICAL: Role is REQUIRED for routing
    if (!role || (role !== "DOCTOR" && role !== "PATIENT")) {
      return res.status(400).json({ 
        ok: false, 
        error: "role_required", 
        message: "Role parameter is required (DOCTOR or PATIENT), or send type: patient|doctor." 
      });
    }

    // Strict parameter validation
    if (!otp || typeof otp !== 'string' || !otp.trim()) {
      return res.status(400).json({ ok: false, error: "otp_required", message: "OTP kodu gereklidir." });
    }

    if ((!email || !String(email).trim()) && (!phone || !String(phone).trim())) {
      return res.status(400).json({ ok: false, error: "email_or_phone_required", message: "Email veya telefon gereklidir." });
    }

    const emailNormalized = email ? String(email).trim().toLowerCase() : "";
    const otpCode = String(otp).trim();

    // Validate OTP format (should be 6 digits)
    if (otpCode.length !== 6 || !/^\d{6}$/.test(otpCode)) {
      return res.status(400).json({ ok: false, error: "invalid_otp_format", message: "OTP kodu 6 haneli olmalıdır." });
    }



    // 🔥 UNIFIED LOGIC: Route based on role
    if (role === "DOCTOR") {
      // DOCTOR FLOW
      const resolved = await resolveDoctorForOtp({ email: emailNormalized, phone });

      const resolvedEmail = resolved.email || emailNormalized;
      
      if (!resolvedEmail || !resolved.doctorId) {
        return res.status(404).json({
          ok: false,
          error: "doctor_not_found",
          message: "Bu email veya telefon ile kayıtlı doktor bulunamadı.",
        });
      }

      // Get OTP data for this email
      const otpDevBypass = isOtpDevBypassEnabled();
      const otpData = normalizeOtpRowFromStore(await getOTPsForEmail(resolvedEmail));
      if (!otpData && !otpDevBypass) {
        return res.status(404).json({ 
          ok: false, 
          error: "otp_not_found", 
          message: "OTP kodu bulunamadı veya süresi dolmuş. Lütfen önce OTP isteyin." 
        });
      }
      
      if (!otpDevBypass) {
        if (otpData.verified) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_already_used", 
            message: "Bu OTP zaten kullanılmış. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        const expiresAt = otpData.expires_at || otpData.created_at || (now() + OTP_EXPIRY_MS);
        if (expiresAt < now()) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_expired", 
            message: "OTP süresi dolmuş. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_max_attempts", 
            message: "Maksimum doğrulama denemesi aşıldı. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        const isValid = await verifyOTP(String(otpCode).trim(), otpData.otp_hash || otpData.hashedOTP);
        if (!isValid) {
          incrementOTPAttempt(emailNormalized);
          return res.status(401).json({ 
            ok: false, 
            error: "invalid_otp", 
            message: "Geçersiz OTP kodu. Lütfen tekrar deneyin." 
          });
        }
      } else {
        console.warn("[OTP] DEV BYPASS: doctor /auth/verify-otp — OTP not enforced (non-production, set OTP_DEV_BYPASS=0 to disable)");
      }
      
      // Get doctor data
      const foundDoctor = resolved.doctor;
      const foundDoctorId = resolved.doctorId;
      
      if (!foundDoctorId) {
        return res.status(404).json({
          ok: false,
          error: "doctor_not_found",
          message: "Bu email ile kayıtlı doktor bulunamadı.",
        });
      }
      
      // Mark OTP as verified
      markOTPVerified(emailNormalized);

      // 🔥 DOCTOR TOKEN RESPONSE
      const token = jwt.sign(
        { 
          type: "doctor",
          doctorId: foundDoctorId,
          clinicId: foundDoctor.clinic_id,
          role: "DOCTOR",
          status: foundDoctor.status || "PENDING",
          email: emailNormalized || "",
        },
        JWT_SECRET,
        { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
      );
      

      
      return res.json({
        ok: true,
        token,
        role: "DOCTOR",
        doctorId: foundDoctorId,
        status: foundDoctor.status || "PENDING",
        name: foundDoctor.name || "",
        email: emailNormalized || "",
      });

    } else {
      // PATIENT FLOW
      const resolved = await resolvePatientForOtp({ email: emailNormalized, phone });

      const resolvedEmail = resolved.email || emailNormalized;
      
      if (!resolvedEmail || !resolved.patientId) {
        return res.status(404).json({
          ok: false,
          error: "patient_not_found",
          message: "Bu email veya telefon ile kayıtlı hasta bulunamadı.",
        });
      }

      // Get OTP data for this email
      const otpDevBypass = isOtpDevBypassEnabled();
      const otpData = normalizeOtpRowFromStore(await getOTPsForEmail(resolvedEmail));
      if (!otpData && !otpDevBypass) {
        return res.status(404).json({ 
          ok: false, 
          error: "otp_not_found", 
          message: "OTP kodu bulunamadı veya süresi dolmuş. Lütfen önce OTP isteyin." 
        });
      }
      
      if (!otpDevBypass) {
        if (otpData.verified) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_already_used", 
            message: "Bu OTP zaten kullanılmış. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        const expiresAt = otpData.expires_at || otpData.created_at || (now() + OTP_EXPIRY_MS);
        if (expiresAt < now()) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_expired", 
            message: "OTP süresi dolmuş. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        if (otpData.attempts >= OTP_MAX_ATTEMPTS) {
          return res.status(400).json({ 
            ok: false, 
            error: "otp_max_attempts", 
            message: "Maksimum doğrulama denemesi aşıldı. Lütfen yeni bir OTP isteyin." 
          });
        }
        
        const isValid = await verifyOTP(String(otpCode).trim(), otpData.otp_hash || otpData.hashedOTP);
        if (!isValid) {
          incrementOTPAttempt(emailNormalized);
          return res.status(401).json({ 
            ok: false, 
            error: "invalid_otp", 
            message: "Geçersiz OTP kodu. Lütfen tekrar deneyin." 
          });
        }
      } else {
        console.warn("[OTP] DEV BYPASS: patient /auth/verify-otp — OTP not enforced (non-production, set OTP_DEV_BYPASS=0 to disable)");
      }
      
      // Get patient data
      console.log("[PATIENT VERIFY] Resolved object:", resolved);
      const foundPatient = resolved.patient;
      const resolvedPid = resolved.patientId;
      const canonicalPatientId =
        (foundPatient &&
          (foundPatient.id || foundPatient.patient_id || foundPatient.patientId)) ||
        resolvedPid;
      
      console.log("[PATIENT VERIFY] foundPatient:", foundPatient);
      console.log("[PATIENT VERIFY] canonicalPatientId:", canonicalPatientId);
      
      if (!canonicalPatientId) {
        return res.status(404).json({
          ok: false,
          error: "patient_not_found",
          message: "Bu email ile kayıtlı hasta bulunamadı.",
        });
      }
      
      // Mark OTP as verified
      markOTPVerified(emailNormalized);

      const patientStatus = String(foundPatient?.status || "PENDING").toUpperCase();

      // 🔥 PATIENT TOKEN RESPONSE (onaysız PENDING ile de giriş — klinik onayı ayrı ekranda)
      const token = jwt.sign(
        { 
          type: "patient",
          patientId: canonicalPatientId,
          role: "PATIENT",
          status: patientStatus,
          email: emailNormalized || "",
        },
        JWT_SECRET,
        { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
      );
      

      
      return res.json({
        ok: true,
        type: "patient",
        token,
        role: "PATIENT",
        patientId: canonicalPatientId,
        status: patientStatus,
        name: foundPatient.name || "",
        email: emailNormalized || "",
      });
    }

  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// ================== PATIENT LOGIN ==================
// POST /api/patient/login
// Patient login with phone + clinicCode, returns JWT token
// Checks Supabase first (production), falls back to local JSON (dev)
app.post("/api/patient/login", async (req, res) => {
  try {
    const { phone, patientId, clinicCode } = req.body || {};

    if (!phone && !patientId) {
      return res.status(400).json({ ok: false, error: "phone_or_patientId_required" });
    }

    // Normalize phone: strip +90/90 country code and leading 0 so it matches DB format
    const phoneNorm = phone ? normalizePhone(String(phone).trim()) : null;
    const clinicCodeNorm = clinicCode ? String(clinicCode).trim().toUpperCase() : null;

    // ── Supabase path ──────────────────────────────────────────────────────────
    if (isSupabaseEnabled()) {
      let patientRow = null;

      // If clinicCode supplied, resolve clinic_id first for a scoped query
      let clinicIdFilter = null;
      let clinicRow = null;
      if (clinicCodeNorm) {
        const { data: c } = await supabase
          .from('clinics')
          .select('id, clinic_code, name, plan, settings')
          .eq('clinic_code', clinicCodeNorm)
          .maybeSingle();
        if (c) {
          clinicIdFilter = c.id;
          clinicRow = c;
        }
      }

      const PATIENT_SELECT = 'id, patient_id, name, phone, email, status, clinic_id, clinic_code, referral_code, language';
      const phoneOrFilter = phoneNorm ? buildPhoneMatchOrFilter(phoneNorm) : "";

      // Search by phone: match common DB formats; prefer clinic_id, then patients.clinic_code, then unambiguous row
      if (phoneNorm && phoneOrFilter) {
        const tryPhone = async (extra) => {
          let q = supabase.from("patients").select(PATIENT_SELECT).or(phoneOrFilter);
          if (extra.clinic_id) q = q.eq("clinic_id", extra.clinic_id);
          if (extra.clinic_code) q = q.eq("clinic_code", extra.clinic_code);
          const { data } = await q.limit(1);
          return data?.[0] || null;
        };
        if (clinicIdFilter) patientRow = await tryPhone({ clinic_id: clinicIdFilter });
        if (!patientRow && clinicCodeNorm) patientRow = await tryPhone({ clinic_code: clinicCodeNorm });
        if (!patientRow) {
          const { data: multi } = await supabase
            .from("patients")
            .select(PATIENT_SELECT)
            .or(phoneOrFilter)
            .limit(8);
          const arr = multi || [];
          if (arr.length === 1) patientRow = arr[0];
          else if (arr.length > 1 && clinicCodeNorm) {
            const up = String(clinicCodeNorm).toUpperCase();
            patientRow = arr.find((p) => String(p.clinic_code || "").toUpperCase() === up) || null;
            if (!patientRow) {
              console.warn("[PATIENT LOGIN] multiple rows for phone; none matched clinic_code:", clinicCodeNorm);
            }
          } else if (arr.length > 1) {
            console.warn("[PATIENT LOGIN] multiple patients share this phone; pass clinicCode to disambiguate");
          }
        }
      }

      // Search by patientId if still not found
      if (!patientRow && patientId) {
        const UUID_RE_L = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
        const isUuidL = UUID_RE_L.test(String(patientId));
        let q2 = supabase.from('patients').select(PATIENT_SELECT);
        if (isUuidL) q2 = q2.eq('id', patientId);
        else q2 = q2.eq('patient_id', patientId);
        if (clinicIdFilter) q2 = q2.eq('clinic_id', clinicIdFilter);
        const { data: rows2 } = await q2.limit(1);
        if (rows2 && rows2[0]) patientRow = rows2[0];
      }

      if (!patientRow) {
        console.log('[PATIENT LOGIN] not found in Supabase, phone:', phoneNorm, 'clinicCode:', clinicCodeNorm);
        return res.status(404).json({ ok: false, error: 'patient_not_found' });
      }

      // Load clinic row if not already loaded
      if (!clinicRow && patientRow.clinic_id) {
        const { data: c2 } = await supabase
          .from('clinics')
          .select('id, clinic_code, name, plan, settings')
          .eq('id', patientRow.clinic_id)
          .maybeSingle();
        if (c2) clinicRow = c2;
      }

      // Always use UUID as patientId — TEXT patient_id is only a display label
      const foundPatientId = patientRow.id;
      const foundLanguage = patientRow.language || 'tr';
      const foundName = patientRow.name || '';
      console.log('[PATIENT LOGIN] uuid:', foundPatientId, '| name:', foundName, '| phone:', patientRow.phone);

      const token = jwt.sign(
        {
          type: 'patient',
          patientId: foundPatientId,
          role: 'PATIENT',
          phone: patientRow.phone || '',
          language: foundLanguage,
        },
        JWT_SECRET,
        { expiresIn: `${TOKEN_EXPIRY_DAYS}d` }
      );

      // Also persist in legacy TOK_FILE so other middleware can find it
      const tokens = readJson(TOK_FILE, {});
      tokens[token] = { type: 'patient', patientId: foundPatientId, role: 'PATIENT', createdAt: now(), phone: patientRow.phone || '', language: foundLanguage };
      writeJson(TOK_FILE, tokens);

      return res.json({
        ok: true,
        type: 'patient',
        token,
        id: patientRow.id,
        patientId: foundPatientId,
        role: 'PATIENT',
        status: patientRow.status || 'APPROVED',
        name: foundName,
        phone: patientRow.phone || '',
        email: patientRow.email || '',
        language: foundLanguage,
        clinicId: patientRow.clinic_id || (clinicRow && clinicRow.id) || null,
        clinicCode: patientRow.clinic_code || (clinicRow && clinicRow.clinic_code) || clinicCodeNorm || null,
        referralCode: patientRow.referral_code || null,
      });
    }

    // ── Legacy file-based fallback (dev only) ──────────────────────────────────
    const patients = readJson(PAT_FILE, {});
    const tokensFile = readJson(TOK_FILE, {});
    let foundPatient = null;
    let foundPatientId = null;

    if (patientId) {
      foundPatient = patients[patientId];
      if (foundPatient) foundPatientId = patientId;
    }
    if (!foundPatient && phoneNorm) {
      for (const pid in patients) {
        if (patients[pid].phone === phoneNorm) {
          foundPatient = patients[pid];
          foundPatientId = pid;
          break;
        }
      }
    }
    if (!foundPatient) {
      return res.status(404).json({ ok: false, error: 'patient_not_found' });
    }

    let existingToken = null;
    for (const tok in tokensFile) {
      if (tokensFile[tok]?.patientId === foundPatientId) { existingToken = tok; break; }
    }
    if (!existingToken) {
      existingToken = makeToken();
      tokensFile[existingToken] = { patientId: foundPatientId, role: foundPatient.status || 'PENDING', createdAt: now() };
      writeJson(TOK_FILE, tokensFile);
    }

    return res.json({
      ok: true,
      token: existingToken,
      patientId: foundPatientId,
      status: foundPatient.status || 'PENDING',
      name: foundPatient.name || '',
      phone: foundPatient.phone || '',
    });
  } catch (error) {
    console.error('[PATIENT LOGIN] error:', error.message);
    res.status(500).json({ ok: false, error: error?.message || 'internal_error' });
  }
});

// ================== PATIENT ME (alias) ==================
app.get("/api/patient/me", requireToken, async (req, res) => {
  try {
    // Supabase is the single source of truth in production
    if (isSupabaseEnabled()) {
      const mePatientId = req.patientId;
      const UUID_RE_ME = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
      const isUuidMe = UUID_RE_ME.test(mePatientId);
      const ME_SELECT = "id,patient_id,name,phone,email,status,clinic_id,created_at,updated_at";

      let p = null;
      // Try UUID lookup first if token holds a UUID
      if (isUuidMe) {
        const r1 = await supabase.from("patients").select(ME_SELECT).eq("id", mePatientId).maybeSingle();
        if (!r1.error && r1.data) p = r1.data;
      }
      // Fallback: TEXT patient_id lookup
      if (!p) {
        const r2 = await supabase.from("patients").select(ME_SELECT).eq("patient_id", mePatientId).maybeSingle();
        if (!r2.error && r2.data) p = r2.data;
      }

      if (!p) {
        console.error("[ME] patient not found for patientId:", mePatientId);
        return res.status(404).json({ ok: false, error: "patient_not_found" });
      }

      const pErr = null;

      let clinicCode = "";
      let clinicPlan = "FREE";
      let branding = null;
      let clinicData = null;

      if (p?.clinic_id) {
        const { data: c, error: cErr } = await supabase
          .from("clinics")
          .select("id,clinic_code,plan,name,phone,address,settings")
          .eq("id", p.clinic_id)
          .single();

        if (cErr) {
          console.error("[ME] Supabase clinic fetch failed", {
            message: cErr.message,
            code: cErr.code,
            details: cErr.details,
          });
        } else if (c) {
          clinicData = c;
          if (typeof clinicData.settings === "string") {
            try {
              clinicData.settings = JSON.parse(clinicData.settings);
            } catch (e) {
              clinicData.settings = {};
            }
          }
          clinicCode = clinicData.clinic_code || "";
          clinicPlan = clinicData.plan || "FREE";
          const b = clinicData.settings?.branding || null;
          branding = b
            ? b
            : {
                clinicName: clinicData.name || "",
                clinicLogoUrl: "",
                address: clinicData.address || "",
                googleMapLink: "",
                primaryColor: undefined,
                secondaryColor: undefined,
                welcomeMessage: "",
                showPoweredBy: true,
                phone: clinicData.phone || "",
              };
        }
      }

      const finalStatus = p?.status || "PENDING";
      const meName = p?.name || '';
      const referralLevels =
        clinicData?.settings?.referralLevels ||
        {
          level1: clinicData?.settings?.defaultInviterDiscountPercent ?? null,
          level2: null,
          level3: null,
        };
      return res.json({
        ok: true,
        patientId: req.patientId,
        role: finalStatus,
        status: finalStatus,
        name: meName,
        phone: p?.phone || "",
        email: p?.email || "",
        clinicCode,
        clinicPlan,
        branding,
        referralLevels,
        financialSnapshot: {
          totalEstimatedCost: 0,
          totalPaid: 0,
          remainingBalance: 0,
        },
      });
    }

    // Legacy fallback (file-based)
    const patients = readJson(PAT_FILE, {});
    const p = patients[req.patientId] || null;
    const finalStatus = p?.status || req.role || "PENDING";
    return res.json({
      ok: true,
      patientId: req.patientId,
      role: finalStatus,
      status: finalStatus,
      name: p?.name || "",
      phone: p?.phone || "",
      email: p?.email || "",
      clinicCode: p?.clinicCode || p?.clinic_code || "",
      clinicPlan: p?.clinicPlan || "FREE",
      branding: null,
      financialSnapshot: p?.financialSnapshot || {
        totalEstimatedCost: 0,
        totalPaid: 0,
        remainingBalance: 0,
      },
    });
  } catch (e) {

    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

/** Display rating per clinic: 80% avg(treatment) + 20% avg(experience); untyped rows fall back to simple average for that bucket. */
function buildClinicRatingMapWeighted(ratingRows) {
  const ratingMap = {};
  if (!Array.isArray(ratingRows) || !ratingRows.length) return ratingMap;
  const WT = 0.8;
  const WE = 0.2;
  const byClinic = {};
  const push = (cid, bucket, v) => {
    if (!byClinic[cid]) byClinic[cid] = { treatment: [], experience: [], other: [] };
    byClinic[cid][bucket].push(v);
  };
  for (const r of ratingRows) {
    const cid = r.clinic_id;
    if (cid == null || String(cid).trim() === "") continue;
    const v = r.overall;
    if (typeof v !== "number" || !Number.isFinite(v)) continue;
    const typ = String(r.type || "").trim().toLowerCase();
    if (typ === "treatment") push(cid, "treatment", v);
    else if (typ === "experience") push(cid, "experience", v);
    else push(cid, "other", v);
  }
  const avg = (arr) => (arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : null);
  for (const [cid, g] of Object.entries(byClinic)) {
    const at = avg(g.treatment);
    const ae = avg(g.experience);
    const ao = avg(g.other);
    let score = null;
    if (at != null && ae != null) score = WT * at + WE * ae;
    else if (at != null) score = at;
    else if (ae != null) score = ae;
    else if (ao != null) score = ao;
    if (score != null) ratingMap[cid] = Math.round(score * 10) / 10;
  }
  return ratingMap;
}

// ================== PATIENT: BROWSE CLINICS ("Find a clinic") ==================
// Priority: (1) Supabase RPC nearby_clinics(lat,lng) — (2) same country — (3) all (cap 20).
// Avoid PostgREST .or(status...) — filter suspended/inactive in JS instead.
// GET /api/patient/clinics?lat=&lng=&country= — pass country (e.g. Georgia or GE) to prioritize same-country clinics
app.get("/api/patient/clinics", requireToken, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.json({ ok: true, clinics: [] });
    }

    const selFull = "id, name, city, country, clinic_code, latitude, longitude, status";
    const selLite = "id, name, city, country, clinic_code, status";

    const { rows } = await fetchPatientVisibleClinicRows(supabase, {
      patientId: req.patientId,
      lat: req.query.lat,
      lng: req.query.lng,
      country: req.query.country || req.query.userCountry,
      selectFull: selFull,
      selectLite: selLite,
    });

    const ids = rows.map((c) => c.id).filter((id) => id != null && String(id).trim() !== "");
    let ratingMap = {};
    if (ids.length) {
      try {
        const { data: ratingRows, error: ratingErr } = await supabase
          .from("ratings")
          .select("clinic_id, overall, type")
          .in("clinic_id", ids);
        if (ratingErr) {
          console.warn("[GET /api/patient/clinics] ratings query skipped:", ratingErr.message);
        } else if (ratingRows?.length) {
          ratingMap = buildClinicRatingMapWeighted(ratingRows);
        }
      } catch (re) {
        console.warn("[GET /api/patient/clinics] ratings exception:", re?.message);
      }
    }

    const clinics = rows.map((c) => ({
      id: c.id,
      name: c.name || "Klinik",
      city: c.city || null,
      country: c.country || null,
      clinicCode: c.clinic_code || null,
      rating: ratingMap[c.id] ?? null,
      latitude: c.latitude ?? null,
      longitude: c.longitude ?? null,
    }));

    return res.json({ ok: true, clinics });
  } catch (e) {
    console.error("[GET /api/patient/clinics]", e?.message, e?.details || e?.hint || "");
    return res.status(500).json({
      ok: false,
      error: "db_error",
      message: "Klinik listesi yüklenemedi. Lütfen daha sonra tekrar deneyin.",
    });
  }
});

// GET /api/clinics/nearby — Haversine distance filter (no auth; optional Bearer for future use)
// Query: lat, lng (required), radius (km, default 10, max 200), optional country|userCountry (prioritize same country, then distance).
app.get("/api/clinics/nearby", async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.json({ ok: true, clinics: [], radius_km: 10, center: null });
    }
    const lat = parseFloat(String(req.query.lat ?? "").replace(",", "."));
    const lng = parseFloat(String(req.query.lng ?? "").replace(",", "."));
    const radiusRaw = parseFloat(String(req.query.radius ?? "").replace(",", "."));
    const radiusKm =
      Number.isFinite(radiusRaw) && radiusRaw > 0 ? Math.min(Math.max(radiusRaw, 0.5), 200) : 10;
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
      return res.status(400).json({ ok: false, error: "lat_lng_required" });
    }

    const selects = [
      "id, name, city, country, clinic_code, latitude, longitude, lat, lng, status",
      "id, name, city, country, clinic_code, latitude, longitude, status",
    ];
    let raw = [];
    let lastSelErr = null;
    for (const sel of selects) {
      const { data, error } = await supabase.from("clinics").select(sel).limit(500);
      if (!error && Array.isArray(data)) {
        raw = data;
        break;
      }
      lastSelErr = error || lastSelErr;
    }
    if (!raw.length && lastSelErr) {
      console.warn("[GET /api/clinics/nearby] clinics select:", lastSelErr.message);
    }

    let matched = filterClinicsWithinRadiusKm(raw, lat, lng, radiusKm);
    const userCountryNearby = req.query.country || req.query.userCountry;
    if (userCountryNearby) {
      matched = sortNearbyMatchesByUserCountry(matched, String(userCountryNearby));
    }
    const ids = matched.map((m) => m.row.id).filter(Boolean);
    let ratingMap = {};
    if (ids.length) {
      try {
        const { data: ratingRows, error: ratingErr } = await supabase
          .from("ratings")
          .select("clinic_id, overall, type")
          .in("clinic_id", ids);
        if (!ratingErr && ratingRows?.length) {
          ratingMap = buildClinicRatingMapWeighted(ratingRows);
        }
      } catch (re) {
        console.warn("[GET /api/clinics/nearby] ratings:", re?.message);
      }
    }

    const clinics = matched.map(({ row, distance_km }) => ({
      id: row.id,
      name: row.name || "Klinik",
      city: row.city || null,
      country: row.country || null,
      clinicCode: row.clinic_code || null,
      rating: ratingMap[row.id] ?? null,
      latitude: row.latitude ?? row.lat ?? null,
      longitude: row.longitude ?? row.lng ?? null,
      distance_km: Math.round(distance_km * 10) / 10,
    }));

    return res.json({
      ok: true,
      clinics,
      radius_km: radiusKm,
      center: { lat, lng },
    });
  } catch (e) {
    console.error("[GET /api/clinics/nearby]", e?.message || e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// PATCH /api/patient/clinic — join / switch clinic by code (mobile: "Kliniğe katıl")
// Body: { clinic_code, referral_code? } — country is not required; lookup is by clinic_code only.
app.patch("/api/patient/clinic", requireToken, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({
        ok: false,
        error: "supabase_required",
        message: "Klinik katılımı şu an kullanılamıyor.",
      });
    }

    const body = req.body || {};
    const clinicCodeRaw = String(body.clinic_code || body.clinicCode || "").trim().toUpperCase();
    if (!clinicCodeRaw) {
      return res.status(400).json({ ok: false, error: "clinic_code_required" });
    }

    const clinic = await getClinicByCode(clinicCodeRaw);
    if (!clinic?.id) {
      console.warn("[PATCH /api/patient/clinic] clinic_not_found:", clinicCodeRaw);
      return res.status(404).json({ ok: false, error: "clinic_not_found" });
    }

    const st = String(clinic.status ?? "active").toLowerCase();
    if (["suspended", "reject", "rejected", "inactive", "closed"].includes(st)) {
      return res.status(400).json({ ok: false, error: "clinic_unavailable", message: "Bu klinik şu an katılıma kapalı." });
    }

    const resolvedUuid = await resolveMessagesPatientDbId(req.patientId);
    if (!resolvedUuid) {
      console.warn("[PATCH /api/patient/clinic] patient_not_found token:", String(req.patientId || "").slice(0, 16));
      return res.status(404).json({ ok: false, error: "patient_not_found" });
    }

    let patientRow = null;
    for (const sel of [
      "id, patient_id, name, email, phone, status, language",
      "id, patient_id, name, email, phone, status",
      "id, name, email, phone, status",
    ]) {
      const r = await supabase.from("patients").select(sel).eq("id", resolvedUuid).maybeSingle();
      if (!r.error && r.data) {
        patientRow = r.data;
        break;
      }
    }
    if (!patientRow?.id) {
      return res.status(404).json({ ok: false, error: "patient_not_found" });
    }

    const codeStored = String(clinic.clinic_code || clinicCodeRaw).trim().toUpperCase();
    const upJoin = await updatePatientRowWithColumnPruning(patientRow.id, {
      clinic_id: clinic.id,
      clinic_code: codeStored,
      updated_at: new Date().toISOString(),
      is_lead: false,
    });

    if (!upJoin.ok) {
      const upErr = upJoin.error;
      console.error("[PATCH /api/patient/clinic] update failed:", upErr?.message || upErr);
      return res.status(500).json({
        ok: false,
        error: "update_failed",
        message: upErr?.message || "Güncelleme başarısız.",
      });
    }

    const patientStatus = String(patientRow.status || "PENDING").toUpperCase();
    const emailNorm = String(patientRow.email || "").trim().toLowerCase();
    const foundPhone = String(patientRow.phone || "").trim();
    const foundLanguage = patientRow.language;

    const tokenPayload = {
      type: "patient",
      patientId: patientRow.id,
      role: "PATIENT",
      status: patientStatus,
      email: emailNorm,
      clinicId: clinic.id,
      clinicCode: codeStored,
      ...(foundPhone ? { phone: foundPhone } : {}),
      ...(foundLanguage ? { language: foundLanguage } : {}),
    };

    const token = jwt.sign(tokenPayload, JWT_SECRET, { expiresIn: `${TOKEN_EXPIRY_DAYS}d` });

    try {
      const tokens = readJson(TOK_FILE, {});
      tokens[token] = {
        type: "patient",
        patientId: patientRow.id,
        role: "PATIENT",
        createdAt: now(),
        email: emailNorm,
        clinicId: clinic.id,
        clinicCode: codeStored,
        ...(foundPhone ? { phone: foundPhone } : {}),
        ...(foundLanguage ? { language: foundLanguage } : {}),
      };
      writeJson(TOK_FILE, tokens);
    } catch (tokErr) {
      console.warn("[PATCH /api/patient/clinic] TOK_FILE write:", tokErr?.message);
    }

    console.log("[PATCH /api/patient/clinic] ok patient:", String(patientRow.id).slice(0, 8), "clinic:", codeStored);

    return res.json({
      ok: true,
      token,
      clinic: {
        id: clinic.id,
        name: clinic.name || "Klinik",
        clinic_code: codeStored,
      },
      referral: null,
    });
  } catch (e) {
    console.error("[PATCH /api/patient/clinic]", e?.message || e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

