// GET /api/patient/:patientId/intraoral-photos — grouped by angle with validation status
app.get("/api/patient/:patientId/intraoral-photos", requireToken, handleGetIntraoralPhotos);

async function handleGetIntraoralPhotos(req, res) {
  try {
    const rawPid = String(req.params.patientId || "").trim();
    const patientId =
      rawPid.toLowerCase() === "me" ? String(req.patientId || "").trim() : String(req.params.patientId || "").trim();
    if (!(await patientIdsMatchForToken(req.patientId, patientId))) {
      return res.status(403).json({ ok: false, error: "patient_id_mismatch" });
    }

    const REQUIRED_ANGLES = ['FRONT', 'LEFT', 'RIGHT', 'UPPER', 'LOWER'];
    const byAngle = {};
    const allPhotos = [];

    // ── Source 1: Supabase patient_files table ─────────────────────────────
    if (isSupabaseEnabled()) {
      const patientUUID = await resolvePatientUUID(patientId);
      const { data: rows } = await supabase
        .from('patient_files')
        .select('id, file_url, file_name, angle_type, validation_status, validation_score, validation_issues, created_at, mime_type')
        .eq('patient_id', patientUUID)
        .not('angle_type', 'is', null)
        .order('created_at', { ascending: false });

      for (const row of (rows || [])) {
        const angle = String(row.angle_type || '').toUpperCase();
        if (!REQUIRED_ANGLES.includes(angle)) continue;
        if (byAngle[angle]) continue; // keep most recent per angle
        byAngle[angle] = {
          id: String(row.id),
          angle_type: angle,
          url: row.file_url,
          name: row.file_name,
          validation_status: row.validation_status || 'UNKNOWN',
          score: row.validation_score != null ? row.validation_score : null,
          issues: Array.isArray(row.validation_issues) ? row.validation_issues : [],
          created_at: row.created_at,
          source: 'supabase',
        };
      }
    }

    // ── Source 2: local disk uploads/patient/:patientId/ ──────────────────
    const LOCAL_DIR = path.join(__dirname, 'public', 'uploads', 'patient', patientId);
    if (fs.existsSync(LOCAL_DIR)) {
      const files = fs.readdirSync(LOCAL_DIR).sort().reverse();
      for (const fname of files) {
        const fnameLow = fname.toLowerCase();
        if (!fnameLow.match(/\.(jpg|jpeg|png)$/)) continue;
        const angle = REQUIRED_ANGLES.find(a => fnameLow.includes(a.toLowerCase()));
        if (!angle || byAngle[angle]) continue;
        const stat = fs.statSync(path.join(LOCAL_DIR, fname));
        const buf = fs.readFileSync(path.join(LOCAL_DIR, fname));
        const vr = validateIntraoralBuffer(buf);
        byAngle[angle] = {
          id: 'local_' + fname,
          angle_type: angle,
          url: `/uploads/patient/${encodeURIComponent(patientId)}/${encodeURIComponent(fname)}`,
          name: fname,
          validation_status: vr.status,
          score: vr.score,
          issues: vr.issues,
          created_at: stat.mtime.toISOString(),
          source: 'local',
        };
      }
    }

    // ── Source 3: local intraoral dir ─────────────────────────────────────
    const INTRAORAL_DIR = path.join(__dirname, 'public', 'uploads', 'intraoral', patientId);
    if (fs.existsSync(INTRAORAL_DIR)) {
      const files = fs.readdirSync(INTRAORAL_DIR).sort().reverse();
      for (const fname of files) {
        const fnameLow = fname.toLowerCase();
        if (!fnameLow.match(/\.(jpg|jpeg|png)$/)) continue;
        const angle = REQUIRED_ANGLES.find(a => fnameLow.includes(a.toLowerCase()));
        if (!angle || byAngle[angle]) continue;
        const stat = fs.statSync(path.join(INTRAORAL_DIR, fname));
        const buf = fs.readFileSync(path.join(INTRAORAL_DIR, fname));
        const vr = validateIntraoralBuffer(buf);
        byAngle[angle] = {
          id: 'intraoral_' + fname,
          angle_type: angle,
          url: `/uploads/intraoral/${encodeURIComponent(patientId)}/${encodeURIComponent(fname)}`,
          name: fname,
          validation_status: vr.status,
          score: vr.score,
          issues: vr.issues,
          created_at: stat.mtime.toISOString(),
          source: 'intraoral',
        };
      }
    }

    for (const [, photo] of Object.entries(byAngle)) allPhotos.push(photo);
    allPhotos.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());

    const missingAngles = REQUIRED_ANGLES.filter(a => !byAngle[a]);
    const allPresent    = missingAngles.length === 0;
    const allValid      = allPresent && allPhotos.every(p => p.validation_status === 'VALID');

    return res.json({
      ok: true,
      photos: allPhotos,
      byAngle,
      missingAngles,
      allPresent,
      allValid,
      requiredAngles: REQUIRED_ANGLES,
    });
  } catch (err) {
    console.error('[INTRAORAL PHOTOS] error:', err.message);
    return res.status(500).json({ ok: false, error: 'server_error', photos: [], byAngle: {}, missingAngles: [], allPresent: false, allValid: false });
  }
}

// GET /api/doctor/patient/:patientId/intraoral-photos — Doctor views patient's intraoral photos
app.get('/api/doctor/patient/:patientId/intraoral-photos', requireDoctorAuth, async (req, res) => {
  try {
    const patientId = String(req.params.patientId || '').trim();
    const REQUIRED_ANGLES = ['FRONT', 'LEFT', 'RIGHT', 'UPPER', 'LOWER'];
    const byAngle = {};

    if (isSupabaseEnabled()) {
      const patientUUID = await resolvePatientUUID(patientId);
      const { data: rows } = await supabase
        .from('patient_files')
        .select('id, file_url, file_name, angle_type, validation_status, validation_score, validation_issues, created_at')
        .eq('patient_id', patientUUID)
        .not('angle_type', 'is', null)
        .order('created_at', { ascending: false });

      for (const row of (rows || [])) {
        const angle = String(row.angle_type || '').toUpperCase();
        if (!REQUIRED_ANGLES.includes(angle) || byAngle[angle]) continue;
        byAngle[angle] = {
          id: String(row.id),
          angle_type: angle,
          url: row.file_url,
          name: row.file_name,
          validation_status: row.validation_status || 'UNKNOWN',
          score: row.validation_score,
          issues: row.validation_issues || [],
          created_at: row.created_at,
        };
      }
    }

    // Fallback: local dirs
    for (const dir of ['patient', 'intraoral']) {
      const D = path.join(__dirname, 'public', 'uploads', dir, patientId);
      if (!fs.existsSync(D)) continue;
      for (const fname of fs.readdirSync(D).sort().reverse()) {
        if (!fname.match(/\.(jpg|jpeg|png)$/i)) continue;
        const angle = REQUIRED_ANGLES.find(a => fname.toLowerCase().includes(a.toLowerCase()));
        if (!angle || byAngle[angle]) continue;
        const buf = fs.readFileSync(path.join(D, fname));
        const vr = validateIntraoralBuffer(buf);
        byAngle[angle] = {
          id: `${dir}_${fname}`,
          angle_type: angle,
          url: `/uploads/${dir}/${encodeURIComponent(patientId)}/${encodeURIComponent(fname)}`,
          name: fname,
          validation_status: vr.status,
          score: vr.score,
          issues: vr.issues,
          created_at: fs.statSync(path.join(D, fname)).mtime.toISOString(),
        };
      }
    }

    const photos = Object.values(byAngle);
    const missingAngles = REQUIRED_ANGLES.filter(a => !byAngle[a]);

    return res.json({
      ok: true,
      photos,
      byAngle,
      missingAngles,
      allPresent: missingAngles.length === 0,
      allValid: photos.length === 5 && photos.every(p => p.validation_status === 'VALID'),
      requiredAngles: REQUIRED_ANGLES,
    });
  } catch (err) {
    console.error('[DOCTOR INTRAORAL PHOTOS] error:', err.message);
    return res.status(500).json({ ok: false, error: 'server_error' });
  }
});

function logPerfLine(message) {
  if (!PERF_LOGS_ENABLED) return;
  console.log(message);
}

async function timedDbQuery(label, queryFactory) {
  const startedAt = Date.now();
  const result = await queryFactory();
  const duration = Date.now() - startedAt;
  if (PERF_LOGS_ENABLED) {
    const code = String(result?.error?.code || "").trim();
    console.log(`[DB PERF] ${label} ${duration}ms${code ? ` code=${code}` : ""}`);
  }
  return result;
}

function canUseFileFallback() {
  // Only allow file fallback when explicitly enabled.
  // This prevents data loss on deploy/restart in ephemeral environments.
  return ALLOW_FILE_FALLBACK === true;
}

function supabaseDisabledPayload(scope) {
  const s = scope ? ` (${scope})` : "";
  return {
    ok: false,
    error: "supabase_disabled",
    message: `Supabase is disabled${s}. Set SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY in deploy environment.`,
  };
}

function isMissingTableError(error, tableName) {
  const msg = String(error?.message || "");
  const details = String(error?.details || "");
  const hint = String(error?.hint || "");
  const combined = `${msg} ${details} ${hint}`.toLowerCase();
  const t = String(tableName || "").toLowerCase();
  return combined.includes("does not exist") && combined.includes(t);
}

function isMissingColumnError(error, columnName) {
  const msg = String(error?.message || "");
  const details = String(error?.details || "");
  const hint = String(error?.hint || "");
  const combined = `${msg} ${details} ${hint}`.toLowerCase();
  const code = String(error?.code ?? "");
  const isMissingCode =
    code === "PGRST204" ||
    code === "PGRST205" ||
    code === "42703" ||
    code.endsWith("42703");
  if (!columnName) return isMissingCode;
  const col = String(columnName || "").toLowerCase();
  if (combined.includes(`patients.${col}`) && combined.includes("does not exist")) {
    return true;
  }
  return isMissingCode && combined.includes(col);
}
// POST /api/chat/upload (patient uploads files/images to chat)
app.post("/api/chat/upload", requireToken, chatUpload.array("files", 5), async (req, res) => {
  try {
    const body = req.body || {};
    const bodyPid = String(body.patientId || "").trim();
    const patientId = String((bodyPid && bodyPid !== "me" ? bodyPid : req.patientId) || "").trim();
    if (!patientId) {
      return res.status(400).json({ ok: false, error: "patientId_required" });
    }
    if (req.patientId !== patientId) {
      return res.status(403).json({ ok: false, error: "patientId_mismatch" });
    }

    // Messages must be persistent in production
    if (!isSupabaseEnabled() && !canUseFileFallback()) {
      return res.status(500).json(supabaseDisabledPayload("messages"));
    }

    const files = Array.isArray(req.files) ? req.files : [];
    if (files.length === 0) {
      return res.status(400).json({ ok: false, error: "no_files", message: "No files received" });
    }

    const isImageUpload = String(body.isImage || "").toLowerCase() === "true";
    const allowedImageMimes = new Set(["image/jpeg", "image/jpg", "image/png", "image/heic", "image/heif"]);
    const allowedDocMimes = new Set([
      "application/pdf",
      "application/msword",
      "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
      "text/plain",
      "application/vnd.ms-excel",
      "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      "application/zip",
      "application/x-zip-compressed",
    ]);

    const CHAT_UPLOAD_DIR = path.join(__dirname, "public", "uploads", "chat", patientId);
    if (!fs.existsSync(CHAT_UPLOAD_DIR)) fs.mkdirSync(CHAT_UPLOAD_DIR, { recursive: true });

    const useFileStore = !isSupabaseEnabled() && canUseFileFallback();
    let chatFile = null;
    let messages = [];
    if (useFileStore) {
      const CHAT_DIR = path.join(DATA_DIR, "chats");
      if (!fs.existsSync(CHAT_DIR)) fs.mkdirSync(CHAT_DIR, { recursive: true });
      chatFile = path.join(CHAT_DIR, `${patientId}.json`);
      const existing = readJson(chatFile, { messages: [] });
      messages = Array.isArray(existing.messages) ? existing.messages : [];
    }

    const uploadedFiles = [];
    for (const file of files) {
      const mime = String(file.mimetype || "").toLowerCase();
      const size = Number(file.size || 0);
      const originalName = String(file.originalname || "file");

      const isImage = isImageUpload || mime.startsWith("image/");
      if (isImage && !allowedImageMimes.has(mime)) {
        return res.status(400).json({ ok: false, error: "invalid_file_type", message: "Geçersiz resim formatı" });
      }
      if (!isImage && !allowedDocMimes.has(mime)) {
        return res.status(400).json({ ok: false, error: "invalid_file_type", message: "Geçersiz dosya formatı" });
      }

      if (isImage && size > IMAGE_MAX_SIZE_BYTES) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: `Resim ${IMAGE_MAX_SIZE_MB}MB'dan küçük olmalıdır.` });
      }
      const isZip = mime === "application/zip" || mime === "application/x-zip-compressed";
      if (!isImage && isZip && size > 50 * 1024 * 1024) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: "ZIP 50MB'dan küçük olmalıdır." });
      }
      if (!isImage && !isZip && size > 20 * 1024 * 1024) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: "Dosya 20MB'dan küçük olmalıdır." });
      }

      let ext = path.extname(originalName || "").toLowerCase();
      if (!ext) {
        if (mime === "image/png") ext = ".png";
        else if (mime === "image/heic" || mime === "image/heif") ext = ".heic";
        else if (mime === "application/pdf") ext = ".pdf";
        else if (mime === "application/msword") ext = ".doc";
        else if (mime === "application/vnd.openxmlformats-officedocument.wordprocessingml.document") ext = ".docx";
        else if (mime === "application/vnd.ms-excel") ext = ".xls";
        else if (mime === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") ext = ".xlsx";
        else if (mime === "text/plain") ext = ".txt";
        else if (isZip) ext = ".zip";
        else ext = ".bin";
      }

      const safeName = `${patientId}_${now()}_${crypto.randomBytes(4).toString("hex")}${ext}`;
      const diskPath = path.join(CHAT_UPLOAD_DIR, safeName);
      fs.writeFileSync(diskPath, file.buffer);

      // Use relative URL so mobile app can prepend correct API_BASE
      // This ensures Android emulator uses 10.0.2.2 instead of localhost
      const fileUrl = `/uploads/chat/${encodeURIComponent(patientId)}/${encodeURIComponent(safeName)}`;
      const fileType = isImage ? "image" : "pdf";
      uploadedFiles.push({
        name: originalName,
        size,
        url: fileUrl,
        mimeType: mime,
        fileType,
      });

      // Photo metadata tags for patient-uploaded images
      const photoTags = isImage ? {
        source: "Patient Uploaded",
        sourceDescription: "Hasta tarafından mobil uygulama üzerinden yüklenmiştir.",
        photoType: "Pre-Treatment",
        photoTypeDescription: "Tedavi öncesi ön değerlendirme fotoğrafı",
        filterStatus: "No Filter Applied",
        filterStatusDescription: "Fotoğrafa herhangi bir filtre veya görsel manipülasyon uygulanmamıştır.",
        captureDate: new Date(now()).toLocaleDateString('tr-TR', {
          day: '2-digit',
          month: '2-digit',
          year: 'numeric'
        }),
        captureTimestamp: now(),
        // V2 fields for Before/After compatibility
        comparisonStatus: "Before", // Default for patient uploads
        clinicApprovalStatus: "Not Approved", // Default
        // Clinic-selectable fields (empty by default)
        visualQuality: null,
        clinicNote: null,
      } : null;

      const newMessage = {
        id: `msg_${now()}_${crypto.randomBytes(4).toString("hex")}`,
        text: "",
        from: "PATIENT",
        type: fileType,
        attachment: {
          name: originalName,
          size,
          url: fileUrl,
          mimeType: mime,
          fileType,
          ...(photoTags && { tags: photoTags }),
        },
        createdAt: now(),
        patientId,
      };

      if (isSupabaseEnabled()) {
        const ctxCode = body.clinicCode ?? body.clinic_code;
        const ctxId = body.clinicId ?? body.clinic_id;
        const { error: saveErr } = await insertMessageToSupabase({
          patientId,
          sender: "patient",
          message: "",
          attachments: newMessage.attachment,
          type: fileType,
          ...(ctxCode != null && String(ctxCode).trim()
            ? { contextClinicCode: String(ctxCode).trim() }
            : {}),
          ...(ctxId != null && String(ctxId).trim() ? { contextClinicId: String(ctxId).trim() } : {}),
        });
        if (saveErr) {
          const supabasePublic = supabaseErrorPublic(saveErr);
          console.error("[MESSAGES] Supabase save failed", {
            message: saveErr.message,
            code: saveErr.code,
            details: saveErr.details,
          });
          if (isMissingTableError(saveErr, "messages")) {
            return res.status(500).json({
              ok: false,
              error: "messages_table_missing",
              message: "Supabase schema missing: messages table. Run migration 008_create_messages_table.sql",
              supabase: supabasePublic,
            });
          }
          return res.status(500).json({ ok: false, error: "messages_save_failed", supabase: supabasePublic });
        }
      } else {
        messages.push(newMessage);
      }
    }

    if (useFileStore && chatFile) {
      writeJson(chatFile, { patientId, messages, updatedAt: now() });
    }
    return res.json({
      ok: true,
      files: uploadedFiles,
      message: uploadedFiles.length === 1 ? "File uploaded successfully" : `${uploadedFiles.length} files uploaded successfully`,
    });
  } catch (error) {

    return res.status(500).json({ ok: false, error: "upload_exception", message: error?.message || "Upload failed" });
  }
});

// ─── Google Maps coords: parseGoogleMapsCoords / resolveClinicCoords → lib/clinicCoords.cjs

// ─── AI Clinic Recommendation Helpers ────────────────────────────────────────

/**
 * Haversine distance between two GPS coordinates (returns km).
 */
function haversineKm(lat1, lon1, lat2, lon2) {
  const R    = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a    = Math.sin(dLat / 2) ** 2 +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

/** Format a km distance to a human-readable string: "2.3 km" or "900 m". */
function formatDistance(km) {
  if (km < 1) return `${Math.round(km * 1000)} m`;
  return `${km.toFixed(1)} km`;
}

// Max radius when user location is available (keeps results local; falls back
// to global top-3-by-rating when no clinics are within this range).
const MAX_CLINIC_DISTANCE_KM = 50;

/**
 * Maps insight keywords → dental specialty label.
 * Order matters: first match wins.
 */
const INSIGHT_SPECIALTY_MAP = [
  { pattern: /dizilim|alignment|eğri|çapraşık|ortodon/i,         label: 'Ortodonti' },
  { pattern: /eksik diş|missing.*tooth|implant/i,                label: 'İmplant' },
  { pattern: /diş eti|gum|periodont|kızarık|şişlik|bleeding/i,  label: 'Periodontoloji' },
  { pattern: /estetik|beyazlatma|smile|whiten|renk değişikliği/i, label: 'Estetik Diş Hekimliği' },
  { pattern: /çürük|cavity|leke|delik|dark spot/i,               label: 'Genel Diş Hekimliği' },
];

/** Determine the primary specialty needed from a list of insight strings. */
function detectSpecialtyFromInsights(insights) {
  const text = insights.join(' ');
  for (const { pattern, label } of INSIGHT_SPECIALTY_MAP) {
    if (pattern.test(text)) return label;
  }
  return 'Genel Diş Hekimliği';
}

/**
 * Fetches up to 3 recommended active clinics from Supabase.
 *
 * preferredCountry (ISO-2 or full name, e.g. "TR" / "Turkey"):
 *   - Takes precedence over userLocation
 *   - Filters clinics by country, sorts by rating DESC
 *
 * userLocation { latitude, longitude } (when no preferredCountry):
 *   - Haversine distance filter (MAX_CLINIC_DISTANCE_KM = 50 km)
 *   - Sorts by distance ASC → rating DESC
 *
 * Excludes patient's own clinic. Returns [] on error (non-fatal).
 */
async function getRecommendedClinics({ insights = [], patientId, userLocation, preferredCountry, userCountry } = {}) {
  if (!isSupabaseEnabled()) return [];
  try {
    const specialty = detectSpecialtyFromInsights(insights);

    // Exclude patient's own clinic
    let excludeClinicId = null;
    if (patientId) {
      const { data: pt } = await supabase
        .from('patients')
        .select('clinic_id')
        .eq('id', patientId)
        .maybeSingle();
      excludeClinicId = pt?.clinic_id || null;
    }

    // Fetch active clinics — include location fields
    //
    // CRITICAL: DB migration uses DEFAULT 'ACTIVE' (uppercase).  PostgREST
    // string equality is case-sensitive — .eq('status','active') matches ZERO
    // rows when the column holds 'ACTIVE', which made recommended clinics
    // (and any UI depending on this) always empty.
    //
    // Accept: NULL (legacy), 'active' / 'ACTIVE' / any case via ilike
    let query = supabase
      .from('clinics')
      .select('id, name, city, country, latitude, longitude, status')
      .or('status.is.null,status.ilike.active')
      .limit(20);
    if (excludeClinicId) query = query.neq('id', excludeClinicId);

    // Country filter: when a destination is preferred, skip distance logic entirely
    if (preferredCountry && preferredCountry !== 'nearby') {
      // Accept both ISO-2 codes and full country names (case-insensitive)
      query = query.or(`country.ilike.${preferredCountry},country.ilike.%${preferredCountry}%`);
    }

    const { data: rawClinics } = await query;
    // Exclude suspended/rejected even if legacy rows slipped through
    const clinics = (rawClinics || []).filter((c) => {
      const s = String(c.status ?? 'active').toLowerCase();
      return !['suspended', 'reject', 'rejected', 'inactive', 'closed'].includes(s);
    });
    if (!clinics?.length) return [];

    // Fetch avg ratings
    const ids = clinics.map(c => c.id);
    const { data: ratingRows } = await supabase
      .from('ratings')
      .select('clinic_id, overall, type')
      .in('clinic_id', ids);

    const ratingMap = ratingRows?.length ? buildClinicRatingMapWeighted(ratingRows) : {};

    const useCountryFilter = preferredCountry && preferredCountry !== 'nearby';
    const hasUserLocation  = !useCountryFilter &&
                             userLocation?.latitude != null && userLocation?.longitude != null;

    const withDistance = clinics.map(c => {
      let distanceKm = null;
      if (hasUserLocation && c.latitude != null && c.longitude != null) {
        distanceKm = haversineKm(
          userLocation.latitude, userLocation.longitude,
          c.latitude, c.longitude
        );
      }
      return {
        id:          c.id,
        name:        c.name    || 'Klinik',
        city:        c.city    || null,
        country:     c.country || null,
        specialty,
        rating:      ratingMap[c.id] ?? null,
        distanceKm,
        distance:    distanceKm != null ? formatDistance(distanceKm) : null,
      };
    });

    let candidates = withDistance;

    if (hasUserLocation) {
      // Distance-based: filter to radius, fall back if no clinic qualifies
      const nearby = withDistance.filter(
        c => c.distanceKm != null && c.distanceKm <= MAX_CLINIC_DISTANCE_KM
      );
      if (nearby.length > 0) candidates = nearby;
    }
    // Country mode: no radius filter — all results already filtered by DB query

    const countryHint =
      String(userCountry || "").trim() ||
      (preferredCountry && preferredCountry !== "nearby" ? String(preferredCountry).trim() : "");

    // Sort: user's country first → distance ASC (when available) → rating DESC
    candidates.sort((a, b) => {
      if (countryHint) {
        const p = countryPriorityScore(a.country, countryHint) - countryPriorityScore(b.country, countryHint);
        if (p !== 0) return -p;
      }
      if (a.distanceKm != null && b.distanceKm != null && a.distanceKm !== b.distanceKm) {
        return a.distanceKm - b.distanceKm;
      }
      if (a.distanceKm != null && b.distanceKm == null) return -1;
      if (b.distanceKm != null && a.distanceKm == null) return 1;
      return (b.rating ?? 0) - (a.rating ?? 0);
    });

    // Strip internal distanceKm before returning
    return candidates.slice(0, 3).map(({ distanceKm: _d, ...rest }) => rest);
  } catch (err) {
    logAI('warn', 'clinic_recommendations_error', { patientId, message: err?.message });
    return [];
  }
}

// ─── AI Dental Analysis Helpers ──────────────────────────────────────────────

/** Safe fallback returned whenever AI output is invalid or unrecoverable. */
const DENTAL_AI_FALLBACK = {
  insights:       ['Görüntü analiz edilemedi, lütfen tekrar deneyin.'],
  confidence:     'low',
  summary:        'Net bir değerlendirme yapılamadı.',
  recommendation: 'Farklı açılardan fotoğraf ekleyebilir veya diş hekiminize danışabilirsiniz.',
};

// ── Vague / generic phrases to reject (Turkish + English, case-insensitive) ──
// HARD RULES: any insight matching these is treated as invalid.
// "Görüntü kalitesi sınırlı…" is still ALLOWED as a quality qualifier.
const VAGUE_PATTERNS = [
  // Generic non-answers
  /\bsome issue\b/i,
  /\bproblem detected\b/i,
  /\bsomething wrong\b/i,
  /\bthere is a problem\b/i,
  /\bsomething may be wrong\b/i,
  /\bsorun (var|tespit edildi|mevcut)\b/i,
  /\bbir (sorun|problem|şey) (var|görünüyor)\b/i,
  /\bgenel (bir )?sorun\b/i,
  /\biyi görünüyor\b/i,            // "looks fine" without specifics
  /^(ok|iyi|normal|tamam|güzel)\.?$/i,  // single-word non-answers

  // ── Hard-rule refusal / cop-out phrases (trigger retry) ──
  /analiz edilemedi/i,             // "görüntü analiz edilemedi"
  /değerlendirilemedi/i,
  /net değil/i,                    // "görüntü net değil"
  /tekrar (deneyin|çekin)/i,       // "tekrar deneyin" as an insight = cop-out
  /görüntü (çok )?(bulanık|karanlık|yetersiz|kullanılamaz)/i,
  /yeterli (görüntü|bilgi|veri) (yok|bulunamadı)/i,
  /bu (görüntüden|fotoğraftan) (analiz|değerlendirme) (yapılamaz|edilemez)/i,

  // Pure refusal phrases — no observation at all
  /^(cannot|unable to) (analyze|analyse|assess|evaluate)\.?$/i,
  /^(analiz edilemez|değerlendirme yapılamaz)\.?$/i,
  /^(I cannot|I am unable to|I'm unable to) (analyze|assess|evaluate)/i,
];

/**
 * Count words in a string (handles Turkish multi-byte chars safely).
 */
function wordCount(str) {
  return str.trim().split(/\s+/).filter(Boolean).length;
}

/**
 * Returns true if the string matches any vague/generic phrase.
 */
function isVague(str) {
  return VAGUE_PATTERNS.some(p => p.test(str));
}

/**
 * Score a single insight string: 0–100.
 * Penalises short, vague, or non-specific text.
 */
function scoreInsight(text) {
  if (!text || text.length < 10) return 0;
  if (isVague(text))             return 10;
  // Reward cautious language — these are required for safe output
  const hasCautious = /olabilir|görünüyor|gibi görünüyor|olası|may indicate|possible|could be/i.test(text);
  // Reward specificity (mentions a tooth area, condition, symptom)
  const hasSpecific = /çürük|diş eti|dizilim|eksik|renk|leke|şişlik|kızarıklık|kırık|taş|kanal|dolgu|crown|cavity|align|gum|missing|color|stain|swelling|crack|calculus/i.test(text);
  let score = 40;                         // base: non-empty, non-vague, min length
  if (hasCautious) score += 30;
  if (hasSpecific) score += 30;
  return Math.min(score, 100);
}

/**
 * Score a summary or recommendation string: 0–100.
 */
function scoreText(text) {
  if (!text) return 0;
  const wc = wordCount(text);
  if (wc < 8)       return 0;            // too short
  if (isVague(text)) return 10;          // generic — unhelpful
  return Math.min(40 + Math.min(wc, 20) * 3, 100);  // reward length up to a point
}

/**
 * Runs full quality validation on a parsed AI result.
 * Returns { ok: boolean, score: number, reasons: string[] }
 */
function validateDentalAIQuality(parsed) {
  const reasons = [];

  // ── Insights ────────────────────────────────────────────────────────
  const insights = parsed.insights || [];
  const insightScores = insights.map(scoreInsight);
  const avgInsight = insights.length > 0
    ? insightScores.reduce((a, b) => a + b, 0) / insights.length
    : 0;

  if (insights.length === 0) {
    reasons.push('no_insights');
  } else {
    // Require at least 2 insights that are NOT refusal/vague phrases.
    // A quality disclaimer ("Görüntü kalitesi sınırlı...") does NOT count
    // toward the minimum — it must be accompanied by real observations.
    const nonRefusalInsights = insights.filter(t => t.length >= 10 && !isVague(t));
    if (nonRefusalInsights.length < 2) {
      reasons.push(
        nonRefusalInsights.length === 0
          ? 'all_insights_vague_or_refusal'
          : 'insufficient_real_insights'  // only 1 real insight — need 2
      );
    }
    insights.forEach((t, i) => {
      if (t.length < 10) reasons.push(`insight_${i}_too_short`);
    });
  }

  // ── Summary ─────────────────────────────────────────────────────────
  const summaryScore = scoreText(parsed.summary || '');
  if (summaryScore === 0) reasons.push('summary_weak');

  // ── Recommendation ──────────────────────────────────────────────────
  const recScore = scoreText(parsed.recommendation || '');
  if (recScore === 0) reasons.push('recommendation_weak');

  // ── Confidence ──────────────────────────────────────────────────────
  if (!['low', 'medium', 'high'].includes(parsed.confidence)) {
    reasons.push('invalid_confidence');
  }

  // ── Overall score (0–100) ────────────────────────────────────────────
  const score = Math.round((avgInsight * 0.5) + (summaryScore * 0.25) + (recScore * 0.25));

  return { ok: reasons.length === 0 && score >= 40, score, reasons };
}

/**
 * Per-photoType analysis focus and context hints.
 * photoType: 'front' | 'left' | 'right' | 'upper' | 'lower' | 'general'
 */
const PHOTO_TYPE_CONTEXT = {
  front: {
    label:   'Ön görünüm (front)',
    focus:   'Özellikle ön dişlerdeki dizilim sorunlarına, renk değişikliklerine ve diş eti çekilmesine odaklan.',
  },
  left: {
    label:   'Sol yan görünüm (left)',
    focus:   'Sol taraftaki dişlerdeki çürük belirtileri, eksik diş ve ısırma düzlemine odaklan.',
  },
  right: {
    label:   'Sağ yan görünüm (right)',
    focus:   'Sağ taraftaki dişlerdeki çürük belirtileri, eksik diş ve ısırma düzlemine odaklan.',
  },
  upper: {
    label:   'Üst çene (upper)',
    focus:   'Üst dişlerdeki çürük lekeleri, diş eti durumu ve genel hijyene odaklan.',
  },
  lower: {
    label:   'Alt çene (lower)',
    focus:   'Alt dişlerdeki çürük lekeleri, diş taşı birikimi ve diş eti sağlığına odaklan.',
  },
  general: {
    label:   'Genel ağız görünümü',
    focus:   'Olası çürük, eksik diş, dizilim sorunu ve dişeti durumuna eşit ağırlıkla odaklan.',
  },
};

/**
 * Generates a production-ready system+user prompt for dental photo analysis.
 * @param {string} photoType  'front' | 'left' | 'right' | 'upper' | 'lower' | 'general'
 */
function generateDentalAnalysisPrompt(photoType = 'general') {
  const ctx = PHOTO_TYPE_CONTEXT[photoType] || PHOTO_TYPE_CONTEXT.general;

  return {
    system: `You are a dental assistant AI. Analyze ONLY the teeth visible in the image. Ignore background, lips, and face.

If teeth are not clearly visible, return:
{ "insights": ["Image not suitable for dental analysis"], "confidence": "low", "summary": "Diş analizi için uygun görüntü bulunamadı.", "recommendation": "Lütfen dişlerinizi daha net gösteren bir fotoğraf çekin." }

Otherwise describe exactly three things in Turkish — one per insight:
1. Tooth color — stains, yellowing, discoloration
2. Alignment — crowding, spacing, crooked teeth
3. Visible issues — decay, chips, calculus buildup, gum recession

STRICT RULES:
- Analyze ONLY teeth. Never comment on face, skin, or background.
- Be concise and medical-focused. One sentence per insight.
- Use cautious language: "görünüyor", "olabilir", "gibi görünüyor".
- NEVER diagnose. NEVER guarantee treatment outcomes.
- Also set missingTeethLikely: "yes" if a tooth appears missing or there is a clear empty socket/gap where a tooth should be; "no" if all teeth appear present; "unclear" if you cannot judge from this image.
- Classify the dentalCondition: "missing_tooth" (empty socket / tooth absent), "misalignment" (crowding, overlapping, crooked teeth), "diastema" (small symmetric natural gap between front teeth, midline spacing), or "none" if none of these apply. Use "unclear" only if you cannot classify.
- Return ONLY valid JSON — no markdown, no extra text.`,

    user: `Photo type: ${ctx.label}

Examine the teeth in this image and return ONLY this JSON:
{
  "insights": ["tooth color observation in Turkish", "alignment observation in Turkish", "visible issue in Turkish"],
  "confidence": "low" | "medium" | "high",
  "summary": "1-sentence overall dental assessment in Turkish",
  "recommendation": "1 concrete next step for the patient in Turkish",
  "missingTeethLikely": "yes" | "no" | "unclear",
  "dentalCondition": "missing_tooth" | "misalignment" | "diastema" | "none" | "unclear",
  "dentalConditionConfidence": "low" | "medium" | "high"
}

Classify this dental condition: missing tooth (gap from absent tooth), misalignment (overlap/crowding), or natural front gap (diastema). Set dentalConditionConfidence to match how sure you are.

confidence guide: "low" = blurry or teeth barely visible | "medium" = partially visible | "high" = clear, well-lit photo`,
  };
}

/**
 * Stronger retry prompt — used when the first response is vague or refused.
 */
function generateRetryPrompt(photoType = 'general') {
  const ctx = PHOTO_TYPE_CONTEXT[photoType] || PHOTO_TYPE_CONTEXT.general;
  return {
    system: `You are a dental assistant AI. Your ONLY job is to describe what you see in the teeth.

MANDATORY — you MUST return exactly 2–3 observations about:
- Tooth color (yellowing, staining, whiteness)
- Tooth alignment (straight, crowded, gaps)
- Any visible problems (decay, chips, tartar, gum line)

FORBIDDEN: "analiz edilemedi", "net değil", "tekrar deneyin", empty insights.
Even a blurry photo has visible tooth shapes, approximate color, and a gum line — describe those.
Include missingTeethLikely: "yes" | "no" | "unclear" (missing tooth / empty socket vs all teeth present).
Include dentalCondition: "missing_tooth" | "misalignment" | "diastema" | "none" | "unclear" and dentalConditionConfidence.
Return ONLY valid JSON — no markdown, no extra text.`,

    user: `Photo type: ${ctx.label}

Your previous response lacked sufficient observations. Look again at the teeth only.

Return ONLY this JSON with 2–3 real dental observations in Turkish:
{
  "insights": ["renk gözlemi", "dizilim gözlemi", "görünür sorun (varsa)"],
  "confidence": "low",
  "summary": "1-sentence honest summary in Turkish",
  "recommendation": "1-sentence next step for the patient",
  "missingTeethLikely": "yes" | "no" | "unclear",
  "dentalCondition": "missing_tooth" | "misalignment" | "diastema" | "none" | "unclear",
  "dentalConditionConfidence": "low" | "medium" | "high"
}`,
  };
}

/**
 * Parses vision model field missingTeethLikely → true | false | null (unclear / missing).
 */
function parseMissingTeethVisionFlag(raw) {
  const v = raw?.missingTeethLikely;
  if (v === undefined || v === null) return null;
  if (typeof v === 'boolean') return v;
  const s = String(v).toLowerCase().trim();
  if (s === 'yes' || s === 'true' || s === 'evet') return true;
  if (s === 'no' || s === 'false' || s === 'hayır') return false;
  if (s === 'unclear' || s === 'unknown' || s === 'belirsiz') return null;
  return null;
}

/**
 * Vision JSON: dentalCondition + dentalConditionConfidence → { condition, confidence } or null.
 */
function parseDentalConditionFields(raw) {
  if (!raw || typeof raw !== 'object') return null;
  const c = raw.dentalCondition ?? raw.gapCondition;
  let s = String(c || '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '_')
    .replace(/-/g, '_');
  const aliases = {
    missing_tooth: 'missing_tooth',
    missingtooth: 'missing_tooth',
    tooth_loss: 'missing_tooth',
    misalignment: 'misalignment',
    crowding: 'misalignment',
    overlap: 'misalignment',
    crooked: 'misalignment',
    diastema: 'diastema',
    normal_gap: 'diastema',
    normalgap: 'diastema',
    spacing_normal: 'diastema',
    none: 'none',
    normal: 'none',
    unclear: 'unclear',
    unknown: 'unclear',
  };
  let norm = aliases[s];
  if (!norm && ['missing_tooth', 'misalignment', 'diastema', 'none', 'unclear'].includes(s)) norm = s;
  if (!norm || norm === 'unclear' || norm === 'none') return null;

  let conf = String(raw.dentalConditionConfidence || raw.conditionConfidence || 'medium').toLowerCase();
  if (!['low', 'medium', 'high'].includes(conf)) conf = 'medium';
  return { condition: norm, confidence: conf };
}

function higherDentalConfidence(a, b) {
  const o = { low: 1, medium: 2, high: 3 };
  return (o[a] || 0) >= (o[b] || 0) ? a : b;
}

/**
 * Merge rule-based + vision classification; vision wins on conflict.
 */
function mergeDentalCondition(rule, vision) {
  const rc = rule?.condition;
  const vc = vision?.condition;
  if (rc && vc && rc === vc) {
    return {
      condition: rc,
      confidence: higherDentalConfidence(rule.confidence || 'medium', vision.confidence || 'medium'),
    };
  }
  if (rc && vc && rc !== vc) {
    return { condition: vc, confidence: vision.confidence || 'medium' };
  }
  if (rc) return { condition: rc, confidence: rule.confidence || 'medium' };
  if (vc) return { condition: vc, confidence: vision.confidence || 'medium' };
  return null;
}

/**
 * Rule-based gap / alignment classification from insight text (not a diagnosis).
 */
function inferDentalConditionFromRules(t) {
  const text = String(t || '').toLowerCase();

  const misalignment =
    /\boverlap|overlapping|overlapping\s+teeth|crowding|crowded|crooked|rotat|çapraş|çapraz|üst\s*üste|stacked|misalignment|crossbite|malocclusion|çapraşık/i.test(
      text
    ) || text.includes('üst üste');
  if (misalignment) return { condition: 'misalignment', confidence: 'medium' };

  const diastemaHint =
    /\bdiastema\b|midi\s*line\s*gap|midline\s*gap|simetrik\s*(aralık|boşluk|gap)|symmetric\s*(gap|space|spacing|boşluk)/i.test(
      text
    ) ||
    (/\b(small|slight|narrow|minor|hafif|ince|küçük)\s+(gap|space|spacing|boşluk|aralık)/i.test(text) &&
      /\b(front|anterior|ön|midline|orta\s*hatt|central)/i.test(text));

  if (diastemaHint) return { condition: 'diastema', confidence: 'medium' };

  const largeGap =
    /\b(large|wide|significant|major|geniş|büyük)\s+(gap|space|spacing|boşluk|aralık)|empty\s+socket|boş\s+soket/i.test(text);
  const asymmetry =
    /\basymmetr|asymmetric|uneven|dengesiz|farklı\s+(taraf|yan)|one\s+side|tek\s+taraf/i.test(text);
  const explicitMissing =
    /\bmissing\s+tooth|eksik\s*diş|eksik\s*dişler|diş\s*eksikliği|missing\s+teeth/i.test(text);
  if ((largeGap && asymmetry) || explicitMissing) {
    return { condition: 'missing_tooth', confidence: explicitMissing ? 'high' : 'medium' };
  }
  return null;
}

/**
 * Calls OpenAI Vision once and returns { parsed, usage, model }.
 * Throws on HTTP / network errors. Never throws on parse failure.
 */
async function callOpenAIVision(system, user, imageDataUrl, { apiKey, timeoutMs = 30000 } = {}) {
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type':  'application/json',
      'Authorization': `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: system },
        {
          role: 'user',
          content: [
            { type: 'text',      text: user },
            { type: 'image_url', image_url: { url: imageDataUrl, detail: 'high' } },
          ],
        },
      ],
      max_tokens: 800,
      response_format: { type: 'json_object' },
    }),
    signal: AbortSignal.timeout(timeoutMs),
  });

  if (!res.ok) {
    const errBody = await res.json().catch(() => ({}));
    const err = new Error(errBody?.error?.message || 'OpenAI request failed');
    err.code   = 'openai_error';
    err.status = res.status;
    err.detail = errBody?.error;
    throw err;
  }

  const data    = await res.json();
  const content = data.choices?.[0]?.message?.content || '{}';

  let raw = {};
  try { raw = JSON.parse(content); } catch { /* fall through */ }

  const parsed = {
    insights:       Array.isArray(raw.insights)
                      ? raw.insights.map(s => String(s).trim()).filter(Boolean).slice(0, 3)
                      : [],
    confidence:     raw.confidence,
    summary:        String(raw.summary        || '').trim(),
    recommendation: String(raw.recommendation || '').trim(),
    missingTeethLikely: parseMissingTeethVisionFlag(raw),
    dentalConditionParsed: parseDentalConditionFields(raw),
  };

  return { parsed, usage: data.usage, model: data.model || 'gpt-4o' };
}

/**
 * Calls OpenAI Vision with automatic retry on weak/refusal responses.
 *
 * Flow:
 *   1. First call with normal prompt
 *   2. If quality validation fails → retry ONCE with a stronger "must observe" prompt
 *   3. If retry also fails → return DENTAL_AI_FALLBACK (never throws on content issues)
 *
 * Still throws on HTTP / network errors so the caller can return 502/504.
 */
async function processDentalAI(imageDataUrl, photoType = 'general', { apiKey, timeoutMs = 30000 } = {}) {
  // ── First attempt ────────────────────────────────────────────────────
  const { system: sys1, user: usr1 } = generateDentalAnalysisPrompt(photoType);
  const attempt1 = await callOpenAIVision(sys1, usr1, imageDataUrl, { apiKey, timeoutMs });

  const q1 = validateDentalAIQuality(attempt1.parsed);
  if (q1.ok) {
    return {
      insights:       attempt1.parsed.insights,
      confidence:     attempt1.parsed.confidence,
      summary:        attempt1.parsed.summary,
      recommendation: attempt1.parsed.recommendation,
      missingTeethLikely: attempt1.parsed.missingTeethLikely ?? null,
      dentalConditionParsed: attempt1.parsed.dentalConditionParsed ?? null,
      _usage:          attempt1.usage,
      _model:          attempt1.model,
      _fallback:       false,
      _retried:        false,
      _qualityScore:   q1.score,
      _qualityReasons: [],
    };
  }

  // ── Retry with stronger prompt ───────────────────────────────────────
  console.warn('[AI] First attempt weak — retrying with stronger prompt.', {
    photoType, score: q1.score, reasons: q1.reasons,
    insights: attempt1.parsed.insights,
  });

  const { system: sys2, user: usr2 } = generateRetryPrompt(photoType);
  const attempt2 = await callOpenAIVision(sys2, usr2, imageDataUrl, {
    apiKey,
    timeoutMs: Math.min(timeoutMs, 20_000), // shorter budget for retry
  });

  const q2 = validateDentalAIQuality(attempt2.parsed);
  if (q2.ok) {
    console.log('[AI] Retry succeeded.', { photoType, score: q2.score });
    return {
      insights:       attempt2.parsed.insights,
      confidence:     attempt2.parsed.confidence,
      summary:        attempt2.parsed.summary,
      recommendation: attempt2.parsed.recommendation,
      missingTeethLikely: attempt2.parsed.missingTeethLikely ?? null,
      dentalConditionParsed: attempt2.parsed.dentalConditionParsed ?? null,
      _usage:          attempt2.usage,
      _model:          attempt2.model,
      _fallback:       false,
      _retried:        true,
      _qualityScore:   q2.score,
      _qualityReasons: [],
    };
  }

  // ── Both calls failed validation ─────────────────────────────────────
  console.error('[AI] Both attempts failed quality validation.', {
    photoType,
    attempt1: { score: q1.score, reasons: q1.reasons },
    attempt2: { score: q2.score, reasons: q2.reasons },
  });

  return {
    ...DENTAL_AI_FALLBACK,
    missingTeethLikely: null,
    dentalConditionParsed: null,
    _usage:          attempt2.usage,
    _model:          attempt2.model,
    _fallback:       true,
    _retried:        true,
    _qualityScore:   q2.score,
    _qualityReasons: q2.reasons,
  };
}

// ─── Dental Enhancement Engine — structured teeth-first pipeline ───────────────
// Steps: (1) mouth crop (2) teeth mask + feather (3) normalize (4) Replicate? or LAB
// (5) mask-only blend (6) geometry/highlights (7) QC + composite. Not orthodontic simulation.
//
// TRANSFORM INTENT (product requirement — implemented via blend/LAB below):
//   "Visibly improve the smile. Teeth must look whiter, cleaner, and more
//   aesthetic. The result must be clearly different from the original at first glance."
// NEGATIVE CONSTRAINTS: never ship a no-op visually identical to the input;
//   the final look inside the teeth mask must not keep a yellow / dull tooth color.
//
// Canonical “prompt” line for logging / product parity (no external img2img here):
const SIM_VISUAL_INTENT_PROMPT =
  'perfect white teeth, straight aligned teeth, remove stains, close gaps, cosmetic dental improvement, clearly visible enhancement, ideal smile design, natural but noticeable difference';
//
// SIM_TRANSFORM_STRENGTH: programmatic LAB/blend (0.35 … 0.98). Default 0.5 — natural, not over-edited.
//
// QUALITY RULES (canonical):
//   ACCEPT:          stain removal, tartar cleaning, mild whitening,
//                    preserve tooth shape and spacing exactly
//   PARTIAL ACCEPT:  subtle alignment (max ±3 px) — disabled by default
//   REJECT:          full smile reconstruction, paper-white artificial look,
//                    shape-changing restorations, any geometry invention
//   KEY PRINCIPLE:   "Improve quality, not geometry"
//
// Pipeline:
//  1. Fetch original → tight mouth crop (lips + teeth; excludes most chin/beard)
//  2. Build teeth mask (brightness+saturation+hue filter, σ=3 blur)
//  3. computeLocalStats  → per-pixel 7×7 mean + std (adaptive tartar detection)
//  4. computeEnhancedRaw → tartar removal + LAB whitening (strong visible lift)
//  5. bilateralFilter    → edge-preserving smooth (r=3, σ_color=25, σ_space=3)
//  6. blendCropWithMask  → alpha blend + dark-floor + line-reduce + micro-tex
//                          + uniform whitening (higher target factor; visible-first)
//  7. [optional] microAlignment — disabled; enable via MICRO_ALIGN_ENABLED
//  8. sharpen + composite onto full original + upload Supabase

const _SIM_STR_RAW = process.env.SIM_TRANSFORM_STRENGTH;
const _SIM_STR_NUM =
  _SIM_STR_RAW !== undefined && String(_SIM_STR_RAW).trim() !== ''
    ? Number(_SIM_STR_RAW)
    : NaN;
/** Programmatic / LAB blend aggressiveness (default 0.5; max 0.98). */
const SIM_TRANSFORM_STRENGTH = Number.isFinite(_SIM_STR_NUM)
  ? Math.min(0.98, Math.max(0.35, _SIM_STR_NUM))
  : 0.5;

/** Max RGB in tooth pipeline — avoids chalk-white flat patches (was 245). */
const ENAMEL_OUTPUT_CAP = 236;

/** Client copy for chat/mobile — use confidenceLabelTr instead of “low confidence”; hide slider if no URL. */
const SIMULATION_UI_COPY = {
  confidenceLabelTr: 'AI tahmini sonuç',
  photoGuidanceTr:
    'Fotoğrafı önden, iyi ışıkta ve dişleriniz net görünecek şekilde çekin.',
  photoGuidanceBothRowsTr:
    'Fotoğrafta hem üst hem alt dişleriniz görünmelidir. Aksi halde simülasyon çalışmaz.',
};

const INVALID_PHOTO_BOTH_ARCHES_EN =
  'Please take a photo where both upper and lower teeth are clearly visible.';
const INVALID_PHOTO_BOTH_ARCHES_TR =
  'Lütfen üst ve alt dişlerinizin net göründüğü bir fotoğraf çekin.';
const INVALID_PHOTO_LOWER_UNCHANGED_EN =
  'Simulation could not improve lower teeth on this photo. Retake with both rows visible.';
const INVALID_PHOTO_LOWER_UNCHANGED_TR =
  'Alt dişler bu fotoğrafta yeterince iyileştirilemedi; üst ve alt dişlerinizin net göründüğü bir kare deneyin.';

/** Extra L* lift — kept subtle to preserve texture (used in computeEnhancedRaw). */
function simLabStrengthMultiplier() {
  const s = SIM_TRANSFORM_STRENGTH;
  return 1 + Math.max(0, s - 0.48) * 0.45;
}

function applySimTransformStrength(cfg) {
  const s = SIM_TRANSFORM_STRENGTH;
  const kBlend = 0.88 + s * 0.28;
  const uniBoost = 1 + (s - 0.35) * 0.38;
  return {
    ...cfg,
    blendAlpha: {
      strong: Math.min(0.98, cfg.blendAlpha.strong * kBlend),
      edge: Math.min(0.72, cfg.blendAlpha.edge * kBlend),
    },
    uniformTargetFactor: Math.min(1.62, cfg.uniformTargetFactor * uniBoost),
  };
}

/**
 * STEP 1 — Mouth region (nose-bottom → upper chin), not full face.
 * Tunable: SMILE_CROP_*_FRAC env. `enforceMouthOnlyCrop` rejects face-wide boxes.
 */
function getSmileMouthCropBox(origW, origH) {
  const L = Number(process.env.SMILE_CROP_LEFT_FRAC);
  const T = Number(process.env.SMILE_CROP_TOP_FRAC);
  const Wf = Number(process.env.SMILE_CROP_WIDTH_FRAC);
  const Hf = Number(process.env.SMILE_CROP_HEIGHT_FRAC);
  const left = Number.isFinite(L) ? L : 0.17;
  const top = Number.isFinite(T) ? T : 0.54;
  const wid = Number.isFinite(Wf) ? Wf : 0.66;
  const ht = Number.isFinite(Hf) ? Hf : 0.24;
  return {
    cropLeft:   Math.round(origW * left),
    cropTop:    Math.round(origH * top),
    cropWidth:  Math.round(origW * wid),
    cropHeight: Math.round(origH * ht),
  };
}

/** Debug: log a short data-URL prefix for JPEG buffers (server logs). */
function logSimDebugPreview(label, buf) {
  if (!buf || !buf.length) return;
  const b64 = buf.toString("base64");
  const clip = b64.length > 220 ? b64.slice(0, 220) + "…" : b64;
  console.log(`[SIM DEBUG] ${label}: data:image/jpeg;base64,${clip}`);
}

/** Soft edge weight 0–1 inside crop (distance to crop border), for feathered merge. */
function buildCropFeatherMap(w, h, featherPx) {
  const out = new Float32Array(w * h);
  const f = Math.max(1, featherPx);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const dx = Math.min(x, w - 1 - x);
      const dy = Math.min(y, h - 1 - y);
      const d = Math.min(dx, dy);
      out[y * w + x] = Math.min(1, d / f);
    }
  }
  return out;
}

/**
 * MVP mouth band when face landmarks are unavailable (full-frame relative).
 * STEP 1 approximate mouth: mouth.x ≈ 0.2·W, mouth.y ≈ 0.55·H, width ≈ 0.6·W, height ≈ 0.35·H (face-sized frame).
 */
function getSpecFallbackMouthRectFromFullImage(origW, origH) {
  let cropLeft = Math.floor(origW * 0.2);
  let cropTop = Math.floor(origH * 0.55);
  let cropWidth = Math.round(origW * 0.6);
  let cropHeight = Math.round(origH * 0.35);
  cropLeft = Math.max(0, Math.min(cropLeft, origW - 64));
  cropTop = Math.max(0, Math.min(cropTop, origH - 64));
  if (cropLeft + cropWidth > origW) cropWidth = origW - cropLeft;
  if (cropTop + cropHeight > origH) cropHeight = origH - cropTop;
  cropWidth = Math.max(64, cropWidth);
  cropHeight = Math.max(64, cropHeight);
  return { cropLeft, cropTop, cropWidth, cropHeight };
}

/** Reject full-face-sized extracts — recrop to a fixed mouth band. */
function enforceMouthOnlyCrop(origW, origH) {
  let box = getSmileMouthCropBox(origW, origH);
  const hr = box.cropHeight / origH;
  const wr = box.cropWidth / origW;
  if (hr > 0.38 || wr > 0.88 || hr < 0.10 || wr < 0.45) {
    console.warn(
      `[SIM CROP] Non-mouth ratios detected (h=${(hr * 100).toFixed(1)}% w=${(wr * 100).toFixed(1)}%) — hard mouth recrop`
    );
    box = {
      cropLeft:   Math.round(origW * 0.16),
      cropTop:    Math.round(origH * 0.555),
      cropWidth:  Math.round(origW * 0.68),
      cropHeight: Math.round(origH * 0.22),
    };
  }
  return box;
}

/** STEP 2 follow-up — feathered teeth mask; Gaussian on mask only (σ ~12–14 typical). Not full-image blur. */
async function featherTeethMaskForBlend(maskBuf, w, h) {
  const sigma = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_MASK_FEATHER_SIGMA ?? '14'), 10);
    return Number.isFinite(v) ? Math.min(20, Math.max(8, v)) : 14;
  })();
  return sharp(maskBuf).resize(w, h).blur(sigma).png().toBuffer();
}

/**
 * Smile-simulation crop polish (cropCompositeSimulation only): mouth brightness match, lower depth,
 * shadow under uppers, lower-only desat (SIM_SMILE_LOWER_SAT_MULT), softer lower arch, micro color.
 */
async function applySmileSimCropRealismPass(blendedCropBuf, origCropBuf, maskBuf, w, h) {
  const lowerMult = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_LOWER_DARKEN_MULT ?? '0.87'), 10);
    return Number.isFinite(v) ? Math.min(0.99, Math.max(0.82, v)) : 0.87;
  })();
  const shadowMult = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_UPPER_SHADOW_MULT ?? '0.92'), 10);
    return Number.isFinite(v) ? Math.min(1, Math.max(0.86, v)) : 0.92;
  })();
  const lowerSoftenSigma = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_LOWER_SOFTEN_SIGMA ?? '1.2'), 10);
    return Number.isFinite(v) ? Math.min(1.8, Math.max(0, v)) : 1.2;
  })();
  const softenBlend = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_LOWER_SOFTEN_BLEND ?? '0.82'), 10);
    return Number.isFinite(v) ? Math.min(0.95, Math.max(0, v)) : 0.82;
  })();
  const lowerSatMult = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_LOWER_SAT_MULT ?? '0.95'), 10);
    return Number.isFinite(v) ? Math.min(1, Math.max(0.88, v)) : 0.95;
  })();

  const cropRaw = await sharp(blendedCropBuf).resize(w, h).removeAlpha().raw().toBuffer();
  const origRaw = await sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer();
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const out = Buffer.from(cropRaw);

  const lumRgb = (raw, ii) => {
    const r = raw[ii * 3],
      g = raw[ii * 3 + 1],
      b = raw[ii * 3 + 2];
    return 0.299 * r + 0.587 * g + 0.114 * b;
  };
  let refSum = 0,
    refN = 0,
    toothSum = 0,
    toothN = 0;
  for (let i = 0; i < w * h; i++) {
    const m = maskRaw[i];
    if (m > 35 && m < 115) {
      refSum += lumRgb(origRaw, i);
      refN++;
    }
    if (m > 185) {
      toothSum += lumRgb(out, i);
      toothN++;
    }
  }
  const refAvg = refN > 0 ? refSum / refN : 105;
  const toothAvg = toothN > 0 ? toothSum / toothN : refAvg;
  const mouthMatch = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_MOUTH_MATCH_STRENGTH ?? '0.72'), 10);
    return Number.isFinite(v) ? Math.min(1, Math.max(0, v)) : 0.72;
  })();
  let brightPull = 1;
  if (toothAvg > refAvg * 1.05 && toothN > 80) {
    const target = refAvg * 1.03;
    brightPull = 1 + (target / toothAvg - 1) * mouthMatch;
  }

  const yLower = Math.floor(h * 0.48);
  const ySh0 = Math.floor(h * 0.26);
  const ySh1 = Math.floor(h * 0.46);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (maskRaw[i] <= 64) continue;
      let m = brightPull;
      if (y >= yLower) m *= lowerMult;
      if (y >= ySh0 && y <= ySh1) {
        const t = (y - ySh0) / Math.max(1, ySh1 - ySh0);
        const band = Math.sin(t * Math.PI);
        m *= 1 + (shadowMult - 1) * band;
      }
      for (let c = 0; c < 3; c++) {
        out[i * 3 + c] = Math.min(255, Math.round(out[i * 3 + c] * m));
      }
    }
  }

  // Lower-only chroma pull (less saturated than uppers) — luminance-preserving
  if (lowerSatMult < 0.999) {
    for (let y = yLower; y < h; y++) {
      for (let x = 0; x < w; x++) {
        const i = y * w + x;
        if (maskRaw[i] <= 64) continue;
        const r = out[i * 3],
          g = out[i * 3 + 1],
          b = out[i * 3 + 2];
        const L = 0.299 * r + 0.587 * g + 0.114 * b;
        out[i * 3] = Math.min(255, Math.round(L + (r - L) * lowerSatMult));
        out[i * 3 + 1] = Math.min(255, Math.round(L + (g - L) * lowerSatMult));
        out[i * 3 + 2] = Math.min(255, Math.round(L + (b - L) * lowerSatMult));
      }
    }
  }

  let softenedBuf = await sharp(out, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 92 })
    .toBuffer();
  if (lowerSoftenSigma > 0.03) {
    const blurRaw = await sharp(softenedBuf).blur(lowerSoftenSigma).removeAlpha().raw().toBuffer();
    for (let y = yLower; y < h; y++) {
      for (let x = 0; x < w; x++) {
        const i = y * w + x;
        if (maskRaw[i] <= 64) continue;
        const sb = softenBlend;
        for (let c = 0; c < 3; c++) {
          const o = out[i * 3 + c];
          const br = blurRaw[i * 3 + c];
          out[i * 3 + c] = Math.min(255, Math.round(o * (1 - sb) + br * sb));
        }
      }
    }
    softenedBuf = await sharp(out, { raw: { width: w, height: h, channels: 3 } })
      .jpeg({ quality: 92 })
      .toBuffer();
  } else {
    softenedBuf = await sharp(out, { raw: { width: w, height: h, channels: 3 } })
      .jpeg({ quality: 92 })
      .toBuffer();
  }

  const sat = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_MICRO_SAT ?? '0.978'), 10);
    return Number.isFinite(v) ? Math.min(1.02, Math.max(0.94, v)) : 0.978;
  })();
  const contrastMult = (() => {
    const v = parseFloat(String(process.env.SIM_SMILE_MICRO_CONTRAST ?? '1.025'), 10);
    return Number.isFinite(v) ? Math.min(1.03, Math.max(0.98, v)) : 1.025;
  })();
  const b = 128 * (1 - contrastMult);
  return sharp(softenedBuf)
    .modulate({ saturation: sat })
    .linear(contrastMult, b)
    .jpeg({ quality: 92 })
    .toBuffer();
}

/**
 * STEP 3 — Teeth normalization (pre-enhancement): mild brightness + contrast + yellow pull inside mask.
 * Stabilizes input; does not replace final clinical blend.
 */
async function normalizeTeethPreEnhance(cropBuf, maskBuf, w, h) {
  const [raw, maskRaw] = await Promise.all([
    sharp(cropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  let sumL = 0, n = 0;
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 64) continue;
    const r = raw[i * 3], g = raw[i * 3 + 1], b = raw[i * 3 + 2];
    const [L] = rgbToLab(r, g, b);
    sumL += L;
    n++;
  }
  const meanL = n > 0 ? sumL / n : 76;
  const targetL = Math.min(86, Math.max(70, meanL + 3.5));
  const out = Buffer.from(raw);
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 64) continue;
    const r0 = raw[i * 3], g0 = raw[i * 3 + 1], b0 = raw[i * 3 + 2];
    const [L, A, B] = rgbToLab(r0, g0, b0);
    const Ln = L + (targetL - meanL) * 0.38;
    const [Lw, Aw, Bw] = neutralizeLabWarmWhite(Ln, A, B, {
      lockL: true,
      aScale: 0.85,
      bScale: 0.78,
      Lmax: 94,
    });
    let [r, g, b] = labToRgb(Math.min(94, Lw), Aw, Bw);
    const k = 0.62;
    r = Math.min(ENAMEL_OUTPUT_CAP, Math.round(r0 * (1 - k) + r * k));
    g = Math.min(ENAMEL_OUTPUT_CAP, Math.round(g0 * (1 - k) + g * k));
    b = Math.min(ENAMEL_OUTPUT_CAP, Math.round(b0 * (1 - k) + b * k));
    out[i * 3] = r;
    out[i * 3 + 1] = g;
    out[i * 3 + 2] = b;
  }
  return sharp(out, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 95 })
    .toBuffer();
}

// Teeth-aware img2img — set REPLICATE_IMG2IMG_VERSION to stability-ai/stable-diffusion-img2img (version hash on replicate.com).
// Single-pass + dual-pass default (STEP 4 — same prompt for upper and lower Replicate calls).
const SIM_REPLICATE_PROMPT_DEFAULT =
  'perfect white teeth, straight aligned teeth, remove stains, close gaps, cosmetic dental improvement, clearly visible enhancement, ideal smile design, natural but noticeable difference';

// Dual-region: upper strip + lower strip use the SAME prompt (split controls focus, not wording).
// Override: REPLICATE_DUAL_PROMPT or REPLICATE_TEETH_PROMPT.
const SIM_REPLICATE_DUAL_PROMPT = SIM_REPLICATE_PROMPT_DEFAULT;

// Default: dual upper/lower strips when Replicate is configured (no single full-crop by default).
// SIM_DUAL_REGION_REPLICATE=0 — skip dual; then programmatic only unless SIM_USE_SINGLE_PASS_REPLICATE=1.
const SIM_DUAL_REGION_REPLICATE_ENABLED = String(process.env.SIM_DUAL_REGION_REPLICATE || '').trim() !== '0';

const SIM_REPLICATE_NEGATIVE_DEFAULT =
  'fake teeth, plastic teeth, overly white, perfect symmetry, cartoon, blurry, distorted face, ' +
  'unnatural smile, duplicated teeth, ignoring lower teeth, unchanged lower teeth, upper teeth only, ' +
  'lower teeth brighter than inner mouth or gums, oversharpened lower teeth, harsh glossy lower arch, ' +
  'watermark, text, extra teeth, wrong tooth count';

/**
 * Img2img denoise (Replicate prompt_strength). Values below 0.8 are raised to 0.85 for visible change.
 */
const REPLICATE_PROMPT_STRENGTH_DEFAULT = 0.5;

/**
 * Classifier-free guidance — medium (not aggressive). Default 6.5; clamp 5–9. Set GUIDANCE_SCALE=0 to omit.
 */
function replicateGuidanceScaleFromEnv() {
  const raw = process.env.GUIDANCE_SCALE;
  if (raw === '0' || raw === 'false') return null;
  if (raw === undefined || String(raw).trim() === '') return 6.5;
  const n = Number(raw);
  if (!Number.isFinite(n)) return 6.5;
  return Math.min(9, Math.max(5, n));
}

function replicateNumInferenceStepsFromEnv() {
  const raw = process.env.REPLICATE_NUM_INFERENCE_STEPS;
  if (raw === '0' || raw === 'false') return null;
  const def = 30;
  if (raw === undefined || String(raw).trim() === '') return def;
  const n = parseInt(String(raw), 10);
  if (!Number.isFinite(n)) return def;
  return Math.min(50, Math.max(15, n));
}

/**
 * STEP 4 (optional) — Replicate img2img on mouth crop only; result still merged via teeth mask later.
 * opts.promptSuffix / opts.strengthOverride — lower-arch retry path.
 */
async function replicateTeethImg2ImgOptional(cropJpegBuf, w, h, opts = {}) {
  const token = process.env.REPLICATE_API_TOKEN;
  const version = process.env.REPLICATE_IMG2IMG_VERSION;
  if (!token || !version) return null;
  const envStr = Number(process.env.REPLICATE_PROMPT_STRENGTH);
  let strength = Math.min(
    0.98,
    Math.max(
      0.35,
      Number.isFinite(envStr) ? envStr : REPLICATE_PROMPT_STRENGTH_DEFAULT
    )
  );
  if (typeof opts.strengthOverride === 'number' && Number.isFinite(opts.strengthOverride)) {
    strength = Math.min(0.98, Math.max(0.35, opts.strengthOverride));
  }
  if (strength < 0.8) {
    strength = 0.85;
  }
  const envPrompt = process.env.REPLICATE_TEETH_PROMPT;
  const basePrompt = envPrompt || SIM_REPLICATE_PROMPT_DEFAULT;
  let prompt;
  if (opts.promptOverride != null && String(opts.promptOverride).trim() !== '') {
    prompt = String(opts.promptOverride);
  } else {
    prompt = basePrompt + (opts.promptSuffix ? String(opts.promptSuffix) : '');
  }
  const image = `data:image/jpeg;base64,${cropJpegBuf.toString('base64')}`;
  const negRaw = process.env.REPLICATE_TEETH_NEGATIVE_PROMPT;
  const input = { image, prompt, prompt_strength: strength };
  if (negRaw === '0' || negRaw === 'false') {
    // allow disabling for models that reject negative_prompt
  } else {
    input.negative_prompt = (negRaw && String(negRaw).trim()) || SIM_REPLICATE_NEGATIVE_DEFAULT;
  }
  const g = replicateGuidanceScaleFromEnv();
  if (g != null) input.guidance_scale = g;
  const steps = replicateNumInferenceStepsFromEnv();
  if (steps != null) input.num_inference_steps = steps;
  console.log(
    `[SIMSTEP 4] Replicate img2img strength=${strength.toFixed(2)} guidance=${g != null ? g.toFixed(1) : 'omit'} steps=${steps ?? 'omit'}`
  );
  try {
    const create = await fetch('https://api.replicate.com/v1/predictions', {
      method: 'POST',
      headers: {
        Authorization: `Token ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ version, input }),
    });
    const txt = await create.text();
    if (!create.ok) {
      console.warn('[SIMSTEP 4] Replicate create failed:', txt.slice(0, 400));
      return null;
    }
    const pred = JSON.parse(txt);
    const pollUrl = pred.urls?.get;
    if (!pollUrl) return null;
    const deadline = Date.now() + 120_000;
    while (Date.now() < deadline) {
      const pr = await fetch(pollUrl, {
        headers: { Authorization: `Token ${token}` },
      });
      const st = await pr.json();
      if (st.status === 'succeeded') {
        const out = st.output;
        const url = Array.isArray(out) ? out[0] : out;
        if (typeof url !== 'string') {
          console.warn('[SIMSTEP 4] Replicate unexpected output shape');
          return null;
        }
        const imgRes = await fetch(url, { signal: AbortSignal.timeout(60_000) });
        if (!imgRes.ok) return null;
        return Buffer.from(await imgRes.arrayBuffer());
      }
      if (st.status === 'failed' || st.status === 'canceled') {
        console.warn('[SIMSTEP 4] Replicate job:', st.status, st.error);
        return null;
      }
      await new Promise((r) => setTimeout(r, 1500));
    }
    console.warn('[SIMSTEP 4] Replicate timeout');
    return null;
  } catch (e) {
    console.warn('[SIMSTEP 4] Replicate error:', e?.message);
    return null;
  }
}

/**
 * Feather-merge two Replicate outputs (upper strip + lower strip) back to full crop WxH.
 * seam at ySplit with 2*overlap px horizontal blend band.
 */
async function mergeDualVerticalReplicateStrips(upperOutBuf, lowerOutBuf, w, h, ySplit, overlap) {
  const topLower = Math.max(0, ySplit - overlap);
  const hUp = Math.min(ySplit + overlap, h);
  const hLo = h - topLower;
  const upperRaw = await sharp(upperOutBuf).resize(w, hUp).removeAlpha().raw().toBuffer();
  const lowerRaw = await sharp(lowerOutBuf).resize(w, hLo).removeAlpha().raw().toBuffer();
  const seam0 = ySplit - overlap;
  const seam1 = ySplit + overlap;
  const blendH = Math.max(1, seam1 - seam0);
  const out = Buffer.alloc(w * h * 3);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const di = (y * w + x) * 3;
      let r;
      let g;
      let b;
      if (y < seam0) {
        const ui = (y * w + x) * 3;
        r = upperRaw[ui];
        g = upperRaw[ui + 1];
        b = upperRaw[ui + 2];
      } else if (y >= seam1) {
        const li = ((y - topLower) * w + x) * 3;
        r = lowerRaw[li];
        g = lowerRaw[li + 1];
        b = lowerRaw[li + 2];
      } else {
        const t = blendH <= 1 ? 0 : (y - seam0) / (blendH - 1);
        const ui = (y * w + x) * 3;
        const li = ((y - topLower) * w + x) * 3;
        r = upperRaw[ui] * (1 - t) + lowerRaw[li] * t;
        g = upperRaw[ui + 1] * (1 - t) + lowerRaw[li + 1] * t;
        b = upperRaw[ui + 2] * (1 - t) + lowerRaw[li + 2] * t;
      }
      out[di] = Math.round(r);
      out[di + 1] = Math.round(g);
      out[di + 2] = Math.round(b);
    }
  }
  const mergedJpeg = await sharp(out, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 92 })
    .toBuffer();
  return applyDualSeamEdgeBlur(mergedJpeg, w, h, ySplit, overlap);
}

/**
 * STEP 6 — slight blur on the horizontal seam band to hide strip boundaries.
 * Set SIM_DUAL_SEAM_BLUR=0 to disable.
 */
async function applyDualSeamEdgeBlur(jpegBuf, w, h, ySplit, overlap) {
  const raw = process.env.SIM_DUAL_SEAM_BLUR;
  if (raw === '0' || raw === 'false') return jpegBuf;
  let sigma = 0.85;
  if (raw !== undefined && String(raw).trim() !== '') {
    const n = parseFloat(String(raw), 10);
    if (Number.isFinite(n)) sigma = Math.min(3, Math.max(0.25, n));
  }
  const pad = Math.max(4, Math.min(28, Math.floor(overlap * 0.65)));
  const top = Math.max(0, ySplit - pad);
  const height = Math.min(h - top, 2 * pad + 4);
  if (height < 6) return jpegBuf;
  try {
    const blurredStrip = await sharp(jpegBuf)
      .extract({ left: 0, top, width: w, height })
      .blur(sigma)
      .toBuffer();
    return await sharp(jpegBuf)
      .composite([{ input: blurredStrip, left: 0, top }])
      .jpeg({ quality: 92 })
      .toBuffer();
  } catch (e) {
    console.warn('[SIM DUAL] seam blur skipped:', e?.message);
    return jpegBuf;
  }
}

/**
 * STEP 1 — Mouth ROI is already the working crop (MediaPipe lips/teeth or heuristic band).
 *        Heuristic fallback matches ~face: x+20%·w, y+55%·h, w=60%·h, h=30% (see getSpecFallbackMouthRectFromFullImage).
 * STEP 2 — Split at 50% height (upper / lower half of mouth) with small overlap for blend.
 * STEP 3–5 — Same prompt both passes; merge overlays strips back to full mouth crop; STEP 6 blurs seam.
 * Does NOT fall back to single full-crop — caller uses programmatic path or SIM_USE_SINGLE_PASS_REPLICATE=1.
 */
async function replicateDualRegionTeethImg2Img(workingCropBuf, w, h, opts = {}) {
  const token = process.env.REPLICATE_API_TOKEN;
  const version = process.env.REPLICATE_IMG2IMG_VERSION;
  if (!token || !version) return null;

  // Top 50% / bottom 50% of mouth (default); SIM_DUAL_REGION_SPLIT_Y overrides (clamped).
  const splitEnv = parseFloat(String(process.env.SIM_DUAL_REGION_SPLIT_Y || '0.5'), 10);
  const yFrac = Number.isFinite(splitEnv) ? Math.min(0.62, Math.max(0.38, splitEnv)) : 0.5;
  const ySplit = Math.floor(h * yFrac);
  const overlap = Math.max(8, Math.min(32, Math.floor(h * 0.06)));

  const hUp = Math.min(ySplit + overlap, h);
  const topLower = Math.max(0, ySplit - overlap);
  const hLo = h - topLower;

  if (hUp < 24 || hLo < 24) {
    console.warn('[SIM DUAL] crop too small for dual-region — skip Replicate (use programmatic)');
    return null;
  }

  let upperExtract;
  let lowerExtract;
  try {
    upperExtract = await sharp(workingCropBuf)
      .extract({ left: 0, top: 0, width: w, height: hUp })
      .jpeg({ quality: 92 })
      .toBuffer();
    lowerExtract = await sharp(workingCropBuf)
      .extract({ left: 0, top: topLower, width: w, height: hLo })
      .jpeg({ quality: 92 })
      .toBuffer();
  } catch (e) {
    console.warn('[SIM DUAL] extract failed:', e?.message);
    return null;
  }

  const dualPrompt =
    (process.env.REPLICATE_DUAL_PROMPT && String(process.env.REPLICATE_DUAL_PROMPT).trim()) ||
    (process.env.REPLICATE_TEETH_PROMPT && String(process.env.REPLICATE_TEETH_PROMPT).trim()) ||
    SIM_REPLICATE_DUAL_PROMPT;

  const strengthDual = (() => {
    const o = opts.strengthOverride;
    if (typeof o === 'number' && Number.isFinite(o)) return o;
    const envStr = Number(process.env.REPLICATE_PROMPT_STRENGTH_DUAL);
    if (Number.isFinite(envStr)) return Math.min(0.98, Math.max(0.35, envStr));
    return undefined;
  })();

  const upOpts = { promptOverride: dualPrompt };
  const loOpts = { promptOverride: dualPrompt };
  if (strengthDual != null) {
    upOpts.strengthOverride = strengthDual;
    loOpts.strengthOverride = strengthDual;
  }

  console.log(
    `[SIM DUAL] ySplit=${ySplit}/${h} overlap=${overlap} | upper ${w}×${hUp} | lower ${w}×${hLo} (parallel Replicate)`
  );

  const [upOut, loOut] = await Promise.all([
    replicateTeethImg2ImgOptional(upperExtract, w, hUp, upOpts),
    replicateTeethImg2ImgOptional(lowerExtract, w, hLo, loOpts),
  ]);

  if (upOut && loOut) {
    try {
      const merged = await mergeDualVerticalReplicateStrips(upOut, loOut, w, h, ySplit, overlap);
      console.log('[SIM DUAL] merged upper+lower strips → full crop');
      return merged;
    } catch (e) {
      console.warn('[SIM DUAL] merge failed:', e?.message);
    }
  } else {
    console.warn('[SIM DUAL] one or both region calls failed — no single-pass fallback (SIM_USE_SINGLE_PASS_REPLICATE=1 for legacy)');
  }

  return null;
}

/**
 * Heuristic: both arches should have some mask mass. Defaults are lenient — many real
 * smiles have more upper-mask pixels; set SIM_STRICT_BOTH_ARCH=1 for hard rejects.
 */
async function validateBothArchesVisible(maskBuf, w, h) {
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const yMid = Math.floor(h * 0.5);
  let upper = 0;
  let lower = 0;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (maskRaw[i] <= 64) continue;
      if (y < yMid) upper++;
      else lower++;
    }
  }
  const minPx = Math.max(28, Math.floor(w * h * 0.00045));
  if (upper < minPx || lower < minPx) {
    console.warn(`[SIM ARCH] sparse: upper=${upper} lower=${lower} min=${minPx}`);
    return { ok: false, upper, lower, reason: 'sparse_arch' };
  }
  const ratio = upper > 0 ? lower / upper : 0;
  // Smiles often bias mask to upper incisors — do not fail unless extremely lopsided
  if (ratio < 0.042) {
    console.warn(`[SIM ARCH] imbalance: upper=${upper} lower=${lower} ratio=${ratio.toFixed(3)}`);
    return { ok: false, upper, lower, reason: 'lower_arch_weak', ratio };
  }
  return { ok: true, upper, lower };
}

/** Mean abs RGB change on lower half of crop (y ≥ 48%) inside teeth mask. */
async function measureLowerArchChange(origCropBuf, resCropBuf, maskBuf, w, h) {
  const [o, r, m] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const y0 = Math.floor(h * 0.48);
  let sum = 0;
  let n = 0;
  for (let y = y0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (m[i] <= 64) continue;
      n++;
      for (let c = 0; c < 3; c++) sum += Math.abs(o[i * 3 + c] - r[i * 3 + c]);
    }
  }
  const meanAbs = n > 0 ? sum / (n * 3) : 0;
  return { meanAbs, maskPx: n };
}

/** Stronger whitening blend on lower band only (Replicate off or retry path). */
async function boostLowerArchMerge(origCropBuf, blendedCropBuf, maskBuf, w, h, cfg) {
  const enc = await computeEnhancedRaw(origCropBuf, w, h, true);
  const strongCfg = scaleSimStrength(cfg, 1.45);
  const boosted = await blendCropWithMask(origCropBuf, enc, maskBuf, w, h, strongCfg);
  const [r, b, m] = await Promise.all([
    sharp(blendedCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(boosted).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const yCut = Math.floor(h * 0.47);
  const out = Buffer.from(r);
  for (let y = yCut; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (m[i] <= 64) continue;
      const a = m[i] / 255;
      for (let c = 0; c < 3; c++) {
        out[i * 3 + c] = Math.min(
          ENAMEL_OUTPUT_CAP,
          Math.round(r[i * 3 + c] * (1 - a * 0.72) + b[i * 3 + c] * (a * 0.72))
        );
      }
    }
  }
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

