// Resolve incoming mode string → canonical config
function resolveSimMode(mode) {
  return SIM_MODES[mode] ?? SIM_MODES.full;  // default: full
}

// Feature flags
const MICRO_ALIGN_ENABLED = false; // legacy global; per-mode cfg.alignment governs runtime

// ── Teeth mask ───────────────────────────────────────────────────────────────
// ── Connected-component filter (binary mask, pure JS BFS) ────────────────────
// Teeth form one or two large contiguous blobs (upper arch / lower arch).
// Any isolated pixel cluster smaller than `minSize` is noise — pores, specular
// reflections on skin, lone bright pixels in beard — and must be removed.
// The function keeps only components whose size is ≥ `minSize` OR ≥ 20 % of
// the largest component found, whichever is bigger.
function keepLargestComponents(maskData, w, h, minSize = 80) {
  const visited = new Uint8Array(w * h);
  const components = [];

  for (let start = 0; start < w * h; start++) {
    if (maskData[start] === 0 || visited[start]) continue;

    // BFS
    const queue = [start];
    const pixels = [];
    visited[start] = 1;
    while (queue.length) {
      const idx = queue.shift();
      pixels.push(idx);
      const y = Math.floor(idx / w), x = idx % w;
      const neighbours = [
        y > 0     ? idx - w : -1,
        y < h - 1 ? idx + w : -1,
        x > 0     ? idx - 1 : -1,
        x < w - 1 ? idx + 1 : -1,
      ];
      for (const n of neighbours) {
        if (n >= 0 && maskData[n] > 0 && !visited[n]) {
          visited[n] = 1;
          queue.push(n);
        }
      }
    }
    components.push(pixels);
  }

  // Determine size threshold: keep anything ≥ 15% of the largest component,
  // or above the absolute minSize floor.  15% (was 20%) gives more tolerance
  // for cases where upper and lower arches are detected separately and the
  // lower arch is significantly smaller due to staining.
  const maxSize   = components.reduce((m, c) => Math.max(m, c.length), 0);
  const threshold = Math.max(minSize, Math.round(maxSize * 0.15));

  // Build clean mask: only keep large components
  const result = Buffer.alloc(w * h);
  let kept = 0, removed = 0;
  for (const comp of components) {
    if (comp.length >= threshold) {
      for (const idx of comp) result[idx] = 255;
      kept++;
    } else {
      removed++;
    }
  }
  console.log(`[SIM MASK CC] kept=${kept} comps, removed=${removed} small blobs (threshold=${threshold}px)`);
  return result;
}

// ── Morphological erosion (binary mask, pure JS) ─────────────────────────────
// Shrinks "on" (255) regions inward by `radius` pixels.  Any on-pixel that has
// at least one off-pixel (or image border) within the square neighbourhood is
// turned off.  This prevents boundary pixels — which sit on the lip/gum edge —
// from surviving into the feathered output, eliminating colour bleed at the
// teeth/soft-tissue transition.
function erodeMask(maskData, w, h, radius = 2) {
  const result = Buffer.from(maskData);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      if (maskData[y * w + x] === 0) continue;  // already off — skip
      let mustErode = false;
      outer: for (let dy = -radius; dy <= radius; dy++) {
        for (let dx = -radius; dx <= radius; dx++) {
          const ny = y + dy, nx = x + dx;
          // Border pixel → erode (mask never extends to crop boundary)
          if (ny < 0 || ny >= h || nx < 0 || nx >= w) { mustErode = true; break outer; }
          if (maskData[ny * w + nx] === 0)             { mustErode = true; break outer; }
        }
      }
      if (mustErode) result[y * w + x] = 0;
    }
  }
  return result;
}

/** Remove warm brown / stubble-like pixels from lower crop (beard overlaps “tooth” heuristics). */
function stripBeardAndChinFromMask(maskData, data, w, h) {
  const y0 = Math.floor(h * 0.50);
  let stripped = 0;
  for (let y = y0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (maskData[i] === 0) continue;
      const r = data[i * 3], g = data[i * 3 + 1], b = data[i * 3 + 2];
      const sat = Math.max(r, g, b) - Math.min(r, g, b);
      const br = (r + g + b) / 3;
      const warmBeard =
        r > g && g > b && sat > 16 && r / (b + 1) > 1.15 && br < 200;
      const stubbleTex = sat > 28 && br < 150 && r > g;
      const chinBand = y > h * 0.66 && br < 95;
      if (warmBeard || stubbleTex || chinBand) {
        maskData[i] = 0;
        stripped++;
      }
    }
  }
  if (stripped > 0)
    console.log(`[SIM MASK] beard/chin exclusion: stripped ${stripped} px from lower face`);
}

/** Dark, low-saturation lower-face strands (beard shadow) — exclude from teeth mask. */
function excludeDarkBeardFromMask(maskData, data, w, h) {
  const y0 = Math.floor(h * 0.52);
  let z = 0;
  for (let y = y0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (maskData[i] === 0) continue;
      const r = data[i * 3], g = data[i * 3 + 1], b = data[i * 3 + 2];
      const br = (r + g + b) / 3;
      const sat = Math.max(r, g, b) - Math.min(r, g, b);
      if (br < 92 && sat < 55) {
        maskData[i] = 0;
        z++;
        continue;
      }
      if (y > h * 0.62 && br < 118 && r > g && g > b && sat > 22 && sat < 70) {
        maskData[i] = 0;
        z++;
      }
    }
  }
  if (z > 0) console.log(`[SIM MASK] dark-beard exclusion: cleared ${z} px`);
}

/**
 * Soft elliptical ROI when colour-based mask is empty — still only mid-crop “enamel band”,
 * not chin/beard (vertical span ~middle 38% of crop).
 */
async function buildFallbackTeethMask(origCropBuf, w, h) {
  const { data } = await sharp(origCropBuf)
    .resize(w, h).removeAlpha().raw().toBuffer({ resolveWithObject: true });
  const maskData = Buffer.alloc(w * h);
  const cx = w / 2;
  const cy = h * 0.40;
  const rx = w * 0.33;
  const ry = h * 0.11;
  const yTop = Math.floor(h * 0.22);
  const yBot = Math.floor(h * 0.72);
  for (let y = yTop; y < yBot; y++) {
    for (let x = 0; x < w; x++) {
      const nx = (x - cx) / rx;
      const ny = (y - cy) / ry;
      const d = nx * nx + ny * ny;
      if (d <= 1.0) {
        const i = y * w + x;
        const alpha = Math.max(0, 1 - d * 0.35);
        maskData[i] = Math.floor(255 * alpha);
      }
    }
  }
  stripBeardAndChinFromMask(maskData, data, w, h);
  excludeDarkBeardFromMask(maskData, data, w, h);
  return sharp(maskData, { raw: { width: w, height: h, channels: 1 } })
    .blur(2.5)
    .png()
    .toBuffer();
}

async function buildTeethMask(origCropBuf, w, h) {
  const { data } = await sharp(origCropBuf)
    .resize(w, h).removeAlpha().raw().toBuffer({ resolveWithObject: true });
  const maskData = Buffer.alloc(w * h);
  let white = 0;

  // ── Spatial exclusion zones ───────────────────────────────────────────────
  // The crop now covers 56–82 % of image height, which tightly spans
  // upper-lip → lower-teeth.  The mask must be even tighter:
  //   • Top 20 %   : upper lip, philtrum
  //   • Bottom 22 %: lower lip boundary, gum, early chin
  //     (bottom 22% of 26%-height crop ≈ top-5.7% of original → ends ~76% of image)
  //     Teeth never extend below this line even in fully open-mouth shots.
  //   • Left  5 %  : lip corner
  //   • Right 5 %  : lip corner
  const Y_TOP_EXCL = Math.floor(h * 0.18);
  // Include lower incisors (was 0.66 — cut off too much of the lower arch).
  const Y_BOT_EXCL = Math.floor(h * 0.80);
  const X_L_EXCL   = Math.floor(w * 0.05);
  const X_R_EXCL   = Math.floor(w * 0.95);

  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      // Hard spatial gate
      if (y < Y_TOP_EXCL || y >= Y_BOT_EXCL) continue;
      if (x < X_L_EXCL   || x >= X_R_EXCL)   continue;

      const i = y * w + x;
      const r = data[i*3], g = data[i*3+1], b = data[i*3+2];
      const brightness  = (r + g + b) / 3;
      const saturation  = Math.max(r, g, b) - Math.min(r, g, b);

      // ── LAB-space gum / lip rejection ──────────────────────────────────
      // Gums and lips carry elevated A* (red-green axis > 0 = reddish/pink).
      // Tooth enamel always sits near A* ≈ 0 (neutral to very slightly warm).
      // Any pixel with A* > 12 is almost certainly soft tissue — reject.
      const [, labA] = rgbToLab(r, g, b);
      if (labA > 12) continue;

      // ── Warm-tone skin / beard guard ────────────────────────────────────
      // Skin and beard: R > G > B with significant saturation and R/B ratio.
      // Teeth enamel is neutral or mildly yellow — never deeply warm-orange.
      if (r > g && saturation > 35 && (r / (b + 1)) > 1.45) continue;

      // ── Standard tooth: bright, low-saturation, neutral/slightly yellow ─
      // Floor = 115 (not 130): moderately-stained upper incisors sit at 115-130.
      // Beard/skin at this brightness is already caught by the LAB A* guard above
      // and the warm-tone ratio guard below — brightness alone is a bad discriminator.
      const isStdTooth = brightness > 115
        && saturation <= 70
        && g >= r * 0.70    // not too red-warm
        && b >= r * 0.58;   // not too orange

      // ── Stained / lower incisor (relaxed, lower half only) ─────────────
      // Tartar-covered lower incisors routinely fall at brightness 90-120.
      // The spatial exclusion (Y_BOT_EXCL = 78%), LAB A* guard, and the
      // warm-tone ratio guard below are sufficient to reject beard/stubble.
      // Do NOT use brightness as the primary beard discriminator.
      const isLowerRegion = y / h > 0.44;
      const isLowerTooth  = isLowerRegion
        && brightness > 100          // stained lower incisors can be 90-120
        && saturation <= 95          // tartar adds chroma but stays below 95
        && g >= r * 0.56             // not too red-warm (beard: g/r ~ 0.70-0.85)
        && b >= r * 0.38             // not too orange
        // Saturated warm guard (stubble): reject if deeply warm AND saturated
        && !(r > 165 && saturation > 42 && r > g * 1.16);

      if (isStdTooth || isLowerTooth) { maskData[i] = 255; white++; }
    }
  }

  stripBeardAndChinFromMask(maskData, data, w, h);
  excludeDarkBeardFromMask(maskData, data, w, h);

  // ── Connected-component cleanup ───────────────────────────────────────────
  // Remove small isolated blobs (pores, skin specular reflections, stray bright
  // pixels in beard).  Teeth form one or two large continuous arches; anything
  // smaller than 15 % of the largest component is noise.  Absolute min = 50 px.
  const ccClean = keepLargestComponents(maskData, w, h, 50);
  const afterCC = ccClean.reduce((s, v) => s + (v > 0 ? 1 : 0), 0);

  // ── Morphological erosion (2 px) ─────────────────────────────────────────
  // Shrinks the binary mask inward by 2 pixels so no boundary pixels (sitting
  // on the lip/gum edge) survive into the blended output.
  // NOTE: 3 px was too aggressive — it eliminated stained/thin teeth that barely
  // passed the colour filter.  2 px + CC cleanup provides equivalent safety.
  const eroded = erodeMask(ccClean, w, h, 2);
  const afterErosion = eroded.reduce((s, v) => s + (v > 0 ? 1 : 0), 0);

  console.log(`[SIM MASK] ${white}/${w*h} raw → CC=${afterCC} → 2-px eroded=${afterErosion} (${((afterErosion/(w*h))*100).toFixed(1)}%)`);

  // blur(2) adds gentle feathering at the eroded boundary.
  return sharp(eroded, { raw: { width: w, height: h, channels: 1 } }).blur(2).png().toBuffer();
}

// ── Local stats (7×7 window): mean + std per pixel ───────────────────────────
function computeLocalStats(brightness, w, h, radius = 3) {
  const R = radius; // default 7×7; pass 2 for 5×5
  const mean = new Float32Array(w * h);
  const std  = new Float32Array(w * h);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      let sum = 0, sum2 = 0, n = 0;
      for (let dy = -R; dy <= R; dy++) {
        for (let dx = -R; dx <= R; dx++) {
          const ny = y+dy, nx = x+dx;
          if (ny >= 0 && ny < h && nx >= 0 && nx < w) {
            const v = brightness[ny*w+nx]; sum += v; sum2 += v*v; n++;
          }
        }
      }
      mean[y*w+x] = sum / n;
      std[y*w+x]  = Math.sqrt(Math.max(0, sum2/n - (sum/n)**2));
    }
  }
  return { mean, std };
}

// ── Real RGB↔LAB conversion ───────────────────────────────────────────────────
function rgbToLab(r, g, b) {
  let rn = r/255, gn = g/255, bn = b/255;
  const lin = c => c > 0.04045 ? Math.pow((c+0.055)/1.055, 2.4) : c/12.92;
  rn = lin(rn); gn = lin(gn); bn = lin(bn);
  const x = rn*0.4124564 + gn*0.3575761 + bn*0.1804375;
  const y = rn*0.2126729 + gn*0.7151522 + bn*0.0721750;
  const z = rn*0.0193339 + gn*0.1191920 + bn*0.9503041;
  const f = t => t > 0.008856 ? Math.cbrt(t) : 7.787*t + 16/116;
  return [116*f(y/1.00000)-16, 500*(f(x/0.95047)-f(y/1.00000)), 200*(f(y/1.00000)-f(z/1.08883))];
}
function labToRgb(L, A, B) {
  const fy = (L+16)/116, fx = A/500+fy, fz = fy-B/200;
  const fi = t => t > 0.206897 ? t**3 : (t-16/116)/7.787;
  const x = 0.95047*fi(fx), y = 1.00000*fi(fy), z = 1.08883*fi(fz);
  let r =  x*3.2404542 - y*1.5371385 - z*0.4985314;
  let gn = -x*0.9692660 + y*1.8760108 + z*0.0415560;
  let bn =  x*0.0556434 - y*0.2040259 + z*1.0572252;
  r = Math.max(0,Math.min(1,r)); gn = Math.max(0,Math.min(1,gn)); bn = Math.max(0,Math.min(1,bn));
  const gam = c => c > 0.0031308 ? 1.055*c**(1/2.4)-0.055 : 12.92*c;
  return [Math.min(245,Math.round(gam(r)*255)), Math.min(245,Math.round(gam(gn)*255)), Math.min(245,Math.round(gam(bn)*255))];
}

/**
 * Whitening in LAB: boost L and partially neutralize a-star / b-star (not to zero; avoids grey enamel).
 * If chroma collapses, add slight +b (warm ivory).
 */
function neutralizeLabWarmWhite(L, A, B, opts = {}) {
  const {
    Lscale = 1.0,
    Lmax = 96,
    aScale = 0.7,
    bScale = 0.6,
    lockL = false,
  } = opts;
  let Lw = lockL ? L : Math.min(Lmax, L * Lscale);
  let Aw = A * aScale;
  let Bw = B * bScale;
  if (Math.abs(Aw) < 2 && Math.abs(Bw) < 2) {
    Bw += 3;
  }
  return [Lw, Aw, Bw];
}

/** User-selectable tooth shade (CIE L*a*b* deltas). Applied inside teeth mask after mask detect (Stage 2). */
const COLOR_PRESETS = {
  natural:   { L: 10, a: -5, b: -8 },
  bright:    { L: 18, a: -8, b: -12 },
  hollywood: { L: 28, a: -12, b: -18 },
  soft:      { L: 14, a: -6, b: -10 },
};

const SMILE_COLOR_PRESET_KEYS = Object.keys(COLOR_PRESETS);

function resolveSmileColorPreset(key) {
  const k = String(key || '').toLowerCase().trim();
  return COLOR_PRESETS[k] ? k : 'natural';
}

function clampLab(L, A, B) {
  return [
    Math.max(0, Math.min(100, L)),
    Math.max(-128, Math.min(127, A)),
    Math.max(-128, Math.min(127, B)),
  ];
}

function applyColorPresetLab(L, A, B, preset) {
  let Ln = L + preset.L;
  let An = A + preset.a;
  let Bn = B + preset.b;
  return clampLab(Ln, An, Bn);
}

/**
 * One RGB pixel + preset name → whitened RGB (LAB deltas from COLOR_PRESETS).
 * `pixel` may be `{ r, g, b }` or `[r, g, b]`.
 */
function applyColorPreset(pixel, presetKey) {
  const r = pixel && typeof pixel === 'object' && 'r' in pixel ? pixel.r : pixel[0];
  const g = pixel && typeof pixel === 'object' && 'g' in pixel ? pixel.g : pixel[1];
  const b = pixel && typeof pixel === 'object' && 'b' in pixel ? pixel.b : pixel[2];
  const k = resolveSmileColorPreset(presetKey);
  const preset = COLOR_PRESETS[k];
  const [L, A, B] = rgbToLab(r, g, b);
  const [Lw, Aw, Bw] = applyColorPresetLab(L, A, B, preset);
  const [ro, go, bo] = labToRgb(Lw, Aw, Bw);
  return {
    r: Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, ro)),
    g: Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, go)),
    b: Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, bo)),
  };
}

/**
 * Stage-2 color: LAB deltas inside teeth mask only (after mask detection).
 * Uses full 0–255 RGB cap so presets stay visibly distinct (ENAMEL_OUTPUT_CAP was saturating all to ~236).
 */
async function applySmileColorPresetToMaskedCrop(jpegBuf, maskBuf, w, h, presetKey) {
  const k = resolveSmileColorPreset(presetKey);
  const selected = COLOR_PRESETS[k];
  if (!selected) {
    console.warn('[SIM COLOR] missing COLOR_PRESETS entry for', k);
    return jpegBuf;
  }
  console.log('APPLYING PRESET VALUES:', selected, '| key:', k);

  const hashIn = crypto.createHash('sha256').update(jpegBuf).digest('hex').slice(0, 16);
  const { data } = await sharp(jpegBuf).resize(w, h).removeAlpha().raw().toBuffer({ resolveWithObject: true });
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const out = Buffer.from(data);

  const maskMin = Number.isFinite(Number(process.env.SIM_PRESET_MASK_MIN))
    ? Math.max(0, Math.min(220, Number(process.env.SIM_PRESET_MASK_MIN)))
    : 32;

  let toothPx = 0;
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= maskMin) continue;
    toothPx++;
    const r = data[i * 3];
    const g = data[i * 3 + 1];
    const b = data[i * 3 + 2];
    let [L, A, B] = rgbToLab(r, g, b);
    L += selected.L;
    A += selected.a;
    B += selected.b;
    [L, A, B] = clampLab(L, A, B);
    L = Math.min(L, 92);
    const [ro, go, bo] = labToRgb(L, A, B);
    out[i * 3] = Math.min(255, Math.max(0, Math.round(ro)));
    out[i * 3 + 1] = Math.min(255, Math.max(0, Math.round(go)));
    out[i * 3 + 2] = Math.min(255, Math.max(0, Math.round(bo)));
  }

  const jpegOut = await sharp(out, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 92 })
    .toBuffer();
  const hashOut = crypto.createHash('sha256').update(jpegOut).digest('hex').slice(0, 16);
  console.log(
    `[SIM PRESET] teethPx=${toothPx} maskMin=${maskMin} L*<=92 sha256 in=${hashIn} out=${hashOut} ${hashIn !== hashOut ? 'DIFF' : 'SAME'}`
  );
  if (toothPx === 0) {
    console.warn('[SIM PRESET] zero tooth pixels above maskMin — preset had no effect; try lowering SIM_PRESET_MASK_MIN');
  }
  return jpegOut;
}

/**
 * Post-preset: natural enamel — upper/lower whitening split, soft mask feather (0.6–0.8),
 * final = 0.65*mod + 0.35*orig (scaled by feather), L*<=92, subtle L* variation.
 * Set SIM_ENAMEL_NATURALISM=0 to skip.
 */
async function applyEnamelNaturalismAfterPreset(modifiedJpeg, origCropBuf, maskBuf, w, h) {
  if (String(process.env.SIM_ENAMEL_NATURALISM || '').trim() === '0') {
    console.log('[SIM ENAMEL] naturalism pass skipped (SIM_ENAMEL_NATURALISM=0)');
    return modifiedJpeg;
  }

  const maskMin = Number.isFinite(Number(process.env.SIM_PRESET_MASK_MIN))
    ? Math.max(0, Math.min(220, Number(process.env.SIM_PRESET_MASK_MIN)))
    : 32;
  const MOD_MIX = 0.65;
  const ORG_MIX = 0.35;
  const L_CAP = Number.isFinite(Number(process.env.SIM_ENAMEL_L_CAP))
    ? Math.min(100, Math.max(70, Number(process.env.SIM_ENAMEL_L_CAP)))
    : 92;

  const modRaw = await sharp(modifiedJpeg).resize(w, h).removeAlpha().raw().toBuffer();
  const origRaw = await sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer();
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const out = Buffer.alloc(w * h * 3);

  let n = 0;
  for (let y = 0; y < h; y++) {
    const vy = h > 1 ? y / (h - 1) : 0.5;
    const isUpper = y < h * 0.48;
    // Upper arch: slightly stronger lift; lower: softer (less plastic / patchy)
    const lVerticalBase = 6.5 * (1 - vy) + 2.5 * vy;
    const lVertical = isUpper ? lVerticalBase * 1.12 : lVerticalBase * 0.78;

    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (maskRaw[i] <= maskMin) {
        out[i * 3] = modRaw[i * 3];
        out[i * 3 + 1] = modRaw[i * 3 + 1];
        out[i * 3 + 2] = modRaw[i * 3 + 2];
        continue;
      }
      n++;

      let r = modRaw[i * 3];
      let g = modRaw[i * 3 + 1];
      let b = modRaw[i * 3 + 2];
      const ro0 = origRaw[i * 3];
      const go0 = origRaw[i * 3 + 1];
      const bo0 = origRaw[i * 3 + 2];

      let [L, A, B] = rgbToLab(r, g, b);
      L += lVertical;
      L *= isUpper ? 1.04 : 1.02;

      const frac =
        fract01(Math.sin(i * 0.413 + y * 0.091 + x * 0.037 + 1.7) * 43758.5453123);
      L += frac * 4 - 2;

      if (L > 68 && L < L_CAP - 2) {
        L += 1.5 + frac * 1.5;
      }

      [L, A, B] = clampLab(L, A, B);
      L = Math.min(L, L_CAP);

      [r, g, b] = labToRgb(L, A, B);
      r = Math.min(255, Math.max(0, Math.round(r)));
      g = Math.min(255, Math.max(0, Math.round(g)));
      b = Math.min(255, Math.max(0, Math.round(b)));

      // Feather alpha in 0.6–0.8; scale so full mask → wMod=0.65, wOrig=0.35
      const mNorm = maskRaw[i] / 255;
      const feather = 0.6 + 0.2 * mNorm;
      const wMod = MOD_MIX * (feather / 0.8);
      const wOrig = 1 - wMod;

      out[i * 3] = Math.round(ro0 * wOrig + r * wMod);
      out[i * 3 + 1] = Math.round(go0 * wOrig + g * wMod);
      out[i * 3 + 2] = Math.round(bo0 * wOrig + b * wMod);
    }
  }

  console.log(
    `[SIM ENAMEL] naturalism: px=${n} | upper/lower split | feather 0.6–0.8 | blend ${MOD_MIX}/${ORG_MIX} | L*<=${L_CAP}`
  );
  return sharp(out, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 92 })
    .toBuffer();
}

function fract01(x) {
  return x - Math.floor(x);
}

// ── Sobel gradient magnitude (brightness array → Float32Array) ────────────────
function computeGradient(brightness, w, h) {
  const grad = new Float32Array(w * h);
  for (let y = 1; y < h-1; y++) {
    for (let x = 1; x < w-1; x++) {
      const gx =
        -brightness[(y-1)*w+(x-1)] + brightness[(y-1)*w+(x+1)]
        -2*brightness[y*w+(x-1)]   + 2*brightness[y*w+(x+1)]
        -brightness[(y+1)*w+(x-1)] + brightness[(y+1)*w+(x+1)];
      const gy =
        -brightness[(y-1)*w+(x-1)] - 2*brightness[(y-1)*w+x] - brightness[(y-1)*w+(x+1)]
        +brightness[(y+1)*w+(x-1)] + 2*brightness[(y+1)*w+x] + brightness[(y+1)*w+(x+1)];
      grad[y*w+x] = Math.sqrt(gx*gx + gy*gy) / 4; // normalise Sobel scale
    }
  }
  return grad;
}

// ── Main enhancement: tartar removal + LAB color neutralization + whitening ───
//
//  Tartar:     adaptive removal in two tiers (contrast 0.15–0.35 / ≥ 0.35)
//  Color:      L* scaled + a*/b* damped (×0.7 / ×0.6) + warm b* bump if chroma collapses
//  Whitening:  L* boosted (×~1.1–1.2 with sim strength), not L-only
//  Safety:     result ≥ original pixel for every channel
//
// boosted = true → wider detection thresholds + stronger lift for the auto-retry pass.
// opts.skipLabWhitening: default true — tartar/cleaning only; tooth color comes from COLOR_PRESETS Stage 2.
// SIM_LEGACY_LAB_WHITENING=1 restores old in-pipeline LAB whitening (discouraged with presets).
async function computeEnhancedRaw(origCropBuf, w, h, boosted = false, opts = {}) {
  const skipLabWhitening =
    String(process.env.SIM_LEGACY_LAB_WHITENING || '').trim() === '1'
      ? false
      : opts.skipLabWhitening !== false;
  const { data } = await sharp(origCropBuf)
    .resize(w, h).removeAlpha().raw().toBuffer({ resolveWithObject: true });

  const brightness = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++)
    brightness[i] = (data[i*3] + data[i*3+1] + data[i*3+2]) / 3;

  const { mean, std } = computeLocalStats(brightness, w, h);
  const gradient      = computeGradient(brightness, w, h);

  const GRAD_EDGE_THRESH = 25; // gradient magnitude above which we treat pixel as on a tooth edge

  const out = Buffer.alloc(w * h * 3);
  for (let i = 0; i < w*h; i++) {
    const origR = data[i*3], origG = data[i*3+1], origB = data[i*3+2];
    let r = origR, g = origG, b = origB;
    const br = brightness[i], lm = mean[i], ls = std[i];

    // Lower-region flag (bottom 58% of the crop = lower incisors area).
    // Lower teeth are naturally darker (shadow) AND accumulate more tartar/stain.
    // Thresholds for them must be wider on every axis.
    const isLower = Math.floor(i / w) > h * 0.42;

    // ── Stain classification ──────────────────────────────────────────────────
    const delta     = Math.max(origR, origG, origB) - Math.min(origR, origG, origB);
    const isWarmHue = origR > origG && origG > origB;

    // Boosted mode widens each threshold to attack stains the first pass left behind.
    // Lower-region base thresholds are already wider to account for natural shadow.
    const colorStainBr   = boosted ? 165 : (isLower ? 158 : 145);
    const yellowStainBr  = boosted ? 185 : (isLower ? 178 : 170);
    const yellowDelta    = boosted ? 18  : (isLower ? 20  : 25);
    const contextBr      = boosted ? 200 : 185;
    const contextDelta   = boosted ? 8   : (isLower ? 9   : 12);

    const isColorStain   = br < colorStainBr;
    const isYellowStain  = br < yellowStainBr && delta > yellowDelta && isWarmHue;
    const isContextStain = br < contextBr && (lm - br) > contextDelta;
    const isStain        = isColorStain || isYellowStain || isContextStain;

    // ── Tooth structure protection ─────────────────────────────────────────────
    // Gate 1 — Natural texture guard.
    // Lower incisors can be UNIFORMLY discoloured (the whole tooth is stained,
    // not just a patch). Their local mean is therefore also dark, so |br - lm|
    // stays small even for genuine tartar. Tighten the guard for the lower region
    // (12 instead of 25) so uniformly stained incisors still enter Stage 1.
    const naturalTextureThresh = isLower ? 12 : 25;
    const isNaturalTexture     = Math.abs(br - lm) < naturalTextureThresh;

    // Gate 2 — Structural edge: high gradient = tooth boundary / inter-tooth gap.
    // In boosted mode, raise the bar slightly so deep stains at edges are still treated.
    const edgeThresh = boosted ? GRAD_EDGE_THRESH * 1.4 : GRAD_EDGE_THRESH;
    const isStructuralEdge = gradient[i] > edgeThresh;

    // Stage 1 only runs if: detected as stain  AND  not natural texture  AND  not an edge
    if (isStain && !isNaturalTexture && !isStructuralEdge) {
      const contrast  = (lm - br) / (lm + 1e-5);
      const baseBoost = boosted ? 1.20 : 1.0;  // global lift multiplier in retry pass
      const boostMult = (br < 120 ? 1.4 : br < 160 ? 1.2 : 1.0) * baseBoost;

      const heavyThresh = boosted ? 0.25 : 0.35;  // catch more as heavy tartar when retrying
      if (contrast >= heavyThresh) {
        // ── HEAVY TARTAR: partial replacement ──────────────────────────────
        // (isStructuralEdge already excluded above — inner edge check retained
        //  as a safety reference for the mix-reduction logic)
        const baseMix = 0.75;
        const mix     = Math.min(0.90, baseMix * boostMult);
        const target  = Math.min(245, lm + 0.25 * ls);
        r = Math.round(r + (target - r) * mix);
        g = Math.round(g + (target - g) * mix);
        b = Math.round(b + (target - b) * mix);
      } else if (contrast >= 0.05) {
        // ── NORMAL TARTAR / COLOURED STAIN: lift toward local mean ─────────
        const lift   = Math.min(0.85, contrast * 0.8 * boostMult);
        const target = Math.min(245, lm + 0.2 * ls);
        r = Math.round(r + (target - r) * lift);
        g = Math.round(g + (target - g) * lift);
        b = Math.round(b + (target - b) * lift);
      }
      // contrast < 0.05 → Stage 2 LAB handles colour correction
    }
    // Stage 2 (LAB) always runs — colour-only stains (isYellowStain with low luma delta)
    // are still corrected even when Stage 1 is skipped by isNaturalTexture.

    // Clamp: result can never be darker than the original pixel
    r = Math.max(origR, r);
    g = Math.max(origG, g);
    b = Math.max(origB, b);

    if (skipLabWhitening) {
      out[i * 3] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origR, r));
      out[i * 3 + 1] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origG, g));
      out[i * 3 + 2] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origB, b));
    } else {
      // Legacy: LAB whitening (use SIM_LEGACY_LAB_WHITENING=1 or pass skipLabWhitening: false)
      const [L, Alab, Blab] = rgbToLab(r, g, b);
      const sLab = simLabStrengthMultiplier();
      const Lscale = (boosted ? 1.16 : 1.12) * sLab;
      const bScale =
        isYellowStain || Blab > 8 ? (boosted ? 0.55 : 0.58) : boosted ? 0.58 : 0.6;
      const [Lw, Aw, Bw] = neutralizeLabWarmWhite(L, Alab, Blab, {
        Lscale,
        Lmax: 96,
        aScale: boosted ? 0.68 : 0.7,
        bScale,
      });
      const [ro, go, bo] = labToRgb(Lw, Aw, Bw);
      out[i * 3] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origR, ro));
      out[i * 3 + 1] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origG, go));
      out[i * 3 + 2] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(origB, bo));
    }
  }
  return out;
}

// ── Stain detector — mirrors the classification logic in computeEnhancedRaw ───
//
// Returns { count, ratio } where ratio = stain pixels / masked pixels.
// Used to validate that cleaning actually removed deposits before accepting output.
//
// MIN_STAIN_RATIO: skip validation when < 3% of tooth pixels are stained
//                 (teeth are clean enough to begin with).
// PASS_REMOVAL_RATE: require at least 50% of pre-existing stains to be gone.
//
const MIN_STAIN_RATIO    = 0.03;  // 3 % of tooth mask
const PASS_REMOVAL_RATE  = 0.50;  // must remove ≥ 50 % of detected stains

// ── Structural integrity constants ────────────────────────────────────────────
// PROFILE_CORR_MIN: minimum Pearson r between before/after column brightness
//   profiles inside the tooth mask.  Below this = tooth geometry has shifted.
// GAP_KEEP_MIN:     fraction of inter-tooth gap segments that must survive.
//   If we go from 5 gaps to 2, teeth have effectively been merged.
// Simulation may visibly narrow gaps / align — too-strict thresholds reverted output to “no change”.
const PROFILE_CORR_MIN = 0.78;  // column-brightness profile still related to original
const GAP_KEEP_MIN     = 0.38;  // allow moderate gap-closure in preview (not fully reliable clinically)

function detectStains(rawBuf, maskRaw, w, h) {
  let stainCount = 0, maskCount = 0;
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 64) continue;
    maskCount++;
    const r = rawBuf[i*3], g = rawBuf[i*3+1], b = rawBuf[i*3+2];
    const br    = (r + g + b) / 3;
    const delta = Math.max(r, g, b) - Math.min(r, g, b);

    // Mirror the isColorStain / isYellowStain conditions.
    // Lower region (y > 42% of crop) uses slightly wider thresholds to match
    // the looser stain detection applied there in computeEnhancedRaw.
    const isLower      = Math.floor(i / w) / h > 0.42;
    const darkThresh   = isLower ? 165 : 155;
    const yellowBr     = isLower ? 182 : 175;
    const yellowDelta  = isLower ? 20  : 22;

    if (br < darkThresh) { stainCount++; continue; }
    if (br < yellowBr && delta > yellowDelta && r > g && g > b) stainCount++;
  }
  return { count: stainCount, ratio: maskCount > 0 ? stainCount / maskCount : 0 };
}

// ── Structural integrity helpers ──────────────────────────────────────────────
//
// analyzeToothProfile: column-average brightness inside the tooth mask.
// Each entry is the mean brightness for that x-column, or -1 when no mask pixels
// fall in that column.
//
function analyzeToothProfile(rawBuf, maskRaw, w, h) {
  const sum   = new Float32Array(w);
  const count = new Float32Array(w);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y*w + x;
      if (maskRaw[i] <= 64) continue;
      sum[x]   += (rawBuf[i*3] + rawBuf[i*3+1] + rawBuf[i*3+2]) / 3;
      count[x] += 1;
    }
  }
  const profile = new Float32Array(w);
  for (let x = 0; x < w; x++)
    profile[x] = count[x] > 0 ? sum[x] / count[x] : -1;
  return profile;
}

// countInterToothGaps: number of contiguous dark-column valleys in the profile.
// A column is a "gap" if its brightness < gap_threshold (average × 0.68).
// Each contiguous run of gap-columns counts as one inter-tooth gap.
//
function countInterToothGaps(profile, w) {
  const valid = profile.filter(v => v >= 0);
  if (valid.length === 0) return 0;
  const avg   = valid.reduce((s, v) => s + v, 0) / valid.length;
  const thr   = avg * 0.68;
  let gaps = 0, inGap = false;
  for (let x = 0; x < w; x++) {
    if (profile[x] < 0) continue; // column outside mask — ignore
    if (profile[x] < thr) {
      if (!inGap) { gaps++; inGap = true; }
    } else {
      inGap = false;
    }
  }
  return gaps;
}

// profileCorrelation: Pearson r between two column brightness profiles.
// Columns where either profile returns -1 (no mask) are excluded.
//
function profileCorrelation(a, b, w) {
  let sumA = 0, sumB = 0, n = 0;
  for (let x = 0; x < w; x++) {
    if (a[x] < 0 || b[x] < 0) continue;
    sumA += a[x]; sumB += b[x]; n++;
  }
  if (n < 4) return 1; // too few valid columns — assume fine
  const mA = sumA/n, mB = sumB/n;
  let cov = 0, vA = 0, vB = 0;
  for (let x = 0; x < w; x++) {
    if (a[x] < 0 || b[x] < 0) continue;
    cov += (a[x]-mA) * (b[x]-mB);
    vA  += (a[x]-mA) ** 2;
    vB  += (b[x]-mB) ** 2;
  }
  const denom = Math.sqrt(vA) * Math.sqrt(vB);
  return denom > 0 ? Math.max(-1, Math.min(1, cov/denom)) : 1;
}

// checkStructuralIntegrity: decode both JPEG buffers, compare profiles.
// Returns { valid, correlation, origGaps, resultGaps, gapRatio, issues[] }.
//
async function checkStructuralIntegrity(origBuf, resultBuf, maskBuf, w, h) {
  const [origRaw, resRaw, maskRaw] = await Promise.all([
    sharp(origBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resultBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);

  const origProfile = analyzeToothProfile(origRaw, maskRaw, w, h);
  const resProfile  = analyzeToothProfile(resRaw,  maskRaw, w, h);
  const corr        = profileCorrelation(origProfile, resProfile, w);
  const origGaps    = countInterToothGaps(origProfile, w);
  const resultGaps  = countInterToothGaps(resProfile,  w);
  const gapRatio    = origGaps > 0 ? resultGaps / origGaps : 1;

  const issues = [];
  if (corr     < PROFILE_CORR_MIN) issues.push(`low_corr:${corr.toFixed(3)}`);
  if (gapRatio < GAP_KEEP_MIN)     issues.push(`gaps_lost:${origGaps}→${resultGaps}`);

  return { valid: issues.length === 0, correlation: corr, origGaps, resultGaps, gapRatio, issues };
}

// ── Edge-preserving bilateral filter (r=3, σ_c=25, σ_s=3) ───────────────────
function bilateralFilter(data, w, h, radius = 3, sigmaColor = 25, sigmaSpace = 3) {
  const SC2 = 2*sigmaColor*sigmaColor, SS2 = 2*sigmaSpace*sigmaSpace, R = radius;
  const out = new Uint8Array(w * h * 3);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const ci = (y*w+x)*3;
      const r0=data[ci], g0=data[ci+1], b0=data[ci+2];
      let rs=0, gs=0, bs=0, ws=0;
      for (let dy=-R; dy<=R; dy++) {
        for (let dx=-R; dx<=R; dx++) {
          const ny=y+dy, nx=x+dx;
          if (ny<0||ny>=h||nx<0||nx>=w) continue;
          const ni=(ny*w+nx)*3;
          const r1=data[ni], g1=data[ni+1], b1=data[ni+2];
          const wt = Math.exp(-(dx*dx+dy*dy)/SS2) *
                     Math.exp(-((r0-r1)**2+(g0-g1)**2+(b0-b1)**2)/SC2);
          rs+=r1*wt; gs+=g1*wt; bs+=b1*wt; ws+=wt;
        }
      }
      out[ci]  =Math.min(245,Math.round(rs/ws));
      out[ci+1]=Math.min(245,Math.round(gs/ws));
      out[ci+2]=Math.min(245,Math.round(bs/ws));
    }
  }
  return out;
}

// ── Inter-tooth dark line reduction ──────────────────────────────────────────
//
// Thin dark lines between teeth survive standard tartar removal because they
// are high-contrast edges, not just globally dark pixels.  This pass:
//   1. Detects them via brightness < 75% local_mean AND |Gx| > 20
//   2. Dilates the detected region by 1 px to cover full line width
//   3. Blends toward local_mean:  mix=0.85 normally, 0.50 near very strong edges
//   4. Applies a radius-1 box blur on the treated region to soften transitions
//
function reduceDarkLines(result, maskRaw, w, h) {
  const HORIZ_THRESH  = 20;  // |Gx| threshold for "this is an edge pixel"
  const EDGE_STRONG   = 50;  // |Gx| above which we protect tooth borders (mix 0.50)
  const DARK_FACTOR   = 0.75; // pixel must be < 75% of local mean to qualify

  // Brightness of current result buffer
  const br = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++)
    br[i] = (result[i*3] + result[i*3+1] + result[i*3+2]) / 3;

  // 5×5 local mean
  const { mean: lm5 } = computeLocalStats(br, w, h, 2);

  // Horizontal Sobel (Gx) — large value = vertical edge = inter-tooth line
  const gx = new Float32Array(w * h);
  for (let y = 1; y < h-1; y++) {
    for (let x = 1; x < w-1; x++) {
      const v =
        -br[(y-1)*w+(x-1)] + br[(y-1)*w+(x+1)]
        -2*br[y*w+(x-1)]   + 2*br[y*w+(x+1)]
        -br[(y+1)*w+(x-1)] + br[(y+1)*w+(x+1)];
      gx[y*w+x] = Math.abs(v) / 4;
    }
  }

  // Step 1 — detect
  const darkLine = new Uint8Array(w * h);
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] > 64 && br[i] < lm5[i] * DARK_FACTOR && gx[i] > HORIZ_THRESH)
      darkLine[i] = 1;
  }

  // Step 2 — dilate 1 px (expand to cover full line width)
  const dilated = new Uint8Array(w * h);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      if (maskRaw[y*w+x] <= 64) continue;
      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          const ny = y+dy, nx = x+dx;
          if (ny >= 0 && ny < h && nx >= 0 && nx < w && darkLine[ny*w+nx]) {
            dilated[y*w+x] = 1; break;
          }
        }
        if (dilated[y*w+x]) break;
      }
    }
  }

  // Step 3 — blend toward local mean
  const blended = Buffer.from(result);
  let lineCount = 0;
  for (let i = 0; i < w*h; i++) {
    if (!dilated[i]) continue;
    const mix    = gx[i] > EDGE_STRONG ? 0.50 : 0.85;
    const target = Math.min(245, lm5[i]);
    for (let c = 0; c < 3; c++)
      blended[i*3+c] = Math.min(245, Math.round(result[i*3+c] + (target - result[i*3+c]) * mix));
    lineCount++;
  }

  // Step 4 — radius-1 box blur on treated pixels only (softens transitions).
  // Only sample neighbour pixels that are also inside the teeth mask to
  // avoid pulling lip/skin colour into the tooth boundary.
  const out = Buffer.from(blended);
  for (let y = 1; y < h-1; y++) {
    for (let x = 1; x < w-1; x++) {
      if (!dilated[y*w+x]) continue;
      for (let c = 0; c < 3; c++) {
        let sum = 0, n = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            const ny = y+dy, nx = x+dx;
            if (maskRaw[ny*w+nx] <= 64) continue;  // skip non-mask neighbours
            sum += blended[ny*w*3+nx*3+c]; n++;
          }
        }
        if (n > 0)
          out[(y*w+x)*3+c] = Math.min(245, Math.round(sum / n));
      }
    }
  }

  if (lineCount > 0)
    console.log(`[SIM DARK-LINE] softened ${lineCount} inter-tooth line pixels`);
  return out;
}

// ── Micro-texture cleaning: removes rough/speckled tartar surface noise ───────
//
// Tartar leaves behind a noisy, high-variance texture on enamel even after
// pixel-level lifting.  This pass:
//   1. Computes local std-dev (5×5 window) from current result brightness
//   2. Marks pixels with std > STD_THRESH as NOISY_AREA
//   3. Skips edge pixels (gradient > EDGE_THRESH) — preserves tooth boundaries
//   4. Applies a tight bilateral filter (r=2, σ_c=20, σ_s=2) to a copy
//   5. Blends: result = orig×0.4 + smoothed×0.6 only where NOISY_AREA
//
function microTextureClean(result, maskRaw, w, h) {
  const STD_THRESH  = 12;  // std > 12 = rough texture / speckled surface
  const EDGE_THRESH = 20;  // gradient > 20 = tooth boundary — do not touch
  const MIX         = 0.24; // was 0.48 — ~50% less smoothing to avoid flat/matte teeth

  const br = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++)
    br[i] = (result[i*3] + result[i*3+1] + result[i*3+2]) / 3;

  const { std }  = computeLocalStats(br, w, h, 2); // 5×5 variance map
  const grad     = computeGradient(br, w, h);       // Sobel magnitude

  // Tight bilateral — ~50% weaker sigmas vs before (less matte / muddy look)
  const smoothed = bilateralFilter(result, w, h, 2, 10, 1);

  const out = Buffer.from(result);
  let count = 0;
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] <= 64)         continue; // outside tooth mask
    if (std[i]  <= STD_THRESH)    continue; // already smooth — leave it
    if (grad[i] > EDGE_THRESH)    continue; // tooth border — preserve
    for (let c = 0; c < 3; c++)
      out[i*3+c] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(result[i*3+c]*(1-MIX) + smoothed[i*3+c]*MIX));
    count++;
  }
  if (count > 0)
    console.log(`[SIM MICRO-TEX] smoothed ${count} noisy surface pixels`);
  return out;
}

// ── Smart uniform whitening — independent upper/lower region targets ───────────
//
// KEY CHANGE: upper and lower teeth are whitened toward their OWN brightness
// targets (computed separately), so brighter upper teeth no longer pull the
// shared average up and leave lower incisors under-lifted.
//
// Each region independently computes: avg, p95 → target = min(p95×0.96, avg×factor)
// Yellow tint kill and highlight guard apply to all regions.
//
function uniformWhitening(result, maskRaw, w, h, targetFactor = 1.28) {
  const snap = Buffer.from(result);

  const br = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++)
    br[i] = (snap[i*3] + snap[i*3+1] + snap[i*3+2]) / 3;

  // Collect brightnesses split by vertical region
  // Upper = top 45% of crop;  Lower = bottom 55% (lower incisors)
  const upperVals = [], lowerVals = [];
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] <= 64) continue;
    const y = Math.floor(i / w);
    (y < h * 0.45 ? upperVals : lowerVals).push(br[i]);
  }
  if (upperVals.length === 0 && lowerVals.length === 0) return result;

  function regionTarget(vals) {
    if (vals.length === 0) return null;
    vals.sort((a, b) => a - b);
    const avg = vals.reduce((s, v) => s + v, 0) / vals.length;
    const p95 = vals[Math.floor(vals.length * 0.95)];
    return { target: Math.min(p95 * 0.96, avg * targetFactor), avg, p95 };
  }
  const upper = regionTarget(upperVals);
  const lower = regionTarget(lowerVals);
  console.log(`[SIM UNIFORM] upper px=${upperVals.length} avg=${upper?.avg.toFixed(1)} target=${upper?.target.toFixed(1)} | lower px=${lowerVals.length} avg=${lower?.avg.toFixed(1)} target=${lower?.target.toFixed(1)}`);

  const out = Buffer.from(snap);
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] <= 64) continue;
    if (br[i] > 208)      continue; // highlight guard (allow a bit more headroom vs 202)

    const y    = Math.floor(i / w);
    const reg  = y < h * 0.45 ? upper : lower;
    if (!reg) continue;
    const { target } = reg;

    const pixBr = br[i];
    const delta  = target - pixBr;
    const lift   = Math.min(0.78, Math.max(0.12, delta / 255));

    let r = snap[i*3], g = snap[i*3+1], b = snap[i*3+2];
    const rn = r + delta * lift, gn = g + delta * lift, bn = b + delta * lift;
    let ro = r * 0.28 + rn * 0.72;
    let go = g * 0.28 + gn * 0.72;
    let bo = b * 0.28 + bn * 0.72;

    // Yellow reduction — gentle (harsh kills read as flat paint)
    if (r > g && g > b) bo += (r - b) * 0.28;

    // ── LAB: cap L* + neutralize a*/b* (prevents grey from L-only lifts)
    const LAB_L_CAP = 91;
    let [Ll, Al, Bl] = rgbToLab(Math.round(ro), Math.round(go), Math.round(bo));
    if (Ll > LAB_L_CAP) Ll = LAB_L_CAP;
    const [Ll2, Al2, Bl2] = neutralizeLabWarmWhite(Ll, Al, Bl, {
      lockL: true,
      aScale: 0.82,
      bScale: 0.75,
      Lmax: LAB_L_CAP,
    });
    const [cr, cg, cb] = labToRgb(Ll2, Al2, Bl2);
    ro = cr;
    go = cg;
    bo = cb;

    // ── Subtle natural variation (anti-plastic) ───────────────────────────
    const noise = ((i * 1664525 + 1013904223) & 0x7fffffff) % 3 - 1;  // −1 … +1
    ro = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(ro) + noise));
    go = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(go) + noise));
    bo = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(bo) + noise));

    out[i*3]   = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(ro)));
    out[i*3+1] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(go)));
    out[i*3+2] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(0, Math.round(bo)));
  }
  return out;
}

// ── Micro-alignment — subtle horizontal shift along a natural arch (not a ruler line)
//
//  1. Column-sum mask → segments = visible teeth (roughly)
//  2. Per segment: mask centroid (cx, cy) + principal-axis angle (identity only, no rotation warp)
//  3. Target cx: blend (a) linear spacing along span  (b) circular-arch fit  sin(θ) model
//     — avoids “perfect straight line” equal spacing; mimics frontal dental arch
//  4. Small deterministic jitter breaks mirror symmetry (same person, small imperfections kept)
//  5. Shift clamped ±MAX_SHIFT, scaled by alignSymmetryMix; horizontal warp only (no resize/clone)
//
// cfg: microShiftMax, alignSymmetryMix, alignWarpBlend, alignArchCurveMix (0=linear … 1=arc),
//      alignOrganicJitter (0…~0.25 fraction of MAX_SHIFT for per-tooth wobble)
async function microAlignment(cropBuf, maskBuf, w, h, cfg = {}) {
  const MAX_SHIFT =
    typeof cfg.microShiftMax === 'number' ? cfg.microShiftMax : 3;
  const SYM_MIX =
    typeof cfg.alignSymmetryMix === 'number' ? cfg.alignSymmetryMix : 0.74;
  const WARP_BLEND =
    typeof cfg.alignWarpBlend === 'number' ? cfg.alignWarpBlend : 0.76;
  const ARCH_MIX =
    typeof cfg.alignArchCurveMix === 'number' ? cfg.alignArchCurveMix : 0.6;
  const ORG_JIT =
    typeof cfg.alignOrganicJitter === 'number' ? cfg.alignOrganicJitter : 0.18;
  const FEATHER_PX   = 8;   // px — transition width at segment edges
  const MIN_SEG_W    = 8;   // px — ignore blobs narrower than this
  const MIN_SEGMENTS = 2;   // need ≥ 2 teeth to do anything meaningful

  /** Mask-weighted centroid + principal-axis angle (deg) — no geometric rotation applied. */
  function segmentCentroidAngle(seg) {
    let sx = 0, sy = 0, cnt = 0;
    for (let y = 0; y < h; y++) {
      for (let x = seg.start; x <= seg.end; x++) {
        const idx = y * w + x;
        if (maskRaw[idx] > 64) {
          sx += x;
          sy += y;
          cnt++;
        }
      }
    }
    if (cnt < 8) {
      return {
        cx: (seg.start + seg.end) / 2,
        cy: h * 0.35,
        angleDeg: 0,
      };
    }
    const mx = sx / cnt;
    const my = sy / cnt;
    let cxx = 0, cxy = 0, cyy = 0;
    for (let y = 0; y < h; y++) {
      for (let x = seg.start; x <= seg.end; x++) {
        const idx = y * w + x;
        if (maskRaw[idx] <= 64) continue;
        const dx = x - mx;
        const dy = y - my;
        cxx += dx * dx;
        cxy += dx * dy;
        cyy += dy * dy;
      }
    }
    cxx /= cnt;
    cxy /= cnt;
    cyy /= cnt;
    const angleRad = 0.5 * Math.atan2(2 * cxy, cxx - cyy);
    return {
      cx: mx,
      cy: my,
      angleDeg: (angleRad * 180) / Math.PI,
    };
  }

  const [imgRaw, maskRaw] = await Promise.all([
    sharp(cropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);

  // Column-sum of mask (> 64 = in teeth zone)
  const colSum = new Float32Array(w);
  for (let y = 0; y < h; y++)
    for (let x = 0; x < w; x++)
      if (maskRaw[y*w+x] > 64) colSum[x]++;

  const maxCol = Math.max(...Array.from(colSum));
  if (maxCol < h * 0.05) {
    console.log('[SIM ALIGN] no meaningful mask — skipping');
    return cropBuf;
  }

  // Detect tooth segments as runs of columns above valley threshold
  const VALLEY_THRESH = maxCol * 0.15;
  const segments = [];
  let inSeg = false, segStart = 0;
  for (let x = 0; x <= w; x++) {
    const above = x < w && colSum[x] > VALLEY_THRESH;
    if (!inSeg && above) { inSeg = true; segStart = x; }
    else if (inSeg && !above) {
      inSeg = false;
      if (x - segStart >= MIN_SEG_W) segments.push({ start: segStart, end: x - 1 });
    }
  }
  if (segments.length < MIN_SEGMENTS) {
    console.log(`[SIM ALIGN] ${segments.length} segment(s) — need ${MIN_SEGMENTS}+, skipping`);
    return cropBuf;
  }

  const perSeg = segments.map((seg) => segmentCentroidAngle(seg));
  const centroids = perSeg.map((p) => p.cx);
  const n = segments.length;

  // (A) Linear “ruler” targets — only used as partial blend (avoid pure straight-line look)
  const span = centroids[n - 1] - centroids[0];
  const idealLinear = centroids.map((_, i) =>
    n <= 1 ? centroids[0] : centroids[0] + (span * i) / (n - 1)
  );

  // (B) Arch-shaped targets: fit x ≈ cx + R·sin(θ) with θ from left→right along a segment of arc
  let idealArc = idealLinear.slice();
  if (n >= 3) {
    const theta = centroids.map((_, i) => (Math.PI * i) / (n - 1) - Math.PI / 2);
    const s = theta.map(Math.sin);
    const meanC = centroids.reduce((a, b) => a + b, 0) / n;
    const meanS = s.reduce((a, b) => a + b, 0) / n;
    let varS = 0, covCS = 0;
    for (let i = 0; i < n; i++) {
      const ds = s[i] - meanS;
      covCS += (centroids[i] - meanC) * ds;
      varS += ds * ds;
    }
    const Rfit = varS > 1e-6 ? covCS / varS : 0;
    const cxFit = meanC - Rfit * meanS;
    idealArc = centroids.map((_, i) => cxFit + Rfit * s[i]);
  }

  // Blend linear vs arch; then tiny per-tooth organic offset (not mirror-perfect)
  const idealPos = centroids.map((_, i) => {
    const base =
      idealLinear[i] * (1 - ARCH_MIX) + idealArc[i] * ARCH_MIX;
    const jitter =
      Math.sin(i * 2.91 + n * 0.37 + 1.1) * ORG_JIT * MAX_SHIFT;
    return base + jitter;
  });

  const segShift = centroids.map((c, i) => {
    const raw = idealPos[i] - c;
    const lim = Math.max(-MAX_SHIFT, Math.min(MAX_SHIFT, raw));
    return lim * SYM_MIX;
  });

  const angSample = perSeg
    .slice(0, Math.min(8, n))
    .map((p, i) => `(${i}:°${p.angleDeg.toFixed(0)})`)
    .join(' ');
  console.log(
    `[SIM ALIGN] ${n} teeth archMix=${ARCH_MIX.toFixed(2)} maxShift=${MAX_SHIFT} ` +
    `symMix=${SYM_MIX.toFixed(2)} | angles ${angSample}${n > 8 ? ' …' : ''} | ` +
    `shifts=[${segShift.map((s) => s.toFixed(1)).join(',')}]px`
  );

  // Per-column shift map: feathered within segments, interpolated in gaps
  const colShift = new Float32Array(w);
  for (let si = 0; si < n; si++) {
    const { start, end } = segments[si];
    for (let x = start; x <= end; x++) {
      const feather = Math.min(1, Math.min(x - start, end - x) / FEATHER_PX);
      colShift[x] = segShift[si] * feather;
    }
  }
  for (let si = 0; si < n - 1; si++) {
    const gapStart = segments[si].end + 1, gapEnd = segments[si+1].start - 1;
    for (let x = gapStart; x <= gapEnd; x++) {
      const t = (x - gapStart) / Math.max(1, gapEnd - gapStart + 1);
      colShift[x] = segShift[si] * (1 - t) + segShift[si+1] * t;
    }
  }

  // Inverse-map warp: for each output pixel, sample from shifted source
  const output = Buffer.from(imgRaw);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const m = maskRaw[y*w+x];
      if (m <= 64) continue;                 // outside mask — untouched
      const blend = (m / 255) * WARP_BLEND;  // mask-weighted warp strength (mode-tuned)
      const srcX  = Math.max(0, Math.min(w - 1.001, x - colShift[x]));
      const x0    = Math.floor(srcX), fx = srcX - x0;
      const x1    = Math.min(w - 1, x0 + 1);
      for (let c = 0; c < 3; c++) {
        const warped = imgRaw[(y*w+x0)*3+c] * (1-fx) + imgRaw[(y*w+x1)*3+c] * fx;
        output[(y*w+x)*3+c] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(
          imgRaw[(y*w+x)*3+c] * (1 - blend) + warped * blend
        ));
      }
    }
  }

  // Validation: large average diff means something went wrong — revert
  let diffSum = 0;
  for (let i = 0; i < w*h*3; i++) diffSum += Math.abs(output[i] - imgRaw[i]);
  const avgDiff = diffSum / (w*h*3);
  if (avgDiff > 6) {
    console.warn(`[SIM ALIGN] avgDiff=${avgDiff.toFixed(2)} > 6 — reverting`);
    return cropBuf;
  }
  console.log(`[SIM ALIGN] applied — avgDiff=${avgDiff.toFixed(2)}`);
  return sharp(output, { raw: { width: w, height: h, channels: 3 } })
    .jpeg({ quality: 92 }).toBuffer();
}

// ── Step 6: Shape refinement — gentle edge softening ─────────────────────────
// Only for design mode.  Applies a 40%-weighted box-blur ONLY to pixels with a
// moderate Sobel gradient (15–32): these are minor incisal-edge irregularities.
// Hard boundaries (gradient > 32) and smooth surfaces (< 15) are untouched.
//
async function edgeSoftening(cropBuf, maskBuf, w, h) {
  const [raw, maskRaw] = await Promise.all([
    sharp(cropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const br = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++) br[i] = (raw[i*3]+raw[i*3+1]+raw[i*3+2])/3;
  const grad = computeGradient(br, w, h);

  const out = Buffer.from(raw);
  let count = 0;
  for (let y = 1; y < h-1; y++) {
    for (let x = 1; x < w-1; x++) {
      const i = y*w+x;
      if (maskRaw[i] <= 64) continue;
      if (grad[i] < 15 || grad[i] > 32) continue; // moderate edges only
      for (let c = 0; c < 3; c++) {
        let sum = 0;
        for (let dy = -1; dy <= 1; dy++)
          for (let dx = -1; dx <= 1; dx++)
            sum += raw[(y+dy)*w*3+(x+dx)*3+c];
        out[i*3+c] = Math.min(245, Math.round(raw[i*3+c]*0.60 + (sum/9)*0.40));
      }
      count++;
    }
  }
  console.log(`[SIM EDGE-SOFT] smoothed ${count} moderate-edge pixels`);
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

// ── Step 7: Light & reflection — subtle enamel highlights ─────────────────────
// Only for design mode.  Existing bright smooth areas (enamel specular zone) get
// a proportional boost of up to ~+10%.  Preserves natural light gradients.
//
async function addReflectionHighlights(cropBuf, maskBuf, w, h) {
  const [raw, maskRaw] = await Promise.all([
    sharp(cropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const br = new Float32Array(w * h);
  for (let i = 0; i < w*h; i++) br[i] = (raw[i*3]+raw[i*3+1]+raw[i*3+2])/3;
  const grad = computeGradient(br, w, h);

  const out = Buffer.from(raw);
  let count = 0;
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] <= 128) continue; // only core teeth
    if (br[i]    <= 185)   continue; // only existing bright areas
    if (grad[i]  >  12)    continue; // only smooth flat surface (not edges)
    const boost = 1 + (br[i] - 185) / 600; // max ~+10% at br=245
    for (let c = 0; c < 3; c++)
      out[i*3+c] = Math.min(245, Math.round(raw[i*3+c] * boost));
    count++;
  }
  console.log(`[SIM HIGHLIGHT] boosted ${count} highlight pixels`);
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

// ── CRITICAL: Teeth mask boundary enforcer ───────────────────────────────────
//
// This is the absolute last step applied to blendedCropBuf before the final
// composite.  It guarantees that every pixel whose mask value is 0 is copied
// back from the original image verbatim, eliminating any leak from any
// upstream pass (smile arc warp, alignment, edge softening, highlights, etc).
//
// Pixels inside the mask are untouched — blending that already happened in
// blendCropWithMask() remains intact.
//
async function enforceTeethMaskBoundary(processedBuf, origBuf, maskBuf, w, h) {
  const [proc, orig, mask] = await Promise.all([
    sharp(processedBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(origBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const out = Buffer.from(proc);
  let restored = 0;
  for (let i = 0; i < w * h; i++) {
    if (mask[i] > 0) continue;  // inside mask — keep processed result
    for (let c = 0; c < 3; c++) {
      if (out[i*3+c] !== orig[i*3+c]) {
        out[i*3+c] = orig[i*3+c];
        restored++;
      }
    }
  }
  if (restored > 0)
    console.log(`[SIM FENCE] Restored ${Math.ceil(restored/3)} px outside teeth mask to original`);
  else
    console.log('[SIM FENCE] No leakage detected — all modifications within mask boundaries');
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

// ── Hard-fail leakage validator ───────────────────────────────────────────────
//
// Compares every outside-mask pixel between `origCropBuf` and `processedCropBuf`.
// After enforceTeethMaskBoundary() these should be byte-identical; any residual
// difference indicates upstream bleed (bilateral filter sampling, warp spill, etc.).
//
// Threshold: 3.0 brightness units average (JPEG re-encode produces ≤ 1.5 rounding
// error naturally; 3.0 gives safe headroom without triggering false positives).
//
// Returns: { passed: bool, avgDiff: number, leakedPx: number }
//
async function validateNoLeakage(origCropBuf, processedCropBuf, maskBuf, w, h) {
  const [orig, proc, mask] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(processedCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);

  let totalDiff = 0, leakedPx = 0, count = 0;
  for (let i = 0; i < w * h; i++) {
    if (mask[i] > 0) continue;  // inside mask — changes are expected here
    const diff = Math.abs(
      (proc[i*3] + proc[i*3+1] + proc[i*3+2]) -
      (orig[i*3] + orig[i*3+1] + orig[i*3+2])
    ) / 3;
    if (diff > 0) leakedPx++;
    totalDiff += diff;
    count++;
  }

  const avgDiff = count > 0 ? totalDiff / count : 0;
  const passed  = avgDiff < 3.0;

  console.log(
    `[SIM VALIDATE] outside-mask avg Δ=${avgDiff.toFixed(2)} leaked=${leakedPx}px` +
    ` → ${passed ? 'PASS ✓' : 'HARD FAIL ✗ — beard/skin/chin modified'}`
  );
  return { passed, avgDiff, leakedPx };
}

// ── Step: Smile Arc — align incisal edges to a natural parabolic arch curve ──
//
// The natural smile arc means upper central incisors are the longest teeth,
// lateral incisors slightly shorter, canines at intermediate height — the
// bottom edge of upper teeth follows a gentle concave-upward parabola.
//
// Algorithm:
//  1. Per column, detect the bottommost masked pixel of the upper arch
//     (incisal edge) and the topmost (gingival margin).
//  2. Fit an ideal parabola:
//       y_ideal(x) = median_edge + ARC_DEPTH × (1 − ((x−cx)/(span/2))²)
//     → center columns sit ARC_DEPTH px lower = teeth appear longer.
//  3. For columns where actual edge < ideal (tooth too short): apply a
//     gradual downward warp in the bottom 35 % of the tooth with bilinear
//     interpolation.  Max correction: ±4 px.
//  4. For columns already longer than ideal (too long): apply a gentle
//     upward compression (max −3 px).
//
async function applySmileArc(cropBuf, maskBuf, w, h, cfg = {}) {
  const ARC_DEPTH =
    typeof cfg.smileArcDepthPx === 'number' ? cfg.smileArcDepthPx : 4;

  const [raw, maskRaw] = await Promise.all([
    sharp(cropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);

  const upperLimit = Math.floor(h * 0.52); // upper arch only

  // Per-column: topmost and bottommost masked pixel in the upper half
  const colTop = new Int32Array(w).fill(-1);
  const colBot = new Int32Array(w).fill(-1);
  for (let y = 0; y < upperLimit; y++) {
    for (let x = 0; x < w; x++) {
      if (maskRaw[y*w+x] > 128) {
        if (colTop[x] === -1) colTop[x] = y;
        colBot[x] = y;
      }
    }
  }

  const validCols = [];
  for (let x = 0; x < w; x++) {
    if (colBot[x] !== -1 && colTop[x] !== -1 && colBot[x] - colTop[x] > 5)
      validCols.push(x);
  }
  if (validCols.length < 10) {
    console.log('[SIM ARC] Not enough upper tooth data — skipping');
    return cropBuf;
  }

  // Arch centre (x-axis) and span
  const cx   = validCols.reduce((s, x) => s + x, 0) / validCols.length;
  const minX = validCols[0];
  const maxX = validCols[validCols.length - 1];
  const span = Math.max(maxX - minX, 1);

  // Median incisal edge (baseline)
  const botArr = validCols.map(x => colBot[x]).sort((a, b) => a - b);
  const medianBot = botArr[Math.floor(botArr.length / 2)];

  function idealBot(x) {
    const t = Math.min(1, Math.abs(x - cx) / (span / 2 + 1));
    return medianBot + Math.round(ARC_DEPTH * (1 - t * t));
  }

  function lerp(a, b, t) { return a + (b - a) * t; }

  const out = Buffer.from(raw);
  let corrected = 0;

  for (const x of validCols) {
    const tTop = colTop[x];
    const tBot = colBot[x];
    const tH   = tBot - tTop;
    if (tH < 6) continue;

    const target     = idealBot(x);
    const correction = Math.max(-3, Math.min(4, Math.round(target - tBot)));
    if (correction === 0) continue;

    const warpStart = tTop + Math.floor(tH * 0.65); // bottom 35% of tooth
    const warpEnd   = Math.min(tBot + Math.abs(correction) + 2, upperLimit - 1);
    const zoneH     = warpEnd - warpStart;
    if (zoneH < 2) continue;

    if (correction > 0) {
      // Elongate: shift pixels DOWN (process bottom-to-top)
      for (let y = warpEnd; y >= warpStart; y--) {
        // CRITICAL: only warp pixels inside the teeth mask — never touch lip/skin
        if (maskRaw[y * w + x] <= 0) continue;

        const t    = (y - warpStart) / zoneH;
        const srcY = y - correction * t;
        const yf   = Math.max(0, Math.floor(srcY));
        const yc   = Math.min(yf + 1, upperLimit - 1);
        const frac = srcY - yf;

        const di = y * w * 3 + x * 3;
        if (di + 2 >= out.length) continue;
        for (let c = 0; c < 3; c++) {
          const v1 = raw[yf * w * 3 + x * 3 + c] ?? raw[di + c];
          const v2 = raw[yc * w * 3 + x * 3 + c] ?? v1;
          out[di + c] = Math.round(lerp(v1, v2, frac));
        }
      }
    } else {
      // Shorten: compress pixels UP (process top-to-bottom)
      const compAmt = -correction;
      for (let y = warpStart; y <= warpEnd; y++) {
        // CRITICAL: only warp pixels inside the teeth mask — never touch lip/skin
        if (maskRaw[y * w + x] <= 0) continue;

        const t    = (y - warpStart) / zoneH;
        const srcY = Math.min(y + compAmt * t, upperLimit - 1);
        const yf   = Math.floor(srcY);
        const yc   = Math.min(yf + 1, upperLimit - 1);
        const frac = srcY - yf;

        const di = y * w * 3 + x * 3;
        if (di + 2 >= out.length) continue;
        for (let c = 0; c < 3; c++) {
          const v1 = raw[yf * w * 3 + x * 3 + c] ?? raw[di + c];
          const v2 = raw[yc * w * 3 + x * 3 + c] ?? v1;
          out[di + c] = Math.round(lerp(v1, v2, frac));
        }
      }
    }
    corrected++;
  }

  console.log(`[SIM ARC] Smile arc applied: ${corrected}/${validCols.length} columns adjusted  ARC_DEPTH=${ARC_DEPTH}px`);
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

// ── Confidence — how much did the tooth area change? ─────────────────────────
// Low modification → high confidence (result is safe/believable).
// avgPixelChange 0–10: high, 10–30: medium, >30: aggressive/risky.
//
async function computeConfidence(origCropBuf, resultCropBuf, maskBuf, w, h) {
  const [origRaw, resRaw, maskRaw] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resultCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  let totalDiff = 0, maskPx = 0;
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] <= 64) continue;
    maskPx++;
    for (let c = 0; c < 3; c++) totalDiff += Math.abs(origRaw[i*3+c] - resRaw[i*3+c]);
  }
  const avgChange = maskPx > 0 ? totalDiff / (maskPx * 3) : 0;
  const score     = Math.max(0.45, Math.min(1.00, 1 - avgChange / 60));
  console.log(`[SIM CONFIDENCE] avgChange=${avgChange.toFixed(1)}  score=${score.toFixed(2)}`);
  return { confidence: Math.round(score * 100) / 100, avgPixelChange: Math.round(avgChange * 10) / 10 };
}

// ── Transformation-aware confidence score ────────────────────────────────────
//
// Unlike the raw pixel-delta score, this considers WHAT was applied:
//
//   whitening mode  → max 0.82 (colour change alone ≠ clinical result)
//   alignment mode  → max 0.90 (geometry improved)
//   full / premium  → max per cfg (≈0.96 / 0.94 — full smile design tiers)
//
// Stain / structure warnings degrade the score.
// stainRemovalRate: fraction of original stains that were removed (0–1).
//
function computeTransformationScore({ cfg, stainRemovalRate, stainWarning, structureWarning }) {
  const maxScore = cfg.maxConfidence ?? 0.88;
  let score = maxScore;

  // Stain removal contribution (loosened so visible whitening is not always "low confidence")
  if (stainRemovalRate >= 0.70)      score *= 1.00;   // full credit
  else if (stainRemovalRate >= 0.50) score *= 0.98;
  else if (stainRemovalRate >= 0.30) score *= 0.94;
  else                               score *= 0.88;   // stains mostly remain

  // Penalties
  if (stainWarning)     score = Math.min(score, 0.50); // residual stain after retry
  if (structureWarning) score = Math.min(score, 0.40); // structure was compromised

  score = Math.max(0.40, Math.min(maxScore, score));
  return Math.round(score * 100) / 100;
}

// ── Blend: alpha 0.6 (core teeth) / 0.3 (feathered edges) / 0.0 (outside) ───
//
// STRICT MASK ENFORCEMENT — order of operations matters:
//
//  1. Alpha-blend first (mask-gated).
//     Outside mask: alpha = 0  →  result = origRaw exactly.
//     This is critical: when the bilateral filter (step 2) samples pixel
//     neighbourhoods, outside-mask neighbours return the ORIGINAL skin/lip
//     values — not processed ones — so tooth-edge pixels cannot be
//     contaminated by modified beard/lip colour.
//
//  2. Bilateral filter on the already-blended buffer, write-gated by mask.
//     Outside mask: never written — original value preserved.
//
//  Every subsequent pass (dark-floor, reduceDarkLines, microTextureClean,
//  uniformWhitening) independently gates its writes on maskRaw > 64.
//
// blendOpts.skipUniformWhitening: default → skip uniform pass (tooth color from COLOR_PRESETS Stage 2).
// SIM_LEGACY_LAB_WHITENING=1 forces uniform whitening back on.
async function blendCropWithMask(
  origCropBuf,
  enhancedRaw,
  maskBuf,
  w,
  h,
  cfg = SIM_MODES.natural,
  blendOpts = {}
) {
  const skipUniformWhitening =
    String(process.env.SIM_LEGACY_LAB_WHITENING || '').trim() === '1'
      ? false
      : blendOpts.skipUniformWhitening !== false;
  const [origRaw, maskRaw] = await Promise.all([
    sharp(origCropBuf).resize(w,h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w,h).greyscale().raw().toBuffer(),
  ]);

  // Step 1 — Mask-gated alpha blend (NO filter yet).
  // Outside mask (alpha = 0): result[i] = origRaw[i]  ← exact original pixel.
  // Inside mask: feather alpha in ~0.6–0.8 (softer edges, less patchy / plastic).
  let result = Buffer.alloc(w * h * 3);
  for (let i = 0; i < w*h; i++) {
    const mNorm = maskRaw[i] / 255;
    let alpha = 0;
    if (mNorm > 0.1) {
      alpha = 0.6 + 0.2 * Math.min(1, (mNorm - 0.1) / 0.9);
      alpha = Math.min(0.8, alpha);
    }
    for (let c = 0; c < 3; c++)
      result[i*3+c] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(origRaw[i*3+c]*(1-alpha) + enhancedRaw[i*3+c]*alpha));
  }

  // Step 2 — Edge-preserving bilateral filter on the blended buffer.
  // Because result[outside_mask] = origRaw, neighbourhood sampling near mask
  // boundaries reads real skin/lip values — zero processed-pixel contamination.
  // Filtered output is written ONLY inside the mask.
  {
    // Narrower bilateral — ~50% weaker than before (1,18,2) → (1,9,1) to preserve enamel texture
    const filtered = bilateralFilter(result, w, h, 1, 9, 1);
    for (let i = 0; i < w*h; i++) {
      if (maskRaw[i] <= 64) continue;  // outside mask: preserve exact original
      for (let c = 0; c < 3; c++)
        result[i*3+c] = Math.min(ENAMEL_OUTPUT_CAP, filtered[i*3+c]);
    }
  }

  // ── Dark-pixel guarantee (inside tooth mask only) ─────────────────────────
  // Any remaining pixel darker than 85% of its 5×5 neighbourhood is force-lifted.
  // This catches residual tartar halo pixels that survived the blending step.
  {
    const resBr = new Float32Array(w * h);
    for (let i = 0; i < w*h; i++)
      resBr[i] = (result[i*3] + result[i*3+1] + result[i*3+2]) / 3;
    const { mean: lm5 } = computeLocalStats(resBr, w, h, 2); // 5×5 window

    let lifted = 0;
    for (let i = 0; i < w*h; i++) {
      if (maskRaw[i] <= 64) continue;          // only inside teeth mask
      const pixBr = resBr[i];
      const lm    = lm5[i];
      // Lower-region floor is tighter (0.88) because tartar leaves more residual
      // dark halos on lower incisors that survive the standard 0.85 floor.
      const isLower = Math.floor(i / w) > h * 0.42;
      const floor   = lm * (isLower ? 0.88 : 0.85);
      if (pixBr < floor) {
        const liftDelta = (lm - pixBr) * 0.42; // gentler — preserves local shading
        for (let c = 0; c < 3; c++) {
          result[i*3+c] = Math.min(ENAMEL_OUTPUT_CAP, Math.max(
            origRaw[i*3+c],                           // never darker than original
            Math.round(floor),                        // hard floor
            Math.round(result[i*3+c] + liftDelta),   // lift
          ));
        }
        lifted++;
      }
    }
    if (lifted > 0)
      console.log(`[SIM DARK-FLOOR] forced lift on ${lifted} dark tooth pixels`);
  }

  // ── Inter-tooth dark line reduction ───────────────────────────────────────
  // Runs after the dark-floor pass so it operates on already-lifted pixels.
  // Returns a new Buffer; reassign result so validation sees the final state.
  result = reduceDarkLines(result, maskRaw, w, h);

  // ── Micro-texture cleaning (noisy/speckled tartar surface) ────────────────
  result = microTextureClean(result, maskRaw, w, h);

  // ── Uniform whitening — skipped when using preset-based Stage-2 color
  if (!skipUniformWhitening) {
    result = uniformWhitening(result, maskRaw, w, h, cfg.uniformTargetFactor);
  }

  // Validation: result must be at least as bright as original in teeth zone
  let origSum = 0, resSum = 0, cnt = 0;
  for (let i = 0; i < w*h; i++) {
    if (maskRaw[i] > 64) {
      origSum += (origRaw[i*3]+origRaw[i*3+1]+origRaw[i*3+2])/3;
      resSum  += (result[i*3]+result[i*3+1]+result[i*3+2])/3;
      cnt++;
    }
  }
  if (cnt > 0) {
    let ratio = resSum / origSum;
    console.log(`[SIM BLEND] brightness ratio: ${ratio.toFixed(3)} (${cnt} px)`);
    // Never return the untouched original (identical output). If the blend landed
    // dimmer than the source in-mask, emergency-lift masked pixels instead.
    if (ratio < 0.93) {
      console.warn('[SIM BLEND] result dimmer than original in-mask — emergency lift (no revert)');
      let guard = 0;
      while (ratio < 0.93 && guard++ < 10) {
        for (let i = 0; i < w * h; i++) {
          if (maskRaw[i] <= 64) continue;
          for (let c = 0; c < 3; c++) {
            const o = origRaw[i * 3 + c];
            const v = result[i * 3 + c];
            result[i * 3 + c] = Math.min(
              ENAMEL_OUTPUT_CAP,
              Math.round(Math.max(o, v * 1.022 + 0.8))
            );
          }
        }
        let o2 = 0, r2 = 0, n2 = 0;
        for (let i = 0; i < w * h; i++) {
          if (maskRaw[i] <= 64) continue;
          o2 += (origRaw[i * 3] + origRaw[i * 3 + 1] + origRaw[i * 3 + 2]) / 3;
          r2 += (result[i * 3] + result[i * 3 + 1] + result[i * 3 + 2]) / 3;
          n2++;
        }
        ratio = n2 > 0 ? r2 / o2 : 1;
      }
      console.log(`[SIM BLEND] post-lift ratio: ${ratio.toFixed(3)}`);
    }
  }

  // Unsharp mask: restore fine texture (gaps, enamel ridges) after bilateral smooth
  return sharp(result, { raw: { width: w, height: h, channels: 3 } })
    .sharpen({ sigma: 1.0, m1: 0.5, m2: 8 })
    .jpeg({ quality: 92 }).toBuffer();
}

// ── Mask quality assessor ─────────────────────────────────────────────────────
//
// Analyses the built mask and returns a simulation LEVEL that controls which
// passes are safe to apply.  The level drives the fallback cascade — we never
// hard-fail unless truly zero teeth are found.
//
//  strict  → full simulation (alignment + whitening)     dangerRatio ≤ 5%, totalOn ≥ 300
//  relaxed → whitening only, no shape changes            dangerRatio ≤ 12%, totalOn ≥ 120
//  minimal → best-effort strong whitening (sparse / beard-heavy / very few teeth px)
//            — never “fail” the pipeline; caller may replace mask with synthetic ROI
//
async function assessMaskQuality(maskBuf, w, h) {
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const dangerRowStart = Math.floor(h * 0.72);  // bottom 28 % of crop = chin/beard zone
  let dangerOn = 0, totalOn = 0;
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 0) continue;
    totalOn++;
    if (Math.floor(i / w) >= dangerRowStart) dangerOn++;
  }
  const dangerRatio = totalOn > 0 ? dangerOn / totalOn : 0;
  const beardHeavy =
    dangerRatio > 0.09 || (dangerOn > 35 && dangerRatio > 0.055);

  let level;
  if      (totalOn < 6) level = 'minimal';
  else if (totalOn < 50 || dangerRatio > 0.24 || beardHeavy) level = 'minimal';
  else if (totalOn < 300 || dangerRatio > 0.05) level = 'relaxed';
  else                                           level = 'strict';

  console.log(
    `[SIM LEVEL] ${level.toUpperCase()} | totalOn=${totalOn} dangerOn=${dangerOn} ` +
    `dangerRatio=${(dangerRatio * 100).toFixed(1)}% beardHeavy=${beardHeavy}`
  );
  return { level, totalOn, dangerRatio, beardHeavy };
}

// ── Safe-region mask clamp ────────────────────────────────────────────────────
// Zeroes all mask pixels below `safeRowFraction` of the crop height.
// Called for relaxed/minimal levels so that any borderline chin pixels are
// surgically removed before the blending pass.
async function clampMaskToSafeRegion(maskBuf, w, h, safeRowFraction = 0.72) {
  const maskRaw = await sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer();
  const cutRow  = Math.floor(h * safeRowFraction);
  let zeroed = 0;
  for (let y = cutRow; y < h; y++) {
    for (let x = 0; x < w; x++) {
      if (maskRaw[y * w + x] > 0) { maskRaw[y * w + x] = 0; zeroed++; }
    }
  }
  if (zeroed > 0)
    console.log(`[SIM CLAMP] Zeroed ${zeroed} px below row ${cutRow} (${(safeRowFraction*100).toFixed(0)}%)`);
  return sharp(maskRaw, { raw: { width: w, height: h, channels: 1 } }).png().toBuffer();
}

// ── Level → cfg override table ────────────────────────────────────────────────
// The caller's requested mode defines the upper bound; level can only reduce the
// intensity — never increase it above what was requested.
function levelCfg(requestedCfg, level) {
  switch (level) {
    case 'strict':
      return requestedCfg;  // full requested mode as-is

    case 'relaxed':
      // Whitening only — no geometric changes that could spill outside mask.
      return {
        ...SIM_MODES.whitening,
        name:                `${requestedCfg.name}→relaxed`,
        label:               requestedCfg.label,
        blendAlpha:          {
          strong: Math.min(requestedCfg.blendAlpha.strong, 0.62),
          edge:   Math.min(requestedCfg.blendAlpha.edge,   0.28),
        },
        uniformTargetFactor: Math.min(requestedCfg.uniformTargetFactor, 1.16),
        alignment:    false,
        smileArc:     false,
        edgeSoftening:false,
        highlights:   false,
      };

    case 'minimal':
      // Best-effort: visible but natural — mask was sparse / beard-heavy.
      return {
        ...SIM_MODES.whitening,
        name:                `${requestedCfg.name}→minimal`,
        label:               requestedCfg.label,
        blendAlpha:          { strong: 0.72, edge: 0.34 },
        uniformTargetFactor: Math.min(1.22, requestedCfg.uniformTargetFactor),
        alignment:    false,
        smileArc:     false,
        edgeSoftening:false,
        highlights:   false,
        sharpenSigma: 1.12,
        sharpenM1:    0.52,
        sharpenM2:    9,
        maxConfidence:0.62,
      };

    default:
      return requestedCfg;
  }
}

// ── Visible-improvement helpers (multi-variation + minimum lift guarantee) ───
// Strict threshold lowered from 22 → 10: accept mid lifts without extra forced passes;
// only re-boost when mean lift is still below 10%.
const MIN_VISIBLE_TOOTH_LIFT_PCT_STRICT   = 10;
const MIN_VISIBLE_TOOTH_LIFT_PCT_RELAXED  = 8;
const MIN_VISIBLE_TOOTH_LIFT_PCT_MINIMAL  = 6;

/** Scale blend strength & uniform whitening target for internal A/B/C candidates. */
function scaleSimStrength(baseCfg, mult) {
  if (mult <= 1.001) return { ...baseCfg };
  return {
    ...baseCfg,
    blendAlpha: {
      strong: Math.min(0.94, baseCfg.blendAlpha.strong * mult),
      edge:   Math.min(0.62, baseCfg.blendAlpha.edge * mult),
    },
    uniformTargetFactor: Math.min(1.58, baseCfg.uniformTargetFactor * (1 + (mult - 1) * 0.32)),
  };
}

/** Mean tooth-region brightness lift (%), masked pixels only — Δ vs original. */
async function measureTeethBrightnessLiftPct(origCropBuf, resultBuf, maskBuf, w, h) {
  const [o, r, m] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resultBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  let sumO = 0, sumR = 0, n = 0;
  for (let i = 0; i < w * h; i++) {
    if (m[i] <= 64) continue;
    sumO += (o[i*3] + o[i*3+1] + o[i*3+2]) / 3;
    sumR += (r[i*3] + r[i*3+1] + r[i*3+2]) / 3;
    n++;
  }
  if (n < 8) return 0;
  const meanO = sumO / n, meanR = sumR / n;
  return ((meanR - meanO) / (meanO + 1e-6)) * 100;
}

/**
 * Post-generation quality gate: masked weighted mean |ΔRGB|/3, luma lift %, and
 * Bhattacharyya coefficient between 16-bin Luma histograms (1 = identical).
 * Used to detect no-op outputs that slipped through variant selection.
 */
async function assessPostGenerationChange(origCropBuf, resultBuf, maskBuf, w, h) {
  const [o, r, m] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resultBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const BINS = 16;
  const histO = new Array(BINS).fill(0);
  const histR = new Array(BINS).fill(0);
  let sumAbs = 0, sumW = 0;

  for (let i = 0; i < w * h; i++) {
    const wgt = m[i] / 255;
    if (wgt < 0.01) continue;
    const d =
      (Math.abs(o[i*3]   - r[i*3])
        + Math.abs(o[i*3+1] - r[i*3+1])
        + Math.abs(o[i*3+2] - r[i*3+2])) / 3;
    sumAbs += d * wgt;
    sumW   += wgt;

    const lo = (o[i*3] + o[i*3+1] + o[i*3+2]) / 3;
    const lr = (r[i*3] + r[i*3+1] + r[i*3+2]) / 3;
    const bo = Math.min(BINS - 1, Math.floor((lo / 256) * BINS));
    const br = Math.min(BINS - 1, Math.floor((lr / 256) * BINS));
    histO[bo] += wgt;
    histR[br] += wgt;
  }

  const meanAbs = sumW > 0 ? sumAbs / sumW : 0;
  const lumaLiftPct = await measureTeethBrightnessLiftPct(origCropBuf, resultBuf, maskBuf, w, h);

  let histBC = 1;
  const nO = histO.reduce((a, b) => a + b, 0);
  const nR = histR.reduce((a, b) => a + b, 0);
  if (nO > 1e-6 && nR > 1e-6) {
    let s = 0;
    for (let k = 0; k < BINS; k++)
      s += Math.sqrt((histO[k] / nO) * (histR[k] / nR));
    histBC = Math.max(0, Math.min(1, s));
  }

  return { meanAbs, lumaLiftPct, histBC };
}

/** Returns true if output is still too close to input (pixel + histogram sense). */
function shouldPostGenRegenerate(metrics, simLevel) {
  const { meanAbs, lumaLiftPct, histBC } = metrics;
  // Relaxed vs earlier gates — prefer visible whitening over re-running toward “subtle realism”
  const absMin =
    simLevel === 'minimal' ? 3.2 : simLevel === 'relaxed' ? 3.8 : 4.5;
  const liftMin =
    simLevel === 'minimal' ? 4.0 : simLevel === 'relaxed' ? 5.0 : 6.0;
  const tooFlatPixels = meanAbs < absMin;
  const tooFlatBright = lumaLiftPct < liftMin;
  const histTooClose =
    histBC > (simLevel === 'minimal' ? 0.994 : 0.991) && meanAbs < absMin + 0.8;
  return tooFlatPixels || tooFlatBright || histTooClose;
}

/**
 * Stronger enhance+blend only (no alignment re-run — avoids double geometry).
 * attempt 0 → ×~2.0 strength, attempt 1 → ×~2.45
 */
/** Chalk patches / extreme lifts vs original — triggers gentle re-blend. */
async function detectWhiteningArtifacts(origCropBuf, resultBuf, maskBuf, w, h) {
  const [o, r, m] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(resultBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  let hiJump = 0, n = 0;
  for (let i = 0; i < w * h; i++) {
    if (m[i] <= 64) continue;
    n++;
    const lo = (o[i * 3] + o[i * 3 + 1] + o[i * 3 + 2]) / 3;
    const lr = (r[i * 3] + r[i * 3 + 1] + r[i * 3 + 2]) / 3;
    if (lr > 230 && lr - lo > 32) hiJump++;
  }
  const ratio = n > 0 ? hiJump / n : 0;
  const bad = ratio > 0.065 || hiJump > 220;
  if (bad) {
    console.warn(
      `[SIM ARTIFACT] unnatural bright lifts: ${hiJump}px (${(ratio * 100).toFixed(1)}% of mask)`
    );
  }
  return { bad, ratio, hiJump };
}

async function regenerateBlendPostCheck(origCropBuf, maskBuf, w, h, cfg, attempt) {
  const mult = 1.28 + attempt * 0.42;
  const cfgStrong = scaleSimStrength(cfg, mult);
  const enc = await computeEnhancedRaw(origCropBuf, w, h, true);
  return blendCropWithMask(origCropBuf, enc, maskBuf, w, h, cfgStrong);
}

/** Last resort: LAB lift + yellow pull on masked pixels only (no geometry). */
async function applyFailsafeManualWhiten(origCropBuf, maskBuf, w, h) {
  const [raw, maskRaw] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);
  const out = Buffer.from(raw);
  let n = 0;
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 64) continue;
    const r = raw[i * 3], g = raw[i * 3 + 1], b = raw[i * 3 + 2];
    const [L, A, B] = rgbToLab(r, g, b);
    const wgt = maskRaw[i] / 255;
    const L2 = Math.min(93, L + 10 + wgt * 4);
    const A2 = A * 0.92;
    const B2 = B * 0.82;
    const [r2, g2, b2] = labToRgb(L2, A2, B2);
    const mx = 0.78 * wgt;
    out[i * 3] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(r * (1 - mx) + r2 * mx));
    out[i * 3 + 1] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(g * (1 - mx) + g2 * mx));
    out[i * 3 + 2] = Math.min(ENAMEL_OUTPUT_CAP, Math.round(b * (1 - mx) + b2 * mx));
    n++;
  }
  console.warn(`[SIM FAILSAFE] Manual LAB whitening on ${n} masked px`);
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

async function cropCompositeSimulation(publicImageUrl, patientId, mode = 'full', colorPresetKey = 'natural') {
  const resolvedColorPreset = resolveSmileColorPreset(colorPresetKey);
  console.log("SMILE PIPELINE ACTIVE");
  let cfg = { ...resolveSimMode(mode) };
  console.log(`[SIM] Mode: ${cfg.name} (label: ${cfg.label}) strength≈${SIM_TRANSFORM_STRENGTH}`);
  console.log('[SIM] colorPreset:', resolvedColorPreset);
  console.log('[SIM INTENT]', SIM_VISUAL_INTENT_PROMPT);
  // 1. Fetch original
  let origBuf, origW, origH;
  try {
    const res = await fetch(publicImageUrl, { signal: AbortSignal.timeout(25_000) });
    if (!res.ok) throw new Error(`fetch_http_${res.status}`);
    origBuf = Buffer.from(await res.arrayBuffer());
    const meta = await sharp(origBuf).metadata();
    origW = meta.width; origH = meta.height;
    console.log(`[SIM CROP] Original: ${origW}×${origH}`);
  } catch (e) { return { url: null, failReason: 'fetch_orig: ' + e?.message }; }

  // Hard verification: set SIM_SMILE_DEBUG_BLACK=1 on server → UI must show all-black result or this path is not used.
  if (String(process.env.SIM_SMILE_DEBUG_BLACK || '').trim() === '1') {
    console.warn('[SIM DEBUG] SIM_SMILE_DEBUG_BLACK=1 — short-circuit: solid black full-frame JPEG upload');
    try {
      const blackBuf = await sharp({
        create: { width: origW, height: origH, channels: 3, background: { r: 0, g: 0, b: 0 } },
      })
        .jpeg({ quality: 92 })
        .toBuffer();
      const ts = Date.now();
      const rand = Math.random().toString(36).slice(2, 8);
      const storagePath = `ai-photos/${patientId}/sim-debug-black-${ts}-${rand}.jpg`;
      const { error: upErr } = await supabase.storage
        .from('patient-files')
        .upload(storagePath, blackBuf, { contentType: 'image/jpeg', upsert: false });
      if (upErr) return { url: null, failReason: 'debug_black_upload: ' + upErr.message };
      const { data: dbgSigned, error: dbgSignErr } = await supabase.storage
        .from('patient-files')
        .createSignedUrl(storagePath, 365 * 24 * 3600);
      let finalUrl = dbgSigned?.signedUrl;
      if (dbgSignErr || !finalUrl) {
        const { data: urlData } = supabase.storage.from('patient-files').getPublicUrl(storagePath);
        finalUrl = urlData?.publicUrl;
      }
      if (!finalUrl) return { url: null, failReason: 'debug_black_no_url' };
      return {
        url: finalUrl,
        mode: cfg.name,
        confidence: 0.2,
        lowerArchWeak: false,
        avgPixelChange: 255,
        stainWarning: false,
        structureWarning: false,
        failReason: null,
        level: 'strict',
        status: 'success',
      };
    } catch (e) {
      return { url: null, failReason: 'debug_black: ' + e?.message };
    }
  }

  // 2. Mouth-only crop — MediaPipe Face Mesh via TF.js (landmarks on lips → expand for teeth).
  //    SIM_FORCE_HEURISTIC_CROP=1 bypasses mesh (emergency / dev only).
  let cropLeft;
  let cropTop;
  let cropWidth;
  let cropHeight;
  if (String(process.env.SIM_FORCE_HEURISTIC_CROP || "").trim() === "1") {
    const box = enforceMouthOnlyCrop(origW, origH);
    cropLeft = box.cropLeft;
    cropTop = box.cropTop;
    cropWidth = box.cropWidth;
    cropHeight = box.cropHeight;
    console.warn("[SIM CROP] SIM_FORCE_HEURISTIC_CROP=1 — fraction-based band (face mesh skipped)");
  } else {
    const mp = await computeMouthCropFromImageBuffer(origBuf);
    if (!mp.ok) {
      console.warn(
        "[SIM MEDIAPIPE] Mouth ROI rejected:",
        mp.reason,
        mp.debug || "",
        "— using heuristic mouth band (same image, no strict face dependency)"
      );
      const box = getSpecFallbackMouthRectFromFullImage(origW, origH);
      cropLeft = box.cropLeft;
      cropTop = box.cropTop;
      cropWidth = box.cropWidth;
      cropHeight = box.cropHeight;
    } else {
      cropLeft = mp.cropLeft;
      cropTop = mp.cropTop;
      cropWidth = mp.cropWidth;
      cropHeight = mp.cropHeight;
      console.log(
        `[SIM MEDIAPIPE] crop rect: left=${cropLeft} top=${cropTop} width=${cropWidth} height=${cropHeight} ` +
          `mouthOpen≈${(mp.mouthOpenPx || 0).toFixed(1)}px`
      );
    }
  }

  let origCropBuf;
  try {
    origCropBuf = await sharp(origBuf)
      .extract({ left: cropLeft, top: cropTop, width: cropWidth, height: cropHeight })
      .jpeg({ quality: 95 }).toBuffer();
  } catch (e) { return { url: null, failReason: 'crop_extract: ' + e?.message }; }

  logSimDebugPreview("cropped_input_to_simulation (AI + programmatic path)", origCropBuf);

  // 3. Build teeth mask
  let maskBuf;
  try { maskBuf = await buildTeethMask(origCropBuf, cropWidth, cropHeight); }
  catch (e) { return { url: null, failReason: 'crop_mask: ' + e?.message }; }

  // 3b. Assess mask quality → determine fallback level ─────────────────────
  //
  // Cascade: strict → full mode | relaxed → whitening+ | minimal → best-effort |
  // Sparse mask (totalOn < 6) → synthetic mid-crop enamel ROI — never skip processing.
  // Beard-heavy: tighter vertical clamp so only enamel band is blended.
  let simLevel = 'strict';
  let beardHeavy = false;
  try {
    const qa = await assessMaskQuality(maskBuf, cropWidth, cropHeight);
    simLevel   = qa.level;
    beardHeavy = !!qa.beardHeavy;

    if (qa.totalOn < 6) {
      console.warn('[SIM LEVEL] Mask nearly empty — synthetic enamel ROI + best-effort whitening');
      maskBuf = await buildFallbackTeethMask(origCropBuf, cropWidth, cropHeight);
      simLevel = 'minimal';
    }

    if (simLevel !== 'strict') {
      cfg = levelCfg(cfg, simLevel);
      console.log(`[SIM LEVEL] Downgraded to ${simLevel} — mode overridden to ${cfg.name}`);
      const safeFrac = beardHeavy ? 0.62 : 0.70;
      maskBuf = await clampMaskToSafeRegion(maskBuf, cropWidth, cropHeight, safeFrac);
    }
  } catch (e) { console.warn('[SIM LEVEL] non-fatal:', e?.message); }

  cfg = applySimTransformStrength(cfg);

  // ── Structured pipeline (teeth-focused cosmetic preview — not full orthodontic sim) ──
  console.log('[SIMSTEP 1] Mouth region crop (face → mouth band)');
  console.log('[SIMSTEP 2] Teeth segmentation mask (+ soft feather)');
  try {
    maskBuf = await featherTeethMaskForBlend(maskBuf, cropWidth, cropHeight);
  } catch (e) {
    console.warn('[SIMSTEP 2] mask feather non-fatal:', e?.message);
  }

  if (String(process.env.SIM_SKIP_BOTH_ARCH_CHECK || "").trim() !== "1") {
    try {
      const archOk = await validateBothArchesVisible(maskBuf, cropWidth, cropHeight);
      if (!archOk.ok) {
        const strict = String(process.env.SIM_STRICT_BOTH_ARCH || "").trim() === "1";
        if (strict) {
          return {
            url: null,
            failReason: 'invalid_photo',
            errorCode: 'invalid_photo',
            message: INVALID_PHOTO_BOTH_ARCHES_EN,
            messageTr: INVALID_PHOTO_BOTH_ARCHES_TR,
          };
        }
        console.warn('[SIM ARCH] soft-pass (set SIM_STRICT_BOTH_ARCH=1 to hard-reject):', archOk.reason);
      }
    } catch (e) {
      console.warn('[SIM ARCH] validation non-fatal:', e?.message);
    }
  }

  let workingCropBuf = origCropBuf;
  try {
    workingCropBuf = await normalizeTeethPreEnhance(origCropBuf, maskBuf, cropWidth, cropHeight);
    console.log('[SIMSTEP 3] Normalization: brightness / mild contrast / yellow pull (masked)');
  } catch (e) {
    console.warn('[SIMSTEP 3] normalize skipped — using raw crop:', e?.message);
  }

  const replicateConfigured = !!(
    process.env.REPLICATE_API_TOKEN &&
    String(process.env.REPLICATE_API_TOKEN).trim() &&
    process.env.REPLICATE_IMG2IMG_VERSION &&
    String(process.env.REPLICATE_IMG2IMG_VERSION).trim()
  );
  const allowLegacySinglePassReplicate =
    String(process.env.SIM_USE_SINGLE_PASS_REPLICATE || '').trim() === '1';

  // STEP 4: Replicate — region-based dual strip only (no single full-crop unless SIM_USE_SINGLE_PASS_REPLICATE=1).
  let blendedCropBuf = null;
  let aiJpeg = null;
  if (replicateConfigured && SIM_DUAL_REGION_REPLICATE_ENABLED) {
    aiJpeg = await replicateDualRegionTeethImg2Img(workingCropBuf, cropWidth, cropHeight, {});
  }
  if (!aiJpeg && replicateConfigured && allowLegacySinglePassReplicate) {
    console.warn('[SIMSTEP 4] legacy single full-crop Replicate (SIM_USE_SINGLE_PASS_REPLICATE=1)');
    aiJpeg = await replicateTeethImg2ImgOptional(workingCropBuf, cropWidth, cropHeight);
  }
  if (aiJpeg) {
    try {
      const aiRaw = await sharp(aiJpeg)
        .resize(cropWidth, cropHeight)
        .removeAlpha()
        .raw()
        .toBuffer();
      // Moderate α — enough to show img2img but avoid flat “veneer block” look.
      const mergeCfg = {
        ...cfg,
        blendAlpha: { strong: 0.72, edge: 0.32 },
        uniformTargetFactor: Math.min(1.18, cfg.uniformTargetFactor * 0.98),
      };
      blendedCropBuf = await blendCropWithMask(
        origCropBuf, aiRaw, maskBuf, cropWidth, cropHeight, mergeCfg
      );
      console.log('[SIMSTEP 4] External img2img merged (teeth-forward blend, mask-limited)');
    } catch (e) {
      console.warn('[SIMSTEP 4] AI merge failed — programmatic path:', e?.message);
      blendedCropBuf = null;
    }
  }

  // STEP 4b: programmatic enhancement (always if Replicate off or failed)
  if (!blendedCropBuf) {
    console.log('[SIMSTEP 4b] Programmatic enhancement (LAB + blend — not generic full-image img2img)');
    try {
      const minLift =
        simLevel === 'minimal'
          ? MIN_VISIBLE_TOOTH_LIFT_PCT_MINIMAL
          : simLevel === 'relaxed'
            ? MIN_VISIBLE_TOOTH_LIFT_PCT_RELAXED
            : MIN_VISIBLE_TOOTH_LIFT_PCT_STRICT;
      const mults =
        simLevel === 'minimal'
          ? [1.0, 1.2, 1.38]
          : [1.0, 1.1, 1.22, 1.34, 1.42];

      let bestBuf = null;
      let bestLift = -Infinity;
      let bestTag = '';

      for (const mult of mults) {
        const cfgTry = scaleSimStrength(cfg, mult);
        const boosted = mult > 1.05;
        const enhancedRaw = await computeEnhancedRaw(
          workingCropBuf,
          cropWidth,
          cropHeight,
          boosted
        );
        const buf = await blendCropWithMask(
          origCropBuf,
          enhancedRaw,
          maskBuf,
          cropWidth,
          cropHeight,
          cfgTry
        );
        const lift = await measureTeethBrightnessLiftPct(
          origCropBuf,
          buf,
          maskBuf,
          cropWidth,
          cropHeight
        );
        console.log(
          `[SIM VARIANT] mult=${mult.toFixed(2)} boosted=${boosted} meanLift=${lift.toFixed(1)}%`
        );
        if (lift > bestLift) {
          bestLift = lift;
          bestBuf = buf;
          bestTag = `×${mult.toFixed(2)}`;
        }
      }

      if (bestLift < minLift && simLevel !== 'minimal') {
        console.warn(
          `[SIM VIS] best lift ${bestLift.toFixed(1)}% < ${minLift}% — forced pass`
        );
        const forced = scaleSimStrength(cfg, 1.55);
        const encForced = await computeEnhancedRaw(
          workingCropBuf,
          cropWidth,
          cropHeight,
          true
        );
        bestBuf = await blendCropWithMask(
          origCropBuf,
          encForced,
          maskBuf,
          cropWidth,
          cropHeight,
          forced
        );
        bestLift = await measureTeethBrightnessLiftPct(
          origCropBuf,
          bestBuf,
          maskBuf,
          cropWidth,
          cropHeight
        );
        bestTag = 'forced';
        console.log(`[SIM VIS] forced pass meanLift=${bestLift.toFixed(1)}%`);
      }

      blendedCropBuf = bestBuf;
      console.log(
        `[SIM CROP] Blended [${simLevel}] picked ${bestTag} meanLift≈${bestLift.toFixed(1)}% | ${Math.round(
          blendedCropBuf.byteLength / 1024
        )} KB`
      );
    } catch (e) {
      return { url: null, failReason: 'crop_blend: ' + e?.message };
    }
  }

  // STEP 5–6: geometry + highlights + QC continue below (blend-back to full frame at composite)
  console.log('[SIMSTEP 5] Teeth result ready for geometry/highlights + quality gates');

  // Step 5a: Horizontal micro-alignment (alignment + full modes)
  if (cfg.alignment) {
    try {
      blendedCropBuf = await microAlignment(
        blendedCropBuf, maskBuf, cropWidth, cropHeight, cfg
      );
    } catch (e) { console.warn('[SIM ALIGN] non-fatal error:', e?.message); }
  }

  // Step 5b: Smile arc — parabolic incisal-edge correction (alignment + full modes)
  if (cfg.smileArc) {
    try {
      blendedCropBuf = await applySmileArc(
        blendedCropBuf, maskBuf, cropWidth, cropHeight, cfg
      );
    } catch (e) { console.warn('[SIM ARC] non-fatal:', e?.message); }
  }

  // Step 6: Shape refinement — soft incisal edges (alignment + full modes)
  if (cfg.edgeSoftening) {
    try {
      blendedCropBuf = await edgeSoftening(blendedCropBuf, maskBuf, cropWidth, cropHeight);
    } catch (e) { console.warn('[SIM EDGE-SOFT] non-fatal:', e?.message); }
  }

  // Step 7: Light & reflection highlights (full mode only)
  if (cfg.highlights) {
    try {
      blendedCropBuf = await addReflectionHighlights(blendedCropBuf, maskBuf, cropWidth, cropHeight);
    } catch (e) { console.warn('[SIM HIGHLIGHT] non-fatal:', e?.message); }
  }

  // ── Stain validation ─────────────────────────────────────────────────────────
  // Decode both the original crop and the current result, then measure how many
  // stain pixels survived. If > 50% remain AND teeth were significantly stained to
  // begin with, retry the entire enhance+blend pass with boosted parameters.
  //
  let stainWarning = false;
  let stainRemovalRate = 1.0; // assume clean unless we detect otherwise
  try {
    const [origDecoded, maskDecoded] = await Promise.all([
      sharp(origCropBuf).resize(cropWidth, cropHeight).removeAlpha().raw().toBuffer(),
      sharp(maskBuf).resize(cropWidth, cropHeight).greyscale().raw().toBuffer(),
    ]);
    const beforeStains = detectStains(origDecoded, maskDecoded, cropWidth, cropHeight);
    console.log(`[SIM VALIDATE] before: count=${beforeStains.count} ratio=${(beforeStains.ratio*100).toFixed(1)}%`);

    if (beforeStains.ratio >= MIN_STAIN_RATIO) {
      const resDecoded   = await sharp(blendedCropBuf).resize(cropWidth, cropHeight).removeAlpha().raw().toBuffer();
      const afterStains  = detectStains(resDecoded, maskDecoded, cropWidth, cropHeight);
      const removalRate  = beforeStains.count > 0 ? (beforeStains.count - afterStains.count) / beforeStains.count : 1;
      stainRemovalRate   = Math.max(0, Math.min(1, removalRate));
      console.log(`[SIM VALIDATE] after: count=${afterStains.count} ratio=${(afterStains.ratio*100).toFixed(1)}%  removed=${(removalRate*100).toFixed(1)}%`);

      if (removalRate < PASS_REMOVAL_RATE) {
        console.log('[SIM VALIDATE] ⚠️ < 50% stains removed — retrying with boosted params');

        const boostCfg = {
          ...cfg,
          blendAlpha:          { strong: Math.min(0.93, cfg.blendAlpha.strong * 1.18), edge: Math.min(0.58, cfg.blendAlpha.edge * 1.18) },
          uniformTargetFactor: Math.min(1.32, cfg.uniformTargetFactor * 1.12),
        };

        try {
          const enhancedBoosted = await computeEnhancedRaw(origCropBuf, cropWidth, cropHeight, true);
          let retryBuf = await blendCropWithMask(origCropBuf, enhancedBoosted, maskBuf, cropWidth, cropHeight, boostCfg);
          if (boostCfg.edgeSoftening)
            retryBuf = await edgeSoftening(retryBuf, maskBuf, cropWidth, cropHeight).catch(e => { console.warn('[SIM RETRY ES]', e?.message); return retryBuf; });
          if (boostCfg.highlights)
            retryBuf = await addReflectionHighlights(retryBuf, maskBuf, cropWidth, cropHeight).catch(e => { console.warn('[SIM RETRY HL]', e?.message); return retryBuf; });

          const retryDecoded  = await sharp(retryBuf).resize(cropWidth, cropHeight).removeAlpha().raw().toBuffer();
          const retryStains   = detectStains(retryDecoded, maskDecoded, cropWidth, cropHeight);
          const retryRemoval  = (beforeStains.count - retryStains.count) / beforeStains.count;
          console.log(`[SIM VALIDATE] retry: count=${retryStains.count} removed=${(retryRemoval*100).toFixed(1)}%`);

          if (retryRemoval >= PASS_REMOVAL_RATE) {
            console.log('[SIM VALIDATE] ✅ Retry passed — using boosted result');
            blendedCropBuf = retryBuf;
          } else {
            console.warn('[SIM VALIDATE] ⚠️ Stains persist after retry — using boosted result anyway, flagging stainWarning');
            blendedCropBuf = retryBuf;  // still better than first pass
            stainWarning   = true;
          }
        } catch (retryErr) {
          console.warn('[SIM VALIDATE] retry exception (keeping first-pass result):', retryErr?.message);
          stainWarning = true;
        }
      } else {
        console.log(`[SIM VALIDATE] ✅ ${(removalRate*100).toFixed(1)}% stains removed — no retry needed`);
      }
    } else {
      console.log('[SIM VALIDATE] Teeth are clean — validation skipped');
    }
  } catch (validErr) {
    console.warn('[SIM VALIDATE] non-fatal validation error:', validErr?.message);
  }

  // ── Structural integrity check ────────────────────────────────────────────────
  // Compare the column brightness profile of the original crop vs the current result.
  // If the Pearson correlation drops below 0.82 OR inter-tooth gaps are reduced by
  // more than 45%, the output has effectively changed tooth geometry.
  //
  // On failure: revert to a "safe fallback" — a gentle re-blend (α 0.25/0.12) of
  // the original non-boosted enhanced raw, which is purely a colour correction
  // with almost no luminance shift.
  //
  let structureWarning = false;
  try {
    const integ = await checkStructuralIntegrity(origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight);
    console.log(`[SIM STRUCTURE] corr=${integ.correlation.toFixed(3)}  gaps=${integ.origGaps}→${integ.resultGaps}(ratio=${integ.gapRatio.toFixed(2)})  valid=${integ.valid}`);

    if (!integ.valid) {
      console.warn('[SIM STRUCTURE] ⚠️ Structure changed:', integ.issues.join(', '), '— reverting to safe fallback');
      structureWarning = true;

      // Safe fallback: still visibly brighter teeth (never near-identical to input)
      const safeCfg = {
        ...cfg,
        blendAlpha:          { strong: 0.64, edge: 0.30 },
        uniformTargetFactor: 1.18,
        edgeSoftening:       false,
        highlights:          false,
        alignment:           false,
      };
      try {
        const safeEnhanced = await computeEnhancedRaw(origCropBuf, cropWidth, cropHeight, false);
        blendedCropBuf     = await blendCropWithMask(origCropBuf, safeEnhanced, maskBuf, cropWidth, cropHeight, safeCfg);
        console.log('[SIM STRUCTURE] ✅ Safe fallback applied');
      } catch (fbErr) {
        console.warn('[SIM STRUCTURE] Fallback failed — keeping original result:', fbErr?.message);
      }
    } else {
      console.log('[SIM STRUCTURE] ✅ Tooth structure preserved');
    }
  } catch (structErr) {
    console.warn('[SIM STRUCTURE] non-fatal:', structErr?.message);
  }

  // Final sharpening — mode-specific sigma keeps gaps crisp
  try {
    blendedCropBuf = await sharp(blendedCropBuf)
      .sharpen({ sigma: cfg.sharpenSigma, m1: cfg.sharpenM1, m2: cfg.sharpenM2 })
      .jpeg({ quality: 92 })
      .toBuffer();
    console.log('[SIM CROP] Sharpened');
  } catch (e) {
    console.warn('[SIM CROP] Sharpen failed (non-fatal):', e?.message);
  }

  // Confidence score — transformation-aware (mode + stain removal + warnings)
  let confidence = 0.75, avgPixelChange = 0;
  try {
    const conf = await computeConfidence(origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight);
    avgPixelChange = conf.avgPixelChange;
    // Transformation-aware score (replaces raw pixel-delta score)
    confidence = computeTransformationScore({ cfg, stainRemovalRate, stainWarning, structureWarning });
    console.log(`[SIM CONFIDENCE] mode=${cfg.name} stainRemoval=${(stainRemovalRate*100).toFixed(0)}% score=${confidence}`);
  } catch (e) { console.warn('[SIM CONFIDENCE] non-fatal:', e?.message); }

  // CRITICAL: Hard mask fence — restore original for every non-mask pixel.
  // This is the last line of defence against any upstream leakage (warp,
  // blur, alignment) that touched skin, lip, beard, or background pixels.
  try {
    blendedCropBuf = await enforceTeethMaskBoundary(
      blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
    );
  } catch (e) { console.warn('[SIM FENCE] non-fatal:', e?.message); }

  // ── Post-generation gate: pixel + histogram vs original ────────────────────
  // If the fenced crop still looks almost identical to the input, run stronger
  // enhance+blend passes (max 3; strength increases each time), then re-sharpen + re-fence.
  const POST_GEN_MAX = 3;
  for (let pg = 0; pg < POST_GEN_MAX; pg++) {
    try {
      const pm = await assessPostGenerationChange(
        origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight
      );
      console.log(
        `[SIM POST-GEN] check=${pg} meanAbs=${pm.meanAbs.toFixed(2)} ` +
        `lumaLift=${pm.lumaLiftPct.toFixed(1)}% histBC=${pm.histBC.toFixed(4)}`
      );
      if (!shouldPostGenRegenerate(pm, simLevel)) break;

      console.warn(`[SIM POST-GEN] Output too close to original — regenerating (pass ${pg + 1}/${POST_GEN_MAX})`);
      blendedCropBuf = await regenerateBlendPostCheck(
        origCropBuf, maskBuf, cropWidth, cropHeight, cfg, pg
      );
      try {
        blendedCropBuf = await sharp(blendedCropBuf)
          .sharpen({ sigma: cfg.sharpenSigma * 1.08, m1: cfg.sharpenM1, m2: cfg.sharpenM2 })
          .jpeg({ quality: 92 })
          .toBuffer();
      } catch (e) {
        console.warn('[SIM POST-GEN] sharpen failed:', e?.message);
      }
      blendedCropBuf = await enforceTeethMaskBoundary(
        blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
      );
    } catch (e) {
      console.warn('[SIM POST-GEN] non-fatal:', e?.message);
      break;
    }
  }

  // If still too flat vs original, one moderate pass (not chalk-boost)
  try {
    const pmEnd = await assessPostGenerationChange(
      origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight
    );
    if (shouldPostGenRegenerate(pmEnd, simLevel)) {
      console.warn('[SIM POST-GEN] Moderate boost pass (natural, not ultra-white)');
      const midCfg = scaleSimStrength(cfg, 1.42);
      const encU = await computeEnhancedRaw(origCropBuf, cropWidth, cropHeight, true);
      blendedCropBuf = await blendCropWithMask(
        origCropBuf, encU, maskBuf, cropWidth, cropHeight, midCfg
      );
      blendedCropBuf = await sharp(blendedCropBuf)
        .sharpen({ sigma: cfg.sharpenSigma * 1.1, m1: cfg.sharpenM1, m2: cfg.sharpenM2 })
        .jpeg({ quality: 92 })
        .toBuffer();
      blendedCropBuf = await enforceTeethMaskBoundary(
        blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
      );
    }
  } catch (e) {
    console.warn('[SIM POST-GEN] moderate pass non-fatal:', e?.message);
  }

  // Intentionally no “gentle artifact” re-blend or manual LAB failsafe here — those
  // tended to cancel visible whitening for the sake of ultra-safe realism.

  try {
    const confPost = await computeConfidence(origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight);
    avgPixelChange = confPost.avgPixelChange;
    confidence = computeTransformationScore({ cfg, stainRemovalRate, stainWarning, structureWarning });
    console.log(`[SIM CONFIDENCE] after post-gen gate avgΔ=${avgPixelChange}`);
  } catch (e) { console.warn('[SIM CONFIDENCE] post-gen update failed:', e?.message); }

  // HARD FAIL CHECK: Verify no outside-mask pixels were altered.
  // Rejects the simulation if beard/skin/chin brightness changed.
  // (enforceTeethMaskBoundary already restores them; this validates that
  // the restoration was complete and the diff is within JPEG rounding noise.)
  try {
    const leak = await validateNoLeakage(
      origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight
    );
    if (!leak.passed) {
      // Log the failure but do NOT abort — enforceTeethMaskBoundary has already
      // hard-restored every outside-mask pixel.  Lower confidence instead.
      console.warn(`[SIM HARD FAIL] Leakage avgΔ=${leak.avgDiff.toFixed(2)} px=${leak.leakedPx} — confidence capped at 0.45`);
      confidence = Math.min(confidence, 0.45);
    }
  } catch (e) { console.warn('[SIM VALIDATE] non-fatal:', e?.message); }

  // ── Lower-arch boost: retry if lower band barely changed (do not fail the job by default) ──
  let lowerArchWeak = false;
  const lowerMinAbs = (() => {
    const v = parseFloat(String(process.env.SIM_LOWER_ARCH_MIN_ABS || '1.85'), 10);
    return Number.isFinite(v) ? Math.max(1.0, Math.min(8, v)) : 1.85;
  })();
  try {
    let lowM = await measureLowerArchChange(origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight);
    if (lowM.maskPx >= 40 && lowM.meanAbs < lowerMinAbs) {
      console.warn(
        `[SIM LOWER ARCH] Low change meanAbs=${lowM.meanAbs.toFixed(2)} — retry (Replicate or programmatic boost)`
      );
      const aiRetry =
        replicateConfigured && SIM_DUAL_REGION_REPLICATE_ENABLED
          ? await replicateDualRegionTeethImg2Img(workingCropBuf, cropWidth, cropHeight, {
              strengthOverride: 0.55,
            })
          : allowLegacySinglePassReplicate
            ? await replicateTeethImg2ImgOptional(workingCropBuf, cropWidth, cropHeight, {
                promptSuffix:
                  ' must modify both upper and lower teeth equally. Do not leave lower teeth unchanged.',
                strengthOverride: 0.55,
              })
            : null;
      if (aiRetry) {
        const aiRaw = await sharp(aiRetry)
          .resize(cropWidth, cropHeight)
          .removeAlpha()
          .raw()
          .toBuffer();
        const mergeCfgRetry = {
          ...cfg,
          blendAlpha: { strong: 0.75, edge: 0.34 },
          uniformTargetFactor: Math.min(1.2, cfg.uniformTargetFactor * 0.99),
        };
        blendedCropBuf = await blendCropWithMask(
          origCropBuf, aiRaw, maskBuf, cropWidth, cropHeight, mergeCfgRetry
        );
        blendedCropBuf = await enforceTeethMaskBoundary(
          blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
        );
      } else {
        blendedCropBuf = await boostLowerArchMerge(
          origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight, cfg
        );
        blendedCropBuf = await enforceTeethMaskBoundary(
          blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
        );
      }
      lowM = await measureLowerArchChange(origCropBuf, blendedCropBuf, maskBuf, cropWidth, cropHeight);
      if (lowM.maskPx >= 40 && lowM.meanAbs < 1.35) {
        lowerArchWeak = true;
        console.warn('[SIM LOWER ARCH] still soft after retry — continuing (confidence may be capped)');
        if (String(process.env.SIM_STRICT_LOWER_ARCH_FAIL || "").trim() === "1") {
          return {
            url: null,
            failReason: 'invalid_photo',
            errorCode: 'invalid_photo',
            message: INVALID_PHOTO_LOWER_UNCHANGED_EN,
            messageTr: INVALID_PHOTO_LOWER_UNCHANGED_TR,
          };
        }
      }
    }
  } catch (e) {
    console.warn('[SIM LOWER ARCH] gate non-fatal:', e?.message);
  }
  if (lowerArchWeak) {
    confidence = Math.min(confidence, 0.62);
  }

  // ── Smile-sim realism (UI pipeline): mask already feathered; lower darken + upper shadow + micro post on crop ──
  if (String(process.env.SIM_SMILE_REALISM_POST ?? '1').trim() !== '0') {
    try {
      console.log("REALISM PASS RUNNING");
      blendedCropBuf = await applySmileSimCropRealismPass(
        blendedCropBuf,
        origCropBuf,
        maskBuf,
        cropWidth,
        cropHeight
      );
      blendedCropBuf = await enforceTeethMaskBoundary(
        blendedCropBuf, origCropBuf, maskBuf, cropWidth, cropHeight
      );
      console.log('[SIM REALISM] applySmileSimCropRealismPass + fence OK');
    } catch (e) {
      console.warn('[SIM REALISM] non-fatal:', e?.message);
    }
  }

  // Stage 2 — user-selected LAB color preset (mask only; structure passes unchanged above)
  try {
    blendedCropBuf = await applySmileColorPresetToMaskedCrop(
      blendedCropBuf,
      maskBuf,
      cropWidth,
      cropHeight,
      resolvedColorPreset
    );
    blendedCropBuf = await applyEnamelNaturalismAfterPreset(
      blendedCropBuf,
      origCropBuf,
      maskBuf,
      cropWidth,
      cropHeight
    );
    blendedCropBuf = await enforceTeethMaskBoundary(
      blendedCropBuf,
      origCropBuf,
      maskBuf,
      cropWidth,
      cropHeight
    );
    console.log('[SIM COLOR] Stage-2 preset + enamel naturalism:', resolvedColorPreset);
  } catch (e) {
    console.warn('[SIM COLOR] preset failed (non-fatal):', e?.message);
  }

  // 6. Raw-pixel surgery composite ────────────────────────────────────────────
  //
  // CRITICAL DESIGN:  sharp(origBuf).composite(...).jpeg() re-encodes the ENTIRE
  // original image, which alters EVERY pixel (including beard and chin) by JPEG
  // quantisation noise (±1–3 units).  That is the root cause of visible beard
  // brightness changes.
  //
  // Fix: decode origBuf to raw RGB once, write only mask>0 pixels from the
  // processed crop directly into that raw buffer, then JPEG-encode once.
  //
  //   • mask = 0   → origRawFull pixel is untouched (byte-identical to decode)
  //   • mask > 0   → proportional alpha blend:  orig*(1−α) + processed*α
  //
  // Non-teeth areas (beard, skin, lips, background) are NEVER written — they go
  // straight from decode → JPEG encode with zero intermediate processing.
  //
  let compositedBuf;
  try {
    const [cropRaw, maskRaw, { data: origRawFull, info: { width: origWFull, height: origHFull } }] =
      await Promise.all([
        sharp(blendedCropBuf).resize(cropWidth, cropHeight).removeAlpha().raw().toBuffer(),
        sharp(maskBuf).resize(cropWidth, cropHeight).greyscale().raw().toBuffer(),
        sharp(origBuf).removeAlpha().raw().toBuffer({ resolveWithObject: true }),
      ]);

    // Direct pixel surgery: only masked pixels are written
    let touchedPx = 0;
    for (let cy = 0; cy < cropHeight; cy++) {
      for (let cx = 0; cx < cropWidth; cx++) {
        const mi = cy * cropWidth + cx;
        const mv = maskRaw[mi];
        if (mv === 0) continue;  // outside mask — leave original untouched

        const fy = cropTop  + cy;
        const fx = cropLeft + cx;
        if (fy < 0 || fy >= origHFull || fx < 0 || fx >= origWFull) continue;

        const di = fy * origWFull + fx;
        const alpha = mv / 255;
        for (let c = 0; c < 3; c++) {
          origRawFull[di*3+c] = Math.round(
            origRawFull[di*3+c] * (1 - alpha) + cropRaw[mi*3+c] * alpha
          );
        }
        touchedPx++;
      }
    }
    console.log(`[SIM COMPOSITE] Raw surgery: ${touchedPx} teeth px written — zero non-teeth alteration`);

    // Single JPEG encode — the only encode pass the full image undergoes
    compositedBuf = await sharp(Buffer.from(origRawFull), {
      raw: { width: origWFull, height: origHFull, channels: 3 },
    }).jpeg({ quality: 92 }).toBuffer();
    console.log(`[SIM COMPOSITE] Done: ${Math.round(compositedBuf.byteLength / 1024)} KB`);
  } catch (e) { return { url: null, failReason: 'crop_composite: ' + e?.message }; }

  // 7. Upload to Supabase
  try {
    const ts = Date.now(), rand = Math.random().toString(36).slice(2, 8);
    const storagePath = `ai-photos/${patientId}/sim-${ts}-${rand}.jpg`;
    console.log('[SIM CROP] Uploading to Supabase:', storagePath);
    const { error: upErr } = await supabase.storage
      .from('patient-files')
      .upload(storagePath, compositedBuf, { contentType: 'image/jpeg', upsert: false });
    if (upErr) throw new Error(upErr.message);
    // Same as /api/chat/ai-upload: signed URL so the slider “after” image loads like the
    // “before” signed upload URL (works if the bucket is not public).
    const { data: signed, error: signErr } = await supabase.storage
      .from('patient-files')
      .createSignedUrl(storagePath, 365 * 24 * 3600);
    let finalUrl = signed?.signedUrl;
    if (signErr || !finalUrl) {
      const { data: urlData } = supabase.storage.from('patient-files').getPublicUrl(storagePath);
      finalUrl = urlData?.publicUrl;
    }
    if (!finalUrl) throw new Error('signed and public URL both unavailable');
    console.log('[SIM CROP] Result URL:', finalUrl.slice(0, 100));
    return {
      url: finalUrl,
      mode: cfg.name,
      colorPreset: resolvedColorPreset,
      confidence,
      lowerArchWeak,
      avgPixelChange,
      stainWarning,
      structureWarning,
      failReason: null,
      // Fallback level fields
      level:  simLevel,                                // 'strict' | 'relaxed' | 'minimal'
      status: simLevel === 'strict' ? 'success' : 'fallback',
    };
  } catch (e) {
    console.error('[SIM CROP] Supabase upload failed:', e?.message);
    return { url: null, failReason: 'supabase_upload: ' + e?.message };
  }
}

// ── Teeth condition analyser ──────────────────────────────────────────────────
//
// Runs a pure-pixel analysis over the teeth mask and returns a structured
// clinical summary (problems / treatments / priority) suitable for display
// in the patient-facing UI.  No AI model required — brightness and LAB colour
// statistics reliably distinguish enamel shade from tartar / stain.
//
async function analyzeTeethCondition(origCropBuf, maskBuf, w, h) {
  const [cropRaw, maskRaw] = await Promise.all([
    sharp(origCropBuf).resize(w, h).removeAlpha().raw().toBuffer(),
    sharp(maskBuf).resize(w, h).greyscale().raw().toBuffer(),
  ]);

  const pixels = [];
  for (let i = 0; i < w * h; i++) {
    if (maskRaw[i] <= 64) continue;
    const r = cropRaw[i*3], g = cropRaw[i*3+1], b = cropRaw[i*3+2];
    const [L, A, B] = rgbToLab(r, g, b);
    pixels.push({ L, A, B });
  }

  if (pixels.length < 150) return null;   // not enough tooth pixels for analysis

  const avgL = pixels.reduce((s, p) => s + p.L, 0) / pixels.length;
  const avgB = pixels.reduce((s, p) => s + p.B, 0) / pixels.length;  // + = yellow
  const avgA = pixels.reduce((s, p) => s + p.A, 0) / pixels.length;  // + = reddish

  // Stain: very dark pixels (L < 52) within the enamel region
  const stainRate  = pixels.filter(p => p.L < 52).length / pixels.length;
  // Yellow/brown: elevated B* or reddish A*
  const yellowRate = pixels.filter(p => p.B > 11 || p.A > 7).length / pixels.length;
  // Dark overall: enamel shade below A2 reference (L ≈ 70)
  const darkRate   = pixels.filter(p => p.L < 68).length / pixels.length;
  // Uniformity: std of L across all tooth pixels
  const meanL = avgL;
  const stdL  = Math.sqrt(pixels.reduce((s, p) => s + (p.L - meanL) ** 2, 0) / pixels.length);

  // ── Problem → treatment mapping ─────────────────────────────────────────
  const problems   = [];
  const treatments = [];
  const priority   = [];

  if (stainRate > 0.10) {
    problems.push('Diş yüzeyinde tartar ve koyu leke birikimi tespit edildi');
    treatments.push('Profesyonel diş temizleme (scaling & polishing)');
    priority.push('high');
  }
  if (yellowRate > 0.18 || avgB > 10) {
    problems.push('Sarı/kahverengi renk bozukluğu (intrinsik veya ekstrinsik)');
    treatments.push('Ofis tipi diş beyazlatma (zoom / laser whitening)');
    priority.push('high');
  }
  if (darkRate > 0.30 || avgL < 62) {
    problems.push('Orta-şiddetli diş rengi bozukluğu — yüzey tedavisi yetersiz kalabilir');
    treatments.push('Porselen veneer veya zirkonyum kaplama');
    priority.push('medium');
  } else if (darkRate > 0.15) {
    problems.push('Hafif diş rengi bozukluğu');
    treatments.push('Ev tipi veya ofis beyazlatma');
    priority.push('medium');
  }
  if (stdL > 18) {
    problems.push('Dişler arasında belirgin ton farklılığı (renk uyumsuzluğu)');
    treatments.push('Estetik bonding veya veneer ile ton eşitleme');
    priority.push('low');
  }

  // If no specific issue found → note baseline
  if (problems.length === 0) {
    problems.push('Dişlerde belirgin leke veya renk bozukluğu tespit edilmedi');
    treatments.push('Koruyucu temizlik ve periyodik kontrol');
    priority.push('low');
  }

  return {
    problems,
    treatments,
    priority,
    stats: {
      avgL:       Math.round(avgL * 10) / 10,
      avgB:       Math.round(avgB * 10) / 10,
      stainRate:  Math.round(stainRate  * 100),
      yellowRate: Math.round(yellowRate * 100),
      darkRate:   Math.round(darkRate   * 100),
      teethPx:    pixels.length,
    },
  };
}

// ── Scenario description builder ──────────────────────────────────────────────
// Produces a concise Turkish clinical description for each scenario type,
// contextualised by the analysis result.
function buildScenarioDescription(type, analysis, simResult) {
  const stain  = analysis?.stats?.stainRate  ?? 0;
  const dark   = analysis?.stats?.darkRate   ?? 0;
  const yellow = analysis?.stats?.yellowRate ?? 0;

  const hasStain  = stain  > 10;
  const hasDark   = dark   > 20;
  const hasYellow = yellow > 18;
  const conf      = simResult?.confidence ?? null;
  const confTxt   = conf !== null
    ? ` (simülasyon güveni: ${Math.round(conf * 100)}%)`
    : '';

  switch (type) {
    case 'basic':
      return [
        'Profesyonel diş temizleme ve polishing uygulaması sonrası beklenen görünüm.',
        hasStain  ? 'Yüzeysel tartar ve lekeler giderilmiş.' : '',
        hasYellow ? 'Hafif sarılık azaltılmış, doğal diş tonu korunmuş.' : 'Doğal diş tonu korunmuş.',
        'Diş şekli ve dizilimi değiştirilmemiştir.',
        confTxt,
      ].filter(Boolean).join(' ');

    case 'improved':
      return [
        'Premium estetik gülüş: doğal beyazlık, daha dengeli simetri ve idealize edilmiş oranlar (veneer benzeri düzen); tamamen düz çizgi dizilimi değil, inandırıcı hafif düzeltmeler.',
        hasDark   ? 'Belirgin renk bozukluğu beyazlatma ile normalize edilmiş.' : 'Diş tonu belirgin şekilde parlaklaştırılmış, mine dokusu korunmuştur.',
        'Hafif hizalama, kesici kenar yumuşatma ve gülüş eğrisi iyileştirmesi uygulanmıştır.',
        confTxt,
      ].filter(Boolean).join(' ');

    case 'perfect':
      return [
        'Porselen veneer veya zirkonyum kaplama tedavisi sonrası beklenen görünüm.',
        'İdeal gülüş tasarımı: simetri, oran ve renk uyumu optimize edilmiş.',
        'Veneer estetiği yansıtılmakla birlikte aşırı beyazlık (L*>88) engellenmiştir — klinik gerçekçilik korunmuştur.',
        confTxt,
      ].filter(Boolean).join(' ');

    default:
      return 'Simülasyon sonucu.';
  }
}

// ── Three-scenario simulation pipeline ───────────────────────────────────────
//
// Runs three sequential simulation passes (basic / premium improved / perfect) for a
// single patient image and returns:
//   {
//     analysis:  { problems, treatments, priority, stats }
//     scenarios: [ { type, label, imageUrl, confidence, description }, … ]
//   }
//
// Sequential (not parallel) to avoid Render free-tier OOM on large crops.
//
async function runThreeScenarios({ imageUrl, patientId }) {
  const publicImageUrl = imageUrl
    .replace('/storage/v1/object/sign/', '/storage/v1/object/public/')
    .split('?')[0];

  console.log('[SIM SCENARIOS] Starting 3-scenario pipeline for patient:', patientId);

  // ── 1. Shared crop + mask for the analysis step ──────────────────────────
  let analysis = null;
  try {
    const res = await fetch(publicImageUrl, { signal: AbortSignal.timeout(25_000) });
    if (res.ok) {
      const origBuf = Buffer.from(await res.arrayBuffer());
      const meta    = await sharp(origBuf).metadata();
      const origW   = meta.width, origH = meta.height;

      const { cropLeft, cropTop, cropWidth, cropHeight } = enforceMouthOnlyCrop(origW, origH);

      const origCropBuf = await sharp(origBuf)
        .extract({ left: cropLeft, top: cropTop, width: cropWidth, height: cropHeight })
        .jpeg({ quality: 95 }).toBuffer();

      const maskBuf = await buildTeethMask(origCropBuf, cropWidth, cropHeight);
      analysis = await analyzeTeethCondition(origCropBuf, maskBuf, cropWidth, cropHeight);
      console.log('[SIM SCENARIOS] Analysis:', JSON.stringify(analysis?.stats));
    }
  } catch (e) {
    console.warn('[SIM SCENARIOS] Analysis step failed (non-fatal):', e?.message);
  }

  // ── 2. Run three scenarios sequentially ──────────────────────────────────
  const SCENARIO_PLAN = [
    { key: 'basic',    type: 'basic',    label: SIM_MODES.basic.label   },
    { key: 'premium',  type: 'improved', label: SIM_MODES.premium.label },
    { key: 'perfect',  type: 'perfect',  label: SIM_MODES.perfect.label },
  ];

  const scenarios = [];
  for (const { key, type, label } of SCENARIO_PLAN) {
    console.log(`[SIM SCENARIOS] Running scenario: ${type} (mode=${key})`);
    let r;
    try {
      r = await cropCompositeSimulation(publicImageUrl, patientId, key);
    } catch (e) {
      r = { url: null, failReason: e?.message };
    }
    scenarios.push({
      type,
      label,
      imageUrl:    r.url    ?? null,
      confidence:  r.confidence ?? null,
      lowerArchWeak: r.lowerArchWeak ?? false,
      description: buildScenarioDescription(type, analysis, r),
      status:      r.url ? (r.status ?? 'success') : 'failed',
      level:       r.level ?? (r.url ? 'strict' : 'fail'),
      failed:      !r.url,
      failReason:  r.failReason ?? null,
    });
    console.log(`[SIM SCENARIOS] ${type}: ${r.url ? '✅' : '❌'} conf=${r.confidence ?? '-'}`);
  }

  return { analysis, scenarios };
}

async function runSmileSimulation({ imageUrl, patientId, mode = 'full', preset = 'natural' }) {
  const publicImageUrl = imageUrl
    .replace('/storage/v1/object/sign/', '/storage/v1/object/public/')
    .split('?')[0];

  console.log('USING PRESET:', preset);
  const colorPreset = resolveSmileColorPreset(preset);

  console.log(`[SIM] mode=${mode} | preset=${colorPreset} | patientId:`, patientId);
  console.log('[SIM] Public URL:', publicImageUrl.slice(0, 120));

  const r = await cropCompositeSimulation(publicImageUrl, patientId, mode, colorPreset);

  if (!r.url) {
    console.log('❌ Simulation failed | reason:', r.failReason);
    logAI('warn', 'sim_failed', { patientId, reason: r.failReason });
    const isInvalidPhoto = r.errorCode === 'invalid_photo' || r.failReason === 'invalid_photo';
    return {
      success: false,
      variations: [],
      url: null,
      simulatedImageUrl: null,
      provider: null,
      error: isInvalidPhoto ? 'invalid_photo' : 'simulation_failed',
      errorCode: r.errorCode || (isInvalidPhoto ? 'invalid_photo' : 'simulation_failed'),
      message: r.message || null,
      messageTr: r.messageTr || null,
      failReason: r.failReason,
      fallback: false,
      level: 'fail',
      status: 'failed',
      debugInfo: [r.failReason],
      photoGuidanceBothRowsTr: SIMULATION_UI_COPY.photoGuidanceBothRowsTr,
      colorPreset,
    };
  }

  const label = resolveSimMode(mode).label;
  const simStatus = r.status ?? 'success';
  const simLevel  = r.level  ?? 'strict';
  console.log(`[SIM] Done ✅ | mode=${r.mode} | level=${simLevel} | confidence=${r.confidence}`);
  logAI('info', 'sim_done', { patientId, mode: r.mode, level: simLevel, confidence: r.confidence });
  return {
    success: true,
    variations:     [{ id: mode, label, url: r.url, level: simLevel }],
    url:            r.url,
    simulatedImageUrl: r.url,
    mode:           r.mode,
    confidence:     r.confidence,
    lowerArchWeak:  r.lowerArchWeak ?? false,
    avgPixelChange: r.avgPixelChange,
    stainWarning:     r.stainWarning     ?? false,
    structureWarning: r.structureWarning ?? false,
    provider:         'programmatic',
    error:          null,
    fallback:       simStatus === 'fallback',
    level:          simLevel,
    status:         simStatus,
    debugInfo:      [],
    ...SIMULATION_UI_COPY,
    photoGuidanceBothRowsTr: SIMULATION_UI_COPY.photoGuidanceBothRowsTr,
    colorPreset:    r.colorPreset ?? colorPreset,
  };
}

// ── In-memory store for async smile-simulation jobs ─────────────────────────
// Keyed by jobId (UUID). Cleaned up after 15 minutes so Render memory stays
// small even without restarts.
const _simJobs = new Map(); // jobId → { status, url, variations, failReason, createdAt }
setInterval(() => {
  const cutoff = Date.now() - 15 * 60 * 1000;
  for (const [id, job] of _simJobs) {
    if (job.createdAt < cutoff) _simJobs.delete(id);
  }
}, 5 * 60 * 1000);

// POST /api/chat/smile-simulation
// Returns { ok, jobId, status:"pending" } immediately (no long-held connection).
// Client polls GET /api/chat/sim-status/:jobId for the result.
app.post('/api/chat/smile-simulation', requireToken, async (req, res) => {
  console.log('🎯 SIM ENDPOINT v7 HIT | ASYNC JOB | returning jobId immediately');
  const body = req.body || {};
  const { patientId, imageUrl, mode = 'full' } = body;
  const preset = body.preset || 'natural';
  console.log('USING PRESET:', preset);
  const simMode = SIM_MODES[mode] ? mode : 'full';
  const colorPreset = resolveSmileColorPreset(preset);
  console.log('[SIM] patientId:', patientId, '| mode:', simMode, '| preset:', colorPreset, '| imageUrl:', imageUrl?.slice(0, 120));
  if (!patientId) return res.status(400).json({ ok: false, error: 'patientId_required' });
  if (req.patientId !== patientId) return res.status(403).json({ ok: false, error: 'unauthorized' });
  if (!imageUrl)   return res.status(400).json({ ok: false, error: 'imageUrl_required' });
  if (!ENABLE_SMILE_SIMULATION) return res.status(503).json({ ok: false, error: 'simulation_disabled' });

  const jobId = crypto.randomUUID();
  _simJobs.set(jobId, {
    status: 'pending',
    url: null,
    variations: [],
    failReason: null,
    mode: simMode,
    preset: colorPreset,
    createdAt: Date.now(),
  });

  // Fire-and-forget — do NOT await this
  runSmileSimulation({ imageUrl, patientId, mode: simMode, preset: colorPreset }).then(result => {
    const existing = _simJobs.get(jobId) ?? {};
    const okUrl = result.url || result.simulatedImageUrl;
    _simJobs.set(jobId, {
      ...existing,
      success:        !!okUrl,
      status:         okUrl ? 'succeeded' : 'failed',
      url:            okUrl ?? null,
      variations:     result.variations ?? [],
      mode:           result.mode ?? simMode,
      confidence:     result.confidence ?? null,
      lowerArchWeak:  result.lowerArchWeak ?? false,
      avgPixelChange: result.avgPixelChange ?? null,
      stainWarning:     result.stainWarning     ?? false,
      structureWarning: result.structureWarning ?? false,
      failReason:       result.failReason ?? result.error ?? null,
      error:            okUrl ? null : (result.error || 'simulation_failed'),
      errorCode:        result.errorCode ?? null,
      message:          result.message ?? null,
      messageTr:        result.messageTr ?? null,
      level:            result.level    ?? (okUrl ? 'strict' : 'fail'),
      simStatus:        result.status   ?? (okUrl ? 'success' : 'failed'),
      fallback:         result.fallback ?? false,
      confidenceLabelTr: result.confidenceLabelTr ?? SIMULATION_UI_COPY.confidenceLabelTr,
      photoGuidanceTr:   result.photoGuidanceTr ?? SIMULATION_UI_COPY.photoGuidanceTr,
      photoGuidanceBothRowsTr: result.photoGuidanceBothRowsTr ?? SIMULATION_UI_COPY.photoGuidanceBothRowsTr,
      preset:                  result.colorPreset ?? colorPreset,
      colorPreset:             result.colorPreset ?? colorPreset,
    });
    console.log(`[SIM JOB ${jobId.slice(0,8)}] ${okUrl ? 'succeeded ✅' : 'failed ❌'} level=${result.level ?? '-'} | failReason: ${result.error ?? '-'}`);
  }).catch(err => {
    const existing = _simJobs.get(jobId) ?? {};
    _simJobs.set(jobId, {
      ...existing,
      status: 'failed',
      success: false,
      error: 'simulation_failed',
      failReason: err?.message,
    });
    console.error(`[SIM JOB ${jobId.slice(0,8)}] exception:`, err?.message);
  });

  // Respond immediately — client will poll /api/chat/sim-status/:jobId
  return res.json({
    ok: true,
    jobId,
    status: 'pending',
    preset: colorPreset,
    colorPreset,
    availablePresets: SMILE_COLOR_PRESET_KEYS,
  });
});

// GET /api/chat/sim-status/:jobId
// Returns { ok, status:"pending"|"succeeded"|"failed", simulatedImageUrl?, variations?, error? }
// For scenario jobs also returns: analysis, scenarios[]
app.get('/api/chat/sim-status/:jobId', requireToken, (req, res) => {
  const job = _simJobs.get(req.params.jobId);
  if (!job) return res.status(404).json({ ok: false, error: 'job_not_found' });

  if (job.status === 'pending') {
    return res.json({
      ok: true,
      status: 'pending',
      availablePresets: SMILE_COLOR_PRESET_KEYS,
      ...SIMULATION_UI_COPY,
    });
  }
  if (job.status === 'succeeded' && job.url) {
    return res.json({
      ok:                true,
      success:           true,
      status:            'succeeded',
      simulatedImageUrl: job.url,
      simulationProvider:'programmatic',
      variations:        job.variations ?? [],
      mode:              job.mode ?? 'natural',
      preset:            job.preset ?? job.colorPreset ?? 'natural',
      colorPreset:       job.colorPreset ?? job.preset ?? 'natural',
      availablePresets:  SMILE_COLOR_PRESET_KEYS,
      confidence:        job.confidence ?? null,
      lowerArchWeak:     job.lowerArchWeak ?? false,
      avgPixelChange:    job.avgPixelChange ?? null,
      stainWarning:      job.stainWarning      ?? false,
      structureWarning:  job.structureWarning  ?? false,
      fallback:          job.fallback     ?? false,
      level:             job.level       ?? 'strict',
      simStatus:         job.simStatus   ?? 'success',
      confidenceLabelTr: job.confidenceLabelTr ?? SIMULATION_UI_COPY.confidenceLabelTr,
      photoGuidanceTr:   job.photoGuidanceTr ?? SIMULATION_UI_COPY.photoGuidanceTr,
      photoGuidanceBothRowsTr: job.photoGuidanceBothRowsTr ?? SIMULATION_UI_COPY.photoGuidanceBothRowsTr,
      scenarios:         job.scenarios  ?? null,
      analysis:          job.analysis   ?? null,
    });
  }
  return res.json({
    ok: false,
    success: false,
    status: 'failed',
    error: job.error || job.errorCode || 'simulation_failed',
    errorCode: job.errorCode || job.error || 'simulation_failed',
    simulatedImageUrl: null,
    message: job.message || job.failReason || job.error || 'simulation_failed',
    messageTr: job.messageTr ?? null,
    failReason: job.failReason ?? null,
    ...SIMULATION_UI_COPY,
    photoGuidanceBothRowsTr: job.photoGuidanceBothRowsTr ?? SIMULATION_UI_COPY.photoGuidanceBothRowsTr,
  });
});

// ── POST /api/chat/smile-scenarios ───────────────────────────────────────────
// Generates three treatment-based smile simulations (basic / improved / perfect)
// plus a structured dental-issues analysis.  Returns jobId immediately; client
// polls GET /api/chat/sim-status/:jobId for the result.
//
// Request:  { patientId, imageUrl }
// Response: { ok, jobId, status:"pending" }
//
// Completed job (sim-status): {
//   status:    "succeeded",
//   scenarios: [ { type, label, imageUrl, confidence, description }, … ],
//   analysis:  { problems[], treatments[], priority[], stats{} }
// }
app.post('/api/chat/smile-scenarios', requireToken, async (req, res) => {
  console.log('🎯 SCENARIOS ENDPOINT HIT | async job');
  const { patientId, imageUrl } = req.body || {};

  if (!patientId)  return res.status(400).json({ ok: false, error: 'patientId_required' });
  if (req.patientId !== patientId) return res.status(403).json({ ok: false, error: 'unauthorized' });
  if (!imageUrl)   return res.status(400).json({ ok: false, error: 'imageUrl_required' });
  if (!ENABLE_SMILE_SIMULATION) return res.status(503).json({ ok: false, error: 'simulation_disabled' });

  const jobId = crypto.randomUUID();
  _simJobs.set(jobId, {
    status: 'pending', type: 'scenarios',
    url: null, variations: [], scenarios: null, analysis: null,
    failReason: null, createdAt: Date.now(),
  });

  // Fire-and-forget
  runThreeScenarios({ imageUrl, patientId }).then(({ scenarios, analysis }) => {
    const succeededScenarios = scenarios.filter(s => s.imageUrl);
    _simJobs.set(jobId, {
      ..._simJobs.get(jobId),
      status:     succeededScenarios.length > 0 ? 'succeeded' : 'failed',
      // Primary url = "perfect" scenario for backward compat fields
      url:        scenarios.find(s => s.type === 'perfect')?.imageUrl ?? succeededScenarios[0]?.imageUrl ?? null,
      variations: scenarios.map(s => ({ id: s.type, label: s.label, url: s.imageUrl })),
      scenarios,
      analysis,
      confidence: scenarios.find(s => s.type === 'perfect')?.confidence ?? null,
      failReason: succeededScenarios.length === 0 ? 'all_scenarios_failed' : null,
    });
    console.log(`[SIM SCENARIOS JOB ${jobId.slice(0,8)}] done — ${succeededScenarios.length}/3 succeeded`);
  }).catch(err => {
    _simJobs.set(jobId, { ..._simJobs.get(jobId), status: 'failed', failReason: err?.message });
    console.error(`[SIM SCENARIOS JOB ${jobId.slice(0,8)}] exception:`, err?.message);
  });

  return res.json({ ok: true, jobId, status: 'pending' });
});

// POST /api/chat/ai-upload
// Lightweight upload for AI analysis — no clinic_id required, no messages DB write.
// Stores the photo in Supabase Storage and returns a long-lived signed URL that
// the ai-analyze endpoint can fetch.
app.post('/api/chat/ai-upload', requireToken, chatUpload.single('file'), async (req, res) => {
  try {
    const patientId = String(req.patientId || '').trim();
    if (!patientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const file = req.file;
    if (!file) return res.status(400).json({ ok: false, error: 'no_file', message: 'No file received' });

    const mime = String(file.mimetype || 'image/jpeg').toLowerCase();
    const size = Number(file.size || 0);

    const allowedMimes = new Set(['image/jpeg', 'image/jpg', 'image/png', 'image/heic', 'image/heif']);
    if (!allowedMimes.has(mime)) {
      return res.status(400).json({ ok: false, error: 'invalid_file_type', message: 'Only JPEG/PNG/HEIC accepted' });
    }

    const MAX_BYTES = 5 * 1024 * 1024;
    if (size > MAX_BYTES) {
      return res.status(400).json({ ok: false, error: 'image_too_large', message: 'Image must be under 5MB' });
    }

    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: 'supabase_required', message: 'AI upload requires Supabase storage' });
    }

    const fileName = `${Date.now()}-${crypto.randomBytes(5).toString('hex')}.jpg`;
    const storagePath = `ai-photos/${patientId}/${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from('patient-files')
      .upload(storagePath, file.buffer, { contentType: 'image/jpeg', upsert: false });

    if (uploadError) {
      console.error('[AI UPLOAD] Storage upload failed:', uploadError.message);
      return res.status(500).json({ ok: false, error: 'upload_failed', message: uploadError.message });
    }

    // 1-year signed URL — the ai-analyze endpoint has retry logic for expiry
    const { data: signed, error: signErr } = await supabase.storage
      .from('patient-files')
      .createSignedUrl(storagePath, 365 * 24 * 3600);

    if (signErr || !signed?.signedUrl) {
      console.error('[AI UPLOAD] Signed URL creation failed:', signErr?.message);
      return res.status(500).json({ ok: false, error: 'sign_failed', message: signErr?.message });
    }

    console.log('[AI UPLOAD] OK:', { patientId, storagePath, sizeKB: Math.round(size / 1024) });
    return res.json({ ok: true, url: signed.signedUrl, path: storagePath });

  } catch (err) {
    console.error('[AI UPLOAD] Exception:', err?.message, err?.stack);
    return res.status(500).json({ ok: false, error: 'upload_exception', message: err?.message });
  }
});

// POST /api/chat/replicate-teeth-strip
// Single Replicate img2img on one image URL (upper or lower mouth strip from client split flow).
// Body: { patientId, imageUrl, arch?: 'upper' | 'lower' } — lower strip gets slightly higher strength + alignment suffix.
// → { ok, url, output: [url] }
app.post('/api/chat/replicate-teeth-strip', requireToken, async (req, res) => {
  try {
    if (!ENABLE_SMILE_SIMULATION) {
      return res.status(503).json({ ok: false, error: 'simulation_disabled' });
    }
    const { patientId, imageUrl, arch } = req.body || {};
    if (!patientId) return res.status(400).json({ ok: false, error: 'patientId_required' });
    if (req.patientId !== patientId) return res.status(403).json({ ok: false, error: 'unauthorized' });
    if (!imageUrl) return res.status(400).json({ ok: false, error: 'imageUrl_required' });
    if (!process.env.REPLICATE_API_TOKEN || !process.env.REPLICATE_IMG2IMG_VERSION) {
      return res.status(503).json({ ok: false, error: 'replicate_not_configured' });
    }
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: 'supabase_required' });
    }

    const publicUrl = String(imageUrl)
      .replace('/storage/v1/object/sign/', '/storage/v1/object/public/')
      .split('?')[0];

    const imgRes = await fetch(publicUrl, { signal: AbortSignal.timeout(25_000) });
    if (!imgRes.ok) {
      return res.status(502).json({ ok: false, error: 'image_fetch_failed', status: imgRes.status });
    }
    const buf = Buffer.from(await imgRes.arrayBuffer());
    const meta = await sharp(buf).metadata();
    const w = meta.width || 0;
    const h = meta.height || 0;
    if (!w || !h) {
      return res.status(400).json({ ok: false, error: 'invalid_image' });
    }
    const jpegBuf = await sharp(buf).jpeg({ quality: 95 }).toBuffer();

    const stripOpts = {};
    const archNorm = String(arch || '').toLowerCase();
    if (archNorm === 'lower') {
      const delta = (() => {
        const v = parseFloat(String(process.env.SIM_STRIP_LOWER_STRENGTH_DELTA || '0.045'), 10);
        return Number.isFinite(v) ? Math.min(0.12, Math.max(0, v)) : 0.045;
      })();
      const envStr = Number(process.env.REPLICATE_PROMPT_STRENGTH);
      const baseStrength = Number.isFinite(envStr) ? envStr : REPLICATE_PROMPT_STRENGTH_DEFAULT;
      stripOpts.strengthOverride = Math.min(0.98, Math.max(0.35, baseStrength + delta));
      stripOpts.promptSuffix =
        ' Prioritize subtle orthodontic alignment and leveling on these lower teeth — slightly stronger alignment correction than the upper arch. ' +
        'Match lower-teeth brightness to surrounding inner mouth and oral mucosa — they must not look brighter than gums or cheek; slightly darken lower teeth (~3–4%) vs over-bright AI output. ' +
        'Add subtle shadow and depth to lower teeth to match upper-teeth realism; slight interdental shadow and natural contrast; avoid flat lighting. ' +
        'Add subtle shadow between lower teeth and inner mouth for realistic depth and separation; soft shadow under upper teeth at gum line; depth between tooth layers. ' +
        'Lower arch: softer, less sharp detail than harsh digital overlay; natural diffuse lighting.';
    }

    const outBuf = await replicateTeethImg2ImgOptional(jpegBuf, w, h, stripOpts);
    if (!outBuf) {
      return res.status(502).json({ ok: false, error: 'replicate_failed' });
    }

    const fileName = `strip-${Date.now()}-${crypto.randomBytes(4).toString('hex')}.jpg`;
    const storagePath = `ai-photos/${patientId}/${fileName}`;
    const { error: upErr } = await supabase.storage
      .from('patient-files')
      .upload(storagePath, outBuf, { contentType: 'image/jpeg', upsert: false });
    if (upErr) {
      return res.status(500).json({ ok: false, error: 'upload_failed', message: upErr.message });
    }
    const { data: signed, error: signErr } = await supabase.storage
      .from('patient-files')
      .createSignedUrl(storagePath, 365 * 24 * 3600);
    if (signErr || !signed?.signedUrl) {
      return res.status(500).json({ ok: false, error: 'sign_failed' });
    }
    const url = signed.signedUrl;
    return res.json({ ok: true, url, output: [url] });
  } catch (e) {
    console.error('[TEETH STRIP]', e?.message);
    return res.status(500).json({ ok: false, error: 'strip_exception', message: e?.message });
  }
});

/**
 * Lower strip only before merge: slight darken (2–5%) + micro blur to reduce oversharpened AI look.
 * Does not affect full image. SIM_MERGE_LOWER_LIGHTING=0 to skip.
 */
async function applyLowerStripRealismAdjust(rgbBuffer) {
  if (String(process.env.SIM_MERGE_LOWER_LIGHTING ?? '1').trim() === '0') {
    return rgbBuffer;
  }
  const mult = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_LOWER_BRIGHTNESS_MULT ?? '0.96'), 10);
    return Number.isFinite(v) ? Math.min(0.98, Math.max(0.95, v)) : 0.96;
  })();
  const blurSigma = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_LOWER_SOFTEN_SIGMA ?? '0.45'), 10);
    return Number.isFinite(v) ? Math.min(1.2, Math.max(0, v)) : 0.45;
  })();
  let pipeline = sharp(rgbBuffer).removeAlpha();
  if (blurSigma > 0.01) {
    pipeline = pipeline.blur(blurSigma);
  }
  return pipeline.linear(mult, 0).jpeg({ quality: 95 }).toBuffer();
}

/**
 * Seamless mouth integration: blend hard composite with original using a blurred mouth mask (sharp center, soft edges only).
 * No full-image blur. SIM_MERGE_EDGE_FEATHER_SIGMA (default 12) clamped to SIM_MERGE_EDGE_FEATHER_MIN/MAX (defaults 4–32).
 * NOTE: Previously sigma was hard-capped at 14 — env values like 30 were silently truncated (no visible change).
 */
async function featherBlendMouthComposite(origBuf, compositedBuf, ox, oy, mw, mh) {
  const minFeather = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_EDGE_FEATHER_MIN ?? '4'), 10);
    return Number.isFinite(v) ? Math.min(12, Math.max(1, v)) : 4;
  })();
  const maxFeather = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_EDGE_FEATHER_MAX ?? '32'), 10);
    return Number.isFinite(v) ? Math.min(64, Math.max(minFeather, v)) : 32;
  })();
  const requestedSigma = parseFloat(String(process.env.SIM_MERGE_EDGE_FEATHER_SIGMA ?? '12'), 10);
  const edgeSigma = Number.isFinite(requestedSigma)
    ? Math.min(maxFeather, Math.max(minFeather, requestedSigma))
    : Math.min(maxFeather, Math.max(minFeather, 12));
  console.log('MERGE FUNCTION RUNNING');
  console.log(
    '[MERGE TEETH] feather params: requestedSIGMA=',
    process.env.SIM_MERGE_EDGE_FEATHER_SIGMA,
    'effectiveSIGMA=',
    edgeSigma,
    'MIN=',
    minFeather,
    'MAX=',
    maxFeather
  );
  const lowerAlphaBoost = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_LOWER_ALPHA_BOOST ?? '1'), 10);
    return Number.isFinite(v) ? Math.min(1.15, Math.max(1, v)) : 1;
  })();

  const { data: o, info } = await sharp(origBuf).removeAlpha().raw().toBuffer({ resolveWithObject: true });
  const w = info.width;
  const h = info.height;
  const c = await sharp(compositedBuf).resize(w, h).removeAlpha().raw().toBuffer();
  const ox0 = Math.round(ox);
  const oy0 = Math.round(oy);
  const mw0 = Math.round(mw);
  const mh0 = Math.round(mh);
  const midY = oy0 + Math.floor(mh0 / 2);
  const mouthBottom = oy0 + mh0;
  const rx = Math.min(14, Math.max(4, Math.floor(mw0 * 0.06)));

  const svg = `<svg width="${w}" height="${h}"><rect x="${ox0}" y="${oy0}" width="${mw0}" height="${mh0}" fill="white" rx="${rx}"/></svg>`;
  const maskRaw = await sharp(Buffer.from(svg))
    .resize(w, h)
    .blur(edgeSigma)
    .greyscale()
    .raw()
    .toBuffer();

  const out = Buffer.alloc(w * h * 3);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      let a = maskRaw[i] / 255;
      if (y >= midY && y < mouthBottom && x >= ox0 && x < ox0 + mw0) {
        a = Math.min(1, a * lowerAlphaBoost);
      }
      const oi = i * 3;
      out[oi] = Math.round(o[oi] * (1 - a) + c[oi] * a);
      out[oi + 1] = Math.round(o[oi + 1] * (1 - a) + c[oi + 1] * a);
      out[oi + 2] = Math.round(o[oi + 2] * (1 - a) + c[oi + 2] * a);
    }
  }
  return sharp(out, { raw: { width: w, height: h, channels: 3 } }).jpeg({ quality: 92 }).toBuffer();
}

/** Very light post: +contrast / −saturation to reduce “AI overlay” look. SIM_MERGE_MICRO_* to tune. */
async function applyMergeMicroPostProcess(jpegBuf) {
  const sat = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_MICRO_SAT ?? '0.98'), 10);
    return Number.isFinite(v) ? Math.min(1.05, Math.max(0.92, v)) : 0.98;
  })();
  const contrastMult = (() => {
    const v = parseFloat(String(process.env.SIM_MERGE_MICRO_CONTRAST ?? '1.02'), 10);
    return Number.isFinite(v) ? Math.min(1.1, Math.max(0.98, v)) : 1.02;
  })();
  const b = 128 * (1 - contrastMult);
  if (String(process.env.SIM_MERGE_MICRO_POST ?? '1').trim() === '0') {
    console.log('[MERGE TEETH] micro post: SKIPPED (SIM_MERGE_MICRO_POST=0)');
    return jpegBuf;
  }
  console.log('[MERGE TEETH] micro post: APPLIED sat=', sat, 'contrast=', contrastMult);
  return sharp(jpegBuf)
    .modulate({ saturation: sat })
    .linear(contrastMult, b)
    .jpeg({ quality: 92 })
    .toBuffer();
}

// POST /api/chat/merge-teeth-strips
// Strip pipeline only: client split → replicate-teeth-strip (×2) → THIS endpoint.
// NOT used by POST /api/chat/smile-simulation (that uses cropCompositeSimulation + blendCropWithMask).
// If SIM_MERGE_* env changes show no effect, confirm the app calls this route (see mergeTeeth.ts), not smile-simulation alone.
//
// Pipeline debug (server env): SIM_MERGE_DEBUG=original | black | (unset)
//   original — upload unmodified original only (proves this handler ran; no AI teeth in output)
//   black      — solid black JPEG same size as original (proves merge output is what client displays)
//   Also: SIM_MERGE_DEBUG_RETURN_ORIGINAL=1  /  SIM_MERGE_DEBUG_BLACK=1
app.post('/api/chat/merge-teeth-strips', requireToken, async (req, res) => {
  try {
    console.log('MERGE STARTED');
    console.log('SIGMA:', process.env.SIM_MERGE_EDGE_FEATHER_SIGMA);
    console.log('MICRO_POST:', process.env.SIM_MERGE_MICRO_POST);
    console.log(
      '[MERGE TEETH] strip-merge endpoint — SIM_MERGE_* env vars apply here (not /api/chat/smile-simulation)'
    );
    const { patientId, originalImageUrl, upperImageUrl, lowerImageUrl, mouth } = req.body || {};
    if (!patientId) return res.status(400).json({ ok: false, error: 'patientId_required' });
    if (req.patientId !== patientId) return res.status(403).json({ ok: false, error: 'unauthorized' });
    if (!originalImageUrl || !upperImageUrl || !lowerImageUrl || !mouth) {
      return res.status(400).json({ ok: false, error: 'missing_fields' });
    }
    const ox = Number(mouth.originX);
    const oy = Number(mouth.originY);
    const mw = Number(mouth.width);
    const mh = Number(mouth.height);
    if (![ox, oy, mw, mh].every((n) => Number.isFinite(n)) || mw < 1 || mh < 1) {
      return res.status(400).json({ ok: false, error: 'invalid_mouth' });
    }
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: 'supabase_required' });
    }

    const toPublic = (u) =>
      String(u)
        .replace('/storage/v1/object/sign/', '/storage/v1/object/public/')
        .split('?')[0];

    const [r0, r1, r2] = await Promise.all([
      fetch(toPublic(originalImageUrl), { signal: AbortSignal.timeout(25_000) }),
      fetch(toPublic(upperImageUrl), { signal: AbortSignal.timeout(25_000) }),
      fetch(toPublic(lowerImageUrl), { signal: AbortSignal.timeout(25_000) }),
    ]);
    if (!r0.ok || !r1.ok || !r2.ok) {
      return res.status(502).json({ ok: false, error: 'image_fetch_failed' });
    }
    const origBuf = Buffer.from(await r0.arrayBuffer());
    const upBuf = Buffer.from(await r1.arrayBuffer());
    const loBuf = Buffer.from(await r2.arrayBuffer());

    console.log('MERGE FUNCTION ACTIVE');

    const mergeDbg = String(process.env.SIM_MERGE_DEBUG || '').trim().toLowerCase();
    const debugOriginal =
      mergeDbg === 'original' || String(process.env.SIM_MERGE_DEBUG_RETURN_ORIGINAL || '').trim() === '1';
    const debugBlack =
      mergeDbg === 'black' || String(process.env.SIM_MERGE_DEBUG_BLACK || '').trim() === '1';

    let composited;
    if (debugOriginal) {
      console.log('[MERGE TEETH] DEBUG MODE: returning ORIGINAL image only (no composite). Clear SIM_MERGE_DEBUG when done.');
      composited = await sharp(origBuf).jpeg({ quality: 92 }).toBuffer();
    } else if (debugBlack) {
      console.log('[MERGE TEETH] DEBUG MODE: returning BLACK image. Clear SIM_MERGE_DEBUG when done.');
      const dm = await sharp(origBuf).metadata();
      const bw = dm.width || 1;
      const bh = dm.height || 1;
      composited = await sharp({
        create: { width: bw, height: bh, channels: 3, background: { r: 0, g: 0, b: 0 } },
      })
        .jpeg({ quality: 92 })
        .toBuffer();
    } else {
      const upperH = Math.max(1, Math.floor(mh / 2));
      const lowerH = Math.max(1, mh - upperH);

      const upResized = await sharp(upBuf).resize(Math.round(mw), upperH).removeAlpha().toBuffer();
      const loResizedRgb = await sharp(loBuf).resize(Math.round(mw), lowerH).removeAlpha().toBuffer();
      let loAdjusted = loResizedRgb;
      try {
        loAdjusted = await applyLowerStripRealismAdjust(loResizedRgb);
      } catch (le) {
        console.warn('[MERGE TEETH] lower strip realism adjust skipped:', le?.message);
      }
      const lowerTeethOpacity = (() => {
        const v = parseFloat(String(process.env.SIM_MERGE_LOWER_TEETH_OPACITY ?? '0.92'), 10);
        return Number.isFinite(v) ? Math.min(1, Math.max(0.65, v)) : 0.92;
      })();
      let loInput = loAdjusted;
      if (lowerTeethOpacity < 0.999) {
        const { data, info } = await sharp(loAdjusted).ensureAlpha().raw().toBuffer({ resolveWithObject: true });
        const lw = info.width;
        const lh = info.height;
        const a = Math.round(lowerTeethOpacity * 255);
        for (let i = 0; i < lw * lh; i++) {
          data[i * 4 + 3] = a;
        }
        loInput = await sharp(data, { raw: { width: lw, height: lh, channels: 4 } })
          .png()
          .toBuffer();
      }

      const lx = Math.round(ox);
      const ty = Math.round(oy);
      const ty2 = Math.round(oy) + upperH;

      const hardComposite = await sharp(origBuf)
        .composite([
          { input: upResized, left: lx, top: ty, blend: 'over' },
          { input: loInput, left: lx, top: ty2, blend: 'over' },
        ])
        .jpeg({ quality: 92 })
        .toBuffer();

      composited = hardComposite;
      try {
        composited = await featherBlendMouthComposite(origBuf, hardComposite, ox, oy, mw, mh);
        console.log('[MERGE TEETH] feather blend completed OK');
      } catch (fe) {
        console.warn('[MERGE TEETH] feather blend FAILED — using hard composite (no feather):', fe?.message);
        composited = hardComposite;
      }

      try {
        composited = await applyMergeMicroPostProcess(composited);
      } catch (pe) {
        console.warn('[MERGE TEETH] micro post skipped:', pe?.message);
      }
    }

    const fileName = `merge-${Date.now()}-${crypto.randomBytes(4).toString('hex')}.jpg`;
    const storagePath = `ai-photos/${patientId}/${fileName}`;
    const { error: upErr } = await supabase.storage
      .from('patient-files')
      .upload(storagePath, composited, { contentType: 'image/jpeg', upsert: false });
    if (upErr) {
      return res.status(500).json({ ok: false, error: 'upload_failed', message: upErr.message });
    }
    const { data: signed, error: signErr } = await supabase.storage
      .from('patient-files')
      .createSignedUrl(storagePath, 365 * 24 * 3600);
    if (signErr || !signed?.signedUrl) {
      return res.status(500).json({ ok: false, error: 'sign_failed' });
    }
    const url = signed.signedUrl;
    return res.json({ ok: true, url, output: [url] });
  } catch (e) {
    console.error('[MERGE TEETH]', e?.message);
    return res.status(500).json({ ok: false, error: 'merge_exception', message: e?.message });
  }
});

const DENTAL_CONDITION_UI_TR = {
  missing_tooth: 'Eksik diş olabilir',
  misalignment: 'Dişlerde çapraşıklık görülüyor',
  diastema: 'Doğal diş aralığı bulunuyor',
};

function formatConditionHeadlineTr(condition, confidence) {
  const base = DENTAL_CONDITION_UI_TR[condition];
  if (!base) return '';
  const confTr = { low: 'Düşük güven', medium: 'Orta güven', high: 'Yüksek güven' };
  const c = confTr[confidence] || '';
  return c ? `${base} (${c})` : base;
}

function dentalConditionToPayload(dc) {
  if (!dc || !dc.condition) return null;
  return {
    condition: dc.condition,
    confidence: dc.confidence,
    labelTr: formatConditionHeadlineTr(dc.condition, dc.confidence),
  };
}

/**
 * MVP + hybrid: insight keywords (missing tooth / gap / space), large-gap heuristic,
 * optional vision flag from JSON (missingTeethLikely). Combined with OR. Not a diagnosis.
 * @param {string} fullText  insights + summary (lowercased caller joins)
 * @param {boolean|null} visionLikely  true / false / null (unclear)
 */
function analyzeMissingToothHybrid(fullText, visionLikely) {
  const t = String(fullText || '').toLowerCase();

  const explicitMissing =
    /\bmissing\s+tooth\b|\bmissing\s+teeth\b|eksik\s*diş|eksik\s*dişler|diş\s*eksikliği/.test(t);
  const gapOrSpace = /\bgap\b|\bspace\b|\bspacing\b|boşluk|aralık/i.test(t);
  const insightStrong =
    /çekilmiş\s*diş|edentulous|boş\s*luk|arada\s*boş|implant\s*alanı\s*yok|konserve\s*eksik|extraction|avuls|tooth\s*loss|teeth\s*lost|gap\s*(?:between|in|teeth)/i.test(
      t
    );
  const insightPath = explicitMissing || gapOrSpace || insightStrong;

  const ruleLargeGap =
    /\b(large|wide|significant)\s+(gap|spacing|space)\b|diastema|geniş\s*boşluk|büyük\s*aralık|wide\s+space/i.test(t);

  const visionPath = visionLikely === true;
  const detected = visionPath || insightPath || ruleLargeGap;

  const multipleHints =
    /çoklu|birden\s*fazla|multiple|several|birkaç|iki\s+diş|üç\s+diş|dört\s+diş|\d+\s*diş.*eksik|eksik.*dişler|çok\s*sayıda|üst\s*ve\s*alt|hem\s*üst|multiple\s*missing/i.test(
      t
    );
  const singleMissing = detected ? !multipleHints : true;

  let score = 0;
  if (visionPath) score += 3;
  if (explicitMissing || insightStrong) score += 3;
  if (ruleLargeGap) score += 3;
  if (gapOrSpace && !explicitMissing && !insightStrong) score += 1;

  let confidence = 'low';
  if (score >= 5) confidence = 'high';
  else if (score >= 3) confidence = 'medium';

  return {
    detected,
    singleMissing,
    confidence,
    sources: {
      insight: insightPath,
      ruleGap: ruleLargeGap,
      vision: visionPath,
    },
  };
}

/**
 * Heuristic treatment + indicative price ranges from AI insight text (not a diagnosis).
 * Feeds patient UX only; clinicians set real quotes.
 * @param {boolean|null} visionLikely  from vision JSON missingTeethLikely
 * @param {{ condition: string, confidence: string } | null} visionDentalCondition  from vision JSON dentalCondition
 */
function buildDentalTreatmentPlan(insights = [], summary = '', visionLikely = null, visionDentalCondition = null) {
  const parts = Array.isArray(insights) ? insights : [];
  const text = [...parts, String(summary || '')].join(' ').toLowerCase();

  const issues = [];
  const treatments = [];
  const priceEstimate = {};
  const seenTreat = new Set();

  const add = (issueTr, treatTr, priceKey, range) => {
    if (issueTr && !issues.includes(issueTr)) issues.push(issueTr);
    if (treatTr && !seenTreat.has(treatTr)) {
      seenTreat.add(treatTr);
      treatments.push(treatTr);
    }
    if (priceKey && range && priceEstimate[priceKey] === undefined) {
      priceEstimate[priceKey] = range;
    }
  };

  const miss = analyzeMissingToothHybrid(text, visionLikely);
  const ruleDc = inferDentalConditionFromRules(text);
  let dc = mergeDentalCondition(ruleDc, visionDentalCondition);
  if (!dc && miss.detected) {
    dc = { condition: 'missing_tooth', confidence: miss.confidence };
  }

  const dentalCondition = dentalConditionToPayload(dc);

  let missingTooth = null;
  if (dc && dc.condition === 'missing_tooth') {
    const headline = formatConditionHeadlineTr('missing_tooth', dc.confidence);
    if (!issues.some((line) => String(line).startsWith('Eksik diş olabilir'))) issues.unshift(headline);
    priceEstimate.implant = '500-1500$';
    priceEstimate.bridge = '300-1000$';
    if (miss.singleMissing) {
      if (!seenTreat.has('İmplant')) {
        seenTreat.add('İmplant');
        treatments.push('İmplant');
      }
      if (!seenTreat.has('Köprü (bridge)')) {
        seenTreat.add('Köprü (bridge)');
        treatments.push('Köprü (bridge)');
      }
      missingTooth = {
        headline,
        confidence: dc.confidence,
        sources: miss.sources,
        singleMissing: true,
        options: [
          {
            title: 'İmplant',
            explanation: 'Komşu dişlere zarar vermeden uygulanır',
            price: '500-1500$',
          },
          {
            title: 'Köprü (bridge)',
            explanation: 'Komşu dişler destek olarak kullanılır',
            price: '300-1000$',
          },
        ],
        disclaimer: 'Kesin tedavi planı için klinik muayenesi gereklidir',
      };
    } else {
      if (!seenTreat.has('İmplant üstü protez')) {
        seenTreat.add('İmplant üstü protez');
        treatments.push('İmplant üstü protez');
      }
      if (!seenTreat.has('Köprü (bridge)')) {
        seenTreat.add('Köprü (bridge)');
        treatments.push('Köprü (bridge)');
      }
      missingTooth = {
        headline,
        confidence: dc.confidence,
        sources: miss.sources,
        singleMissing: false,
        options: [
          {
            title: 'İmplant üstü protez',
            explanation: 'İmplantlarla desteklenen sabit protez; komşu dişlere zarar vermeden planlanabilir',
            price: '500-1500$',
          },
          {
            title: 'Köprü (bridge)',
            explanation: 'Komşu dişler destek olarak kullanılır',
            price: '300-1000$',
          },
        ],
        disclaimer: 'Kesin tedavi planı için klinik muayenesi gereklidir',
      };
    }
  } else if (dc && dc.condition === 'misalignment') {
    const headline = formatConditionHeadlineTr('misalignment', dc.confidence);
    if (!issues.some((line) => String(line).includes('çapraşık'))) issues.unshift(headline);
  } else if (dc && dc.condition === 'diastema') {
    const headline = formatConditionHeadlineTr('diastema', dc.confidence);
    if (!issues.some((line) => String(line).includes('Doğal diş aralığı'))) issues.unshift(headline);
  }

  if (/sarı|discolor|renk|yellow|stain|lek|beyazlat|whiten|renk tonu|color|surface stain/i.test(text)) {
    add(
      'Diş yüzeyinde renk / leke farkı',
      'Diş beyazlatma (ofis veya ev tipi)',
      'whitening',
      '150-400$'
    );
  }
  if (/tartar|plak|calculus|temizlik|cleaning|scaling|polish|birikim|taş/i.test(text)) {
    add(
      'Yüzey birikimi / tartar riski',
      'Profesyonel diş temizliği (scaling & polishing)',
      'cleaning',
      '50-150$'
    );
  }
  if (/çapra|crowding|düzensiz|misalignment|alignment|ortodont|braces|invisalign|şeffaf plak|tel/i.test(text)) {
    add(
      'Hafif dizilim / çapraşıklık',
      'Ortodontik değerlendirme (plak / tel)',
      'orthodontics',
      '1.500-4.000$'
    );
  }
  if (/çürük|cavity|caries|dolgu|filling|mine/i.test(text)) {
    add('Çürük / mine kaybı riski', 'Kompozit dolgu / restorasyon', 'filling', '80-250$');
  }
  if (/veneer|kaplama|porselen|zirkon|laminate|estetik gülüş/i.test(text)) {
    add(
      'Estetik görünüm beklentisi',
      'Lamina / veneer veya zirkonyum planlaması',
      'veneer',
      '2.500-6.000$'
    );
  }
  if (/eti|gingiv|kanama|inflam|periodont|diş eti/i.test(text)) {
    add('Diş eti hassasiyeti / inflamasyon riski', 'Diş eti bakımı ve kontrol', 'gum', '80-200$');
  }
  if (dc?.condition !== 'missing_tooth' && !miss.detected && /implant/i.test(text)) {
    add('Eksik diş alanı (varsa)', 'İmplant değerlendirmesi', 'implant', '800-2.500$');
  }

  if (issues.length === 0) {
    issues.push('Klinik muayenesi ile netleştirilmesi gereken bulgular');
  }
  if (treatments.length === 0) {
    treatments.push('Detaylı ağız içi muayene ve gerekiyorsa röntgen');
    priceEstimate.consultation = 'Ücretsiz–75$';
  }

  return {
    issues: issues.slice(0, 8),
    treatments: treatments.slice(0, 10),
    priceEstimate,
    missingTooth,
    dentalCondition,
  };
}

// POST /api/chat/ai-analyze
// Accepts: { patientId, imageUrl, photoType?, userLocation?, preferredCountry?, userCountry? }
// Feature flags: ENABLE_AI_ANALYSIS, ENABLE_SMILE_SIMULATION
// Timeouts:      AI_TIMEOUT_MS (default 30 000 ms)
// Images are processed in-memory as base64 — no external storage required
app.post('/api/chat/ai-analyze', requireToken, aiRateLimitMiddleware, async (req, res) => {
  const _t0 = Date.now();
  try {
    // ── Feature flag guard ──────────────────────────────────────────────
    if (!ENABLE_AI_ANALYSIS) {
      return res.status(503).json({ ok: false, error: 'ai_disabled', message: 'AI analysis is disabled via ENABLE_AI_ANALYSIS=false' });
    }

    const {
      patientId,
      imageUrl,
      photoType = "general",
      userLocation = null,
      preferredCountry = null,
      userCountry = null,
    } = req.body || {};

    if (!patientId) return res.status(400).json({ ok: false, error: 'patientId_required' });
    if (req.patientId !== patientId) return res.status(403).json({ ok: false, error: 'unauthorized' });
    if (!imageUrl) return res.status(400).json({ ok: false, error: 'imageUrl_required' });

    const OPENAI_KEY = process.env.OPENAI_API_KEY;
    if (!OPENAI_KEY) {
      logAI('warn', 'ai_not_configured', { patientId });
      return res.status(501).json({ ok: false, error: 'ai_not_configured', message: 'OPENAI_API_KEY not set' });
    }

    const bypassAiLimit = shouldBypassAiCostLimit(req);
    if (bypassAiLimit) {
      logAI('info', 'ai_cost_limit_bypassed', {
        patientId,
        reason: String(process.env.AI_DEV_BYPASS_LIMIT || "").trim() === "1" ? "AI_DEV_BYPASS_LIMIT" : "developerMode",
      });
    }

    // ── Cost limit check ────────────────────────────────────────────────
    if (!bypassAiLimit) {
      const { limited, totalCost } = await aiCostCheck(patientId);
      if (limited) {
        logAI('warn', 'ai_cost_limit_reached', { patientId, totalCost, limit: AI_COST_LIMIT_PER_USER });
        return res.status(403).json({
          ok: false,
          error: 'ai_limit_reached',
          message: 'AI kullanım limitine ulaştınız',
          totalCost,
          limit: AI_COST_LIMIT_PER_USER,
        });
      }
    }

    logAI('info', 'analyze_start', { patientId, imageUrl });

    // ── Load image — from remote URL (Supabase) or local disk ───────────
    let imageBuffer;
    let mimeType = 'image/jpeg';

    const isRemoteUrl = imageUrl.startsWith('http://') || imageUrl.startsWith('https://');

    if (isRemoteUrl) {
      /**
       * Attempt to fetch a Supabase signed URL.
       * On 401/403 (expired token) re-sign the file using the service-role key
       * and retry once — all within the 15 s budget.
       *
       * Supabase signed URL format:
       *   https://<project>.supabase.co/storage/v1/object/sign/<bucket>/<path...>?token=...
       */
      async function fetchWithSignedUrlRetry(url, timeoutMs) {
        const ctrl = new AbortController();
        const timer = setTimeout(() => ctrl.abort(), timeoutMs);

        try {
          let fetchUrl = url;

          const tryFetch = async (u) => {
            const r = await fetch(u, { signal: ctrl.signal });
            return r;
          };

          let imgRes = await tryFetch(fetchUrl);

          // Expired / forbidden → attempt re-sign once
          if ((imgRes.status === 401 || imgRes.status === 403) && isSupabaseEnabled()) {
            logAI('info', 'signed_url_expired_retry', { patientId, status: imgRes.status });

            // Parse bucket + object path from the URL
            // Pattern: .../object/sign/<bucket>/<object-path>
            const withoutQuery = url.split('?')[0];
            const signMatch = withoutQuery.match(/\/object\/sign\/([^/]+)\/(.+)$/);

            if (signMatch) {
              const bucket  = signMatch[1];
              const objPath = signMatch[2];
              const { data: signed, error: signErr } =
                await supabase.storage.from(bucket).createSignedUrl(objPath, 120); // 2 min

              if (!signErr && signed?.signedUrl) {
                imgRes = await tryFetch(signed.signedUrl);
                logAI('info', 'signed_url_refreshed', { patientId, newStatus: imgRes.status });
              } else {
                logAI('warn', 'signed_url_refresh_failed', { patientId, signErr: signErr?.message });
              }
            }
          }

          clearTimeout(timer);
          return imgRes;
        } catch (e) {
          clearTimeout(timer);
          throw e;
        }
      }

      try {
        const imgRes = await fetchWithSignedUrlRetry(imageUrl, 15_000);

        if (!imgRes.ok) {
          logAI('warn', 'remote_image_fetch_failed', { patientId, imageUrl, status: imgRes.status });
          return res.status(502).json({ ok: false, error: 'image_fetch_failed', message: 'Görsel indirilemedi.' });
        }

        const contentType = imgRes.headers.get('content-type') || 'image/jpeg';
        mimeType = contentType.split(';')[0].trim() || 'image/jpeg';
        const arrayBuf = await imgRes.arrayBuffer();
        imageBuffer = Buffer.from(arrayBuf);
      } catch (e) {
        logAI('warn', 'remote_image_timeout', { patientId, imageUrl });
        return res.status(504).json({ ok: false, error: 'image_fetch_timeout', message: 'Görsel indirme zaman aşımına uğradı.' });
      }
    } else {
      // Local disk path (legacy / same-server deployments)
      const relPath  = decodeURIComponent(imageUrl.split('?')[0]);
      const diskPath = path.join(__dirname, 'public', ...relPath.replace(/^\//, '').split('/'));

      if (!fs.existsSync(diskPath)) {
        logAI('warn', 'image_not_found', { patientId, diskPath });
        return res.status(404).json({ ok: false, error: 'image_not_found' });
      }

      imageBuffer = fs.readFileSync(diskPath);
      const ext = path.extname(diskPath).toLowerCase();
      mimeType = ext === '.png' ? 'image/png' : ext === '.heic' ? 'image/heic' : 'image/jpeg';
    }

    // ── Max size validation ─────────────────────────────────────────────
    if (imageBuffer.length > IMAGE_MAX_SIZE_BYTES) {
      logAI('warn', 'image_too_large', { patientId, sizeBytes: imageBuffer.length, limitBytes: IMAGE_MAX_SIZE_BYTES });
      imageBuffer = null;
      return res.status(413).json({
        ok: false,
        error: 'image_too_large',
        message: `Image too large. Max allowed size is ${IMAGE_MAX_SIZE_MB}MB. Please retake the photo.`,
      });
    }

    // ── Magic-bytes image validation ────────────────────────────────────
    if (!isValidImageBuffer(imageBuffer)) {
      logAI('warn', 'invalid_image_format', { patientId, imageUrl, firstBytes: imageBuffer.slice(0, 8).toString('hex') });
      imageBuffer = null;
      return res.status(400).json({ ok: false, error: 'invalid_image_format', message: 'Dosya geçerli bir görsel formatında değil.' });
    }

    // ── Convert to base64 data URL, then immediately release the raw buffer ──
    // Holding both raw + base64 simultaneously doubles peak memory; null early.
    const imageDataUrl = `data:${mimeType};base64,${imageBuffer.toString('base64')}`;
    imageBuffer = null; // allow GC to reclaim the raw bytes

    // ── OpenAI Vision — structured dental analysis ────────────────────
    let aiAnalysis;
    try {
      aiAnalysis = await processDentalAI(imageDataUrl, photoType, {
        apiKey:    OPENAI_KEY,
        timeoutMs: AI_TIMEOUT_MS,
      });
    } catch (openaiErr) {
      logAI('error', 'openai_error', {
        patientId,
        status:  openaiErr.status,
        message: openaiErr.message,
        code:    openaiErr.code,
        elapsedMs: Date.now() - _t0,
      });
      return res.status(502).json({ ok: false, error: 'openai_error', message: openaiErr.message || 'OpenAI request failed' });
    }

    const { insights, confidence, summary, recommendation, missingTeethLikely, dentalConditionParsed, _usage, _model } = aiAnalysis;

    logAI('info', 'openai_response', {
      patientId,
      photoType,
      insightCount:      insights.length,
      confidence,
      missingTeethLikely,
      hasSummary:        !!summary,
      hasRecommendation: !!recommendation,
      fallback:          aiAnalysis._fallback,
      qualityScore:      aiAnalysis._qualityScore,
      qualityReasons:    aiAnalysis._qualityReasons,
      model:             _model,
      promptTokens:      _usage?.prompt_tokens,
      completionTokens:  _usage?.completion_tokens,
      elapsedMs: Date.now() - _t0,
    });

    // Smile simulation is now on-demand (POST /api/chat/smile-simulation).
    // The frontend triggers it lazily only for engaged users — not auto-run here.
    const simulatedImageUrl  = null;
    const simulationProvider = null;

    // imageDataUrl no longer needed — release before writing to Supabase
    // (GC hint; avoids keeping a large string alive through async I/O)

    const disclaimer = 'Bu sonuçlar AI tarafından oluşturulmuştur ve tıbbi teşhis değildir.';

    const treatmentPlan = buildDentalTreatmentPlan(
      insights,
      summary,
      missingTeethLikely ?? null,
      dentalConditionParsed ?? null
    );

    const missingToothDetected = Boolean(treatmentPlan.missingTooth);
    const missingToothConfidence = treatmentPlan.missingTooth?.confidence ?? null;

    // ── Clinic recommendations (non-blocking — runs concurrently with save) ──
    const recommendedClinics = await getRecommendedClinics({
      insights,
      patientId,
      userLocation,
      preferredCountry,
      userCountry,
    });

    // ── Save AI result as CLINIC message ──────────────────────────────
    await insertMessageToSupabase({
      patientId,
      sender: 'clinic',
      message: 'AI Önizleme',
      attachments: {
        aiResult: {
          insights,
          confidence,
          summary,
          recommendation,
          disclaimer,
          originalImageUrl: imageUrl,
          issues: treatmentPlan.issues,
          treatments: treatmentPlan.treatments,
          priceEstimate: treatmentPlan.priceEstimate,
          missingToothDetected,
          missingToothConfidence,
          ...(treatmentPlan.dentalCondition ? { dentalCondition: treatmentPlan.dentalCondition } : {}),
          ...(treatmentPlan.missingTooth ? { missingTooth: treatmentPlan.missingTooth } : {}),
          ...(simulatedImageUrl ? { simulatedImageUrl } : {}),
          ...(recommendedClinics.length > 0 ? { clinics: recommendedClinics } : {}),
        },
      },
      type: 'ai_result',
    });

    logAI('info', 'analyze_complete', {
      patientId,
      insightCount:  insights.length,
      confidence,
      hasSimulation: !!simulatedImageUrl,
      inMemory:      true,
      totalElapsedMs: Date.now() - _t0,
    });

    // ── Record cost only after a successful AI response (skip when dev bypass) ──
    if (!bypassAiLimit) {
      await aiCostRecord(patientId);
    }

    return res.json({
      ok: true,
      insights,
      confidence,
      summary,
      recommendation,
      simulatedImageUrl,
      simulationProvider,
      disclaimer,
      clinics: recommendedClinics,
      issues: treatmentPlan.issues,
      treatments: treatmentPlan.treatments,
      priceEstimate: treatmentPlan.priceEstimate,
      missingToothDetected,
      missingToothConfidence,
      ...(treatmentPlan.dentalCondition ? { dentalCondition: treatmentPlan.dentalCondition } : {}),
      ...(treatmentPlan.missingTooth ? { missingTooth: treatmentPlan.missingTooth } : {}),
    });

  } catch (err) {
    const isTimeout = err?.name === 'TimeoutError' || err?.name === 'AbortError';
    if (isTimeout) {
      logAI('warn', 'analyze_timeout', {
        patientId: req.body?.patientId,
        elapsedMs: Date.now() - _t0,
      });
      return res.status(504).json({
        ok: false,
        error: 'ai_timeout',
        message: 'AI analysis timed out. Your photo was saved successfully.',
      });
    }
    console.error('[AI BACKEND ERROR]', {
      patientId: req.body?.patientId,
      imageUrl:  req.body?.imageUrl,
      photoType: req.body?.photoType,
      error:     err?.message,
      stack:     err?.stack,
      elapsedMs: Date.now() - _t0,
    });
    logAI('error', 'analyze_exception', {
      patientId: req.body?.patientId,
      message:   err?.message,
      stack:     process.env.NODE_ENV !== 'production' ? err?.stack : undefined,
      elapsedMs: Date.now() - _t0,
    });
    return res.status(500).json({ ok: false, error: err?.message || 'ai_analyze_exception', message: err?.message || 'Server error' });
  }
});

// GET /api/admin/messages/unread-counts — unread counts for admin badge
// ?totalOnly=1 — fast path: COUNT(*) only (no row transfer). Use for sidebar/badge polling.
// (default) — per-patient counts; heavier; also cached briefly.
app.get("/api/admin/messages/unread-counts", requireAdminAuth, async (req, res) => {
  try {
    res.setHeader("Cache-Control", "private, no-cache, must-revalidate");
    if (!isSupabaseEnabled()) return res.json({ ok: true, total: 0, counts: {} });
    const clinicId = req.clinicId;
    const totalOnly = String(req.query.totalOnly || req.query.summary || "").trim() === "1";
    const cacheKey = `${clinicId}:${totalOnly ? "1" : "0"}`;
    const cached = unreadCountsCache.get(cacheKey);
    if (cached && cached.expires > Date.now()) {
      return res.json(cached.body);
    }

    const clinicCode = String(req.clinicCode || "").trim().toUpperCase();

    if (totalOnly) {
      let countResult = null;
      // Try clinic_code first (actual schema), fall back to clinic_id; prefer read_at IS NULL when column exists
      outerTotal: for (const [field, value] of [[`clinic_code`, clinicCode], [`clinic_id`, clinicId]]) {
        if (!value) continue;
        for (const unreadOnly of [true, false]) {
          let q = supabase
            .from("messages")
            .select("id", { count: "exact", head: true })
            .eq("from_patient", true)
            .eq(field, value);
          if (unreadOnly) q = q.is("read_at", null);
          const r = await q;
          if (!r.error) {
            countResult = r;
            break outerTotal;
          }
          if (unreadOnly && isSupabaseSchemaMissingColumnError(r.error)) continue;
          const errCode = String(r.error?.code || "");
          if (["42P01", "42703", "PGRST204", "PGRST205"].includes(errCode) || isSupabaseSchemaMissingColumnError(r.error)) {
            continue;
          }
          if (!errCode) {
            continue;
          }
          if (!["42P01", "42703", "PGRST204"].includes(errCode)) {
            const parts = [r.error?.message, r.error?.details, r.error?.hint].filter(Boolean);
            const summary = parts.length ? parts.join(" | ") : JSON.stringify(r.error || {});
            console.error("[UNREAD COUNTS] count error:", { code: r.error?.code, field, value: String(value).slice(0, 36), unreadOnly, summary });
            break outerTotal;
          }
        }
      }
      const body = { ok: true, total: countResult?.count || 0, counts: {} };
      unreadCountsCache.set(cacheKey, { body, expires: Date.now() + UNREAD_COUNTS_TTL_MS });
      return res.json(body);
    }

    // Legacy: fetch patient_id for every unread row (can be slow with many rows)
    let data = [], fetchError = null;
    outerRows: for (const [field, value] of [[`clinic_code`, clinicCode], [`clinic_id`, clinicId]]) {
      if (!value) continue;
      for (const unreadOnly of [true, false]) {
        let q = supabase
          .from("messages")
          .select("patient_id")
          .eq("from_patient", true)
          .eq(field, value);
        if (unreadOnly) q = q.is("read_at", null);
        const r = await q;
        if (!r.error) {
          data = r.data || [];
          break outerRows;
        }
        fetchError = r.error;
        if (unreadOnly && isSupabaseSchemaMissingColumnError(r.error)) continue;
        const rowEc = String(r.error?.code || "");
        if (["42P01", "42703", "PGRST204", "PGRST205"].includes(rowEc) || isSupabaseSchemaMissingColumnError(r.error) || !rowEc) {
          continue;
        }
        if (!["42P01", "42703", "PGRST204"].includes(rowEc)) break outerRows;
      }
    }
    const error = fetchError;

    if (error && !["42P01", "42703", "PGRST204"].includes(String(error.code || ""))) {
      console.error("[UNREAD COUNTS] messages fetch error:", error.message);
      return res.json({ ok: true, total: 0, counts: {} });
    }
    const rows = Array.isArray(data) ? data : [];
    const counts = {};
    rows.forEach(r => {
      const pid = String(r.patient_id || "");
      if (pid) counts[pid] = (counts[pid] || 0) + 1;
    });
    const total = Object.values(counts).reduce((s, n) => s + n, 0);
    const body = { ok: true, total, counts };
    unreadCountsCache.set(cacheKey, { body, expires: Date.now() + UNREAD_COUNTS_TTL_MS });
    return res.json(body);
  } catch (e) {
    console.error("[UNREAD COUNTS] error:", e.message);
    return res.json({ ok: true, total: 0, counts: {} });
  }
});

// POST /api/admin/chat/upload (Admin uploads files/images to patient chat)
app.post("/api/admin/chat/upload", requireAdminAuth, chatUpload.array("files", 5), async (req, res) => {
  try {



    
    const body = req.body || {};
    const patientId = String(body.patientId || "").trim();

    
    if (!patientId) {

      return res.status(400).json({ ok: false, error: "patientId_required" });
    }

    if (!isSupabaseEnabled() && !canUseFileFallback()) {
      return res.status(500).json(supabaseDisabledPayload("messages"));
    }

    const files = Array.isArray(req.files) ? req.files : [];

    
    if (files.length === 0) {

      return res.status(400).json({ ok: false, error: "no_files", message: "No files received" });
    }

    const isImageUpload = String(body.isImage || "").toLowerCase() === "true";
    const allowedImageMimes = new Set(["image/jpeg", "image/jpg", "image/png", "image/heic", "image/heif"]);
    const allowedDocMimes = new Set([
      "application/pdf",
      "application/msword",
      "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
      "text/plain",
      "application/vnd.ms-excel",
      "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      "application/zip",
      "application/x-zip-compressed",
    ]);

    const CHAT_UPLOAD_DIR = path.join(__dirname, "public", "uploads", "chat", patientId);
    if (!fs.existsSync(CHAT_UPLOAD_DIR)) fs.mkdirSync(CHAT_UPLOAD_DIR, { recursive: true });

    const useFileStore = !isSupabaseEnabled() && canUseFileFallback();
    let chatFile = null;
    let messages = [];
    if (useFileStore) {
      const CHAT_DIR = path.join(DATA_DIR, "chats");
      if (!fs.existsSync(CHAT_DIR)) fs.mkdirSync(CHAT_DIR, { recursive: true });
      chatFile = path.join(CHAT_DIR, `${patientId}.json`);
      const existing = readJson(chatFile, { messages: [] });
      messages = Array.isArray(existing.messages) ? existing.messages : [];
    }

    const uploadedFiles = [];
    for (const file of files) {
      const mime = String(file.mimetype || "").toLowerCase();
      const size = Number(file.size || 0);
      const originalName = String(file.originalname || "file");

      const isImage = isImageUpload || mime.startsWith("image/");
      if (isImage && !allowedImageMimes.has(mime)) {
        return res.status(400).json({ ok: false, error: "invalid_file_type", message: "Geçersiz resim formatı" });
      }
      if (!isImage && !allowedDocMimes.has(mime)) {
        return res.status(400).json({ ok: false, error: "invalid_file_type", message: "Geçersiz dosya formatı" });
      }

      if (isImage && size > IMAGE_MAX_SIZE_BYTES) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: `Resim ${IMAGE_MAX_SIZE_MB}MB'dan küçük olmalıdır.` });
      }
      const isZip = mime === "application/zip" || mime === "application/x-zip-compressed";
      if (!isImage && isZip && size > 50 * 1024 * 1024) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: "ZIP 50MB'dan küçük olmalıdır." });
      }
      if (!isImage && !isZip && size > 20 * 1024 * 1024) {
        return res.status(400).json({ ok: false, error: "file_too_large", message: "Dosya 20MB'dan küçük olmalıdır." });
      }

      let ext = path.extname(originalName || "").toLowerCase();
      if (!ext) {
        if (mime === "image/png") ext = ".png";
        else if (mime === "image/heic" || mime === "image/heif") ext = ".heic";
        else if (mime === "application/pdf") ext = ".pdf";
        else if (mime === "application/msword") ext = ".doc";
        else if (mime === "application/vnd.openxmlformats-officedocument.wordprocessingml.document") ext = ".docx";
        else if (mime === "application/vnd.ms-excel") ext = ".xls";
        else if (mime === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") ext = ".xlsx";
        else if (mime === "text/plain") ext = ".txt";
        else if (isZip) ext = ".zip";
        else ext = ".bin";
      }

      const safeName = `${patientId}_${now()}_${crypto.randomBytes(4).toString("hex")}${ext}`;
      const diskPath = path.join(CHAT_UPLOAD_DIR, safeName);
      fs.writeFileSync(diskPath, file.buffer);

      // Use relative URL so mobile app can prepend correct API_BASE
      // This ensures Android emulator uses 10.0.2.2 instead of localhost
      const fileUrl = `/uploads/chat/${encodeURIComponent(patientId)}/${encodeURIComponent(safeName)}`;
      const fileType = isImage ? "image" : "pdf";
      uploadedFiles.push({
        name: originalName,
        size,
        url: fileUrl,
        mimeType: mime,
        fileType,
      });

      // Admin uploads - message from CLINIC
      const newMessage = {
        id: `msg_${now()}_${crypto.randomBytes(4).toString("hex")}`,
        text: "",
        from: "CLINIC",
        type: fileType,
        attachment: {
          name: originalName,
          size,
          url: fileUrl,
          mimeType: mime,
          fileType,
        },
        createdAt: now(),
      };
      if (isSupabaseEnabled()) {
        const { error: saveErr } = await insertMessageToSupabase({
          patientId,
          sender: "clinic",
          message: "",
          attachments: newMessage.attachment,
          type: fileType,
        });
        if (saveErr) {
          const supabasePublic = supabaseErrorPublic(saveErr);
          console.error("[MESSAGES] Supabase save failed", {
            message: saveErr.message,
            code: saveErr.code,
            details: saveErr.details,
          });
          if (isMissingTableError(saveErr, "messages")) {
            return res.status(500).json({
              ok: false,
              error: "messages_table_missing",
              message: "Supabase schema missing: messages table. Run migration 008_create_messages_table.sql",
              supabase: supabasePublic,
            });
          }
          return res.status(500).json({ ok: false, error: "messages_save_failed", supabase: supabasePublic });
        }
      } else {
        messages.push(newMessage);
      }
    }

    if (useFileStore && chatFile) {
      writeJson(chatFile, { patientId, messages, updatedAt: now() });
    }

    return res.json({
      ok: true,
      files: uploadedFiles,
      message: uploadedFiles.length === 1 ? "File uploaded successfully" : `${uploadedFiles.length} files uploaded successfully`,
    });
  } catch (error) {


    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});
