// GET /api/patient/referral
// Returns patient's own referral code + list of people they've referred
app.get("/api/patient/referral", requireToken, async (req, res) => {
  try {
    const patientId = String(req.patientId || "").trim();
    if (!patientId) return res.status(401).json({ ok: false, error: "unauthorized" });

    const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    const isUuid = UUID_RE.test(patientId);

    if (!isSupabaseEnabled()) {
      // File-based fallback
      const patients = readJson(PAT_FILE, {});
      const patient = patients[patientId] || Object.values(patients).find(
        function(p) { return String(p && (p.patientId || p.patient_id) || "").trim() === patientId; }
      );
      const referralCode = (patient && (patient.referralCode || patient.referral_code)) || null;
      const raw = readJson(REF_FILE, []);
      const list = (Array.isArray(raw) ? raw : Object.values(raw)).filter(
        function(r) { return r && (r.inviterPatientId || r.inviter_patient_id) === patientId; }
      );
      const referrals = list.map(function(r) {
        const invId = r.invitedPatientId || r.invited_patient_id;
        return {
          id: r.id || r.referralId,
          name: r.invitedName || r.invited_name || (patients[invId] && patients[invId].name) || "—",
          status: String(r.status || "invited").toLowerCase(),
          createdAt: r.createdAt || r.created_at || null,
        };
      });
      return res.json({ ok: true, referralCode: referralCode, discountPercent: null, referrals: referrals });
    }

    // ── Supabase path ──────────────────────────────────────────────────────────

    // 1. Fetch patient row (try UUID → then patient_id TEXT)
    let patientRow = null;
    if (isUuid) {
      const r1 = await supabase.from("patients")
        .select("id, patient_id, referral_code, clinic_id, name")
        .eq("id", patientId).maybeSingle();
      patientRow = r1.data || null;
    }
    if (!patientRow) {
      const r2 = await supabase.from("patients")
        .select("id, patient_id, referral_code, clinic_id, name")
        .eq("patient_id", patientId).maybeSingle();
      patientRow = r2.data || null;
    }

    // If patient has no referral_code yet (e.g. manually created by admin), generate and save one now
    let referralCode = patientRow ? (patientRow.referral_code || null) : null;
    if (patientRow && !referralCode) {
      const newCode = generateReferralCodeV2();
      try {
        await supabase
          .from("patients")
          .update({ referral_code: newCode })
          .eq("id", patientRow.id);
        referralCode = newCode;
      } catch (e) {
        console.warn("[REFERRAL] Could not assign referral_code to patient:", e?.message);
        referralCode = newCode; // still use it in response even if save failed
      }
    }
    const clinicId = patientRow ? (patientRow.clinic_id || null) : null;

    // JWT patientId + DB row ids — referrals may store UUID or legacy patient_id text
    const patientTextId = patientRow ? (patientRow.patient_id || null) : null;
    const patientUuid = patientRow ? (patientRow.id || null) : null;
    let selfIds = Array.from(new Set([patientId, patientTextId, patientUuid].filter(Boolean)));

    // Expand: map p_xxx ↔ UUID so referral rows match JWT (resolvePatientUuidForReferral)
    try {
      const expanded = new Set(selfIds.map(String));
      for (const sid of [...selfIds]) {
        const u = await resolvePatientUuidForReferral(sid);
        if (u) expanded.add(String(u).trim());
      }
      selfIds = Array.from(expanded).filter(Boolean);
    } catch (e) {
      console.warn("[/api/patient/referral] expand selfIds:", e?.message || e);
    }

    // 2. Clinic discount percent
    let discountPercent = null;
    if (clinicId) {
      const cr = await supabase.from("clinics").select("settings").eq("id", clinicId).maybeSingle();
      const s = (cr.data && cr.data.settings) || {};
      discountPercent = (s.referralLevels && s.referralLevels.level1 != null)
        ? s.referralLevels.level1
        : (s.referralLevel1Percent != null ? s.referralLevel1Percent : null);
    }

    // UUID columns reject non-UUID values in .in([...]) — one bad id clears the whole query.
    async function queryReferralsByColumn(column, ids) {
      const uniq = Array.from(new Set((ids || []).map(function (x) { return String(x || "").trim(); }).filter(Boolean)));
      if (!uniq.length) return [];
      const uuidList = uniq.filter(function (id) { return UUID_RE.test(id); });
      const textList = uniq.filter(function (id) { return !UUID_RE.test(id); });
      const merged = [];
      const seenRow = new Set();
      async function runChunk(chunk) {
        if (!chunk.length) return;
        const qr = await supabase
          .from("referrals")
          .select("*")
          .in(column, chunk)
          .order("created_at", { ascending: false });
        if (qr.error) {
          const msg = String(qr.error.message || "").toLowerCase();
          const benign =
            msg.includes("does not exist") ||
            msg.includes("column") ||
            msg.includes("invalid input syntax for type uuid");
          if (!benign) {
            console.error("[/api/patient/referral] query", column, qr.error.message);
          }
          return;
        }
        (qr.data || []).forEach(function (row) {
          const rk = row && (row.id != null ? row.id : row.referral_id);
          if (rk == null || seenRow.has(rk)) return;
          seenRow.add(rk);
          merged.push(row);
        });
      }
      await runChunk(uuidList);
      await runChunk(textList);
      merged.sort(function (a, b) {
        return new Date(b.created_at || 0) - new Date(a.created_at || 0);
      });
      return merged;
    }

    async function queryInviterColumn(column) {
      return queryReferralsByColumn(column, selfIds);
    }

    async function queryInvitedColumn(column) {
      return queryReferralsByColumn(column, selfIds);
    }

    // 3a. Outgoing: this patient is inviter
    let outgoingRows = await queryInviterColumn("inviter_patient_id");
    if (outgoingRows.length === 0) {
      outgoingRows = await queryInviterColumn("referrer_patient_id");
    }

    // 3b. Incoming: this patient was invited
    let incomingRows = await queryInvitedColumn("invited_patient_id");
    if (incomingRows.length === 0) {
      incomingRows = await queryInvitedColumn("referred_patient_id");
    }

    function normalizeReferralRow(r) {
      if (!r) return r;
      const inv = r.inviter_patient_id || r.referrer_patient_id;
      const invd = r.invited_patient_id || r.referred_patient_id;
      return { ...r, inviter_patient_id: inv, invited_patient_id: invd };
    }
    outgoingRows = outgoingRows.map(normalizeReferralRow);
    incomingRows = incomingRows.map(normalizeReferralRow);

    const seenRef = new Set();
    const combined = [];
    for (let o = 0; o < outgoingRows.length; o++) {
      const r = outgoingRows[o];
      const rid = r && (r.id != null ? r.id : r.referral_id);
      if (!r || rid == null || seenRef.has(rid)) continue;
      seenRef.add(rid);
      combined.push({ row: r, direction: "outgoing" });
    }
    for (let o = 0; o < incomingRows.length; o++) {
      const r = incomingRows[o];
      const rid = r && (r.id != null ? r.id : r.referral_id);
      if (!r || rid == null || seenRef.has(rid)) continue;
      seenRef.add(rid);
      combined.push({ row: r, direction: "incoming" });
    }

    const needIds = new Set();
    for (let c = 0; c < combined.length; c++) {
      const r = combined[c].row;
      const dir = combined[c].direction;
      if (dir === "outgoing" && r.invited_patient_id != null) {
        needIds.add(String(r.invited_patient_id).trim());
      }
      if (dir === "incoming" && r.inviter_patient_id != null) {
        needIds.add(String(r.inviter_patient_id).trim());
      }
    }
    const allNeed = Array.from(needIds).filter(Boolean);

    const nameMap = {};
    function ingestPatientRow(p) {
      if (!p) return;
      const nm = (p.name && String(p.name).trim()) || "—";
      if (p.id != null) nameMap[String(p.id)] = nm;
      if (p.patient_id != null) nameMap[String(p.patient_id)] = nm;
    }
    for (let i = 0; i < allNeed.length; i += 50) {
      const chunk = allNeed.slice(i, i + 50);
      const uuidChunk = chunk.filter(function(id) { return UUID_RE.test(id); });
      const textChunk = chunk.filter(function(id) { return !UUID_RE.test(id); });
      if (uuidChunk.length > 0) {
        const pr = await supabase.from("patients").select("id, patient_id, name").in("id", uuidChunk);
        (pr.data || []).forEach(ingestPatientRow);
        const pr2 = await supabase.from("patients").select("id, patient_id, name").in("patient_id", uuidChunk);
        (pr2.data || []).forEach(ingestPatientRow);
      }
      if (textChunk.length > 0) {
        const pr = await supabase.from("patients").select("id, patient_id, name").in("patient_id", textChunk);
        (pr.data || []).forEach(ingestPatientRow);
        const pr2 = await supabase.from("patients").select("id, patient_id, name").in("id", textChunk);
        (pr2.data || []).forEach(ingestPatientRow);
      }
    }
    for (let mi = 0; mi < allNeed.length; mi++) {
      const id = allNeed[mi];
      if (!id || nameMap[id]) continue;
      try {
        const q1 = await supabase.from("patients").select("id, patient_id, name").eq("id", id).maybeSingle();
        if (!q1.error && q1.data) ingestPatientRow(q1.data);
        if (!nameMap[id]) {
          const q2 = await supabase.from("patients").select("id, patient_id, name").eq("patient_id", id).maybeSingle();
          if (!q2.error && q2.data) ingestPatientRow(q2.data);
        }
      } catch (_) { /* ignore */ }
    }

    const referrals = combined.map(function(entry) {
      const r = entry.row;
      const dir = entry.direction;
      const otherRaw = dir === "outgoing" ? r.invited_patient_id : r.inviter_patient_id;
      const sid = otherRaw != null ? String(otherRaw).trim() : "";
      const displayName =
        dir === "outgoing"
          ? (
              (sid && nameMap[sid]) ||
              r.invited_patient_name ||
              r.invitedPatientName ||
              r.invited_name ||
              "—"
            )
          : (
              (sid && nameMap[sid]) ||
              r.inviter_patient_name ||
              r.inviterPatientName ||
              r.inviter_name ||
              "—"
            );
      return {
        id: r.id != null ? r.id : r.referral_id,
        name: displayName,
        status: String(r.status || "invited").toLowerCase(),
        createdAt: r.created_at ? new Date(r.created_at).getTime() : null,
        direction: dir,
      };
    });
    referrals.sort(function(a, b) { return (b.createdAt || 0) - (a.createdAt || 0); });

    return res.json({
      ok: true,
      referralCode: referralCode,
      discountPercent: discountPercent,
      referrals: referrals,
      friends: referrals,
      items: referrals,
    });

  } catch (err) {
    console.error("[/api/patient/referral] Error:", err.message);
    return res.status(500).json({ ok: false, error: "server_error" });
  }
});

// POST /api/referrals
// Create a referral (file-based persistence)
app.post("/api/referrals", requireToken, (req, res) => {
  try {
    const inviterPatientId = String(req.patientId || "").trim();
    const invitedPatientId = String(req.body?.invitedPatientId || "").trim();

    if (!inviterPatientId) {
      return res.status(401).json({ ok: false, error: "unauthorized" });
    }
    if (!invitedPatientId) {
      return res.status(400).json({ ok: false, error: "invited_patient_id_required" });
    }
    if (inviterPatientId === invitedPatientId) {
      return res.status(400).json({ ok: false, error: "self_referral_forbidden" });
    }

    const raw = readJson(REF_FILE, []);
    const list = Array.isArray(raw) ? raw : Object.values(raw);
    const existing = list.find(
      (r) =>
        r &&
        (r.inviterPatientId || r.inviter_patient_id) === inviterPatientId &&
        (r.invitedPatientId || r.invited_patient_id) === invitedPatientId &&
        !r.deleted_at
    );
    if (existing) {
      return res.status(409).json({ ok: false, error: "referral_already_exists", item: existing });
    }

    const newReferral = {
      id: rid("ref"),
      inviterPatientId,
      invitedPatientId,
      status: "PENDING",
      createdAt: new Date().toISOString(),
      inviterDiscountPercent: null,
      invitedDiscountPercent: null,
      discountPercent: null,
    };
    list.push(newReferral);
    writeJson(REF_FILE, list);

    return res.json({ ok: true, item: newReferral });
  } catch (error) {

    return res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// GET /api/me/referrals
// Patient sees their own referrals (file-based)
app.get("/api/me/referrals", requireToken, (req, res) => {
  try {
    const patientId = String(req.patientId || "").trim();
    if (!patientId) {
      return res.status(401).json({ ok: false, error: "unauthorized" });
    }

    const status = req.query.status;
    const raw = readJson(REF_FILE, []);
    let items = (Array.isArray(raw) ? raw : Object.values(raw)).filter(
      (r) => r && (r.inviterPatientId || r.inviter_patient_id) === patientId
    );

    if (status && (status === "PENDING" || status === "APPROVED" || status === "REJECTED")) {
      items = items.filter((x) => x.status === status);
    }

    items.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
    return res.json({ ok: true, items });
  } catch (error) {

    return res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// GET /api/admin/referrals?status=PENDING|APPROVED|REJECTED
app.get("/api/admin/referrals", requireAdminAuth, async (req, res) => {
  try {
    const statusRaw = req.query.status;
    const status = String(statusRaw || "").trim().toUpperCase();
    
    // PRODUCTION: Clinic isolation - use req.clinic.id (UUID) from requireAdminToken
    if (!req.clinic || !req.clinicId) {
      return res.status(403).json({ ok: false, error: "clinic_not_authenticated", message: "Klinik kimlik doğrulaması yapılmadı." });
    }
    
    const clinicId = req.clinicId; // UUID from Supabase or file-based ID
    const clinicCode = req.clinicCode;
    

    const respondFromFile = () => {
      const raw = readJson(REF_FILE, []);
      const list = Array.isArray(raw) ? raw : Object.values(raw);

      // Get patients to filter by clinic
      const patients = readJson(PAT_FILE, {});
      
      // Get list of patient IDs that belong to this clinic
      const clinicPatientIds = new Set();
      for (const pid in patients) {
        // ... (rest of the code remains the same)
        const patient = patients[pid];
        if (patient) {
          const patientClinicCode = (patient.clinicCode || patient.clinic_code || "").toUpperCase();
          if (patientClinicCode === clinicCode?.toUpperCase()) {
            clinicPatientIds.add(pid);
            clinicPatientIds.add(patient.patientId || patient.patient_id);
          }
        }
      }
      

      
      let items = [];
      if (clinicPatientIds.size === 0) {
        // No clinic patients found in file store; return all file referrals as fallback.
        items = list.filter((x) => x && !x.deleted_at);
      } else {
        // Filter referrals: only show referrals where inviter OR invited patient belongs to this clinic
        items = list.filter((x) => {
          if (!x || x.deleted_at) return false; // Exclude soft-deleted
          const inviterId = x.inviterPatientId || x.inviter_patient_id;
          const invitedId = x.invitedPatientId || x.invited_patient_id;
          
          const inviterBelongsToClinic = inviterId && clinicPatientIds.has(inviterId);
          const invitedBelongsToClinic = invitedId && clinicPatientIds.has(invitedId);
          
          const referralClinicCode = (x.clinicCode || x.clinic_code || "").toUpperCase();
          const clinicCodeMatches = referralClinicCode && referralClinicCode === clinicCode?.toUpperCase();
          
          return inviterBelongsToClinic || invitedBelongsToClinic || clinicCodeMatches;
        });
      }
      
      if (status && (status === "PENDING" || status === "APPROVED" || status === "REJECTED" || status === "USED")) {
        items = items.filter((x) => x && String(x.status || "").toUpperCase() === status);
      }
      
      // SECURITY: Remove dangerous fallback that returns all referrals
      // NEVER return referrals that don't belong to this clinic
      // if (items.length === 0 && list.length > 0) {
      //   items = list.filter((x) => x && !x.deleted_at);  // ❌ SECURITY RISK!
      // }


      
      items.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
      return res.json({ ok: true, items, source: "file" });
    };

    // SUPABASE: Primary source of truth
    if (isSupabaseEnabled()) {
      try {
        let items = (await getReferralsByClinicFromDB(clinicId, clinicCode)) || [];

        if (items.length === 0) {
          let clinicPatients = [];
          if (clinicId) {
            clinicPatients = await getPatientsByClinic(clinicId, { includeLeads: true });
          }
          if ((!clinicPatients || clinicPatients.length === 0) && clinicCode) {
            try {
              const { data, error } = await supabase
                .from("patients")
                .select("id, patient_id, clinic_id, clinic_code")
                .eq("clinic_code", String(clinicCode).toUpperCase());
              if (error) {
                if (!isMissingColumnError(error, "clinic_code")) {
                  console.error("[REFERRALS] Supabase patient clinic_code lookup failed", {
                    message: error.message,
                    code: error.code,
                    details: error.details,
                  });
                }
              } else if (Array.isArray(data)) {
                clinicPatients = data;
              }
            } catch (e) {

            }
          }

          const patientIds = (clinicPatients || [])
            .map((p) => p.patient_id || p.id)
            .filter(Boolean);
          if (patientIds.length > 0) {
            const idsClause = patientIds.join(",");
            const { data: altData, error: altError } = await supabase
              .from("referrals")
              .select("*")
              .or(`inviter_patient_id.in.(${idsClause}),invited_patient_id.in.(${idsClause})`)
              .order("created_at", { ascending: false });
            if (!altError) {
              items = altData || [];
            }
          }
        }

        if (items.length === 0) {
          // Last-resort fallback: fetch referrals without clinic filter and
          // filter by patient clinic_id (covers referrals missing clinic_id).
          let q = supabase.from("referrals").select("*");
          if (status) {
            const raw = String(status || "").toUpperCase();
            const rawStatuses =
              raw === "PENDING"
                ? ["invited", "registered", "pending"]
                : raw === "APPROVED"
                  ? ["approved", "completed"]
                  : raw === "REJECTED"
                    ? ["rejected", "cancelled"]
                    : raw === "USED"
                      ? ["used"]
                      : [];
            if (rawStatuses.length > 0) {
              q = q.in("status", rawStatuses);
            }
          }
          const { data: allReferrals, error: allErr } = await q.order("created_at", { ascending: false });
          if (!allErr && Array.isArray(allReferrals) && allReferrals.length > 0) {
            const ids = new Set();
            allReferrals.forEach((r) => {
              const inviter = r.inviter_patient_id || r.referrer_patient_id;
              const invited = r.invited_patient_id || r.referred_patient_id;
              if (inviter) ids.add(inviter);
              if (invited) ids.add(invited);
            });
            const idList = Array.from(ids);
            let patientClinicMap = new Map();
            if (idList.length > 0) {
              const idsClause = idList.join(",");
              const { data: patientRows, error: patientErr } = await supabase
                .from("patients")
                .select("id, patient_id, clinic_id")
                .or(`id.in.(${idsClause}),patient_id.in.(${idsClause})`);
              if (!patientErr && Array.isArray(patientRows)) {
                patientRows.forEach((p) => {
                  if (p?.id) patientClinicMap.set(String(p.id), p.clinic_id || null);
                  if (p?.patient_id) patientClinicMap.set(String(p.patient_id), p.clinic_id || null);
                });
              } else if (patientErr && !isMissingColumnError(patientErr, "patient_id")) {
                console.error("[REFERRALS] Supabase patient lookup failed (fallback)", {
                  message: patientErr.message,
                  code: patientErr.code,
                  details: patientErr.details,
                });
              }
            }

            items = allReferrals.filter((r) => {
              if (!r) return false;
              if (clinicId && r.clinic_id && r.clinic_id === clinicId) return true;
              const inviter = r.inviter_patient_id || r.referrer_patient_id;
              const invited = r.invited_patient_id || r.referred_patient_id;
              const inviterClinic = inviter ? patientClinicMap.get(String(inviter)) : null;
              const invitedClinic = invited ? patientClinicMap.get(String(invited)) : null;
              return Boolean(clinicId && (inviterClinic === clinicId || invitedClinic === clinicId));
            });
          }
        }
        
        // Normalize to legacy shape for frontend
        items = items.map(mapReferralRowToLegacyItem).filter(Boolean);

        // Filter by status if provided
        if (status && (status === "PENDING" || status === "APPROVED" || status === "REJECTED" || status === "USED")) {
          items = items.filter((r) => String(r.status || "").toUpperCase() === status);
        }
        
        // Exclude soft-deleted referrals
        items = items.filter((r) => !r.deleted_at);
        
        // Sort by created date (newest first)
        items.sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));
        

        if (items.length === 0) {
          return respondFromFile();
        }
        return res.json({ ok: true, items, source: "supabase" });
      } catch (supabaseError) {

        // Fall through to file-based
      }
    }
    
    return respondFromFile();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// DELETE /api/admin/referrals/:referralId (admin cleanup)
app.delete("/api/admin/referrals/:referralId", requireAdminAuth, async (req, res) => {
  try {
    const referralId = String(req.params.referralId || "").trim();
    if (!referralId) return res.status(400).json({ ok: false, error: "referral_id_required" });

    // SUPABASE: delete by id (UUID) or referral_code (legacy)
    if (isSupabaseEnabled()) {
      const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(referralId);
      let q = supabase.from("referrals").delete();
      if (isUuid) {
        q = q.eq("id", referralId);
      } else {
        q = q.eq("referral_code", referralId);
      }
      if (req.clinicId) q = q.eq("clinic_id", req.clinicId);
      const { error } = await q;
      if (error) {
        console.error("[REFERRALS] Supabase delete failed", {
          message: error.message,
          code: error.code,
          details: error.details,
        });
        return res.status(500).json({ ok: false, error: "referral_delete_failed", supabase: supabaseErrorPublic(error) });
      }
    }

    // FILE fallback cleanup
    if (canUseFileFallback()) {
      const raw = readJson(REF_FILE, []);
      const list = Array.isArray(raw) ? raw : Object.values(raw);
      const filtered = list.filter((x) => {
        const id = x?.id || "";
        const code = x?.referralCode || x?.referral_code || "";
        return id !== referralId && code !== referralId;
      });
      writeJson(REF_FILE, filtered);

      const rawEvents = readJson(REF_EVENT_FILE, []);
      const events = Array.isArray(rawEvents) ? rawEvents : Object.values(rawEvents);
      const filteredEvents = events.filter((e) => {
        const rid = e?.referralId || e?.referral_id || "";
        return rid !== referralId;
      });
      writeJson(REF_EVENT_FILE, filteredEvents);
    }

    return res.json({ ok: true, deleted: true, id: referralId });
  } catch (error) {

    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

function mapReferralRowToLegacyItem(r) {
  if (!r) return null;
  const rawStatus = String(r.status || "").toUpperCase();
  const normalizedStatus =
    rawStatus === "INVITED" || rawStatus === "REGISTERED"
      ? "PENDING"
      : rawStatus === "COMPLETED"
        ? "APPROVED"
        : rawStatus === "CANCELLED"
          ? "REJECTED"
          : rawStatus || "PENDING";
  const createdAt =
    r.createdAt ||
    (r.created_at ? Date.parse(r.created_at) : null) ||
    (r.updated_at ? Date.parse(r.updated_at) : null) ||
    now();

  return {
    id: r.id,
    status: normalizedStatus,
    inviterPatientId: r.inviter_patient_id || r.referrer_patient_id,
    invitedPatientId: r.invited_patient_id || r.referred_patient_id || null,
    inviterPatientName: r.inviterPatientName || r.inviter_patient_name || null,
    invitedPatientName: r.invitedPatientName || r.invited_patient_name || null,
    referralCode: r.referral_code,
    createdAt,
    // v2 reward fields (optional)
    rewardAmount: r.reward_amount ?? null,
    rewardCurrency: r.reward_currency ?? "EUR",
    completedAt: r.completed_at || null,
  };
}

async function getPatientClinicIdForReferral(patientId) {
  // Best-effort: derive clinic_id from patients table for admin isolation/reporting
  try {
    // Prefer patient_id when available; fall back to id
    const q1 = await supabase
      .from("patients")
      .select("clinic_id, patient_id, id")
      .eq("patient_id", patientId)
      .single();
    if (!q1.error && q1.data?.clinic_id) return q1.data.clinic_id;

    const msg = String(q1.error?.message || "");
    const isMissingPatientIdCol =
      msg.toLowerCase().includes("patient_id") && msg.toLowerCase().includes("does not exist");
    const isNotFound = String(q1.error?.code || "") === "PGRST116";
    if (q1.error && !isMissingPatientIdCol && !isNotFound) return null;

    const q2 = await supabase
      .from("patients")
      .select("clinic_id, id")
      .eq("id", patientId)
      .single();
    if (!q2.error && q2.data?.clinic_id) return q2.data.clinic_id;
    return null;
  } catch {
    return null;
  }
}

async function resolvePatientUuidForReferral(candidate) {
  const s = String(candidate || "").trim();
  if (!s) return null;
  const isUuid =
    /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(s);
  if (isUuid) return s;
  if (!isSupabaseEnabled()) return null;
  try {
    const uuidLike = (v) =>
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v || "").trim());

    // Some schemas store the legacy id in `patient_id` and the UUID in `id`.
    // Others might only have `id`. Try both `id` and `patient_id` match.
    const q1 = await supabase
      .from("patients")
      .select("id, patient_id")
      .or(`id.eq.${s},patient_id.eq.${s}`)
      .limit(1)
      .maybeSingle();

    if (!q1.error && q1.data) {
      const candidates = [q1.data.id, q1.data.patient_id].filter(Boolean);
      const found = candidates.find((v) => uuidLike(v));
      if (found) return String(found).trim();
    }

    if (q1.error && isMissingColumnError(q1.error, "patient_id")) {
      const q2 = await supabase
        .from("patients")
        .select("id")
        .eq("id", s)
        .limit(1)
        .maybeSingle();
      if (!q2.error && q2.data?.id && uuidLike(q2.data.id)) {
        return String(q2.data.id).trim();
      }
    }
  } catch {
    // ignore
  }
  return null;
}

/** Persist optional display names when the referrals table has the columns; otherwise retry without them. */
async function createReferralInDBFlexible(payload) {
  try {
    return await createReferralInDB(payload);
  } catch (err) {
    const msg = String(err?.message || "").toLowerCase();
    if (msg.includes("inviter_patient_name") || msg.includes("invited_patient_name")) {
      const copy = { ...(payload || {}) };
      delete copy.inviter_patient_name;
      delete copy.invited_patient_name;
      return await createReferralInDB(copy);
    }
    throw err;
  }
}

function generateReferralCodeV2() {
  // Short, URL-safe code. Collision is guarded by DB unique index + retry.
  const bytes = crypto.randomBytes(6).toString("base64").replaceAll("+", "").replaceAll("/", "").replaceAll("=", "");
  return `R_${bytes.substring(0, 10).toUpperCase()}`;
}

// POST /api/referral/invite
// Patient creates an invite; legacy flow continues to work in parallel.
app.post("/api/referral/invite", requireToken, async (req, res) => {
  try {
    const patientId = String(req.patientId || "").trim();
    if (!patientId) return res.status(401).json({ ok: false, error: "unauthorized" });
    if (!isSupabaseEnabled()) return res.status(500).json({ ok: false, error: "supabase_disabled" });

    // Resolve inviter candidates (UUID vs legacy p_xxx) to support evolving schemas.
    let inviterRow = null;
    try {
      const q1 = await supabase
        .from("patients")
        .select("id, patient_id, clinic_id")
        .eq("patient_id", patientId)
        .maybeSingle();
      if (!q1.error && q1.data) inviterRow = q1.data;
      const isMissingPatientIdCol =
        q1.error && isMissingColumnError(q1.error, "patient_id");
      const isNotFound = String(q1.error?.code || "") === "PGRST116";
      if (!inviterRow && (isMissingPatientIdCol || isNotFound)) {
        const q2 = await supabase
          .from("patients")
          .select("id, patient_id, clinic_id")
          .eq("id", patientId)
          .maybeSingle();
        if (!q2.error && q2.data) inviterRow = q2.data;
      }
    } catch {
      // best-effort only
    }

    const uuidLike = (s) =>
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(s || ""));
    let inviterCandidates = Array.from(
      new Set([inviterRow?.id, inviterRow?.patient_id, patientId].filter(Boolean))
    );

    const resolvedInviterUuids = (await Promise.all(inviterCandidates.map(resolvePatientUuidForReferral))).filter(Boolean);
    inviterCandidates = Array.from(new Set([...inviterCandidates, ...resolvedInviterUuids]));
    inviterCandidates = [
      ...inviterCandidates.filter((x) => uuidLike(x)),
      ...inviterCandidates.filter((x) => !uuidLike(x)),
    ];

    const clinicId = req.clinicId || (await getPatientClinicIdForReferral(patientId));
    let clinicCode = null;
    if (clinicId) {
      try {
        const { data: clinicRow, error: clinicErr } = await supabase
          .from("clinics")
          .select("clinic_code")
          .eq("id", clinicId)
          .single();
        if (!clinicErr && clinicRow?.clinic_code) {
          clinicCode = String(clinicRow.clinic_code).trim().toUpperCase();
        } else if (clinicErr && String(clinicErr.code || "") !== "PGRST116") {
          console.warn("[REFERRAL] clinic_code lookup failed", {
            message: clinicErr.message,
            code: clinicErr.code,
            details: clinicErr.details,
          });
        }
      } catch (e) {

      }
    }

    let lastErr = null;
    for (let i = 0; i < 6; i++) {
      const referral_code = generateReferralCodeV2();
      const doInsert = async (payload) =>
        supabase.from("referrals").insert(payload).select("*").single();

      let inserted = null;
      let insertError = null;

      // Try different inviter id representations (uuid first, then legacy)
      for (const inviterId of inviterCandidates) {
        const insertPayload = {
          // keep existing schema fields (clinic_id is optional)
          ...(clinicId ? { clinic_id: clinicId } : {}),
          ...(clinicCode ? { clinic_code: clinicCode } : {}),
          inviter_patient_id: inviterId,
          referral_code,
          status: "PENDING",
          reward_currency: "EUR",
        };

        let { data, error } = await doInsert(insertPayload);

        // Schema-evolution fallbacks
        if (error && clinicCode && isMissingColumnError(error, "clinic_code")) {
          const fallbackPayload = { ...insertPayload };
          delete fallbackPayload.clinic_code;
          ({ data, error } = await doInsert(fallbackPayload));
        }
        if (error && isMissingColumnError(error, "reward_currency")) {
          const fallbackPayload = { ...insertPayload };
          delete fallbackPayload.reward_currency;
          ({ data, error } = await doInsert(fallbackPayload));
        }

        if (!error) {
          inserted = data;
          break;
        }

        insertError = error;
        // UUID mismatch -> try next candidate representation
        if (isInvalidUuidError(error)) continue;
        // Unique violation -> handled by outer retry (new referral code)
        break;
      }

      if (inserted) {
        let verified = inserted;
        try {
          const { data: verifyRow, error: verifyErr } = await supabase
            .from("referrals")
            .select("*")
            .eq("id", inserted.id)
            .single();
          if (!verifyErr && verifyRow) {
            verified = verifyRow;
          } else if (verifyErr) {
            console.warn("[REFERRAL] Insert verify failed (non-fatal)", {
              message: verifyErr.message,
              code: verifyErr.code,
              details: verifyErr.details,
            });
          }
        } catch (verifyException) {

        }
        return res.json({
          ok: true,
          referralId: verified.id,
          referralCode: verified.referral_code,
          item: mapReferralRowToLegacyItem(verified),
        });
      }

      lastErr = insertError;
      // Unique violation -> retry with a new code
      if (String(insertError?.code || "") === "23505") continue;

      console.error("[REFERRAL] Supabase save failed", {
        message: insertError?.message,
        code: insertError?.code,
        details: insertError?.details,
      });
      return res.status(500).json({ ok: false, error: "referral_invite_failed" });
    }

    console.error("[REFERRAL] Supabase save failed (exhausted retries)", {
      message: lastErr?.message,
      code: lastErr?.code,
      details: lastErr?.details,
    });
    return res.status(500).json({ ok: false, error: "referral_invite_failed" });
  } catch (e) {

    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// GET /api/patient/:patientId/referrals
// Get referrals where this patient is the inviter OR the invited patient (legacy-compatible)
app.get("/api/patient/:patientId/referrals", requireAdminOrPatientToken, async (req, res) => {





  
  try {
    const { patientId } = req.params;
    const status = req.query.status;
    

    
    if (!patientId) {

      return res.status(400).json({ ok: false, error: "patientId_required" });
    }
    
    // Patient can only access their own referrals (admin can access any)
    if (!req.isAdmin && String(req.patientId || "").trim() !== String(patientId || "").trim()) {
      return res.status(403).json({ ok: false, error: "patient_id_mismatch" });
    }

    const respondFromFile = () => {
      const raw = readJson(REF_FILE, []);
      const list = Array.isArray(raw) ? raw : Object.values(raw);


      const normalizedPatientId = String(patientId || "").trim();


      if (list.length > 0) {
        console.log(`[GET /api/patient/:patientId/referrals] All referral patient IDs in DB:`, list.map((r) => ({
          id: r.id,
          inviterPatientId: r.inviterPatientId,
          invitedPatientId: r.invitedPatientId,
          inviterMatch: String(r.inviterPatientId || "").trim() === normalizedPatientId,
          invitedMatch: String(r.invitedPatientId || "").trim() === normalizedPatientId,
        })));
      }

      let items = list.filter((x) => {
        if (!x) return false;
        const inviterId = String(x.inviterPatientId || "").trim();
        const invitedId = String(x.invitedPatientId || "").trim();
        return inviterId === normalizedPatientId || invitedId === normalizedPatientId;
      });

      console.log(`[GET /api/patient/:patientId/referrals] Referral details:`, items.map((r) => ({
        id: r.id,
        status: r.status,
        inviterPatientId: r.inviterPatientId,
        invitedPatientId: r.invitedPatientId,
      })));

      if (status && (status === "PENDING" || status === "APPROVED" || status === "REJECTED")) {
        const beforeFilter = items.length;
        items = items.filter((x) => x.status === status);

      }

      items.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));


      return res.json({ ok: true, items, source: "file" });
    };

    // PRODUCTION: Supabase is source of truth
    if (isSupabaseEnabled()) {
      const normalizedPatientId = String(patientId || "").trim();
      let patientUuid = null;
      try {
        const p = await getPatientById(normalizedPatientId);
        patientUuid = p?.id || null;
      } catch {}

      const candidates = [normalizedPatientId, patientUuid].filter(Boolean);
      const seen = new Set();
      const queryVariants = [];
      for (const candidate of candidates) {
        const clauses = [
          `inviter_patient_id.eq.${candidate},invited_patient_id.eq.${candidate}`,
        ];
        clauses.forEach((c) => {
          if (!seen.has(c)) {
            seen.add(c);
            queryVariants.push(c);
          }
        });
      }

      let lastError = null;
      for (const orClause of queryVariants) {
        let q = supabase.from("referrals").select(`
          *,
          inviter_patient:patients!fk_referrals_inviter (
            patientId:patient_id,
            name
          ),
          invited_patient:patients!fk_referrals_invited (
            patientId:patient_id,
            name
          )
        `).or(orClause);
        if (req.isAdmin && req.clinicId) q = q.eq("clinic_id", req.clinicId);
        const { data, error } = await q.order("created_at", { ascending: false });
        if (!error) {
          let items = (data || []).map(ref => {
            const legacyItem = mapReferralRowToLegacyItem(ref);
            if (legacyItem) {
              const result = {
                ...legacyItem,
                inviterPatientName: ref.inviter_patient?.name || null,
                invitedPatientName: ref.invited_patient?.name || null
              };
              console.log(`[REFERRALS] Patient endpoint - processed referral ${ref.id}:`, {
                inviterPatientId: ref.inviter_patient_id,
                invitedPatientId: ref.invited_patient_id,
                inviterPatientName: result.inviterPatientName,
                invitedPatientName: result.invitedPatientName,
                discountPercent: ref.discount_percent,
                inviterDiscountPercent: ref.inviter_discount_percent,
                invitedDiscountPercent: ref.invited_discount_percent,
                legacyDiscountPercent: legacyItem.discountPercent
              });
              return result;
            }
            return null;
          }).filter(Boolean);
          if (status) items = items.filter((x) => x.status === status);
          if (items.length === 0) {
            return respondFromFile();
          }
          return res.json({ ok: true, items, source: "supabase" });
        }
        lastError = error;
        if (isInvalidUuidError(error)) {
          continue;
        }
        if (!isMissingColumnError(error)) {
          console.error("[REFERRALS] Supabase fetch failed", {
            message: error.message,
            code: error.code,
            details: error.details,
          });
          break;
        }
      }

      if (canUseFileFallback()) {

        return respondFromFile();
      }
      return res.status(500).json({
        ok: false,
        error: "referrals_fetch_failed",
        supabase: supabaseErrorPublic(lastError),
      });
    }

    // Legacy file fallback
    return respondFromFile();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// PUT /api/referral/:referralId
// Status updates (registered/completed/cancelled). Admin only by default.
app.put("/api/referral/:referralId", requireAdminOrPatientToken, async (req, res) => {
  try {
    const referralId = String(req.params.referralId || "").trim();
    if (!referralId) return res.status(400).json({ ok: false, error: "referral_id_required" });
    if (!req.isAdmin) return res.status(403).json({ ok: false, error: "forbidden" });
    if (!isSupabaseEnabled()) return res.status(500).json({ ok: false, error: "supabase_disabled" });

    const body = isPlainObject(req.body) ? req.body : {};
    const nextStatus = body.status ? String(body.status).trim().toLowerCase() : "";
    const allowed = new Set(["invited", "registered", "completed", "cancelled"]);
    if (!allowed.has(nextStatus)) {
      return res.status(400).json({ ok: false, error: "invalid_status" });
    }

    const update = {
      status: nextStatus,
      ...(body.reward_amount !== undefined ? { reward_amount: body.reward_amount } : {}),
      ...(body.reward_currency ? { reward_currency: String(body.reward_currency).trim().toUpperCase() } : {}),
      ...(nextStatus === "completed" ? { completed_at: new Date().toISOString() } : {}),
      updated_at: new Date().toISOString(),
    };

    let q = supabase.from("referrals").update(update).eq("id", referralId);
    if (req.clinicId) q = q.eq("clinic_id", req.clinicId);

    const { data, error } = await q.select("*").single();
    if (error) {
      console.error("[REFERRAL] Supabase save failed", {
        message: error.message,
        code: error.code,
        details: error.details,
      });
      return res.status(500).json({ ok: false, error: "referral_update_failed" });
    }

    return res.json({ ok: true, item: mapReferralRowToLegacyItem(data), referral: data });
  } catch (e) {

    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// PATCH /api/admin/referrals/:id/approve
app.patch("/api/admin/referrals/:id/approve", requireAdminAuth, async (req, res) => {
  try {
    const { id } = req.params;
    const body = req.body || {};
    
    // PRODUCTION: Clinic isolation - use req.clinic.id
    if (!req.clinic || !req.clinicId) {
      return res.status(403).json({ ok: false, error: "clinic_not_authenticated" });
    }
    
    // PRODUCTION: Discount validation - 0-50% range (server-side)
    const inviterDiscountPercent = body.inviterDiscountPercent != null ? Number(body.inviterDiscountPercent) : null;
    const invitedDiscountPercent = body.invitedDiscountPercent != null ? Number(body.invitedDiscountPercent) : null;
    const discountPercent = body.discountPercent != null ? Number(body.discountPercent) : null;
    
    // Validasyon - 0-50% range (fraud prevention)
    if (inviterDiscountPercent != null && (Number.isNaN(inviterDiscountPercent) || inviterDiscountPercent < 0 || inviterDiscountPercent > 50)) {
      return res.status(400).json({ ok: false, error: "inviterDiscountPercent must be 0..50" });
    }
    if (invitedDiscountPercent != null && (Number.isNaN(invitedDiscountPercent) || invitedDiscountPercent < 0 || invitedDiscountPercent > 50)) {
      return res.status(400).json({ ok: false, error: "invitedDiscountPercent must be 0..50" });
    }
    if (discountPercent != null && (Number.isNaN(discountPercent) || discountPercent < 0 || discountPercent > 50)) {
      return res.status(400).json({ ok: false, error: "discountPercent must be 0..50" });
    }
    
    // SUPABASE: Primary source of truth
    if (isSupabaseEnabled()) {
      try {
        // Get referral from Supabase



        
        const { data: referral, error: fetchError } = await supabase
          .from('referrals')
          .select('*')
          .eq('id', id)
          .eq('clinic_id', req.clinicId) // CRITICAL: Clinic isolation
          .single();
        
        if (fetchError || !referral) {


          throw new Error("supabase_referral_not_found");
        }
        
        // PRODUCTION: Self-referral check
        if (referral.inviter_patient_id === referral.invited_patient_id) {
          return res.status(400).json({ ok: false, error: "self_referral_forbidden", message: "Kendi kendine referral yapılamaz." });
        }
        
        // PRODUCTION: State machine - only PENDING can be approved
        const currentStatus = String(referral.status || "").toUpperCase();
        if (!["PENDING", "INVITED", "REGISTERED"].includes(currentStatus)) {
          return res.status(409).json({ ok: false, error: "invalid_state_transition", message: `Sadece PENDING/INVITED/REGISTERED durumundaki referral onaylanabilir. Mevcut durum: ${referral.status}` });
        }
        
        const clinic = req.clinic || {};
        const referralLevels = normalizeReferralLevels(
          clinic?.settings?.referralLevels || clinic?.referralLevels || {},
          {
            level1: clinic.defaultInviterDiscountPercent ?? null,
            level2: null,
            level3: null,
          }
        );
        const referralLevelError = validateReferralLevels(referralLevels);
        if (referralLevelError) {
          return res.status(400).json({ ok: false, error: referralLevelError });
        }

        const inviterId = referral.inviter_patient_id || referral.referrer_patient_id;
        const invitedId = referral.invited_patient_id || referral.referred_patient_id;
        const inviterCountBefore = await countSuccessfulReferrals(inviterId, req.clinicId);
        const inviterCountAfter = inviterCountBefore + 1;
        const inviterPercentAfter = levelPercentForCount(inviterCountAfter, referralLevels);

        const finalInviterPercent = inviterDiscountPercent ?? inviterPercentAfter;
        const finalInvitedPercent = invitedDiscountPercent ?? inviterPercentAfter;
        const finalDiscountPercent = discountPercent ?? inviterPercentAfter;

        if (finalInviterPercent == null || finalInvitedPercent == null) {
          return res.status(400).json({
            ok: false,
            error: "Default discount percentages must be entered in Clinic Settings page",
          });
        }
        
        if (finalInviterPercent == null && finalInvitedPercent == null) {
          finalInviterPercent = finalDiscountPercent;
          finalInvitedPercent = finalDiscountPercent;
        } else if (finalInviterPercent == null) {
          finalInviterPercent = finalInvitedPercent;
        } else if (finalInvitedPercent == null) {
          finalInvitedPercent = finalInviterPercent;
        }
        
        if (finalDiscountPercent == null) {
          finalDiscountPercent = Math.round((finalInviterPercent + finalInvitedPercent) / 2);
        }
        
        // Update in Supabase
        const { data: updated, error: updateError } = await supabase
          .from('referrals')
          .update({
            status: 'APPROVED',
            inviter_discount_percent: finalInviterPercent,
            invited_discount_percent: finalInvitedPercent,
            discount_percent: finalDiscountPercent,
            approved_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
          })
          .eq('id', id)
          .eq('clinic_id', req.clinicId) // CRITICAL: Clinic isolation
          .select()
          .single();
        
        if (updateError) {

          return res.status(500).json({ ok: false, error: "update_failed" });
        }
        


        // Update referral_state for inviter and invited
        const inviterPatient = await getPatientById(inviterId);
        const invitedPatient = await getPatientById(invitedId);
        const inviterState = normalizeReferralState(inviterPatient?.referral_state);
        const invitedState = normalizeReferralState(invitedPatient?.referral_state);

        const cap = referralLevels.level3 ?? referralLevels.level2 ?? referralLevels.level1 ?? 0;
        const inviterNext = computeReferralTotals(
          {
            ...inviterState,
            earnedDiscountPercent: finalInviterPercent,
          },
          cap
        );
        const invitedNext = computeReferralTotals(
          {
            ...invitedState,
            baseDiscountPercent: Math.max(invitedState.baseDiscountPercent, finalInvitedPercent),
          },
          cap
        );

        await updatePatientReferralState(inviterId, inviterNext);
        await updatePatientReferralState(invitedId, invitedNext);
        
        // TODO: Audit log - referral_approved event
        
        return res.json({ ok: true, item: updated });
      } catch (supabaseError) {

        // Fall through to file-based
      }
    }
    
    // FILE-BASED: Fallback
    const raw = readJson(REF_FILE, []);
    const list = Array.isArray(raw) ? raw : Object.values(raw);
    const idx = list.findIndex((x) => x && x.id === id);
    
    if (idx < 0) {
      return res.status(404).json({ ok: false, error: "referral_not_found" });
    }
    
    const referral = list[idx];
    
    // PRODUCTION: Self-referral check
    if (referral.inviterPatientId === referral.invitedPatientId) {
      return res.status(400).json({ ok: false, error: "self_referral_forbidden", message: "Kendi kendine referral yapılamaz." });
    }
    
    // PRODUCTION: State machine - only PENDING can be approved
    const fileStatus = String(referral.status || "").toUpperCase();
    if (!["PENDING", "INVITED", "REGISTERED"].includes(fileStatus)) {
      return res.status(409).json({ ok: false, error: "invalid_state_transition", message: `Sadece PENDING/INVITED/REGISTERED durumundaki referral onaylanabilir. Mevcut durum: ${referral.status}` });
    }
    
    const clinic = req.clinic || {};
    const referralLevels = normalizeReferralLevels(
      clinic?.settings?.referralLevels || clinic?.referralLevels || {},
      {
        level1: clinic.defaultInviterDiscountPercent ?? null,
        level2: null,
        level3: null,
      }
    );
    const referralLevelError = validateReferralLevels(referralLevels);
    if (referralLevelError) {
      return res.status(400).json({ ok: false, error: referralLevelError });
    }

    const inviterCountBefore = countSuccessfulReferralsFile(list, referral.inviterPatientId);
    const inviterPercentAfter = levelPercentForCount(inviterCountBefore + 1, referralLevels);

    let finalInviterPercent = inviterDiscountPercent ?? inviterPercentAfter;
    let finalInvitedPercent = invitedDiscountPercent ?? inviterPercentAfter;
    let finalDiscountPercent = discountPercent ?? inviterPercentAfter;

    if (finalInviterPercent == null || finalInvitedPercent == null) {
      return res.status(400).json({
        ok: false,
        error: "Default discount percentages must be entered in Clinic Settings page",
      });
    }

    // Güncelleme
    const updated = {
      ...list[idx],
      status: "APPROVED",
      approvedAt: now(),
    };
    
    // Yeni format varsa onu kullan
    if (finalInviterPercent != null || finalInvitedPercent != null) {
      updated.inviterDiscountPercent = finalInviterPercent;
      updated.invitedDiscountPercent = finalInvitedPercent;
      if (finalDiscountPercent != null) {
        updated.discountPercent = finalDiscountPercent;
      } else if (finalInviterPercent != null && finalInvitedPercent != null) {
        updated.discountPercent = Math.round((finalInviterPercent + finalInvitedPercent) / 2);
      } else {
        updated.discountPercent = finalInviterPercent ?? finalInvitedPercent;
      }
    } else if (finalDiscountPercent != null) {
      updated.discountPercent = finalDiscountPercent;
      updated.inviterDiscountPercent = finalDiscountPercent;
      updated.invitedDiscountPercent = finalDiscountPercent;
    }
    
    list[idx] = updated;
    writeJson(REF_FILE, list);
    
    res.json({ ok: true, item: updated });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// PATCH /api/admin/referrals/:id/reject
app.patch("/api/admin/referrals/:id/reject", requireAdminAuth, async (req, res) => {
  try {






    
    const { id } = req.params;
    
    // PRODUCTION: Clinic isolation - use req.clinic.id
    if (!req.clinic || !req.clinicId) {
      return res.status(403).json({ ok: false, error: "clinic_not_authenticated" });
    }
    
    // SUPABASE: Primary source of truth
    if (isSupabaseEnabled()) {
      try {
        // Get referral from Supabase


        
        const { data: referral, error: fetchError } = await supabase
          .from('referrals')
          .select('*')
          .eq('id', id)
          .eq('clinic_id', req.clinicId) // CRITICAL: Clinic isolation
          .single();
        
        if (fetchError || !referral) {

          throw new Error("supabase_referral_not_found");
        }
        
        // PRODUCTION: State machine - only PENDING can be rejected
        const currentStatus = String(referral.status || "").toUpperCase();
        if (!["PENDING", "INVITED", "REGISTERED"].includes(currentStatus)) {
          return res.status(409).json({ ok: false, error: "invalid_state_transition", message: `Sadece PENDING/INVITED/REGISTERED durumundaki referral reddedilebilir. Mevcut durum: ${referral.status}` });
        }
        
        // Update in Supabase



        
        const updateData = {
          status: 'REJECTED',
          inviter_discount_percent: null,
          invited_discount_percent: null,
          discount_percent: null,
          approved_at: null,
          updated_at: new Date().toISOString()
        };
        

        
        const { data: updated, error: updateError } = await supabase
          .from('referrals')
          .update(updateData)
          .eq('id', id)
          .eq('clinic_id', req.clinicId) // CRITICAL: Clinic isolation
          .select()
          .single();
        
        if (updateError) {
          console.error(`[REFERRAL REJECT] Supabase error:`, {
            error: updateError,
            message: updateError.message,
            details: updateError.details,
            code: updateError.code,
            hint: updateError.hint
          });
          return res.status(500).json({ 
            ok: false, 
            error: "update_failed", 
            message: updateError.message || "Failed to reject referral",
            details: updateError.details
          });
        }
        

        
        // TODO: Audit log - referral_rejected event
        
        return res.json({ ok: true, item: updated });
      } catch (supabaseError) {

        // Fall through to file-based
      }
    }
    
    // FILE-BASED: Fallback
    const raw = readJson(REF_FILE, []);
    const list = Array.isArray(raw) ? raw : Object.values(raw);
    const idx = list.findIndex((x) => x && x.id === id);
    
    if (idx < 0) {
      return res.status(404).json({ ok: false, error: "referral_not_found" });
    }
    
    // PRODUCTION: State machine - only PENDING/INVITED/REGISTERED can be rejected
    const fileStatus = String(list[idx].status || "").toUpperCase();
    if (!["PENDING", "INVITED", "REGISTERED"].includes(fileStatus)) {
      return res.status(409).json({ ok: false, error: "invalid_state_transition", message: `Sadece PENDING/INVITED/REGISTERED durumundaki referral reddedilebilir. Mevcut durum: ${list[idx].status}` });
    }
    
    list[idx] = {
      ...list[idx],
      status: "REJECTED",
      discountPercent: null,
      inviterDiscountPercent: null,
      invitedDiscountPercent: null,
      approvedAt: null,
      rejectedAt: now(),
    };
    
    writeJson(REF_FILE, list);
    res.json({ ok: true, item: list[idx] });
  } catch (error) {






    
    res.status(500).json({ 
      ok: false, 
      error: error?.message || "internal_error",
      details: error?.stack
    });
  }
});

// ================== REFERRAL EVENTS (Model 1: Invitee-based cap) ==================
// ReferralEvent: Payment-based referral system
// earned_discount = invitee_paid_amount * INVITER_RATE
// invitee_discount = invitee_paid_amount * INVITEE_RATE

// Helper: Round to currency (2 decimals)
function roundToCurrency(amount) {
  return Math.round(amount * 100) / 100;
}

// POST /api/referrals/payment-event
// Called when invitee payment is completed (PAID/CAPTURED status)
app.post("/api/referrals/payment-event", async (req, res) => {
  try {
    const {
      inviteePatientId,
      inviteePaymentId,
      inviteePaidAmount,
      inviterPaidAmount,
      currency = "USD",
      paymentStatus = "PAID",
    } = req.body || {};
    
    if (!inviteePatientId || !inviteePaymentId || !inviteePaidAmount) {
      return res.status(400).json({ ok: false, error: "missing_required_fields" });
    }
    
    const paidAmount = Number(inviteePaidAmount);
    if (isNaN(paidAmount) || paidAmount <= 0) {
      return res.status(400).json({ ok: false, error: "invalid_paid_amount" });
    }
    const inviterAmount = inviterPaidAmount != null ? Number(inviterPaidAmount) : null;
    if (inviterAmount != null && (isNaN(inviterAmount) || inviterAmount <= 0)) {
      return res.status(400).json({ ok: false, error: "invalid_inviter_paid_amount" });
    }
    
    // Only process PAID/CAPTURED payments
    if (paymentStatus !== "PAID" && paymentStatus !== "CAPTURED") {
      return res.status(400).json({ ok: false, error: "payment_not_completed" });
    }
    
    const handleFileFallback = () => {
      // Find referral relationship (inviter for this invitee)
      const referrals = readJson(REF_FILE, []);
      const referralList = Array.isArray(referrals) ? referrals : Object.values(referrals);
      
      // Find the first valid referral (inviter) for this invitee
      const referral = referralList.find(
        (r) => r.invitedPatientId === inviteePatientId && r.status === "APPROVED"
      );
      
      if (!referral) {
        return res.status(404).json({ ok: false, error: "no_referral_found" });
      }
      
      // Check if event already exists for this payment
      const events = readJson(REF_EVENT_FILE, []);
      const eventList = Array.isArray(events) ? events : Object.values(events);
      
      const existingEvent = eventList.find((e) => e.inviteePaymentId === inviteePaymentId);
      if (existingEvent) {
        return res.status(409).json({ ok: false, error: "event_already_exists" });
      }
      
      // Get clinic config for rates
      const clinic = readJson(CLINIC_FILE, {});
      const referralDiscountPercent =
        referral.inviterDiscountPercent ??
        referral.discountPercent ??
        clinic.defaultInviterDiscountPercent ??
        0;
      const inviterRate = Number(referralDiscountPercent || 0) / 100;
      const inviteeRate =
        Number(
          referral.invitedDiscountPercent ??
            referral.discountPercent ??
            clinic.defaultInvitedDiscountPercent ??
            referralDiscountPercent ??
            0
        ) / 100;
      const basePaidAmount = inviterAmount != null ? Math.min(paidAmount, inviterAmount) : paidAmount;
      
      // Calculate earned discount (from invitee's paid amount)
      const earnedDiscountAmount = roundToCurrency(basePaidAmount * inviterRate);
      
      // Create referral event
      const newEvent = {
        id: rid("refevt"),
        inviterPatientId: referral.inviterPatientId,
        inviteePatientId,
        inviteePaymentId,
        inviteePaidAmount: paidAmount,
        inviterPaidAmount: inviterAmount,
        basePaidAmount,
        currency,
        inviterRate,
        inviteeRate,
        earnedDiscountAmount,
        status: "EARNED",
        createdAt: now(),
      };
      
      eventList.push(newEvent);
      writeJson(REF_EVENT_FILE, eventList);
      
      // Update inviter's credit (add to patient record)
      const patients = readJson(PAT_FILE, {});
      if (patients[referral.inviterPatientId]) {
        const inviter = patients[referral.inviterPatientId];
        inviter.referralCredit = (inviter.referralCredit || 0) + earnedDiscountAmount;
        inviter.referralCreditUpdatedAt = now();
        writeJson(PAT_FILE, patients);
      }
      

      
      return res.json({ ok: true, event: newEvent });
    };

    if (isSupabaseEnabled()) {
      try {
        const { data: referrals, error: referralError } = await supabase
          .from("referrals")
          .select("*")
          .eq("invited_patient_id", inviteePatientId)
          .eq("status", "APPROVED")
          .order("created_at", { ascending: false })
          .limit(1);

        if (referralError) {
          if (isMissingTableError(referralError, "referrals") && canUseFileFallback()) {

            return handleFileFallback();
          }
          return res.status(500).json({
            ok: false,
            error: "referral_fetch_failed",
            supabase: supabaseErrorPublic(referralError),
          });
        }

        const referral = Array.isArray(referrals) ? referrals[0] : null;
        if (!referral) {
          return res.status(404).json({ ok: false, error: "no_referral_found" });
        }

        const { data: existing, error: existingError } = await supabase
          .from("referral_events")
          .select("id")
          .eq("invitee_payment_id", inviteePaymentId)
          .limit(1);

        if (existingError) {
          if (isMissingTableError(existingError, "referral_events") && canUseFileFallback()) {

            return handleFileFallback();
          }
          return res.status(500).json({
            ok: false,
            error: "referral_event_fetch_failed",
            supabase: supabaseErrorPublic(existingError),
          });
        }

        if (Array.isArray(existing) && existing.length > 0) {
          return res.status(409).json({ ok: false, error: "event_already_exists" });
        }

        const clinic = referral.clinic_id ? await getClinicById(referral.clinic_id) : null;
        const clinicSettings = clinic?.settings || {};
        const referralDiscountPercent =
          referral.inviter_discount_percent ??
          referral.discount_percent ??
          clinicSettings.defaultInviterDiscountPercent ??
          0;
        const inviterRate = Number(referralDiscountPercent || 0) / 100;
        const inviteeRate =
          Number(
            referral.invited_discount_percent ??
              referral.discount_percent ??
              clinicSettings.defaultInvitedDiscountPercent ??
              referralDiscountPercent ??
              0
          ) / 100;
        const basePaidAmount = inviterAmount != null ? Math.min(paidAmount, inviterAmount) : paidAmount;
        const earnedDiscountAmount = roundToCurrency(basePaidAmount * inviterRate);

        const newEvent = {
          clinic_id: referral.clinic_id || null,
          inviter_patient_id: referral.inviter_patient_id,
          invitee_patient_id: inviteePatientId,
          invitee_payment_id: inviteePaymentId,
          invitee_paid_amount: paidAmount,
          inviter_paid_amount: inviterAmount,
          base_paid_amount: basePaidAmount,
          currency,
          inviter_rate: inviterRate,
          invitee_rate: inviteeRate,
          earned_discount_amount: earnedDiscountAmount,
          status: "EARNED",
          created_at: new Date().toISOString(),
        };

        const { data: inserted, error: insertError } = await supabase
          .from("referral_events")
          .insert(newEvent)
          .select("*")
          .single();

        if (insertError) {
          if (isMissingTableError(insertError, "referral_events") && canUseFileFallback()) {

            return handleFileFallback();
          }
          return res.status(500).json({
            ok: false,
            error: "referral_event_insert_failed",
            supabase: supabaseErrorPublic(insertError),
          });
        }

        try {
          const inviter = await getPatientById(referral.inviter_patient_id);
          const currentCredit = Number(inviter?.referral_credit || inviter?.referralCredit || 0);
          const updatedCredit = roundToCurrency(currentCredit + earnedDiscountAmount);
          const { error: creditError } = await supabase
            .from("patients")
            .update({
              referral_credit: updatedCredit,
              referral_credit_updated_at: new Date().toISOString(),
            })
            .eq("patient_id", referral.inviter_patient_id);

          if (creditError && isMissingColumnError(creditError, "referral_credit")) {

          } else if (creditError) {

          }
        } catch (creditUpdateError) {

        }


        return res.json({ ok: true, event: inserted });
      } catch (supabaseError) {

        if (canUseFileFallback()) {

          return handleFileFallback();
        }
        return res.status(500).json({ ok: false, error: "referral_event_failed" });
      }
    }

    return handleFileFallback();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// POST /api/referrals/payment-refund
// Called when invitee payment is refunded/chargeback
app.post("/api/referrals/payment-refund", async (req, res) => {
  try {
    const { inviteePaymentId } = req.body || {};
    
    if (!inviteePaymentId) {
      return res.status(400).json({ ok: false, error: "payment_id_required" });
    }

    const handleFileFallback = () => {
      // Find existing event
      const events = readJson(REF_EVENT_FILE, []);
      const eventList = Array.isArray(events) ? events : Object.values(events);
      const eventIdx = eventList.findIndex((e) => e.inviteePaymentId === inviteePaymentId && e.status === "EARNED");
      
      if (eventIdx < 0) {
        return res.status(404).json({ ok: false, error: "event_not_found" });
      }
      
      const event = eventList[eventIdx];
      
      // Reverse the event
      event.status = "REVERSED";
      event.reversedAt = now();
      eventList[eventIdx] = event;
      writeJson(REF_EVENT_FILE, eventList);
      
      // Reverse inviter's credit (subtract from patient record)
      const patients = readJson(PAT_FILE, {});
      if (patients[event.inviterPatientId]) {
        const inviter = patients[event.inviterPatientId];
        inviter.referralCredit = Math.max(0, (inviter.referralCredit || 0) - event.earnedDiscountAmount);
        inviter.referralCreditUpdatedAt = now();
        writeJson(PAT_FILE, patients);
      }
      

      
      return res.json({ ok: true, event });
    };

    if (isSupabaseEnabled()) {
      try {
        const { data: events, error: fetchError } = await supabase
          .from("referral_events")
          .select("*")
          .eq("invitee_payment_id", inviteePaymentId)
          .eq("status", "EARNED")
          .limit(1);

        if (fetchError) {
          if (isMissingTableError(fetchError, "referral_events") && canUseFileFallback()) {

            return handleFileFallback();
          }
          return res.status(500).json({
            ok: false,
            error: "referral_event_fetch_failed",
            supabase: supabaseErrorPublic(fetchError),
          });
        }

        const event = Array.isArray(events) ? events[0] : null;
        if (!event) {
          return res.status(404).json({ ok: false, error: "event_not_found" });
        }

        const { data: updated, error: updateError } = await supabase
          .from("referral_events")
          .update({ status: "REVERSED", reversed_at: new Date().toISOString() })
          .eq("id", event.id)
          .select("*")
          .single();

        if (updateError) {
          if (isMissingTableError(updateError, "referral_events") && canUseFileFallback()) {

            return handleFileFallback();
          }
          return res.status(500).json({
            ok: false,
            error: "referral_event_update_failed",
            supabase: supabaseErrorPublic(updateError),
          });
        }

        try {
          const inviter = await getPatientById(event.inviter_patient_id);
          const currentCredit = Number(inviter?.referral_credit || inviter?.referralCredit || 0);
          const updatedCredit = Math.max(0, roundToCurrency(currentCredit - Number(event.earned_discount_amount || 0)));
          const { error: creditError } = await supabase
            .from("patients")
            .update({
              referral_credit: updatedCredit,
              referral_credit_updated_at: new Date().toISOString(),
            })
            .eq("patient_id", event.inviter_patient_id);

          if (creditError && isMissingColumnError(creditError, "referral_credit")) {

          } else if (creditError) {

          }
        } catch (creditUpdateError) {

        }


        return res.json({ ok: true, event: updated });
      } catch (supabaseError) {

        if (canUseFileFallback()) {

          return handleFileFallback();
        }
        return res.status(500).json({ ok: false, error: "referral_refund_failed" });
      }
    }

    return handleFileFallback();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// GET /api/patient/:patientId/referral-credit
// Get inviter's total referral credit
app.get("/api/patient/:patientId/referral-credit", (req, res) => {
  try {
    const { patientId } = req.params;
    if (!patientId) {
      return res.status(400).json({ ok: false, error: "patient_id_required" });
    }

    const respondFromFile = () => {
      const patients = readJson(PAT_FILE, {});
      if (!patients[patientId]) {
        return res.status(404).json({ ok: false, error: "patient_not_found" });
      }
      const credit = patients[patientId].referralCredit || 0;
      return res.json({ ok: true, credit, currency: "USD" });
    };

    if (isSupabaseEnabled()) {
      getPatientById(patientId)
        .then((patient) => {
          if (!patient) {
            if (canUseFileFallback()) return respondFromFile();
            return res.status(404).json({ ok: false, error: "patient_not_found" });
          }
          if (patient.referral_credit == null && canUseFileFallback()) {
            return respondFromFile();
          }
          const credit = Number(patient.referral_credit || 0);
          return res.json({ ok: true, credit, currency: "USD" });
        })
        .catch((error) => {

          if (canUseFileFallback()) return respondFromFile();
          return res.status(500).json({ ok: false, error: "referral_credit_fetch_failed" });
        });
      return;
    }

    return respondFromFile();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// GET /api/admin/referral-events
// Get all referral events (admin view)
app.get("/api/admin/referral-events", requireAdminAuth, async (req, res) => {
  try {
    const respondFromFile = () => {
      const events = readJson(REF_EVENT_FILE, []);
      const eventList = Array.isArray(events) ? events : Object.values(events);
      eventList.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
      return res.json({ ok: true, items: eventList, source: "file" });
    };

    if (isSupabaseEnabled()) {
      const clinicId = req.clinicId || null;
      let q = supabase.from("referral_events").select("*");
      if (clinicId) q = q.eq("clinic_id", clinicId);
      const { data, error } = await q.order("created_at", { ascending: false });
      if (error) {
        if (isMissingTableError(error, "referral_events") && canUseFileFallback()) {

          return respondFromFile();
        }
        return res.status(500).json({
          ok: false,
          error: "referral_events_fetch_failed",
          supabase: supabaseErrorPublic(error),
        });
      }

      const items = (data || []).map((row) => ({
        id: row.id,
        inviterPatientId: row.inviter_patient_id,
        inviteePatientId: row.invitee_patient_id,
        inviteePaymentId: row.invitee_payment_id,
        inviteePaidAmount: row.invitee_paid_amount,
        inviterPaidAmount: row.inviter_paid_amount,
        basePaidAmount: row.base_paid_amount,
        currency: row.currency,
        inviterRate: row.inviter_rate,
        inviteeRate: row.invitee_rate,
        earnedDiscountAmount: row.earned_discount_amount,
        status: row.status,
        createdAt: row.created_at ? new Date(row.created_at).getTime() : null,
        reversedAt: row.reversed_at ? new Date(row.reversed_at).getTime() : null,
      }));

      return res.json({ ok: true, items, source: "supabase" });
    }

    return respondFromFile();
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// GET /api/admin/events
// Get all events from all patients (travel events + treatment events)
// Filters: upcoming (next 14 days, excluding today), overdue (past but not completed)
app.get("/api/admin/appointments", requireAdminAuth, async (req, res) => {
  try {
    const date = String(req.query.date || "").trim();
    const startDate = String(req.query.startDate || "").trim();
    const endDate = String(req.query.endDate || "").trim();

    const isSingleDate = /^\d{4}-\d{2}-\d{2}$/.test(date);
    const isRange = /^\d{4}-\d{2}-\d{2}$/.test(startDate) && /^\d{4}-\d{2}-\d{2}$/.test(endDate);

    if (!isSingleDate && !isRange) {
      return res.status(400).json({
        ok: false,
        error: "invalid_date",
        message: "Use query param 'date' (YYYY-MM-DD) or 'startDate'+'endDate' (YYYY-MM-DD)",
      });
    }

    if (isRange && startDate > endDate) {
      return res.status(400).json({ ok: false, error: "invalid_date_range", message: "startDate must be <= endDate" });
    }

    const rangeStartDate = isSingleDate ? date : startDate;
    const rangeEndDate = isSingleDate ? date : endDate;

    if (!isSupabaseEnabled()) {
      return res.json({
        ok: true,
        ...(isSingleDate ? { date: rangeStartDate } : { startDate: rangeStartDate, endDate: rangeEndDate }),
        appointments: [],
      });
    }

    const dayStartIso = `${rangeStartDate}T00:00:00.000Z`;
    const rangeEndIsoBase = `${rangeEndDate}T00:00:00.000Z`;
    const dayEndDate = new Date(rangeEndIsoBase);
    if (Number.isNaN(dayEndDate.getTime()) || Number.isNaN(Date.parse(dayStartIso))) {
      return res.status(400).json({ ok: false, error: "invalid_date" });
    }
    dayEndDate.setUTCDate(dayEndDate.getUTCDate() + 1);
    const dayEndIso = dayEndDate.toISOString();

    const clinicPatientIds = new Set();
    try {
      const patientAttempts = [
        () => supabase.from("patients").select("id,patient_id").eq("clinic_id", req.clinicId),
        () => req.clinicCode ? supabase.from("patients").select("id,patient_id").eq("clinic_code", req.clinicCode) : Promise.resolve({ data: [], error: null }),
      ];
      for (const run of patientAttempts) {
        const { data, error } = await run();
        if (error) continue;
        (data || []).forEach((p) => {
          if (p?.id) clinicPatientIds.add(String(p.id));
          if (p?.patient_id) clinicPatientIds.add(String(p.patient_id));
        });
        if (clinicPatientIds.size > 0) break;
      }
    } catch (e) {
      console.warn("[ADMIN APPOINTMENTS] clinic patient preload skipped:", e?.message || e);
    }

    const runTableFetch = async (tableName) => {
      const idList = Array.from(clinicPatientIds);
      const safePatientList = idList.slice(0, 1000);
      const attempts = [];
      const pushStartAtRangeAttempts = (builder) => {
        attempts.push(() => builder().gte("start_at", dayStartIso).lt("start_at", dayEndIso));
        attempts.push(() => builder().gte("startAt", dayStartIso).lt("startAt", dayEndIso));
      };

      if (isSingleDate) {
        attempts.push(() => supabase.from(tableName).select("*").eq("clinic_id", req.clinicId).eq("date", rangeStartDate));
        attempts.push(() => supabase.from(tableName).select("*").eq("clinic_id", req.clinicId).eq("appointment_date", rangeStartDate));
      } else {
        attempts.push(() => supabase.from(tableName).select("*").eq("clinic_id", req.clinicId).gte("date", rangeStartDate).lte("date", rangeEndDate));
        attempts.push(() => supabase.from(tableName).select("*").eq("clinic_id", req.clinicId).gte("appointment_date", rangeStartDate).lte("appointment_date", rangeEndDate));
      }

      pushStartAtRangeAttempts(() => supabase.from(tableName).select("*").eq("clinic_id", req.clinicId));

      if (req.clinicCode) {
        if (isSingleDate) {
          attempts.push(() => supabase.from(tableName).select("*").eq("clinic_code", req.clinicCode).eq("date", rangeStartDate));
          attempts.push(() => supabase.from(tableName).select("*").eq("clinic_code", req.clinicCode).eq("appointment_date", rangeStartDate));
        } else {
          attempts.push(() => supabase.from(tableName).select("*").eq("clinic_code", req.clinicCode).gte("date", rangeStartDate).lte("date", rangeEndDate));
          attempts.push(() => supabase.from(tableName).select("*").eq("clinic_code", req.clinicCode).gte("appointment_date", rangeStartDate).lte("appointment_date", rangeEndDate));
        }
        pushStartAtRangeAttempts(() => supabase.from(tableName).select("*").eq("clinic_code", req.clinicCode));
      }

      if (safePatientList.length) {
        if (isSingleDate) {
          attempts.push(() => supabase.from(tableName).select("*").in("patient_id", safePatientList).eq("date", rangeStartDate));
          attempts.push(() => supabase.from(tableName).select("*").in("patient_id", safePatientList).eq("appointment_date", rangeStartDate));
        } else {
          attempts.push(() => supabase.from(tableName).select("*").in("patient_id", safePatientList).gte("date", rangeStartDate).lte("date", rangeEndDate));
          attempts.push(() => supabase.from(tableName).select("*").in("patient_id", safePatientList).gte("appointment_date", rangeStartDate).lte("appointment_date", rangeEndDate));
        }

        pushStartAtRangeAttempts(() => supabase.from(tableName).select("*").in("patient_id", safePatientList));
      }

      let rows = null;
      let lastError = null;
      let sawNonSchemaError = false;
      for (const run of attempts) {
        const { data, error } = await run();
        if (!error) {
          rows = Array.isArray(data) ? data : [];
          break;
        }
        const msg = String(error?.message || "").toLowerCase();
        const code = String(error?.code || "");
        const isMissingTable = msg.includes("does not exist") || code === "42P01";
        const isSchemaMismatch = code === "42703" || code === "PGRST204" || msg.includes("column") || msg.includes("schema cache");

        if (isMissingTable) {
          return [];
        }

        if (isSchemaMismatch) {
          lastError = error;
          continue;
        }

        sawNonSchemaError = true;
        lastError = error;
      }

      if (rows === null) {
        if (!sawNonSchemaError) {
          console.warn(`[ADMIN APPOINTMENTS] ${tableName} schema mismatch, returning empty`, lastError?.message || lastError);
          return [];
        }
        console.error(`[ADMIN APPOINTMENTS] ${tableName} query failed`, lastError);
        throw new Error(`${tableName}_query_failed`);
      }
      return rows;
    };

    const appointmentRows = await runTableFetch("appointments");
    const requestRows = await runTableFetch("appointment_requests");
    const rows = [...appointmentRows, ...requestRows];

    const getField = (obj, keys) => {
      for (const key of keys) {
        if (obj && obj[key] !== undefined && obj[key] !== null && obj[key] !== "") {
          return obj[key];
        }
      }
      return null;
    };

    const doctorIds = [...new Set(rows.map((row) => String(getField(row, ["doctor_id", "doctorId", "doctor"]) || "")).filter(Boolean))];
    const patientIds = [...new Set(rows.map((row) => String(getField(row, ["patient_id", "patientId", "patient"]) || "")).filter(Boolean))];
    const chairIds = [...new Set(rows.map((row) => String(getField(row, ["chair_id", "chairId", "chair"]) || "")).filter(Boolean))];

    const doctorMap = new Map();
    const patientMap = new Map();
    const chairMap = new Map();

    if (doctorIds.length) {
      const doctorAttempts = [
        () => supabase.from("doctors").select("id,name,full_name,email").in("id", doctorIds),
        () => supabase.from("doctors").select("doctor_id,name,full_name,email").in("doctor_id", doctorIds),
      ];
      for (const run of doctorAttempts) {
        const { data, error } = await run();
        if (error) continue;
        (data || []).forEach((doc) => {
          const key = String(getField(doc, ["id", "doctor_id"]) || "");
          const label = String(getField(doc, ["name", "full_name", "email", "id", "doctor_id"]) || "");
          if (key && label) doctorMap.set(key, label);
        });
        break;
      }
    }

    if (patientIds.length) {
      const patientAttempts = [
        () => supabase.from("patients").select("id,patient_id,name,full_name,email").in("id", patientIds),
        () => supabase.from("patients").select("id,patient_id,name,full_name,email").in("patient_id", patientIds),
        () => supabase.from("patients").select("id,patient_id,name,email").in("id", patientIds),
        () => supabase.from("patients").select("id,patient_id,name,email").in("patient_id", patientIds),
      ];
      for (const run of patientAttempts) {
        const { data, error } = await run();
        if (error) continue;
        (data || []).forEach((p) => {
          const keyA = String(getField(p, ["id"]) || "");
          const keyB = String(getField(p, ["patient_id"]) || "");
          const label = String(getField(p, ["name", "full_name", "email", "patient_id", "id"]) || "");
          if (keyA && label) patientMap.set(keyA, label);
          if (keyB && label) patientMap.set(keyB, label);
        });
        break;
      }
    }

    if (chairIds.length) {
      const chairAttempts = [
        () => supabase.from("chairs").select("id,name,label,chair_number").in("id", chairIds),
        () => supabase.from("chairs").select("chair_id,name,label,chair_number").in("chair_id", chairIds),
      ];
      for (const run of chairAttempts) {
        const { data, error } = await run();
        if (error) continue;
        (data || []).forEach((c) => {
          const key = String(getField(c, ["id", "chair_id"]) || "");
          const label = String(getField(c, ["name", "label", "chair_number", "id", "chair_id"]) || "");
          if (key && label) chairMap.set(key, label);
        });
        break;
      }
    }

    const appointments = rows
      .map((row) => {
        const doctorId = String(getField(row, ["doctor_id", "doctorId"]) || "");
        const patientId = String(getField(row, ["patient_id", "patientId"]) || "");
        const chairId = String(getField(row, ["chair_id", "chairId"]) || "");

        const toIsoSafe = (value) => {
          if (!value) return null;
          const ts = Date.parse(String(value));
          if (!Number.isFinite(ts)) return null;
          return new Date(ts).toISOString();
        };

        const startAt = getField(row, ["start_at", "startAt", "starts_at"]) ||
          (getField(row, ["date"]) ? (() => {
            const datePart = String(getField(row, ["date"]));
            const timeRaw = String(getField(row, ["time"]) || "00:00");
            const timePart = /^\d{2}:\d{2}$/.test(timeRaw) ? `${timeRaw}:00` : timeRaw;
            return `${datePart}T${timePart}`;
          })() : null);
        const endAt = getField(row, ["end_at", "endAt", "ends_at"]) || null;
        const status = String(getField(row, ["status"]) || "UNKNOWN").toUpperCase();
        const treatment = String(getField(row, [
          "treatment_code",
          "treatment_name",
          "procedure_code",
          "procedure_name",
          "appointment_type",
          "service",
          "type",
          "procedure",
        ]) || "").trim();
        const durationMinutes = parseMinuteValue(getField(row, [
          "duration_minutes",
          "estimated_duration_minutes",
          "duration",
          "estimated_duration",
        ]), 0);
        const breakMinutes = parseMinuteValue(getField(row, [
          "break_minutes",
          "rest_minutes",
          "break_duration",
          "pause_minutes",
        ]), 0);

        const toothRaw = getField(row, [
          "tooth_number",
          "toothNumber",
          "tooth_fdi_code",
          "fdi_tooth",
          "fdiTooth",
          "tooth",
          "tooth_id",
          "toothId",
          "toothID",
        ]);
        const tooth_number = (() => {
          if (toothRaw == null || toothRaw === "") return "";
          const s = String(toothRaw).trim();
          const digits = s.replace(/\D/g, "");
          const n = digits.length >= 2 ? Number.parseInt(digits.slice(0, 2), 10) : NaN;
          if (Number.isFinite(n) && n >= 11 && n <= 48) return String(n);
          return s;
        })();

        const appointmentDate = (() => {
          const directDate = getField(row, ["date", "appointment_date"]);
          if (directDate) return String(directDate).slice(0, 10);
          const t = startAt ? Date.parse(String(startAt)) : NaN;
          if (Number.isFinite(t)) return new Date(t).toISOString().slice(0, 10);
          return "";
        })();

        return {
          doctor: String(getField(row, ["doctor", "doctor_name", "doctorName"]) || doctorMap.get(doctorId) || doctorId || ""),
          patient: String(getField(row, ["patient", "patient_name", "patientName"]) || patientMap.get(patientId) || patientId || ""),
          chair: String(getField(row, ["chair", "chair_name", "chairName"]) || chairMap.get(chairId) || chairId || ""),
          startAt: toIsoSafe(startAt),
          endAt: toIsoSafe(endAt),
          status,
          treatment,
          ...(tooth_number ? { tooth_number } : {}),
          duration_minutes: durationMinutes,
          break_minutes: breakMinutes,
          _appointmentDate: appointmentDate,
        };
      })
      .filter((item) => {
        if (isSingleDate) return item._appointmentDate === rangeStartDate;
        return item._appointmentDate >= rangeStartDate && item._appointmentDate <= rangeEndDate;
      })
      .sort((a, b) => {
        const at = a.startAt ? Date.parse(a.startAt) : 0;
        const bt = b.startAt ? Date.parse(b.startAt) : 0;
        return at - bt;
      })
      .map(({ _appointmentDate, ...item }) => item);

    return res.json({
      ok: true,
      ...(isSingleDate ? { date: rangeStartDate } : { startDate: rangeStartDate, endDate: rangeEndDate }),
      appointments,
    });
  } catch (error) {
    console.error("[ADMIN APPOINTMENTS] Error:", error);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

app.get("/api/admin/events", requireAdminAuth, async (req, res) => {
  try {
    const clinicCode = String(req.clinicCode || "").trim().toUpperCase();
    if (!clinicCode) {
      return res.status(401).json({ ok: false, error: "clinic_required" });
    }

    const startDate = String(req.query.startDate || "").trim();
    const endDate = String(req.query.endDate || "").trim();
    const hasRangeFilter =
      /^\d{4}-\d{2}-\d{2}$/.test(startDate) &&
      /^\d{4}-\d{2}-\d{2}$/.test(endDate);

    if ((startDate || endDate) && !hasRangeFilter) {
      return res.status(400).json({
        ok: false,
        error: "invalid_date_range",
        message: "Use startDate and endDate in YYYY-MM-DD format",
      });
    }

    if (hasRangeFilter && startDate > endDate) {
      return res.status(400).json({
        ok: false,
        error: "invalid_date_range",
        message: "startDate must be <= endDate",
      });
    }

    const rangeStartTs = hasRangeFilter ? Date.parse(`${startDate}T00:00:00.000Z`) : null;
    const rangeEndTs = hasRangeFilter ? Date.parse(`${endDate}T23:59:59.999Z`) : null;

    const now = Date.now();
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayStart = today.getTime();
    
    // Calculate date range for upcoming (next 14 days, excluding today)
    const upcomingEnd = new Date(today);
    upcomingEnd.setDate(upcomingEnd.getDate() + 14);
    upcomingEnd.setHours(23, 59, 59, 999);
    const upcomingEndTs = upcomingEnd.getTime();
    
    const allEvents = [];

    const toIso = (tsOrIso) => {
      if (!tsOrIso) return null;
      if (typeof tsOrIso === "string") {
        const t = Date.parse(tsOrIso);
        if (Number.isFinite(t)) return new Date(t).toISOString();
        return null;
      }
      const n = Number(tsOrIso);
      if (!Number.isFinite(n)) return null;
      return new Date(n).toISOString();
    };

    const dateTimeToIso = (dateStr, timeStr) => {
      if (!dateStr) return null;
      const time = timeStr ? String(timeStr) : "00:00";
      const iso = `${dateStr}T${time}:00`;
      const t = Date.parse(iso);
      if (!Number.isFinite(t)) return null;
      return new Date(t).toISOString();
    };

    const addEvent = (evt) => {
      const timelineAt = evt.timelineAt || evt.timeline_at || null;
      const iso = timelineAt || dateTimeToIso(evt.date, evt.time) || toIso(evt.timestamp);
      if (!iso) return;
      const ts = Date.parse(iso);
      if (hasRangeFilter) {
        const evtDateStr = String(evt?.date || "").trim();
        if (/^\d{4}-\d{2}-\d{2}$/.test(evtDateStr)) {
          if (evtDateStr < startDate || evtDateStr > endDate) return;
        } else if (Number.isFinite(ts)) {
          // Tolerate timezone shifts for events that don't carry explicit YYYY-MM-DD.
          const marginMs = 24 * 60 * 60 * 1000;
          if (ts < (rangeStartTs - marginMs) || ts > (rangeEndTs + marginMs)) return;
        }
      }
      allEvents.push({
        ...evt,
        timelineAt: iso,
        timestamp: Number.isFinite(ts) ? ts : (evt.timestamp || 0),
      });
    };

    // PRODUCTION: Supabase patients are source of truth
    if (isSupabaseEnabled() && req.clinicId) {
      const priceMap = await fetchTreatmentPricesMap(req.clinicId);
      const useFileFallback = canUseFileFallback();
      const TREATMENTS_DIR = path.join(DATA_DIR, "treatments");

      // Build events from Supabase patient JSON fields (travel / treatments / treatment_events)
      const patientSelectCandidates = [
        // With full_name + all optional columns
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id, treatments",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, doctor_id",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id, treatments",
        "id, patient_id, clinic_id, name, full_name, primary_doctor_id",
        "id, patient_id, clinic_id, name, full_name, doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, full_name, doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, full_name, doctor_id, treatments",
        "id, patient_id, clinic_id, name, full_name, doctor_id",
        "id, patient_id, clinic_id, name, full_name, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, treatments, treatment_events",
        "id, patient_id, clinic_id, name, full_name, travel, treatments",
        "id, patient_id, clinic_id, name, full_name, treatment_events",
        "id, patient_id, clinic_id, name, full_name, treatments",
        "id, patient_id, clinic_id, name, full_name",
        // Without full_name (name-only schema)
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id, treatments",
        "id, patient_id, clinic_id, name, primary_doctor_id, doctor_id",
        "id, patient_id, clinic_id, name, primary_doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, primary_doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, primary_doctor_id, treatments",
        "id, patient_id, clinic_id, name, primary_doctor_id",
        "id, patient_id, clinic_id, name, doctor_id, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, doctor_id, treatments, treatment_events",
        "id, patient_id, clinic_id, name, doctor_id, travel, treatments",
        "id, patient_id, clinic_id, name, doctor_id, treatment_events",
        "id, patient_id, clinic_id, name, doctor_id, treatments",
        "id, patient_id, clinic_id, name, doctor_id",
        "id, patient_id, clinic_id, name, travel, treatments, treatment_events",
        "id, patient_id, clinic_id, name, treatments, treatment_events",
        "id, patient_id, clinic_id, name, travel, treatments",
        "id, patient_id, clinic_id, name, treatment_events",
        "id, patient_id, clinic_id, name, treatments",
        "id, patient_id, clinic_id, name",
      ];

      let list = [];
      // Try cached clause first to avoid schema-discovery overhead on every request
      const patientClausesToTry = _eventsPatientSelectClause
        ? [_eventsPatientSelectClause, ...patientSelectCandidates.filter(c => c !== _eventsPatientSelectClause)]
        : patientSelectCandidates;
      for (const selectClause of patientClausesToTry) {
        const result = await supabase
          .from("patients")
          .select(selectClause)
          .eq("clinic_id", req.clinicId)
          .order("created_at", { ascending: false });

        if (!result.error) {
          _eventsPatientSelectClause = selectClause; // cache the working clause
          list = Array.isArray(result.data) ? result.data : [];
          break;
        }

        if (!isMissingColumnError(result.error, "travel") &&
            !isMissingColumnError(result.error, "treatments") &&
            !isMissingColumnError(result.error, "treatment_events") &&
            !["42703", "PGRST204"].includes(String(result.error.code || ""))) {
          console.error("[ADMIN EVENTS] patients query failed", result.error);
          break;
        }
      }

      const doctorNameById = new Map();
      const clinicDoctorIds = [...new Set(
        (list || [])
          .map((row) => String(row?.primary_doctor_id || row?.doctor_id || "").trim())
          .filter(Boolean)
      )];
      if (clinicDoctorIds.length > 0) {
        const doctorResult = await supabase
          .from("doctors")
          .select("id, doctor_id, name, full_name, email")
          .in("id", clinicDoctorIds);

        if (doctorResult.error && ["42703", "PGRST204"].includes(String(doctorResult.error.code || ""))) {
          const fallbackDoctorResult = await supabase
            .from("doctors")
            .select("id, doctor_id, name, full_name, email")
            .in("doctor_id", clinicDoctorIds);
          if (!fallbackDoctorResult.error) {
            (fallbackDoctorResult.data || []).forEach((doc) => {
              const keyA = String(doc?.id || "").trim();
              const keyB = String(doc?.doctor_id || "").trim();
              const label = String(doc?.name || doc?.full_name || doc?.email || keyA || keyB || "").trim();
              if (keyA && label) doctorNameById.set(keyA, label);
              if (keyB && label) doctorNameById.set(keyB, label);
            });
          }
        } else if (!doctorResult.error) {
          (doctorResult.data || []).forEach((doc) => {
            const keyA = String(doc?.id || "").trim();
            const keyB = String(doc?.doctor_id || "").trim();
            const label = String(doc?.name || doc?.full_name || doc?.email || keyA || keyB || "").trim();
            if (keyA && label) doctorNameById.set(keyA, label);
            if (keyB && label) doctorNameById.set(keyB, label);
          });
        }
      }

      console.log("[EVENTS] Fetch for clinic:", req.clinicId, "clinicCode:", req.clinicCode, "patients found:", list.length);

      // ── patient_treatments bulk query ────────────────────────────────────────
      // Doctor app saves treatments_data.teeth[].procedures[] here.
      // We build a UUID→data map so the per-patient loop can access it cheaply.
      const patientTreatmentsMap = new Map(); // patientUUID → treatments_data
      try {
        const allUuids = [...new Set(list.map((p) => String(p?.id || "").trim()).filter(Boolean))];
        for (let i = 0; i < allUuids.length; i += 50) {
          const chunk = allUuids.slice(i, i + 50);
          const { data: ptRows, error: ptErr } = await supabase
            .from("patient_treatments")
            .select("patient_id, treatments_data")
            .in("patient_id", chunk);
          if (ptErr) {
            if (!["42P01", "PGRST205", "PGRST204"].includes(String(ptErr.code || ""))) {
              console.error("[EVENTS] patient_treatments query failed:", ptErr.message);
            }
            break;
          }
          (ptRows || []).forEach((row) => {
            if (row?.treatments_data) patientTreatmentsMap.set(String(row.patient_id), row.treatments_data);
          });
        }
        console.log("[EVENTS] patient_treatments loaded for", patientTreatmentsMap.size, "patients");
      } catch (ptCatchErr) {
        console.error("[EVENTS] patient_treatments bulk fetch error:", ptCatchErr.message);
      }
      // ────────────────────────────────────────────────────────────────────────

      const UUID_RE_EVENTS = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

      // Pre-fetch all patient encounters in ONE parallel batch (avoids sequential N queries)
      const allPatientUuids = [...new Set(
        list.flatMap(p => [String(p?.id || ''), String(p?.patient_id || '')])
          .filter(id => id && UUID_RE_EVENTS.test(id))
      )];
      const encountersByPatientId = new Map(); // patientUUID → encounter[]
      if (allPatientUuids.length > 0) {
        try {
          for (let i = 0; i < allPatientUuids.length; i += 100) {
            const chunk = allPatientUuids.slice(i, i + 100);
            const { data: encRows } = await supabase
              .from('patient_encounters')
              .select('id, patient_id')
              .in('patient_id', chunk);
            (encRows || []).forEach(row => {
              const pid = String(row.patient_id || '');
              if (!encountersByPatientId.has(pid)) encountersByPatientId.set(pid, []);
              encountersByPatientId.get(pid).push(row);
            });
          }
        } catch (_) {}
      }

      // ── Batch pre-fetch treatment_plans for ALL patients ────────────────────
      // Avoids N×2 sequential treatment_plans queries inside the patient loop.
      const allEncounterIds = [...new Set(
        allPatientUuids.flatMap(uid => (encountersByPatientId.get(uid) || []).map(e => String(e.id || '')))
          .filter(Boolean)
      )];
      // patientId → Set<planId>
      const planIdsByPatientId = new Map();
      try {
        const planFetches = [];
        // by encounter_id (chunked)
        for (let i = 0; i < allEncounterIds.length; i += 100) {
          planFetches.push(
            supabase.from('treatment_plans').select('id, encounter_id, patient_id')
              .in('encounter_id', allEncounterIds.slice(i, i + 100))
          );
        }
        // by patient_id (chunked)
        for (let i = 0; i < allPatientUuids.length; i += 100) {
          planFetches.push(
            supabase.from('treatment_plans').select('id, encounter_id, patient_id')
              .in('patient_id', allPatientUuids.slice(i, i + 100))
          );
        }
        const planResults = await Promise.all(planFetches);

        // Build encounter_id → patient_id reverse lookup from encountersByPatientId
        const encIdToPatientId = new Map();
        for (const [pid, encs] of encountersByPatientId) {
          for (const enc of encs) encIdToPatientId.set(String(enc.id || ''), pid);
        }

        for (const result of planResults) {
          if (result.error) continue;
          (result.data || []).forEach(row => {
            const planId = String(row?.id || '').trim();
            if (!planId) return;
            const pid = String(row?.patient_id || encIdToPatientId.get(String(row?.encounter_id || '')) || '').trim();
            if (!pid) return;
            if (!planIdsByPatientId.has(pid)) planIdsByPatientId.set(pid, new Set());
            planIdsByPatientId.get(pid).add(planId);
          });
        }
      } catch (planBatchErr) {
        console.error('[ADMIN EVENTS] treatment_plans batch fetch error:', planBatchErr.message);
      }

      // ── Batch pre-fetch treatment_items for ALL plan IDs ────────────────────
      // Avoids N×(up to 8) sequential treatment_items queries inside the patient loop.
      const allPlanIds = [...new Set([...planIdsByPatientId.values()].flatMap(s => [...s]))];
      // planId → items[]
      const itemsByPlanId = new Map();
      if (allPlanIds.length > 0) {
        try {
          const itemsTableCandidates = _eventsItemsTableName
            ? [_eventsItemsTableName, ...['treatment_items', 'treatment_plan_items'].filter(t => t !== _eventsItemsTableName)]
            : ['treatment_items', 'treatment_plan_items'];
          const itemsSelectCandidates = _eventsItemsSelectClause
            ? [_eventsItemsSelectClause]
            : [
                "id, treatment_plan_id, tooth_fdi_code, tooth_number, procedure_code, procedure_name, status, scheduled_at, scheduled_date, due_date, appointment_at, appointment_date, date, time, doctor_id, assigned_doctor_id, chair_no, chair, created_at, updated_at",
                "id, treatment_plan_id, tooth_fdi_code, tooth_number, procedure_code, procedure_name, status, scheduled_at, scheduled_date, due_date, appointment_date, date, time, doctor_id, assigned_doctor_id, chair_no, chair, created_at, updated_at",
                "id, treatment_plan_id, tooth_fdi_code, tooth_number, procedure_code, procedure_name, status, scheduled_at, appointment_date, date, time, doctor_id, assigned_doctor_id, chair_no, chair, created_at, updated_at",
                "id, treatment_plan_id, tooth_fdi_code, tooth_number, procedure_code, procedure_name, status, created_at, updated_at",
              ];

          outer: for (const tableName of itemsTableCandidates) {
            for (const selectClause of itemsSelectCandidates) {
              // Fetch in chunks of 100 plan IDs
              let anySuccess = false;
              let anyFatalError = false;
              const chunkRows = [];
              for (let i = 0; i < allPlanIds.length; i += 100) {
                const chunk = allPlanIds.slice(i, i + 100);
                const attempt = await supabase
                  .from(tableName)
                  .select(selectClause)
                  .in('treatment_plan_id', chunk)
                  .order('created_at', { ascending: false });
                if (attempt.error) {
                  if (['42703', 'PGRST204', 'PGRST205', '42P01'].includes(String(attempt.error.code || ''))) {
                    break; // try next select/table
                  }
                  anyFatalError = true;
                  break;
                }
                anySuccess = true;
                chunkRows.push(...(attempt.data || []));
              }
              if (anySuccess && !anyFatalError) {
                _eventsItemsTableName   = tableName;
                _eventsItemsSelectClause = selectClause;
                chunkRows.forEach(item => {
                  const planId = String(item?.treatment_plan_id || '').trim();
                  if (!planId) return;
                  const itemId = String(item?.id || '').trim();
                  const override = itemId ? readTreatmentItemOverride(itemId) : null;
                  const finalItem = override ? applyTreatmentItemOverride(item, override) : item;
                  if (!itemsByPlanId.has(planId)) itemsByPlanId.set(planId, []);
                  itemsByPlanId.get(planId).push(finalItem);
                });
                break outer;
              }
            }
          }
        } catch (itemBatchErr) {
          console.error('[ADMIN EVENTS] treatment_items batch fetch error:', itemBatchErr.message);
        }
      }
      // ────────────────────────────────────────────────────────────────────────

      const encounterIdToPatientIdForDashboard = new Map();
      for (const [pid, encs] of encountersByPatientId) {
        for (const enc of encs || []) {
          const eid = String(enc?.id || "").trim();
          if (eid) encounterIdToPatientIdForDashboard.set(eid, pid);
        }
      }

      const patientRowByLookupId = new Map();
      for (const prow of list) {
        const id = String(prow?.id || "").trim();
        const pLegacy = String(prow?.patient_id || "").trim();
        if (id) patientRowByLookupId.set(id, prow);
        if (pLegacy) patientRowByLookupId.set(pLegacy, prow);
      }

      const isMirroredEncounterTreatmentProcedure = (proc) => {
        const sid = String(proc?.id || proc?.procedureId || "").trim();
        return sid.startsWith("encounter-treatment-");
      };

      // encounter_treatments (doktor uygulaması) — dashboard'ta JSON/stale mirror'dan bağımsız doğru zaman çizelgesi
      try {
        const etRows = [];
        if (allEncounterIds.length > 0) {
          for (let i = 0; i < allEncounterIds.length; i += 100) {
            const chunk = allEncounterIds.slice(i, i + 100);
            const { data: etData, error: etErr } = await supabase
              .from("encounter_treatments")
              .select(
                "id, encounter_id, tooth_number, procedure_type, status, scheduled_at, created_at, updated_at, chair, assigned_doctor_id"
              )
              .in("encounter_id", chunk);
            const ec = String(etErr?.code || "");
            if (!etErr || ["42P01", "42703", "PGRST204"].includes(ec)) {
              (etData || []).forEach((r) => etRows.push(r));
            } else {
              console.warn("[ADMIN EVENTS] encounter_treatments batch:", etErr.message);
            }
          }
        }
        for (const row of etRows) {
          const encId = String(row.encounter_id || "").trim();
          const lookupPid = encounterIdToPatientIdForDashboard.get(encId);
          if (!lookupPid) continue;
          const prow = patientRowByLookupId.get(lookupPid);
          if (!prow) continue;
          const patientId = String(prow?.patient_id || prow?.id || "").trim();
          if (!patientId) continue;
          const patientName = String(prow?.name || prow?.full_name || patientId).trim();
          const prowDoctorId = String(prow?.primary_doctor_id || prow?.doctor_id || "").trim();
          const prowDoctorName = String(doctorNameById.get(prowDoctorId) || "").trim();
          const timelineAt =
            toIso(row.scheduled_at) || toIso(row.updated_at) || toIso(row.created_at);
          if (!timelineAt) continue;
          const st = String(row.status || "").toUpperCase();
          if (st === "CANCELLED" || st === "CANCELED") continue;
          const dt = new Date(Date.parse(timelineAt));
          const assignDoc = String(row.assigned_doctor_id || "").trim();
          const docLabel = String(doctorNameById.get(assignDoc) || prowDoctorName || "").trim();
          const procChair = String(row.chair || "").trim();
          const procType = String(row.procedure_type || "TREATMENT").trim();
          const toothNum = row.tooth_number;
          const normalizedLabel = mapEncounterTreatmentStatusToPatientJsonStatus(row.status);
          const enriched = applyEventPrices(
            [
              {
                id: `encounter_treatment_${row.id}`,
                patientId,
                patient: patientName,
                patientName,
                doctor: docLabel,
                chair: procChair,
                type: "TREATMENT",
                eventType: procType,
                treatment: procType,
                title: `${procType} - Tooth ${toothNum}`,
                description: "",
                date: dt.toISOString().split("T")[0],
                time: null,
                status: procedures.normalizeStatus(normalizedLabel),
                source: "encounter_treatments",
                toothId: toothNum != null ? String(toothNum) : undefined,
                timelineAt,
              },
            ],
            priceMap
          )[0];
          addEvent(enriched);
        }
      } catch (etDashErr) {
        console.warn("[ADMIN EVENTS] encounter_treatments dashboard merge:", etDashErr?.message || etDashErr);
      }

      for (const p of list) {
        const patientId = String(p?.patient_id || p?.id || "").trim();
        if (!patientId) continue;
        const patientName = String(p?.name || p?.full_name || patientId).trim();
        const patientDoctorId = String(p?.primary_doctor_id || p?.doctor_id || "").trim();
        const patientDoctorName = String(doctorNameById.get(patientDoctorId) || "").trim();
        // Only include UUID-format IDs for queries that expect UUID columns (e.g. patient_encounters)
        const patientLookupIds = [
          String(p?.id || "").trim(),
          String(p?.patient_id || "").trim(),
        ].filter(id => id && UUID_RE_EVENTS.test(id));

        // TRAVEL (null-safe)
        const travel = p?.travel || {};
        // travel.events
        if (Array.isArray(travel?.events)) {
          travel.events.forEach((e) => {
            const iso = dateTimeToIso(e?.date, e?.time);
            if (!iso) return;
            addEvent({
              id: e.id || `travel_${patientId}_${iso}`,
              patientId,
              type: "TRAVEL_EVENT",
              eventType: e.type || "TRAVEL",
              title: e.title || "",
              description: e.desc || "",
              date: e.date,
              time: e.time || "",
              status: "PLANNED",
              source: "travel",
              timelineAt: iso,
            });
          });
        }

        // hotel check-in/out
        if (travel?.hotel && travel.hotel.name) {
          if (travel.hotel.checkIn) {
            const iso = dateTimeToIso(travel.hotel.checkIn, "00:00");
            if (iso) addEvent({
              id: `hotel_checkin_${patientId}_${iso}`,
              patientId,
              type: "HOTEL",
              eventType: "CHECKIN",
              title: `Otel Giriş: ${travel.hotel.name}`,
              description: travel.hotel.address || "",
              date: travel.hotel.checkIn,
              time: "",
              status: "PLANNED",
              source: "travel",
              timelineAt: iso,
            });
          }
          if (travel.hotel.checkOut) {
            const iso = dateTimeToIso(travel.hotel.checkOut, "00:00");
            if (iso) addEvent({
              id: `hotel_checkout_${patientId}_${iso}`,
              patientId,
              type: "HOTEL",
              eventType: "CHECKOUT",
              title: `Otel Çıkış: ${travel.hotel.name}`,
              description: travel.hotel.address || "",
              date: travel.hotel.checkOut,
              time: "",
              status: "PLANNED",
              source: "travel",
              timelineAt: iso,
            });
          }
        }

        // flights
        if (Array.isArray(travel?.flights)) {
          travel.flights.forEach((f) => {
            const iso = dateTimeToIso(f?.date, f?.time);
            if (!iso) return;
            addEvent({
              id: f.id || `flight_${patientId}_${iso}`,
              patientId,
              type: "FLIGHT",
              eventType: f.type || "OUTBOUND",
              title: `${String(f.type || "").toUpperCase() === "RETURN" ? "Dönüş" : "Gidiş"} Uçuşu`,
              description: `${String(f.from || "").toUpperCase()} → ${String(f.to || "").toUpperCase()}${f.flightNo ? ` (${f.flightNo})` : ""}`,
              date: f.date,
              time: f.time || "",
              status: "PLANNED",
              source: "travel",
              timelineAt: iso,
            });
          });
        }

        // TREATMENT PROCEDURES (legacy: patients.treatments payload)
        let treatments = p?.treatments || {};
        if (useFileFallback) {
          const treatmentsFile = path.join(TREATMENTS_DIR, `${patientId}.json`);
          const hasSupabaseTreatments = Array.isArray(treatments?.teeth) && treatments.teeth.length > 0;
          if (!hasSupabaseTreatments && fs.existsSync(treatmentsFile)) {
            const fileTreatments = readJson(treatmentsFile, {});
            if (fileTreatments?.teeth) treatments = fileTreatments;
          }
        }
        const teeth = Array.isArray(treatments?.teeth) ? treatments.teeth : [];
        teeth.forEach((tooth) => {
          const toothId = tooth?.toothId;
          const procs = Array.isArray(tooth?.procedures) ? tooth.procedures : [];
          procs.forEach((proc) => {
            if (isMirroredEncounterTreatmentProcedure(proc)) return;
            // scheduledAt preferred, else createdAt (both are ms)
            const timelineAt = toIso(proc?.scheduledAt) || toIso(proc?.createdAt);
            if (!timelineAt) return;
            const dt = new Date(Date.parse(timelineAt));
            const procedureDoctorId = String(
              proc?.assignedDoctorId ||
              proc?.assigned_doctor_id ||
              proc?.doctorId ||
              proc?.doctor_id ||
              proc?.meta?.doctorId ||
              proc?.meta?.doctor_id ||
              ""
            ).trim();
            const procedureDoctorName = String(
              proc?.assignedDoctorName ||
              proc?.doctorName ||
              proc?.doctor ||
              doctorNameById.get(procedureDoctorId) ||
              patientDoctorName ||
              ""
            ).trim();
            const procedureChair = String(
              proc?.chairNo ||
              proc?.chair_no ||
              proc?.chair ||
              proc?.chairId ||
              proc?.chair_id ||
              ""
            ).trim();
            const enriched = applyEventPrices([{
              id: proc?.id || proc?.procedureId || `treatment_${patientId}_${timelineAt}`,
              patientId,
              patient: patientName,
              patientName,
              doctor: procedureDoctorName,
              chair: procedureChair,
              type: "TREATMENT",
              eventType: proc?.type || "PROCEDURE",
              treatment: proc?.type || "PROCEDURE",
              title: `${proc?.type || "Treatment"} - Tooth ${toothId}`,
              description: "",
              date: dt.toISOString().split("T")[0],
              time: dt.toTimeString().slice(0, 5),
              status: procedures.normalizeStatus(proc?.status || "PLANNED"),
              source: "treatment",
              toothId,
              timelineAt,
            }], priceMap)[0];
            addEvent(enriched);
          });
        });

        // PATIENT_TREATMENTS TABLE (doctor app saves treatments_data.teeth[].procedures[])
        const ptData = patientTreatmentsMap.get(String(p?.id || "").trim());
        const ptTeeth = Array.isArray(ptData?.teeth) ? ptData.teeth : [];
        ptTeeth.forEach((tooth) => {
          const toothId = tooth?.id ?? tooth?.toothId;
          const procs = Array.isArray(tooth?.procedures) ? tooth.procedures : [];
          procs.forEach((proc) => {
            if (isMirroredEncounterTreatmentProcedure(proc)) return;
            const timelineAt =
              toIso(proc?.scheduledAt) ||
              toIso(proc?.scheduled_at) ||
              toIso(proc?.createdAt) ||
              toIso(proc?.created_at);
            if (!timelineAt) return;
            const dt = new Date(Date.parse(timelineAt));
            const procStatus = String(proc?.status || "PLANNED").toUpperCase();
            if (procStatus === "CANCELLED") return;
            const procDoctorId = String(
              proc?.assignedDoctorId || proc?.assigned_doctor_id ||
              proc?.doctorId || proc?.doctor_id || ""
            ).trim();
            const procDoctorName = String(
              proc?.assignedDoctorName || proc?.doctorName || proc?.doctor ||
              doctorNameById.get(procDoctorId) || patientDoctorName || ""
            ).trim();
            const procChair = String(
              proc?.chairNo || proc?.chair_no || proc?.chair || ""
            ).trim();
            const procType = String(proc?.type || proc?.procedureType || proc?.code || "TREATMENT").trim();
            const procName = proc?.name || proc?.description || procType;
            const toothLabel = toothId ? `Diş ${toothId}` : "";
            const enriched = applyEventPrices([{
              id: proc?.id || `pt_${patientId}_${toothId}_${timelineAt}`,
              patientId,
              patient: patientName,
              patientName,
              doctor: procDoctorName,
              chair: procChair,
              type: "TREATMENT",
              eventType: procType,
              treatment: procType,
              title: toothLabel ? `${toothLabel} • ${procName}` : procName,
              procedureName: procName,
              description: "",
              date: dt.toISOString().split("T")[0],
              time: null,
              status: procedures.normalizeStatus(procStatus),
              source: "patient_treatments",
              toothId: toothId ? String(toothId) : undefined,
              timelineAt,
            }], priceMap)[0];
            addEvent(enriched);
          });
        });

        // TREATMENT EVENTS (patients.treatment_events)
        let tEvents = p?.treatment_events;
        if (useFileFallback) {
          const eventsFile = path.join(TREATMENTS_DIR, `${patientId}.events.json`);
          const hasSupabaseEvents = Array.isArray(tEvents) && tEvents.length > 0;
          if (!hasSupabaseEvents && fs.existsSync(eventsFile)) {
            const fileEvents = readJson(eventsFile, []);
            tEvents = fileEvents;
          }
        }
        tEvents = applyEventPrices(mapTreatmentEventsForCalendar(tEvents), priceMap);
        tEvents.forEach((e) => {
          const iso =
            toIso(e?.startAt) ||
            dateTimeToIso(e?.date, e?.time) ||
            toIso(e?.scheduledAt) ||
            toIso(e?.createdAt) ||
            toIso(e?.timestamp);
          if (!iso) return;
          const dt = new Date(Date.parse(iso));
          const eventDoctorId = String(
            e?.assignedDoctorId ||
            e?.assigned_doctor_id ||
            e?.doctorId ||
            e?.doctor_id ||
            e?.meta?.doctorId ||
            e?.meta?.doctor_id ||
            ""
          ).trim();
          const eventDoctorName = String(
            e?.assignedDoctorName ||
            e?.doctorName ||
            e?.doctor ||
            doctorNameById.get(eventDoctorId) ||
            patientDoctorName ||
            ""
          ).trim();
          const eventChair = String(
            e?.chairNo ||
            e?.chair_no ||
            e?.chair ||
            e?.chairId ||
            e?.chair_id ||
            ""
          ).trim();
          addEvent({
            id: e?.id || `treatment_event_${patientId}_${iso}`,
            patientId,
            patient: patientName,
            patientName,
            doctor: eventDoctorName,
            chair: eventChair,
            type: "TREATMENT_EVENT",
            eventType: e?.type || "TREATMENT",
            title: e?.title || "Treatment",
            description: e?.desc || "",
            date: e?.date || dt.toISOString().split("T")[0],
            time: e?.time || null,
            status: "PLANNED",
            duration_minutes: parseMinuteValue(e?.duration_minutes ?? e?.duration, 0),
            break_minutes: parseMinuteValue(e?.break_minutes ?? e?.rest_minutes, 0),
            source: "treatment",
            timelineAt: iso,
          });
        });

        // Doctor encounter treatment items – use pre-fetched batch maps (zero extra queries per patient)
        try {
          // Collect plan IDs for this patient from the pre-built map
          const planIdsForPatient = new Set();
          for (const uid of [...patientLookupIds, String(p?.id || '').trim()]) {
            if (!uid) continue;
            const set = planIdsByPatientId.get(uid);
            if (set) set.forEach(id => planIdsForPatient.add(id));
          }

          const itemRows = [...planIdsForPatient].flatMap(pid => itemsByPlanId.get(pid) || []);

          if (itemRows.length > 0) {
            itemRows.forEach((item) => {
                const timelineAt =
                  toIso(item?.scheduled_at) ||
                  toIso(item?.scheduledAt) ||
                  toIso(item?.scheduled_for) ||
                  toIso(item?.appointment_at) ||
                  dateTimeToIso(item?.appointment_date, item?.time || "00:00") ||
                  dateTimeToIso(item?.date, item?.time || "00:00") ||
                  toIso(item?.created_at) ||
                  toIso(item?.updated_at);
                if (!timelineAt) return;

                const dt = new Date(Date.parse(timelineAt));
                const procedureCode = String(item?.procedure_code || item?.procedure_name || "PROCEDURE").trim();
                const procedureType = procedureCode.toUpperCase();
                const toothIdRaw = item?.tooth_fdi_code ?? item?.tooth_number;
                const normalizedStatus = procedures.normalizeStatus(item?.status || "PLANNED");

                const encounterEnriched = applyEventPrices([{
                  id: item?.id || `enc_item_${patientId}_${timelineAt}`,
                  patientId,
                  patient: patientName,
                  patientName,
                  doctor: patientDoctorName,
                  type: ["CONSULT", "FOLLOWUP", "LAB"].includes(procedureType) ? procedureType : "TREATMENT",
                  eventType: procedureType,
                  treatment: procedureType,
                  title: `${item?.procedure_name || procedureCode}${toothIdRaw ? ` - Tooth ${toothIdRaw}` : ""}`,
                  procedureName: item?.procedure_name || procedureCode,
                  procedureCode,
                  description: "Doctor treatment plan",
                  date: dt.toISOString().split("T")[0],
                  time: null,
                  status: normalizedStatus,
                  source: "encounter_treatment",
                  toothId: toothIdRaw ? String(toothIdRaw) : undefined,
                  timelineAt,
                }], priceMap)[0];
                addEvent(encounterEnriched);
              });
            }
        } catch (encounterError) {
          console.error("[ADMIN EVENTS] encounter treatment merge failed", encounterError);
        }
      } // end for (const p of list)
    } else {
      // Legacy FILE-BASED: fallback only when explicitly enabled
      if (!canUseFileFallback()) {
        return res.status(500).json(supabaseDisabledPayload("admin-events"));
      }

      const patients = readJson(PAT_FILE, {});
      const patientClinicMap = {};
      Object.values(patients || {}).forEach((p) => {
        const pid = String(p?.patientId || p?.patient_id || "").trim();
        const code = String(p?.clinicCode || p?.clinic_code || "").trim().toUpperCase();
        if (pid && code) patientClinicMap[pid] = code;
      });
      const isAllowedPatient = (pid) =>
        pid && patientClinicMap[pid] && patientClinicMap[pid] === clinicCode;
      const TRAVEL_DIR = path.join(DATA_DIR, "travel");
      const TREATMENTS_DIR = path.join(DATA_DIR, "treatments");
    
    // Collect events from travel data
    if (fs.existsSync(TRAVEL_DIR)) {
      const travelFiles = fs.readdirSync(TRAVEL_DIR).filter(f => f.endsWith(".json"));
      for (const file of travelFiles) {
        try {
          const travelData = readJson(path.join(TRAVEL_DIR, file), {});
          const patientId = travelData.patientId || file.replace(".json", "");
          if (!isAllowedPatient(patientId)) continue;
          
          // Travel events
          if (Array.isArray(travelData.events)) {
            travelData.events.forEach(evt => {
              if (evt.date) {
                const eventDate = new Date(evt.date + (evt.time ? `T${evt.time}:00` : "T00:00:00"));
                const eventTs = eventDate.getTime();
                
                addEvent({
                  id: evt.id || `travel_${patientId}_${eventTs}`,
                  patientId,
                  type: "TRAVEL_EVENT",
                  eventType: evt.type || "TREATMENT",
                  title: evt.title || "",
                  description: evt.desc || "",
                  date: evt.date,
                  time: evt.time || "",
                  timestamp: eventTs,
                  status: "PLANNED", // Travel events are always planned
                  source: "travel"
                });
              }
            });
          }
          
          // Hotel check-in/check-out as events
          if (travelData.hotel && travelData.hotel.name) {
            // Check-in event
            if (travelData.hotel.checkIn) {
              const checkInDate = new Date(travelData.hotel.checkIn + "T00:00:00");
              const checkInTs = checkInDate.getTime();
              
              addEvent({
                id: `hotel_checkin_${patientId}_${checkInTs}`,
                patientId,
                type: "HOTEL",
                eventType: "CHECKIN",
                title: `Otel Giriş: ${travelData.hotel.name}`,
                description: travelData.hotel.address || "",
                date: travelData.hotel.checkIn,
                time: "",
                timestamp: checkInTs,
                status: "PLANNED",
                source: "travel"
              });
            }
            
            // Check-out event
            if (travelData.hotel.checkOut) {
              const checkOutDate = new Date(travelData.hotel.checkOut + "T00:00:00");
              const checkOutTs = checkOutDate.getTime();
              
              addEvent({
                id: `hotel_checkout_${patientId}_${checkOutTs}`,
                patientId,
                type: "HOTEL",
                eventType: "CHECKOUT",
                title: `Otel Çıkış: ${travelData.hotel.name}`,
                description: travelData.hotel.address || "",
                date: travelData.hotel.checkOut,
                time: "",
                timestamp: checkOutTs,
                status: "PLANNED",
                source: "travel"
              });
            }
          }
          
          // Flights as events
          if (Array.isArray(travelData.flights)) {
            travelData.flights.forEach(flight => {
              if (flight.date) {
                const flightDate = new Date(flight.date + (flight.time ? `T${flight.time}:00` : "T00:00:00"));
                const flightTs = flightDate.getTime();
                
                addEvent({
                  id: flight.id || `flight_${patientId}_${flightTs}`,
                  patientId,
                  type: "FLIGHT",
                  eventType: flight.type || "OUTBOUND",
                  title: `${flight.type === "RETURN" ? "Dönüş" : "Gidiş"} Uçuşu`,
                  description: `${flight.from?.toUpperCase() || ""} → ${flight.to?.toUpperCase() || ""}${flight.flightNo ? ` (${flight.flightNo})` : ""}`,
                  date: flight.date,
                  time: flight.time || "",
                  timestamp: flightTs,
                  status: "PLANNED",
                  source: "travel"
                });
                
                // Airport pickup event for ARRIVAL flights
                if ((flight.type === "ARRIVAL" || flight.type === "INBOUND") && travelData.airportPickup) {
                  const pickup = travelData.airportPickup;
                  if (pickup && (pickup.name || pickup.phone)) {
                    const pickupParts = [];
                    if (pickup.name) pickupParts.push(`İsim: ${pickup.name}`);
                    if (pickup.phone) pickupParts.push(`Tel: ${pickup.phone}`);
                    if (pickup.meetingPoint) pickupParts.push(`Buluşma: ${pickup.meetingPoint}`);
                    if (pickup.vehicle || pickup.vehicleInfo || pickup.plate) {
                      const vehicle = pickup.vehicle || pickup.vehicleInfo || "";
                      const plate = pickup.plate || "";
                      
                      if (vehicle && plate) {
                        pickupParts.push(`Araç: ${vehicle}, Plaka: ${plate}`);
                      } else if (vehicle) {
                        pickupParts.push(`Araç: ${vehicle}`);
                      } else if (plate) {
                        pickupParts.push(`Plaka: ${plate}`);
                      }
                    }
                    if (pickup.note || pickup.notes) {
                      pickupParts.push(`Not: ${pickup.note || pickup.notes}`);
                    }
                    
                    addEvent({
                      id: `airport_pickup_${patientId}_${flightTs}`,
                      patientId,
                      type: "AIRPORT_PICKUP",
                      eventType: "AIRPORT_PICKUP",
                      title: "Havalimanı Karşılama - Alan karşılama girildi",
                      description: pickupParts.join(" • ") || "Alan karşılama girildi",
                      date: flight.date,
                      time: flight.time || "",
                      timestamp: flightTs,
                      status: "PLANNED",
                      source: "travel"
                    });
                  }
                }
              }
            });
          }
        } catch (err) {

        }
      }
    }
    
    // Collect events from treatments data
    if (fs.existsSync(TREATMENTS_DIR)) {
      const treatmentFiles = fs.readdirSync(TREATMENTS_DIR).filter(f => f.endsWith(".json"));
      for (const file of treatmentFiles) {
        try {
          const treatmentData = readJson(path.join(TREATMENTS_DIR, file), {});
          const patientId = treatmentData.patientId || file.replace(".json", "");
          if (!isAllowedPatient(patientId)) continue;
          
          if (Array.isArray(treatmentData.teeth)) {
            treatmentData.teeth.forEach(tooth => {
              if (Array.isArray(tooth.procedures)) {
                tooth.procedures.forEach(proc => {
                  if (proc.scheduledAt) {
                    const procDate = new Date(proc.scheduledAt);
                    const procTs = procDate.getTime();
                    
                    // Normalize status (PLANNED, ACTIVE, COMPLETED, CANCELLED)
                    const procStatus = procedures.normalizeStatus(proc.status || "PLANNED");
                    
                    addEvent({
                      id: proc.id || `treatment_${patientId}_${procTs}`,
                      patientId,
                      type: "TREATMENT",
                      eventType: proc.type || "PROCEDURE",
                      title: `${proc.type || "Treatment"} - Tooth ${tooth.toothId}`,
                      description: "",
                      date: procDate.toISOString().split("T")[0],
                      time: procDate.toTimeString().split(" ")[0].slice(0, 5),
                      timestamp: procTs,
                      status: procStatus,
                      source: "treatment",
                      toothId: tooth.toothId
                    });
                  }
                });
              }
            });
          }
        } catch (err) {

        }
      }
    }
    }
    
    console.log("[EVENTS] Total raw events collected:", allEvents.length, "for clinic:", req.clinicCode);
    const dedupedEvents = dedupeAdminTimelineEvents(allEvents);
    if (dedupedEvents.length !== allEvents.length) {
      console.log("[EVENTS] After dedupe:", dedupedEvents.length, "(removed", allEvents.length - dedupedEvents.length, "duplicate/stale rows)");
    }
    allEvents.length = 0;
    allEvents.push(...dedupedEvents);

    // If explicit date range is requested (calendar week view), return events in that range directly.
    if (hasRangeFilter) {
      const marginMs = 24 * 60 * 60 * 1000;
      const rangeEvents = allEvents
        .filter((evt) => {
          const evtDateStr = String(evt?.date || "").trim();
          if (/^\d{4}-\d{2}-\d{2}$/.test(evtDateStr)) {
            return evtDateStr >= startDate && evtDateStr <= endDate;
          }
          const ts = evt.timestamp || (evt.timelineAt ? Date.parse(evt.timelineAt) : 0) || 0;
          return Number.isFinite(ts) && ts >= (rangeStartTs - marginMs) && ts <= (rangeEndTs + marginMs);
        })
        .sort((a, b) => (a.timestamp || 0) - (b.timestamp || 0));

      return res.json({
        ok: true,
        startDate,
        endDate,
        overdue: [],
        today: [],
        upcoming: rangeEvents,
        total: rangeEvents.length,
        overdueCount: 0,
        todayCount: 0,
        upcomingCount: rangeEvents.length,
      });
    }

    // Default dashboard behavior (without explicit range): overdue/today/upcoming buckets.
    const overdue = [];
    const todayEvents = [];
    const upcoming = [];
    
    // Calculate today end time
    const todayEnd = new Date(today);
    todayEnd.setHours(23, 59, 59, 999);
    const todayEndTs = todayEnd.getTime();
    
    // Treatment event types that should show as overdue
    const treatmentEventTypes = ["TREATMENT", "CONSULT", "FOLLOWUP", "LAB"];
    
    allEvents.forEach(evt => {
      const eventTs = evt.timestamp || (evt.timelineAt ? Date.parse(evt.timelineAt) : 0) || 0;
      const status = String(evt.status || "PLANNED").toUpperCase();
      const isCompleted = status === "DONE" || status === "COMPLETED";
      const isCancelled = status === "CANCELLED";
      const eventType = String(evt.type || "").toUpperCase();
      const isTreatmentEvent = treatmentEventTypes.includes(eventType);
      
      // Skip cancelled or completed events from upcoming/overdue lists
      if (isCancelled || isCompleted) {
        return; // Don't add to overdue or upcoming
      }
      
      // Overdue: past date but not completed - ONLY for treatment events
      // Double check: event must be in the past AND not completed
      if (eventTs < todayStart && isTreatmentEvent && !isCompleted && !isCancelled) {
        overdue.push(evt);
      }
      // Today: events happening today
      else if (eventTs >= todayStart && eventTs <= todayEndTs && !isCompleted && !isCancelled) {
        todayEvents.push(evt);
      }
      // Upcoming: next 14 days (excluding today), but only if not completed/cancelled
      else if (eventTs > todayEndTs && eventTs <= upcomingEndTs && !isCompleted && !isCancelled) {
        upcoming.push(evt);
      }
    });
    
    // Sort overdue by date (oldest first)
    overdue.sort((a, b) => (a.timestamp || 0) - (b.timestamp || 0));
    
    // Sort upcoming by date (soonest first)
    upcoming.sort((a, b) => (a.timestamp || 0) - (b.timestamp || 0));
    
    res.json({
      ok: true,
      overdue,
      today: todayEvents,
      upcoming,
      total: allEvents.length,
      overdueCount: overdue.length,
      todayCount: todayEvents.length,
      upcomingCount: upcoming.length
    });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

