// ================== ADMIN AUTHENTICATION ==================
// Middleware: Validate admin JWT token
async function requireAdminAuth(req, res, next) {
  try {



    
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith("Bearer ")) {

      return res.status(401).json({ ok: false, error: "unauthorized" });
    }
    
    const token = authHeader.substring(7);
    const decoded = jwt.verify(token, JWT_SECRET);
    
    // New JWT format: clinicCode is primary (not clinicId)
    const clinicCode = decoded.clinicCode;

    
    if (!clinicCode) {

      return res.status(401).json({ ok: false, error: "invalid_token", message: "Token geçersiz." });
    }
    
    // SUPABASE: Primary lookup by clinicCode (with timeout to prevent hang)
    if (isSupabaseEnabled()) {
      const clinic = await Promise.race([
        getClinicByCode(clinicCode),
        new Promise((_, reject) => setTimeout(() => reject(new Error("clinic_lookup_timeout")), 8000)),
      ]).catch((err) => { console.error("[requireAdminAuth] clinic lookup error:", err?.message); return null; });
      
      if (clinic) {
        req.clinicId = clinic.id;              // Supabase UUID
        req.clinicCode = clinic.clinic_code;   // e.g. "ORDU"
        req.clinicStatus = clinic.status || "ACTIVE";  // Use direct status field
        req.clinic = clinic;
        
        if (String(process.env.ADMIN_AUTH_DEBUG || "").trim() === "1") {
          console.log("[requireAdminAuth] Clinic auth check:", {
            clinicCode: req.clinicCode,
            clinicId: req.clinicId,
            status: req.clinicStatus,
            isSuspended: req.clinicStatus === "SUSPENDED"
          });
        }
        
        // Only reject if clinic is suspended
        if (req.clinicStatus === "SUSPENDED") {

          return res.status(403).json({ ok: false, error: "clinic_suspended", message: "Clinic account has been suspended" });
        }
        

        return next();
      }
      

    }
    
    // FILE FALLBACK (legacy)
    const code = String(clinicCode).toUpperCase();
    let clinic = null;
    
    // Check CLINICS_FILE
    const clinics = readJson(CLINICS_FILE, {});
    for (const cid in clinics) {
      const c = clinics[cid];
      if (c) {
        const cCode = c.clinicCode || c.code;
        if (cCode && String(cCode).toUpperCase() === code) {
          clinic = c;
          req.clinicId = cid;
          break;
        }
      }
    }
    
    // Check CLINIC_FILE (single clinic)
    if (!clinic) {
      const singleClinic = readJson(CLINIC_FILE, {});
      if (singleClinic?.clinicCode && String(singleClinic.clinicCode).toUpperCase() === code) {
        clinic = singleClinic;
      }
    }
    
    if (!clinic) {
      console.error("[requireAdminAuth] ❌ Clinic not found by code:", clinicCode);
      return res.status(401).json({ ok: false, error: "clinic_not_found" });
    }
    
    // Only reject if clinic is suspended
    if (clinic.status === "SUSPENDED") {
      return res.status(403).json({ ok: false, error: "clinic_suspended", message: "Clinic account has been suspended" });
    }
    
    req.clinicId = req.clinicId || clinic.clinicId || null;
    req.clinicCode = clinic.clinicCode || clinic.code;
    req.clinicStatus = clinic.status || "ACTIVE";
    req.clinic = clinic;

    next();
  } catch (error) {

    if (error?.name === "JsonWebTokenError" || error?.name === "TokenExpiredError") {
      return res.status(401).json({ ok: false, error: "invalid_token", message: "Geçersiz token. Lütfen tekrar giriş yapın." });
    }
    return res.status(500).json({ ok: false, error: "auth_error", message: "Kimlik doğrulama hatası." });
  }
}

// POST /api/admin/register
// Clinic registration (email/password) - Supabase supported
app.post("/api/admin/register", async (req, res) => {
  try {
    const { email, password, name, phone, address, clinicCode } = req.body || {};
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required" });
    }
    if (!password || String(password).length < 6) {
      return res.status(400).json({ ok: false, error: "password_required_min_6" });
    }
    if (!name || !String(name).trim()) {
      return res.status(400).json({ ok: false, error: "name_required" });
    }
    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required", message: "Clinic code is required." });
    }
    
    // Validate clinic code format: minimum 3 characters, only letters and numbers
    const clinicCodeTrimmed = String(clinicCode).trim().toUpperCase();
    if (clinicCodeTrimmed.length < 3) {
      return res.status(400).json({ ok: false, error: "clinic_code_too_short", message: "Clinic code must be at least 3 characters." });
    }
    
    // Allow only alphanumeric characters (letters and numbers), case insensitive
    if (!/^[A-Za-z0-9]+$/.test(clinicCodeTrimmed)) {
      return res.status(400).json({ ok: false, error: "clinic_code_invalid", message: "Clinic code can only contain letters and numbers." });
    }
    
    const emailLower = String(email).trim().toLowerCase();
    
    // Hash password
    const hashedPassword = await bcrypt.hash(String(password), 10);
    
    // SUPABASE: Primary storage
    if (isSupabaseEnabled()) {






      
      // Check if email already exists

      const existingByEmail = await getClinicByEmail(emailLower);
      if (existingByEmail) {

        return res.status(400).json({ ok: false, error: "email_exists" });
      }

      
      // OTP Verification Required for New Admins
      if (OTP_REQUIRED_FOR_NEW_ADMINS) {

        
        // Generate and send OTP
        const otpCode = String(generateOTP()).trim();  // Standardize: String + trim
        const otpHash = await bcrypt.hash(otpCode, 10);
        


        
        try {
          // Send OTP email
          await sendOTPEmail(emailLower, otpCode, "en");

          
          // Store OTP in Supabase for verification

          console.log("[ADMIN REGISTER] Registration data:", JSON.stringify({
            name: String(name).trim(),
            phone: String(phone || "").trim(),
            address: String(address || "").trim(),
            password_hash: hashedPassword,
            registration_data: {
              clinic_code: clinicCodeTrimmed,
              email: emailLower,
              phone: String(phone || "").trim(),
              address: String(address || "").trim(),
              plan: "FREE",
              max_patients: 3
            }
          }, null, 2));
          
          await storeOTPForEmail(emailLower, otpHash, clinicCodeTrimmed, {
            name: String(name).trim(),
            phone: String(phone || "").trim(),
            address: String(address || "").trim(),
            email: emailLower,
            clinic_code: clinicCodeTrimmed,
            password_hash: hashedPassword,
            plan: "FREE",
            max_patients: 3,
          });
          

          
          return res.json({
            ok: true,
            requiresOTP: true,
            message: "Please check your email for verification code",
            email: emailLower,
            clinicCode: clinicCodeTrimmed
          });
          
        } catch (emailError) {

          return res.status(500).json({
            ok: false,
            error: "email_send_failed",
            message: "Failed to send verification email. Please try again."
          });
        }
      }
      
      // Check if clinicCode already exists

      const existingByCode = await getClinicByCode(clinicCodeTrimmed);
      if (existingByCode) {

        return res.status(400).json({ ok: false, error: "clinic_code_exists" });
      }

      
      // Create clinic in Supabase

      try {
        const newClinic = await createClinic({
          clinic_code: clinicCodeTrimmed,
          email: emailLower,
          password_hash: hashedPassword,
          name: String(name).trim(),
          phone: String(phone || "").trim(),
          address: String(address || "").trim(),
          plan: "FREE",
          max_patients: 3,
          settings: {
            status: "ACTIVE",
            subscriptionStatus: "TRIAL",
            subscriptionPlan: null,
            verificationStatus: "verified",
            trialEndsAt: now() + (14 * 24 * 60 * 60 * 1000),
          }
        });
        
        if (!newClinic || !newClinic.id) {
          console.error("[ADMIN REGISTER] ❌ createClinic returned null or no id!");
          throw new Error("Failed to create clinic - no data returned");
        }
        
        // Generate JWT token with proper structure
        const token = jwt.sign({ 
          type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
          clinicId: newClinic.id, // 🔥 REQUIRED: clinicId (UUID)
          clinicCode: newClinic.clinic_code,
          email: emailLower,
          role: "ADMIN", // 🔥 REQUIRED: role
          otpVerified: true
        }, JWT_SECRET, {
          expiresIn: JWT_EXPIRES_IN,
        });
        

        
        return res.json({
          ok: true,
          clinicId: newClinic.id,
          clinicCode: newClinic.clinic_code,
          token,
          status: "ACTIVE",
          subscriptionStatus: "TRIAL",
        });
      } catch (supabaseError) {
        console.error("[ADMIN REGISTER] ❌ Supabase insert FAILED:", supabaseError.message);

        throw supabaseError;
      }
    }
    
    // FILE FALLBACK: Legacy storage

    const clinics = readJson(CLINICS_FILE, {});
    
    // Check if email already exists
    for (const id in clinics) {
      const existingEmail = clinics[id]?.email;
      if (existingEmail && String(existingEmail).trim().toLowerCase() === emailLower) {
        return res.status(400).json({ ok: false, error: "email_exists" });
      }
    }
    
    // Check if clinicCode already exists
    for (const id in clinics) {
      const existingCode = clinics[id]?.clinicCode || clinics[id]?.code;
      if (existingCode && String(existingCode).trim().toUpperCase() === clinicCodeTrimmed) {
        return res.status(400).json({ ok: false, error: "clinic_code_exists" });
      }
    }
    
    // Create clinic
    const clinicId = rid("clinic");
    const clinic = {
      clinicId,
      email: emailLower,
      password: hashedPassword,
      name: String(name).trim(),
      phone: String(phone || "").trim(),
      address: String(address || "").trim(),
      clinicCode: clinicCodeTrimmed,
      plan: "FREE",
      max_patients: 3,
      status: "ACTIVE",
      subscriptionStatus: "TRIAL",
      subscriptionPlan: null,
      verificationStatus: "verified",
      trialEndsAt: now() + (14 * 24 * 60 * 60 * 1000),
      createdAt: now(),
      updatedAt: now(),
    };
    
    clinics[clinicId] = clinic;
    writeJson(CLINICS_FILE, clinics);
    
    // Generate JWT token with proper structure
    const token = jwt.sign({ 
      type: "admin", // 🔥 REQUIRED: type is PRIMARY routing key
      clinicId: clinicId, // 🔥 REQUIRED: clinicId (UUID)
      clinicCode: clinic.clinicCode,
      email: clinic.email,
      role: "ADMIN", // 🔥 REQUIRED: role
      otpVerified: true
    }, JWT_SECRET, {
      expiresIn: JWT_EXPIRES_IN,
    });
    
    res.json({
      ok: true,
      clinicId,
      clinicCode: clinic.clinicCode,
      token,
      status: clinic.status,
      subscriptionStatus: clinic.subscriptionStatus,
    });
  } catch (err) {

    return res.status(400).json({
      error: "registration_failed",
      message: err?.message || "Registration failed",
      code: err?.code || null,
    });
  }
});

// POST /api/admin/login
// Same resolution strategy as main API: admins row first, then clinics row (legacy).
app.post("/api/admin/login", async (req, res) => {
  try {
    const { email, clinicCode, password } = req.body || {};

    console.log("[ADMIN LOGIN] Request received:", { email, clinicCode, hasPassword: !!password });

    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required" });
    }

    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required" });
    }

    if (!password || !String(password).trim()) {
      return res.status(400).json({ ok: false, error: "password_required" });
    }

    const trimmedEmail = String(email).trim().toLowerCase();
    const trimmedPassword = String(password).trim();
    const trimmedClinicCode = String(clinicCode).trim().toUpperCase();

    const isBcryptHash = (value) => typeof value === "string" && /^\$2[aby]\$/.test(value);
    const checkPassword = async (plain, stored) => {
      if (!stored || typeof stored !== "string") return false;
      if (isBcryptHash(stored)) {
        try {
          return await bcrypt.compare(plain, stored);
        } catch {
          return false;
        }
      }
      return stored === plain;
    };

    if (!isSupabaseEnabled()) {
      console.log("[ADMIN LOGIN] Supabase not enabled - cannot authenticate admins");
      return res.status(503).json({
        ok: false,
        error: "admin_service_unavailable",
        message:
          "Admin login requires SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY on this server (set them on your Railway service or admin host).",
      });
    }

    console.log("[ADMIN LOGIN] Supabase enabled, resolving identity:", { email: trimmedEmail, clinicCode: trimmedClinicCode });

    const admin = await getAdminByEmailAndClinicCode(trimmedEmail, trimmedClinicCode);
    let identity = null;
    let clinicForToken = null;

    console.log("[ADMIN LOGIN] admins table lookup:", { found: !!admin });

    if (admin) {
      const adminStatus = String(admin.status || "ACTIVE").toUpperCase();
      if (adminStatus !== "ACTIVE") {
        console.warn("[ADMIN LOGIN] Admin status not ACTIVE:", adminStatus);
        return res.status(401).json({ ok: false, error: "invalid_admin_credentials" });
      }
      const stored = admin.password_hash || admin.password;
      const passwordMatch = await checkPassword(trimmedPassword, stored);
      console.log("[ADMIN LOGIN] admins table password match:", passwordMatch);
      if (!passwordMatch) {
        // Fall through to clinics table in case passwords differ
        console.warn("[ADMIN LOGIN] admins table password mismatch, trying clinics table");
      } else {
        clinicForToken = await getClinicByCode(admin.clinic_code || trimmedClinicCode);
        identity = {
          id: admin.id,
          email: admin.email,
          clinicCode: trimmedClinicCode,
          status: admin.status,
          clinicId: clinicForToken?.id || null,
          clinicName: clinicForToken?.name || "",
        };
        console.log("[ADMIN LOGIN] Authenticated via admins table, clinicId:", identity.clinicId);
      }
    }

    if (!identity) {
      const clinicRow = await getClinicByCode(trimmedClinicCode);
      console.log("[ADMIN LOGIN] clinics table lookup:", { found: !!clinicRow });

      if (!clinicRow) {
        console.log("[ADMIN LOGIN] No clinic for code:", trimmedClinicCode);
        return res.status(401).json({ ok: false, error: "invalid_admin_credentials" });
      }

      const dbEmail = String(clinicRow.email || "").trim().toLowerCase();
      if (dbEmail !== trimmedEmail) {
        console.warn("[ADMIN LOGIN] Email mismatch:", { entered: trimmedEmail, stored: dbEmail });
        return res.status(401).json({ ok: false, error: "invalid_admin_credentials" });
      }

      const clinicStatus = String(clinicRow.status || "ACTIVE").toUpperCase();
      if (clinicStatus === "SUSPENDED") {
        return res.status(403).json({ ok: false, error: "clinic_suspended", message: "Clinic account has been suspended" });
      }

      const stored = clinicRow.password_hash || clinicRow.password;
      const hasHash = !!stored;
      const passwordMatch = await checkPassword(trimmedPassword, stored);
      console.log("[ADMIN LOGIN] clinics table password match:", passwordMatch, "hasHash:", hasHash);

      if (!passwordMatch) {
        console.warn("[ADMIN LOGIN] Password mismatch for clinic:", trimmedClinicCode, "hasHash:", hasHash);
        return res.status(401).json({ ok: false, error: "invalid_admin_credentials" });
      }

      clinicForToken = clinicRow;
      identity = {
        id: clinicRow.id,
        email: clinicRow.email,
        clinicCode: trimmedClinicCode,
        status: clinicStatus,
        clinicId: clinicRow.id,
        clinicName: clinicRow.name || "",
      };
      console.log("[ADMIN LOGIN] Authenticated via clinics table, clinicId:", identity.clinicId);
    }

    if (!identity) {
      console.warn("[ADMIN LOGIN] Could not resolve identity");
      return res.status(401).json({ ok: false, error: "invalid_admin_credentials" });
    }

    const payload = {
      type: "admin",
      adminId: identity.id,
      email: identity.email,
      clinicCode: identity.clinicCode,
      role: "ADMIN",
    };
    if (identity.clinicId) payload.clinicId = identity.clinicId;

    let token;
    try {
      token = jwt.sign(payload, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN });
    } catch (signErr) {
      console.error("[ADMIN LOGIN] jwt.sign failed:", signErr?.message);
      return res.status(500).json({
        ok: false,
        error: "token_sign_failed",
        message: "JWT oluşturulamadı; JWT_SECRET ortam değişkenini kontrol edin.",
      });
    }

    console.log("[ADMIN LOGIN] Token generated successfully for:", identity.email);

    return res.json({
      ok: true,
      token,
      clinicId: identity.clinicId,
      clinicName: identity.clinicName,
      admin: {
        id: identity.id,
        email: identity.email,
        clinicCode: identity.clinicCode,
        role: "ADMIN",
        status: identity.status,
      },
    });
  } catch (error) {
    console.error("[ADMIN LOGIN] Error:", error);
    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// POST /api/admin/forgot-password/verify
// Verify clinic code and email for password reset
app.post("/api/admin/forgot-password/verify", (req, res) => {
  try {
    const { clinicCode, email } = req.body || {};
    
    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required" });
    }
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required" });
    }
    
    const code = String(clinicCode).trim().toUpperCase();
    const emailLower = String(email).trim().toLowerCase();
    const clinic = readJson(CLINIC_FILE, {});
    
    // Check if clinic code matches
    if (!clinic.clinicCode || clinic.clinicCode.toUpperCase() !== code) {
      return res.status(401).json({ ok: false, error: "invalid_clinic_code_or_email" });
    }
    
    // Check if email matches
    if (!clinic.email || clinic.email.toLowerCase() !== emailLower) {
      return res.status(401).json({ ok: false, error: "invalid_clinic_code_or_email" });
    }
    
    res.json({ ok: true });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

// POST /api/admin/forgot-password/reset
// Reset password after verification
app.post("/api/admin/forgot-password/reset", async (req, res) => {
  try {
    const { clinicCode, email, newPassword } = req.body || {};
    
    if (!clinicCode || !String(clinicCode).trim()) {
      return res.status(400).json({ ok: false, error: "clinic_code_required" });
    }
    
    if (!email || !String(email).trim()) {
      return res.status(400).json({ ok: false, error: "email_required" });
    }
    
    if (!newPassword || !String(newPassword).trim()) {
      return res.status(400).json({ ok: false, error: "new_password_required" });
    }
    
    if (String(newPassword).trim().length < 6) {
      return res.status(400).json({ ok: false, error: "password_too_short" });
    }
    
    const code = String(clinicCode).trim().toUpperCase();
    const emailLower = String(email).trim().toLowerCase();
    const clinic = readJson(CLINIC_FILE, {});
    
    // Verify clinic code and email again
    if (!clinic.clinicCode || clinic.clinicCode.toUpperCase() !== code) {
      return res.status(401).json({ ok: false, error: "invalid_clinic_code_or_email" });
    }
    
    if (!clinic.email || clinic.email.toLowerCase() !== emailLower) {
      return res.status(401).json({ ok: false, error: "invalid_clinic_code_or_email" });
    }
    
    // Hash new password
    const hashedPassword = await bcrypt.hash(String(newPassword).trim(), 10);
    clinic.password = hashedPassword;
    clinic.updatedAt = now();
    
    writeJson(CLINIC_FILE, clinic);
    
    res.json({ ok: true });
  } catch (error) {

    res.status(500).json({ ok: false, error: error?.message || "internal_error" });
  }
});

