app.get("/admin/doctor-list", requireAdminAuth, async (req, res) => {
  try {
    const clinicId = req.clinicId || null;
    const clinicCodeUpper = String(req.clinicCode || "").trim().toUpperCase();

    const selectCandidates = [
      "id, doctor_id, full_name, name, email, phone, status, clinic_id, clinic_code, department, title, specialties, license_number, bio, public_profile, photo_url, profile_photo_url, university, graduation_year, experience_years, years_of_experience, created_at, updated_at, approved_at",
      "id, doctor_id, full_name, name, email, phone, status, clinic_id, clinic_code, department, title, specialties, license_number, bio, public_profile, photo_url, created_at, updated_at",
      "id, doctor_id, name, email, phone, status, clinic_id, clinic_code, department, title, specialties, license_number, created_at, updated_at",
      "id, doctor_id, name, email, phone, status, clinic_code, department, title, specialties, license_number, created_at, updated_at",
    ];

    let merged = [];
    let lastError = null;

    for (const selectClause of selectCandidates) {
      const seen = new Set();
      const acc = [];

      const pushUnique = (rows) => {
        for (const row of rows || []) {
          const id = String(row?.id || "").trim();
          if (!id || seen.has(id)) continue;
          seen.add(id);
          acc.push(row);
        }
      };

      if (clinicId) {
        const r1 = await supabase
          .from("doctors")
          .select(selectClause)
          .eq("clinic_id", clinicId)
          .order("created_at", { ascending: false });
        if (r1.error) {
          lastError = r1.error;
          const code = String(r1.error.code || "");
          if (["42703", "PGRST204", "PGRST205"].includes(code)) continue;
          console.error("[DOCTOR LIST] Supabase error:", r1.error);
          return res.status(500).json({ ok: false, error: r1.error?.message || "fetch_failed" });
        }
        pushUnique(r1.data);
      }

      if (clinicCodeUpper) {
        const r2 = await supabase
          .from("doctors")
          .select(selectClause)
          .eq("clinic_code", clinicCodeUpper)
          .order("created_at", { ascending: false });
        if (r2.error) {
          lastError = r2.error;
          const code = String(r2.error.code || "");
          if (["42703", "PGRST204", "PGRST205"].includes(code)) continue;
          console.error("[DOCTOR LIST] Supabase error (clinic_code):", r2.error);
          return res.status(500).json({ ok: false, error: r2.error?.message || "fetch_failed" });
        }
        pushUnique(r2.data);
      }

      acc.sort((a, b) => {
        const ta = new Date(a?.created_at || 0).getTime();
        const tb = new Date(b?.created_at || 0).getTime();
        return tb - ta;
      });
      merged = acc;
      break;
    }

    const doctors = (merged || []).map((d) => {
      const raw = d.public_profile;
      let public_profile = null;
      if (raw === true || raw === "true" || raw === "t" || raw === 1) public_profile = true;
      else if (raw === false || raw === "false" || raw === "f" || raw === 0) public_profile = false;
      return { ...d, public_profile };
    });

    console.log("[DOCTOR LIST] Loaded doctors:", doctors.length);
    res.json({ ok: true, doctors });
  } catch (error) {
    console.error("[DOCTOR LIST] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

/** Match /api/admin/approve-doctor: UI may send UUID (id) or legacy doctor_id string. */
async function updateDoctorRowByAdminId(doctorId, patch) {
  const raw = String(doctorId || "").trim();
  if (!raw) {
    return { data: null, error: { message: "doctorId_required" } };
  }
  let r = await supabase.from("doctors").update(patch).eq("id", raw).select().maybeSingle();
  if (r.error) return r;
  if (r.data) return r;
  r = await supabase.from("doctors").update(patch).eq("doctor_id", raw).select().maybeSingle();
  return r;
}

app.post("/admin/approve-doctor-v2", requireAdminAuth, async (req, res) => {
  try {
    const { doctorId } = req.body;

    if (!doctorId) {
      return res.status(400).json({ ok: false, error: "doctorId_required" });
    }

    console.log("[APPROVE V2] Approving doctor:", doctorId);

    // Same minimal fields as POST /api/admin/approve-doctor — many DBs have no approved_at column
    const minimalPatch = {
      status: "APPROVED",
      updated_at: new Date().toISOString(),
    };
    const withApprovedAt = {
      ...minimalPatch,
      approved_at: new Date().toISOString(),
    };

    let { data, error } = await updateDoctorRowByAdminId(doctorId, withApprovedAt);
    if (
      error &&
      /42703|PGRST204|approved_at|column|schema/i.test(String(error.message || error.details || ""))
    ) {
      ({ data, error } = await updateDoctorRowByAdminId(doctorId, minimalPatch));
    }

    if (error) {
      console.error("[APPROVE V2] Supabase error:", error);
      return res.status(500).json({ ok: false, error: error.message });
    }
    if (!data) {
      return res.status(404).json({ ok: false, error: "doctor_not_found" });
    }

    console.log("[APPROVE V2] Doctor approved successfully:", data);
    res.json({ ok: true, doctor: data });
  } catch (error) {
    console.error("[APPROVE V2] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

app.post("/admin/reject-doctor-v2", requireAdminAuth, async (req, res) => {
  try {
    const { doctorId } = req.body;

    if (!doctorId) {
      return res.status(400).json({ ok: false, error: "doctorId_required" });
    }

    console.log("[REJECT V2] Rejecting doctor:", doctorId);

    // Same as POST /api/admin/reject-doctor — many DBs have no rejected_at column.
    const patch = {
      status: "REJECTED",
      updated_at: new Date().toISOString(),
    };

    const { data, error } = await updateDoctorRowByAdminId(doctorId, patch);

    if (error) {
      console.error("[REJECT V2] Supabase error:", error);
      return res.status(500).json({ ok: false, error: error.message });
    }
    if (!data) {
      return res.status(404).json({ ok: false, error: "doctor_not_found" });
    }

    console.log("[REJECT V2] Doctor rejected successfully:", data);
    res.json({ ok: true, doctor: data });
  } catch (error) {
    console.error("[REJECT V2] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

