// ── Treatment Requests & Offers ───────────────────────────────────────────────
// These endpoints power the patient's "My Requests / Offers" screen.
// Tables: treatment_requests, treatment_offers, ratings, doctors, clinics.

// GET /api/patient/treatment-requests
// Returns all requests by the authenticated patient, each with its doctor offers.
// Uses plain selects + batch name lookups — avoids PostgREST embed failures when FKs are missing in API cache.
app.get('/api/patient/treatment-requests', requireToken, async (req, res) => {
  try {
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const resolvedUuid = await resolveMessagesPatientDbId(tokenPatientId);
    const patientIdFilters = treatmentRequestPatientIdFilters(tokenPatientId, resolvedUuid);
    if (!patientIdFilters.length) {
      return res.json({ ok: true, requests: [] });
    }

    let reqQ = supabase.from('treatment_requests').select('*');
    reqQ =
      patientIdFilters.length === 1
        ? reqQ.eq('patient_id', patientIdFilters[0])
        : reqQ.in('patient_id', patientIdFilters);
    const { data: requests, error: reqErr } = await reqQ.order('created_at', { ascending: false });

    if (reqErr) {
      console.error('[TREATMENT-REQUESTS GET]', reqErr.message);
      return res.status(500).json({ ok: false, error: 'db_error' });
    }

    if (!requests || requests.length === 0) {
      return res.json({ ok: true, requests: [] });
    }

    const requestIds = requests.map((r) => r.id);
    const reqClinicIds = [...new Set(requests.map((r) => r.clinic_id).filter(Boolean))];

    const clinicNameById = {};
    if (reqClinicIds.length > 0) {
      const { data: clinicRows } = await supabase.from('clinics').select('id, name').in('id', reqClinicIds);
      for (const c of clinicRows || []) {
        if (c?.id) clinicNameById[String(c.id)] = c.name || null;
      }
    }

    const { data: offers, error: offErr } = await supabase
      .from('treatment_offers')
      .select('*')
      .in('request_id', requestIds)
      .order('created_at', { ascending: true });

    if (offErr) console.warn('[TREATMENT-REQUESTS OFFERS]', offErr.message);

    const offerDoctorIds = [...new Set((offers || []).map((o) => o.doctor_id).filter(Boolean))];
    const offerClinicIds = [...new Set((offers || []).map((o) => o.clinic_id).filter(Boolean))];
    const doctorNameById = {};
    if (offerDoctorIds.length > 0) {
      const { data: docRows } = await supabase
        .from('doctors')
        .select('id, full_name, name')
        .in('id', offerDoctorIds);
      for (const d of docRows || []) {
        if (d?.id) {
          doctorNameById[String(d.id)] = String(d.full_name || d.name || '').trim() || null;
        }
      }
    }
    const extraClinicIds = offerClinicIds.filter((cid) => cid && clinicNameById[String(cid)] == null);
    if (extraClinicIds.length > 0) {
      const { data: moreClinics } = await supabase.from('clinics').select('id, name').in('id', extraClinicIds);
      for (const c of moreClinics || []) {
        if (c?.id) clinicNameById[String(c.id)] = c.name || null;
      }
    }

    const offersByRequest = {};
    for (const offer of offers || []) {
      const rId = offer.request_id;
      if (!offersByRequest[rId]) offersByRequest[rId] = [];
      const docId = offer.doctor_id ? String(offer.doctor_id) : '';
      const cid = offer.clinic_id ? String(offer.clinic_id) : '';
      offersByRequest[rId].push({
        id: offer.id,
        clinic_id: offer.clinic_id || null,
        clinic_name: cid ? clinicNameById[cid] ?? null : null,
        doctor_name: docId ? doctorNameById[docId] ?? null : null,
        treatment_type: offer.treatment_type,
        price_range: offer.price_range || null,
        duration: offer.duration || null,
        note: offer.note || null,
        disclaimer:
          offer.disclaimer ||
          'This is a preliminary estimate. Final diagnosis requires clinical examination.',
        created_at: offer.created_at,
      });
    }

    const result = requests.map((r) => {
      const cid = r.clinic_id ? String(r.clinic_id) : '';
      return {
        id: r.id,
        clinic_id: r.clinic_id || null,
        clinic_name: cid ? clinicNameById[cid] ?? null : null,
        description: r.description,
        budget: r.budget || null,
        preferred_treatment: r.preferred_treatment || null,
        status: r.status,
        created_at: r.created_at,
        offers: offersByRequest[r.id] || [],
      };
    });

    return res.json({ ok: true, requests: result });
  } catch (e) {
    console.error('[TREATMENT-REQUESTS GET]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// POST /api/patient/treatment-requests — yeni talep (Supabase treatment_requests; doktor /api/doctor/treatment-requests ile görünür)
app.post('/api/patient/treatment-requests', requireToken, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: 'supabase_disabled' });
    }
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const body = req.body || {};
    const resolvedPatientId = await resolveMessagesPatientDbId(tokenPatientId);
    if (!resolvedPatientId) {
      return res.status(404).json({ ok: false, error: 'patient_not_found' });
    }

    const explicitClinicId = String(
      body.target_clinic_id ??
        body.clinic_id ??
        body.clinicId ??
        body.context_clinic_id ??
        "",
    ).trim();
    const explicitClinicCode = String(body.clinicCode || body.clinic_code || "").trim();

    // Route the request to a clinic on treatment_requests only. Do NOT set patients.clinic_id /
    // is_lead here — marketplace quote flow must not auto-enroll the patient as a clinic member;
    // membership stays explicit (registration, invite, "join clinic", etc.).
    const clinicId = await resolveClinicIdForInbound(resolvedPatientId, {
      contextClinicCode: explicitClinicCode,
      contextClinicId: explicitClinicId,
    });
    if (!clinicId || !UUID_RE.test(clinicId)) {
      return res.status(422).json({
        ok: false,
        error: 'CLINIC_NOT_RESOLVED',
        message:
          'Klinik eşleşmedi. Uygulamadan clinicCode veya clinic_id gönderin, hasta kaydına klinik bağlayın veya sunucuda DEFAULT_CLINIC_ID / DEFAULT_CLINIC_CODE tanımlayın.',
      });
    }

    let photoUrls = null;
    const rawPhotos = body.photo_urls != null ? body.photo_urls : body.attachment_urls;
    if (Array.isArray(rawPhotos)) {
      photoUrls = rawPhotos.map((u) => String(u || '').trim()).filter(Boolean).slice(0, 24);
    }
    if ((!photoUrls || photoUrls.length === 0) && Array.isArray(body.photos)) {
      photoUrls = body.photos.map((u) => String(u || '').trim()).filter(Boolean).slice(0, 24);
    }
    if (photoUrls && photoUrls.length === 0) photoUrls = null;

    const description = String(body.description ?? body.message ?? '').trim();
    const budget =
      body.budget != null && String(body.budget).trim() ? String(body.budget).trim() : null;
    let preferred =
      body.preferred_treatment != null && String(body.preferred_treatment).trim()
        ? String(body.preferred_treatment).trim()
        : null;
    if (!preferred && body.treatment != null && String(body.treatment).trim()) {
      preferred = String(body.treatment).trim();
    }

    const hasPayload = Boolean(
      description ||
        budget ||
        preferred ||
        (photoUrls && photoUrls.length > 0),
    );
    if (!hasPayload) {
      return res.status(400).json({
        ok: false,
        error: 'empty_request',
        message: 'En azından açıklama, bütçe, tedavi tercihi veya fotoğraf URL’lerinden biri gerekli.',
      });
    }

    const nowIso = new Date().toISOString();
    const payload = {
      patient_id: resolvedPatientId,
      clinic_id: clinicId,
      description,
      budget,
      preferred_treatment: preferred,
      status: 'pending',
      created_at: nowIso,
      updated_at: nowIso,
    };
    if (photoUrls && photoUrls.length) {
      payload.photo_urls = photoUrls;
      // Some DBs use `photos` (jsonb) instead of `photo_urls`; column pruning keeps whichever exists.
      payload.photos = photoUrls;
    }

    const { data: inserted, error: insErr } = await insertIntoTableWithColumnPruning(
      'treatment_requests',
      payload,
      '*',
    );

    if (insErr) {
      console.error('[TREATMENT-REQUESTS POST]', insErr.message || insErr);
      return res.status(500).json({
        ok: false,
        error: 'insert_failed',
        message: insErr.message || String(insErr),
      });
    }

    const row = inserted || {};
    console.log('[TREATMENT-REQUESTS POST] ok', {
      request_id: row.id,
      patient_id: String(resolvedPatientId).slice(0, 8),
      clinic_id: String(clinicId).slice(0, 8),
    });

    return res.status(201).json({
      ok: true,
      request: {
        id: row.id != null ? String(row.id) : null,
        clinic_id: row.clinic_id || clinicId,
        description: row.description != null ? row.description : description,
        budget: row.budget != null ? row.budget : budget,
        preferred_treatment: row.preferred_treatment != null ? row.preferred_treatment : preferred,
        status: row.status || 'pending',
        created_at: row.created_at || nowIso,
      },
    });
  } catch (e) {
    console.error('[TREATMENT-REQUESTS POST]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// POST /api/patient/treatment-requests/mark-seen
// Sets patient_seen_at = NOW() on all answered requests that haven't been seen yet.
// Called when the patient opens the My Requests screen — clears the home-screen badge.
app.post('/api/patient/treatment-requests/mark-seen', requireToken, async (req, res) => {
  try {
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const resolvedUuid = await resolveMessagesPatientDbId(tokenPatientId);
    const patientIdFilters = treatmentRequestPatientIdFilters(tokenPatientId, resolvedUuid);
    if (!patientIdFilters.length) return res.json({ ok: true });

    let upd = supabase
      .from('treatment_requests')
      .update({ patient_seen_at: new Date().toISOString() })
      .eq('status', 'answered')
      .is('patient_seen_at', null);
    upd =
      patientIdFilters.length === 1
        ? upd.eq('patient_id', patientIdFilters[0])
        : upd.in('patient_id', patientIdFilters);
    const { error } = await upd;

    if (error) console.warn('[MARK-SEEN]', error.message); // non-fatal
    return res.json({ ok: true });
  } catch (e) {
    console.error('[MARK-SEEN]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// GET /api/patient/ratings
// Returns all ratings submitted by the authenticated patient.
app.get('/api/patient/ratings', requireToken, async (req, res) => {
  try {
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const resolvedUuid = await resolveMessagesPatientDbId(tokenPatientId);
    const patientIdFilters = treatmentRequestPatientIdFilters(tokenPatientId, resolvedUuid);
    if (!patientIdFilters.length) return res.json({ ok: true, ratings: [] });

    let ratQ = supabase
      .from('ratings')
      .select('id, clinic_id, offer_id, type, overall, created_at');
    ratQ =
      patientIdFilters.length === 1
        ? ratQ.eq('patient_id', patientIdFilters[0])
        : ratQ.in('patient_id', patientIdFilters);
    const { data: ratings, error } = await ratQ;

    if (error) {
      console.error('[RATINGS GET]', error.message);
      return res.status(500).json({ ok: false, error: 'db_error' });
    }
    return res.json({ ok: true, ratings: ratings || [] });
  } catch (e) {
    console.error('[RATINGS GET]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// POST /api/patient/ratings — submit experience (communication) or treatment-outcome rating (mobile: app/rate.tsx)
app.post('/api/patient/ratings', requireToken, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: 'supabase_disabled' });
    }
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const body = req.body || {};
    const offerId = String(body.offer_id || body.offerId || '').trim();
    const type = String(body.type || '').trim().toLowerCase();
    if (!offerId || !UUID_RE.test(offerId)) {
      return res.status(400).json({ ok: false, error: 'offer_id_required' });
    }
    if (type !== 'experience' && type !== 'treatment') {
      return res.status(400).json({ ok: false, error: 'invalid_type' });
    }
    const overall = Number(body.overall);
    if (!Number.isFinite(overall) || overall < 1 || overall > 5) {
      return res.status(400).json({ ok: false, error: 'invalid_overall' });
    }

    const resolvedUuid = await resolveMessagesPatientDbId(tokenPatientId);
    const patientIdFilters = treatmentRequestPatientIdFilters(tokenPatientId, resolvedUuid);
    if (!patientIdFilters.length) return res.status(403).json({ ok: false, error: 'forbidden' });

    const { data: offerRow, error: offErr } = await supabase
      .from('treatment_offers')
      .select('id, clinic_id, request_id')
      .eq('id', offerId)
      .maybeSingle();
    if (offErr || !offerRow?.id) {
      return res.status(404).json({ ok: false, error: 'offer_not_found' });
    }

    const { data: reqRow, error: trErr } = await supabase
      .from('treatment_requests')
      .select('id, patient_id')
      .eq('id', offerRow.request_id)
      .maybeSingle();
    if (trErr || !reqRow?.patient_id) {
      return res.status(404).json({ ok: false, error: 'request_not_found' });
    }

    const reqPid = String(reqRow.patient_id);
    if (!patientIdFilters.includes(reqPid)) {
      return res.status(403).json({ ok: false, error: 'forbidden' });
    }

    const clinicId = offerRow.clinic_id != null ? String(offerRow.clinic_id).trim() : '';
    if (!clinicId || !UUID_RE.test(clinicId)) {
      return res.status(422).json({ ok: false, error: 'clinic_not_resolved' });
    }

    let dupQ = supabase.from('ratings').select('id').eq('offer_id', offerId).eq('type', type);
    dupQ =
      patientIdFilters.length === 1
        ? dupQ.eq('patient_id', patientIdFilters[0])
        : dupQ.in('patient_id', patientIdFilters);
    const { data: existing } = await dupQ.maybeSingle();
    if (existing?.id) return res.status(409).json({ ok: false, error: 'already_rated' });

    const insertRow = {
      patient_id: reqPid,
      clinic_id: clinicId,
      offer_id: offerId,
      type,
      overall,
    };
    if (type === 'experience') {
      const c = body.communication != null ? Number(body.communication) : NaN;
      if (Number.isFinite(c) && c >= 1 && c <= 5) insertRow.communication = c;
      const p = body.price != null ? Number(body.price) : NaN;
      if (Number.isFinite(p) && p >= 1 && p <= 5) insertRow.price = p;
    } else {
      const r = body.result != null ? Number(body.result) : NaN;
      if (Number.isFinite(r) && r >= 1 && r <= 5) insertRow.result = r;
    }
    const com = body.comment != null ? String(body.comment).trim() : '';
    if (com) insertRow.comment = com.slice(0, 1000);

    const { error: insErr } = await supabase.from('ratings').insert(insertRow);
    if (insErr) {
      console.error('[RATINGS POST]', insErr.message);
      const msg = String(insErr.message || '');
      if (msg.includes('duplicate') || msg.includes('23505') || insErr.code === '23505') {
        return res.status(409).json({ ok: false, error: 'already_rated' });
      }
      return res.status(500).json({ ok: false, error: 'db_error' });
    }
    return res.json({ ok: true });
  } catch (e) {
    console.error('[RATINGS POST]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// ── Offer-thread chat (mobile: app/offer-chat.tsx — patient + doctor JWT) ───
async function resolveOfferMessagingActor(req, res) {
  const auth = req.headers.authorization || "";
  const headTok = auth.startsWith("Bearer ") ? auth.slice(7) : "";
  const altTok = req.headers["x-patient-token"] || "";
  const token = String(headTok || altTok || "").trim();
  if (!token) {
    res.status(401).json({ ok: false, error: "missing_token" });
    return null;
  }

  const tokens = readJson(TOK_FILE, {});
  if (tokens[token]?.patientId) {
    return { kind: "patient", patientId: String(tokens[token].patientId).trim() };
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    if (decoded?.patientId) {
      return { kind: "patient", patientId: String(decoded.patientId).trim() };
    }
    const roleNorm = String(decoded?.role || "").toUpperCase();
    if (roleNorm === "DOCTOR") {
      const doctorIdFromToken = String(decoded.doctorId || "").trim();
      const doctorEmail = String(decoded.email || "").trim().toLowerCase();
      let doctor = null;
      const attempts = [
        () => supabase.from("doctors").select("id, doctor_id, clinic_id, status, full_name, name").eq("id", doctorIdFromToken).maybeSingle(),
        () => supabase.from("doctors").select("id, doctor_id, clinic_id, status, full_name, name").eq("doctor_id", doctorIdFromToken).maybeSingle(),
        () =>
          doctorEmail
            ? supabase.from("doctors").select("id, doctor_id, clinic_id, status, full_name, name").eq("email", doctorEmail).maybeSingle()
            : Promise.resolve({ data: null }),
      ];
      for (const run of attempts) {
        const { data } = await run();
        if (data) {
          doctor = data;
          break;
        }
      }
      if (!doctor) {
        res.status(401).json({ ok: false, error: "doctor_not_found" });
        return null;
      }
      if (String(doctor.status || "").toUpperCase() !== "APPROVED") {
        res.status(403).json({ ok: false, error: "doctor_not_approved" });
        return null;
      }
      const did = String(doctor.id || doctor.doctor_id || doctorIdFromToken);
      return { kind: "doctor", doctorId: did, doctor };
    }
  } catch (e) {
    res.status(401).json({ ok: false, error: "invalid_token" });
    return null;
  }

  res.status(401).json({ ok: false, error: "unauthorized" });
  return null;
}

async function assertOfferMessagingAccess(actor, offerId) {
  if (!isSupabaseEnabled()) return { error: "supabase_disabled" };
  const ctx = await loadOfferMessagingContext(offerId);
  if (!ctx) return { error: "not_found" };
  const { offer, tr } = ctx;

  if (actor.kind === "patient") {
    const resolvedUuid = await resolveMessagesPatientDbId(actor.patientId);
    const filters = treatmentRequestPatientIdFilters(actor.patientId, resolvedUuid);
    if (!filters.includes(String(tr.patient_id))) return { error: "forbidden" };
    return { ok: true, offer, tr };
  }

  if (actor.kind === "doctor") {
    const keys = await doctorKeysForUuidFkInQuery([actor.doctorId]);
    const oid = String(offer.doctor_id || "");
    const okDoc = keys.some((k) => k && String(k) === oid);
    if (!okDoc) return { error: "forbidden" };
    return { ok: true, offer, tr };
  }
  return { error: "forbidden" };
}

/** Stable public base for URLs when Host header is missing (workers, health checks). */
function publicApiBaseFromEnv() {
  const raw = String(
    process.env.PUBLIC_API_URL ||
      process.env.RAILWAY_PUBLIC_DOMAIN ||
      process.env.PUBLIC_APP_URL ||
      "",
  ).trim();
  if (!raw) return "";
  if (raw.startsWith("http://") || raw.startsWith("https://")) return raw.replace(/\/$/, "");
  return `https://${raw.replace(/^\/+/, "").replace(/\/$/, "")}`;
}

function absoluteOfferFileUrl(req, relPath) {
  const p = String(relPath || "");
  if (!p.startsWith("/")) return p;
  const envBase = publicApiBaseFromEnv();
  if (envBase) return `${envBase}${p}`;
  const host = (req.get("x-forwarded-host") || req.get("host") || "").split(",")[0].trim();
  const proto = String(req.headers["x-forwarded-proto"] || req.protocol || "https").split(",")[0].trim();
  if (host) return `${proto}://${host}${p}`;
  return p;
}

/** DB may store /uploads/... ; clients (RN Image) need https://host/... */
function normalizeOfferAttachmentUrl(req, url) {
  const u = String(url || "").trim();
  if (!u) return null;
  if (/^https?:\/\//i.test(u)) return u;
  if (u.startsWith("/")) return absoluteOfferFileUrl(req, u);
  if (u.startsWith("uploads/") || u.includes("/uploads/")) {
    return absoluteOfferFileUrl(req, u.startsWith("/") ? u : `/${u}`);
  }
  return u;
}

function isOfferMessagesTableUnavailableError(err) {
  if (!err) return false;
  const code = String(err.code || "");
  const m = String(err.message || err.details || err.hint || "").toLowerCase();
  if (code === "42P01" || code === "PGRST205") return true;
  if (m.includes("offer_messages") && (m.includes("does not exist") || m.includes("schema cache"))) return true;
  return false;
}

function isOfferMessagesReadAtColumnMissingError(err) {
  if (!err) return false;
  const m = String(err.message || err.details || err.hint || "").toLowerCase();
  return m.includes("read_at") && (m.includes("does not exist") || m.includes("schema cache"));
}

/**
 * Inbox badge: unread offer_messages for sender_role, usually read_at IS NULL.
 * If read_at column is missing in DB, count all messages for that role (approximate badge).
 */
async function countOfferMessagesByRoleForInbox(offerIds, senderRole) {
  const ids = Array.isArray(offerIds) ? offerIds.filter(Boolean) : [];
  if (!ids.length) return 0;
  const role = String(senderRole || "").trim();
  if (!role) return 0;

  const inList = ids.length === 1 ? [ids[0]] : ids;
  const qUnread = () =>
    supabase
      .from("offer_messages")
      .select("id", { count: "exact", head: true })
      .in("offer_id", inList)
      .eq("sender_role", role)
      .is("read_at", null);

  const { count: c1, error: e1 } = await qUnread();
  if (!e1) return c1 || 0;
  if (isOfferMessagesTableUnavailableError(e1)) return 0;
  if (!isOfferMessagesReadAtColumnMissingError(e1)) {
    console.warn("[countOfferMessagesByRoleForInbox]", e1.message);
    return 0;
  }

  const { count: c2, error: e2 } = await supabase
    .from("offer_messages")
    .select("id", { count: "exact", head: true })
    .in("offer_id", inList)
    .eq("sender_role", role);
  if (e2) {
    if (!isOfferMessagesTableUnavailableError(e2)) console.warn("[countOfferMessagesByRoleForInbox] fallback", e2.message);
    return 0;
  }
  return c2 || 0;
}

/** Normalize treatment_requests photo storage (photo_urls vs photos jsonb, string JSON, {url} objects). */
function extractTreatmentRequestPhotoList(tr) {
  if (!tr || typeof tr !== "object") return [];
  const buckets = [tr.photo_urls, tr.photos, tr.attachment_urls];
  for (const raw of buckets) {
    const urls = coerceTreatmentRequestPhotoUrls(raw);
    if (urls.length) return urls.slice(0, 24);
  }
  return [];
}

function coerceTreatmentRequestPhotoUrls(raw) {
  if (raw == null) return [];
  if (typeof raw === "string") {
    try {
      return coerceTreatmentRequestPhotoUrls(JSON.parse(raw));
    } catch {
      const s = raw.trim();
      return s ? [s] : [];
    }
  }
  if (Array.isArray(raw)) {
    return raw
      .map((x) => {
        if (typeof x === "string") return x.trim();
        if (x && typeof x === "object" && x.url != null) return String(x.url).trim();
        return "";
      })
      .filter(Boolean);
  }
  if (typeof raw === "object") {
    const vals = Object.values(raw).filter((v) => v != null);
    if (!vals.length) return [];
    return coerceTreatmentRequestPhotoUrls(vals);
  }
  return [];
}

/** All attachment URLs on a treatment_requests row (photos + photo_urls + attachment_urls), deduped. */
function mergeAllTreatmentRequestPhotoUrls(tr) {
  if (!tr || typeof tr !== "object") return [];
  const seen = new Set();
  const out = [];
  for (const raw of [tr.photo_urls, tr.photos, tr.attachment_urls]) {
    for (const u of coerceTreatmentRequestPhotoUrls(raw)) {
      const s = String(u || "").trim();
      if (!s || seen.has(s)) continue;
      seen.add(s);
      out.push(s);
    }
  }
  return out.slice(0, 24);
}

function mergeDedupedPhotoUrlLists(primary, secondary) {
  const seen = new Set();
  const out = [];
  for (const list of [primary, secondary]) {
    if (!Array.isArray(list)) continue;
    for (const u of list) {
      const s = String(u || "").trim();
      if (!s || seen.has(s)) continue;
      seen.add(s);
      out.push(s);
    }
  }
  return out.slice(0, 24);
}

/**
 * Eski kayıtlarda treatment_requests.photo_urls boş olabilir; aynı hasta / zaman penceresindeki patient_files satırlarından URL topla.
 * Tek batch sorgu; istek başına talep oluşturma zamanına göre eşleştirir.
 */
async function mapPatientFilesPhotosByTreatmentRequestId(trRows) {
  const out = {};
  if (!isSupabaseEnabled() || !Array.isArray(trRows) || !trRows.length) return out;

  const need = trRows.filter(
    (r) =>
      r &&
      r.id &&
      UUID_RE.test(String(r.patient_id)) &&
      !extractTreatmentRequestPhotoList(r).length
  );
  if (!need.length) return out;

  const pids = [...new Set(need.map((r) => String(r.patient_id)))];
  let pfiles = [];
  try {
    const { data, error } = await supabase
      .from("patient_files")
      .select("patient_id, file_url, file_type, mime_type, created_at, source")
      .in("patient_id", pids.length === 1 ? [pids[0]] : pids)
      .order("created_at", { ascending: true });
    if (error) {
      const c = String(error.code || "");
      if (c !== "42P01" && c !== "PGRST205") {
        console.warn("[mapPatientFilesPhotosByTreatmentRequestId]", error.message);
      }
      return out;
    }
    pfiles = Array.isArray(data) ? data : [];
  } catch (e) {
    console.warn("[mapPatientFilesPhotosByTreatmentRequestId] catch", e?.message);
    return out;
  }

  const byPid = {};
  for (const f of pfiles) {
    const pid = String(f.patient_id || "").trim();
    if (!pid) continue;
    if (!byPid[pid]) byPid[pid] = [];
    byPid[pid].push(f);
  }

  const isImageRow = (f) => {
    const mime = String(f.mime_type || "").toLowerCase();
    const ftype = String(f.file_type || "").toLowerCase();
    return ftype === "image" || ftype === "xray" || mime.startsWith("image/");
  };

  for (const r of need) {
    const pid = String(r.patient_id);
    const created = r.created_at ? new Date(r.created_at).getTime() : Date.now();
    const windowStart = created - 72 * 3600000;
    const windowEnd = created + 45 * 60000;
    let files = (byPid[pid] || []).filter((f) => {
      if (!f.file_url || !isImageRow(f)) return false;
      const ft = f.created_at ? new Date(f.created_at).getTime() : 0;
      return ft >= windowStart && ft <= windowEnd;
    });
    if (!files.length) {
      files = (byPid[pid] || []).filter((f) => {
        if (!f.file_url || !isImageRow(f)) return false;
        const ft = f.created_at ? new Date(f.created_at).getTime() : 0;
        return ft <= created + 20 * 60000 && ft >= created - 7 * 24 * 3600000;
      });
    }
    const urls = mergeDedupedPhotoUrlLists(
      [],
      files.map((f) => String(f.file_url).trim()).filter(Boolean)
    );
    if (urls.length) out[String(r.id)] = urls;
  }
  return out;
}

/**
 * Initial quote/request body lives on treatment_requests, not offer_messages.
 * Reconstruct thread seed so doctor "Open conversation" shows the same text + photos.
 * @param {string[]|null} fallbackPhotoUrls — from patient_files when row never had photo_urls (legacy).
 */
function buildSyntheticOfferMessagesFromTreatmentRequest(req, tr, patientName, fallbackPhotoUrls) {
  const out = [];
  if (!tr || !tr.id) return out;
  const nm = String(patientName || "Patient").trim() || "Patient";
  const pid = String(tr.patient_id || "").trim();
  const baseIso = tr.created_at ? String(tr.created_at) : new Date().toISOString();
  const baseMs = new Date(baseIso).getTime() || Date.now();

  const lines = [];
  const desc = String(tr.description || "").trim();
  if (desc) lines.push(desc);
  const b = tr.budget != null && String(tr.budget).trim() ? String(tr.budget).trim() : "";
  if (b) lines.push(`Budget: ${b}`);
  const pref =
    tr.preferred_treatment != null && String(tr.preferred_treatment).trim()
      ? String(tr.preferred_treatment).trim()
      : "";
  if (pref) lines.push(`Preferred treatment: ${pref}`);
  const textBody = lines.join("\n\n");
  if (textBody) {
    out.push({
      id: `synthetic:tr:${tr.id}:text`,
      sender_id: pid,
      sender_role: "patient",
      sender_name: nm,
      text: textBody,
      attachment_url: null,
      attachment_type: null,
      created_at: baseIso,
      source: "treatment_request",
    });
  }

  const photos = mergeDedupedPhotoUrlLists(extractTreatmentRequestPhotoList(tr), fallbackPhotoUrls);
  photos.forEach((raw, i) => {
    const u = String(raw || "").trim();
    if (!u) return;
    const norm = normalizeOfferAttachmentUrl(req, u) || u;
    out.push({
      id: `synthetic:tr:${tr.id}:photo:${i}`,
      sender_id: pid,
      sender_role: "patient",
      sender_name: nm,
      text: null,
      attachment_url: norm,
      attachment_type: "image",
      created_at: new Date(baseMs + i + 1).toISOString(),
      source: "treatment_request",
    });
  });
  return out;
}

function mergeOfferMessagesByTime(a, b) {
  const all = [...(a || []), ...(b || [])];
  all.sort((x, y) => {
    const tx = new Date(x.created_at || 0).getTime();
    const ty = new Date(y.created_at || 0).getTime();
    return tx - ty;
  });
  return all;
}

/** Fetch offer + treatment_requests row (including description / photos for synthetic thread). */
async function loadOfferMessagingContext(offerId) {
  const { data: offer, error: oErr } = await supabase
    .from("treatment_offers")
    .select("id, request_id, doctor_id")
    .eq("id", offerId)
    .maybeSingle();
  if (oErr || !offer) return null;

  // Prefer columns that exist on minimal schemas first — avoid `photo_urls` until last (many DBs never had that column).
  const trSelects = [
    "id, patient_id, description, budget, preferred_treatment, created_at",
    "id, patient_id, description, budget, preferred_treatment, created_at, updated_at",
    "id, patient_id, description, budget, preferred_treatment, photos, created_at",
    "id, patient_id, description, budget, preferred_treatment, attachment_urls, created_at",
    "id, patient_id, description, budget, preferred_treatment, photos, attachment_urls, created_at, updated_at",
    "id, patient_id, description, created_at",
    "id, patient_id",
    "id, patient_id, description, budget, preferred_treatment, photo_urls, photos, attachment_urls, created_at, updated_at",
    "id, patient_id, description, budget, preferred_treatment, photo_urls, photos, created_at",
    "id, patient_id, description, budget, preferred_treatment, photo_urls, created_at",
    "id, patient_id, description, photo_urls, photos, created_at",
    "id, patient_id, description, photo_urls, created_at",
  ];

  let tr = null;
  for (const sel of trSelects) {
    const { data: t, error: tErr } = await supabase
      .from("treatment_requests")
      .select(sel)
      .eq("id", offer.request_id)
      .maybeSingle();
    if (!tErr && t?.patient_id) {
      tr = t;
      break;
    }
  }
  if (!tr?.patient_id) return null;
  return { offer, tr };
}

async function fetchOfferMessagesForOfferId(offerId) {
  // supabase-js v2: filters (.eq, .order) must chain after .select() / .insert() / etc. — not on .from() alone.
  const build = (cols) =>
    supabase
      .from("offer_messages")
      .select(cols)
      .eq("offer_id", offerId)
      .order("created_at", { ascending: true });

  let { data: rows, error } = await build(
    "id, sender_id, sender_role, sender_name, text, attachment_url, attachment_type, created_at"
  );
  if (error && !isOfferMessagesTableUnavailableError(error)) {
    const r2 = await build("*");
    rows = r2.data;
    error = r2.error;
  }
  if (error && isOfferMessagesTableUnavailableError(error)) {
    return { rows: [], error: null, tableMissing: true };
  }
  if (error) return { rows: null, error, tableMissing: false };
  return { rows: rows || [], error: null, tableMissing: false };
}

// POST /api/offer-messages/upload — must be registered before /api/offer-messages (POST body)
app.post("/api/offer-messages/upload", chatUpload.single("file"), async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: "supabase_disabled" });
    }
    const actor = await resolveOfferMessagingActor(req, res);
    if (!actor) return;

    const offerId = String((req.body && req.body.offer_id) || "").trim();
    if (!UUID_RE.test(offerId)) {
      return res.status(400).json({ ok: false, error: "invalid_offer_id" });
    }

    const access = await assertOfferMessagingAccess(actor, offerId);
    if (access.error === "not_found") return res.status(404).json({ ok: false, error: "not_found" });
    if (access.error === "supabase_disabled") return res.status(503).json({ ok: false, error: access.error });
    if (access.error) return res.status(403).json({ ok: false, error: access.error });

    const file = req.file;
    if (!file || !file.buffer) {
      return res.status(400).json({ ok: false, error: "no_file" });
    }

    const mime = String(file.mimetype || "").toLowerCase();
    const att = String((req.body && req.body.attachment_type) || "image").toLowerCase();
    const isImage = mime.startsWith("image/") || att === "image" || att === "xray";
    const allowedImage = new Set(["image/jpeg", "image/jpg", "image/png", "image/heic", "image/heif", "image/webp"]);
    const allowedPdf = "application/pdf";
    if (isImage && !allowedImage.has(mime)) {
      return res.status(400).json({ ok: false, error: "invalid_file_type" });
    }
    if (!isImage && mime !== allowedPdf && att !== "document") {
      return res.status(400).json({ ok: false, error: "invalid_file_type" });
    }

    let ext = path.extname(file.originalname || "").toLowerCase();
    if (!ext) {
      if (mime === "image/png") ext = ".png";
      else if (mime.includes("jpeg") || mime === "image/jpg") ext = ".jpg";
      else if (mime === "application/pdf") ext = ".pdf";
      else ext = ".bin";
    }
    const safeName = `${crypto.randomUUID()}${ext}`;
    const dir = path.join(__dirname, "public", "uploads", "offer-messages", offerId);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    const diskPath = path.join(dir, safeName);
    fs.writeFileSync(diskPath, file.buffer);

    const rel = `/uploads/offer-messages/${encodeURIComponent(offerId)}/${encodeURIComponent(safeName)}`;
    return res.json({ ok: true, url: absoluteOfferFileUrl(req, rel) });
  } catch (e) {
    console.error("[OFFER-MESSAGES UPLOAD]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// POST /api/offer-messages/:offerId/read — mark other party's messages read
app.post("/api/offer-messages/:offerId/read", async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: "supabase_disabled" });
    }
    const actor = await resolveOfferMessagingActor(req, res);
    if (!actor) return;

    const offerId = String(req.params.offerId || "").trim();
    if (!UUID_RE.test(offerId)) {
      return res.status(400).json({ ok: false, error: "invalid_offer_id" });
    }

    const access = await assertOfferMessagingAccess(actor, offerId);
    if (access.error === "not_found") return res.status(404).json({ ok: false, error: "not_found" });
    if (access.error === "supabase_disabled") return res.status(503).json({ ok: false, error: access.error });
    if (access.error) return res.status(403).json({ ok: false, error: access.error });

    const markSender = actor.kind === "doctor" ? "patient" : "doctor";
    const nowIso = new Date().toISOString();
    const { error: uErr } = await supabase
      .from("offer_messages")
      .update({ read_at: nowIso })
      .eq("offer_id", offerId)
      .eq("sender_role", markSender)
      .is("read_at", null);

    if (uErr) {
      const rmsg = String(uErr.message || uErr.details || "").toLowerCase();
      if (
        rmsg.includes("read_at") &&
        (rmsg.includes("does not exist") || rmsg.includes("schema cache") || isMissingColumnError(uErr, "read_at"))
      ) {
        return res.json({ ok: true, read_receipts_unsupported: true });
      }
      console.error("[OFFER-MESSAGES READ]", uErr.message);
      return res.status(500).json({ ok: false, error: "db_error" });
    }
    return res.json({ ok: true });
  } catch (e) {
    console.error("[OFFER-MESSAGES READ]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// GET /api/offer-messages?offer_id=
app.get("/api/offer-messages", async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: "supabase_disabled" });
    }
    const actor = await resolveOfferMessagingActor(req, res);
    if (!actor) return;

    const offerId = String(req.query.offer_id || "").trim();
    if (!UUID_RE.test(offerId)) {
      return res.status(400).json({ ok: false, error: "invalid_offer_id" });
    }

    const access = await assertOfferMessagingAccess(actor, offerId);
    if (access.error === "not_found") return res.status(404).json({ ok: false, error: "not_found" });
    if (access.error === "supabase_disabled") return res.status(503).json({ ok: false, error: access.error });
    if (access.error) return res.status(403).json({ ok: false, error: access.error });

    const tr = access.tr;
    let patientName = "Patient";
    const pidForName = String(tr?.patient_id || "").trim();
    if (pidForName && UUID_RE.test(pidForName)) {
      const { data: prow } = await supabase
        .from("patients")
        .select("name, full_name")
        .eq("id", pidForName)
        .maybeSingle();
      patientName = String(prow?.full_name || prow?.name || "Patient").trim() || "Patient";
    }

    const fm = await fetchOfferMessagesForOfferId(offerId);
    if (fm.error) {
      console.error("[OFFER-MESSAGES GET]", fm.error.message || fm.error, fm.error.code || "");
      return res.status(500).json({ ok: false, error: "db_error" });
    }

    let patientFileFallbackUrls = [];
    try {
      const fbMap = await mapPatientFilesPhotosByTreatmentRequestId([tr]);
      patientFileFallbackUrls = fbMap[String(tr.id)] || [];
    } catch (fbErr) {
      console.warn("[OFFER-MESSAGES GET] patient_files fallback:", fbErr?.message);
    }

    const syn = buildSyntheticOfferMessagesFromTreatmentRequest(req, tr, patientName, patientFileFallbackUrls);
    const real = (fm.rows || []).map((m) => ({
      id: String(m.id),
      sender_id: String(m.sender_id || ""),
      sender_role: m.sender_role,
      sender_name: m.sender_name || "",
      text: m.text,
      attachment_url: normalizeOfferAttachmentUrl(req, m.attachment_url) || m.attachment_url,
      attachment_type: m.attachment_type,
      created_at: m.created_at,
    }));
    const messages = mergeOfferMessagesByTime(syn, real);
    const payload = { ok: true, messages };
    if (fm.tableMissing) payload.offer_messages_table_missing = true;
    return res.json(payload);
  } catch (e) {
    console.error("[OFFER-MESSAGES GET]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// POST /api/offer-messages — send text and/or attachment
app.post("/api/offer-messages", async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.status(503).json({ ok: false, error: "supabase_disabled" });
    }
    const actor = await resolveOfferMessagingActor(req, res);
    if (!actor) return;

    const body = req.body || {};
    const offerId = String(body.offer_id || body.offerId || "").trim();
    if (!UUID_RE.test(offerId)) {
      return res.status(400).json({ ok: false, error: "invalid_offer_id" });
    }

    const access = await assertOfferMessagingAccess(actor, offerId);
    if (access.error === "not_found") return res.status(404).json({ ok: false, error: "not_found" });
    if (access.error === "supabase_disabled") return res.status(503).json({ ok: false, error: access.error });
    if (access.error) return res.status(403).json({ ok: false, error: access.error });

    const { tr } = access;
    const textRaw = body.text != null ? String(body.text) : "";
    const text = textRaw.trim().slice(0, 5000);
    const attachment_url = body.attachment_url != null ? String(body.attachment_url).trim().slice(0, 2048) : "";
    let attachment_type = body.attachment_type != null ? String(body.attachment_type).trim().toLowerCase() : null;
    if (attachment_type && !["image", "xray", "document"].includes(attachment_type)) {
      return res.status(400).json({ ok: false, error: "invalid_attachment_type" });
    }
    if (!text && !attachment_url) {
      return res.status(400).json({ ok: false, error: "empty_message" });
    }
    if (attachment_url && !attachment_type) attachment_type = "image";

    const attachmentUrlStored = attachment_url
      ? normalizeOfferAttachmentUrl(req, attachment_url) || attachment_url
      : null;

    let sender_id = "";
    let sender_role = "patient";
    let sender_name = "";

    if (actor.kind === "patient") {
      sender_role = "patient";
      sender_id = String(tr.patient_id);
      const { data: prow } = await supabase
        .from("patients")
        .select("name, full_name")
        .eq("id", tr.patient_id)
        .maybeSingle();
      sender_name = String(prow?.full_name || prow?.name || "").trim() || "Patient";
    } else {
      sender_role = "doctor";
      sender_id = String(actor.doctorId);
      sender_name = String(actor.doctor?.full_name || actor.doctor?.name || "").trim() || "Doctor";
    }

    const insertRow = {
      offer_id: offerId,
      sender_id,
      sender_role,
      sender_name,
      text: text || null,
      attachment_url: attachmentUrlStored,
      attachment_type: attachment_type || null,
    };

    const { data: inserted, error: insErr } = await supabase
      .from("offer_messages")
      .insert(insertRow)
      .select("id, sender_id, sender_role, sender_name, text, attachment_url, attachment_type, created_at")
      .maybeSingle();

    if (insErr || !inserted) {
      console.error("[OFFER-MESSAGES POST]", insErr?.message || insErr);
      return res.status(500).json({ ok: false, error: "db_error" });
    }

    const message = {
      id: String(inserted.id),
      sender_id: String(inserted.sender_id || ""),
      sender_role: inserted.sender_role,
      sender_name: inserted.sender_name || "",
      text: inserted.text,
      attachment_url:
        normalizeOfferAttachmentUrl(req, inserted.attachment_url) || inserted.attachment_url,
      attachment_type: inserted.attachment_type,
      created_at: inserted.created_at,
    };
    return res.json({ ok: true, message });
  } catch (e) {
    console.error("[OFFER-MESSAGES POST]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// GET /api/patient/inbox-summary
// Returns badge counts: new_offers (answered requests not yet seen) +
// doctor_messages (unread messages from doctors in offer threads).
app.get('/api/patient/inbox-summary', requireToken, async (req, res) => {
  try {
    const tokenPatientId = String(req.patientId || '').trim();
    if (!tokenPatientId) return res.status(400).json({ ok: false, error: 'patientId_required' });

    const resolvedUuid = await resolveMessagesPatientDbId(tokenPatientId);
    const patientIdFilters = treatmentRequestPatientIdFilters(tokenPatientId, resolvedUuid);
    if (!patientIdFilters.length) {
      return res.json({ ok: true, new_offers: 0, doctor_messages: 0 });
    }

    // Count answered requests the patient hasn't opened yet
    let offerQ = supabase
      .from('treatment_requests')
      .select('id', { count: 'exact', head: true })
      .eq('status', 'answered')
      .is('patient_seen_at', null);
    offerQ =
      patientIdFilters.length === 1
        ? offerQ.eq('patient_id', patientIdFilters[0])
        : offerQ.in('patient_id', patientIdFilters);
    const { count: newOffers, error: offerErr } = await offerQ;

    if (offerErr) console.warn('[INBOX-SUMMARY offers]', offerErr.message);

    // Count unread doctor messages across all offer threads belonging to this patient
    // offer_messages.sender_role = 'doctor' AND read_at IS NULL for messages in the
    // patient's offer threads.
    let doctorMessages = 0;
    try {
      // First get all offer IDs for this patient's requests
      let reqsQ = supabase.from('treatment_requests').select('id');
      reqsQ =
        patientIdFilters.length === 1
          ? reqsQ.eq('patient_id', patientIdFilters[0])
          : reqsQ.in('patient_id', patientIdFilters);
      const { data: reqs } = await reqsQ;

      if (reqs && reqs.length > 0) {
        const reqIds = reqs.map(r => r.id);
        const { data: offerRows } = await supabase
          .from('treatment_offers')
          .select('id')
          .in('request_id', reqIds);

        if (offerRows && offerRows.length > 0) {
          const offerIds = offerRows.map(o => o.id);
          doctorMessages = await countOfferMessagesByRoleForInbox(offerIds, "doctor");
        }
      }
    } catch (e2) {
      console.warn('[INBOX-SUMMARY messages]', e2?.message);
    }

    return res.json({
      ok:              true,
      new_offers:      newOffers    || 0,
      doctor_messages: doctorMessages,
    });
  } catch (e) {
    console.error('[INBOX-SUMMARY]', e);
    return res.status(500).json({ ok: false, error: 'internal_error' });
  }
});

// ── Doctor marketplace (mobile: doctor/index.tsx, doctor/requests.tsx) ───────
// GET /api/doctor/inbox-summary — badge counts (Authorization: Bearer doctor JWT)
app.get("/api/doctor/inbox-summary", requireDoctorAuth, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.json({ ok: true, patient_messages: 0, pending_requests: 0 });
    }
    const clinicId = String(req.clinicId || req?.doctor?.clinic_id || "").trim();
    const rawDoctor = String(req.doctorId || req?.doctor?.id || "").trim();
    const doctorKeys = await doctorKeysForUuidFkInQuery([rawDoctor].filter(Boolean));
    const doctorKey = doctorKeys[0] || rawDoctor;
    if (!doctorKey) {
      return res.status(401).json({ ok: false, error: "Unauthorized", code: "doctor_key_missing" });
    }

    let pending_requests = 0;
    if (clinicId && UUID_RE.test(clinicId)) {
      const { count, error: cErr } = await supabase
        .from("treatment_requests")
        .select("id", { count: "exact", head: true })
        .eq("clinic_id", clinicId)
        .eq("status", "pending");
      if (!cErr) pending_requests = count || 0;
    }

    let patient_messages = 0;
    try {
      const { data: myOffers, error: oErr } = await supabase
        .from("treatment_offers")
        .select("id")
        .eq("doctor_id", doctorKey);
      const offerIds = (myOffers || []).map((o) => o.id).filter(Boolean);
      if (!oErr && offerIds.length > 0) {
        patient_messages = await countOfferMessagesByRoleForInbox(offerIds, "patient");
      }
    } catch (e2) {
      console.warn("[DOCTOR inbox-summary] messages", e2?.message);
    }

    return res.json({
      ok: true,
      patient_messages,
      pending_requests,
    });
  } catch (e) {
    console.error("[DOCTOR inbox-summary]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// GET /api/doctor/inbox — threads assigned to this doctor (not limited to is_lead; patients may graduate)
app.get("/api/doctor/inbox", requireDoctorAuth, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.json({ ok: true, items: [] });
    }
    const clinicId = String(req.clinicId || req?.doctor?.clinic_id || "").trim();
    const rawDoctor = String(req.doctorId || req?.doctor?.id || "").trim();
    const doctorKeys = await doctorKeysForUuidFkInQuery([rawDoctor].filter(Boolean));
    if (!doctorKeys.length || !UUID_RE.test(clinicId)) {
      console.log("[DOCTOR inbox] skip — doctorKeys or clinicId", {
        doctorKeysLen: doctorKeys.length,
        clinicIdOk: UUID_RE.test(clinicId),
      });
      return res.json({ ok: true, items: [] });
    }

    console.log("[DOCTOR inbox] DOCTOR_ID", rawDoctor, "resolvedKeys", doctorKeys, "clinic_id", clinicId);

    let threadsQuery = supabase
      .from("patient_chat_threads")
      .select("id, patient_id, status, assigned_doctor_id, assigned_at, updated_at, created_at, is_lead")
      .eq("clinic_id", clinicId)
      .in("assigned_doctor_id", doctorKeys)
      .order("updated_at", { ascending: false })
      .limit(200);

    const { data: threads, error } = await threadsQuery;

    if (error) {
      const code = String(error.code || "");
      const msg = String(error.message || "").toLowerCase();
      if (code === "42P01" || msg.includes("does not exist")) {
        return res.json({ ok: true, items: [] });
      }
      console.warn("[DOCTOR inbox]", error.message);
      return res.status(500).json({ ok: false, error: "fetch_failed" });
    }

    const rows = Array.isArray(threads) ? threads : [];
    console.log("[DOCTOR inbox] THREADS FOUND", rows.length);
    const pids = [...new Set(rows.map((r) => String(r.patient_id || "").trim()).filter((id) => UUID_RE.test(id)))];
    const patientById = {};
    if (pids.length) {
      const { data: prow, error: pErr } = await supabase
        .from("patients")
        .select("id, name, full_name, email, phone, patient_id")
        .in("id", pids.slice(0, 500));
      if (!pErr && Array.isArray(prow)) {
        for (const p of prow) {
          patientById[String(p.id)] = p;
        }
      }
    }

    const items = rows.map((t) => {
      const pid = String(t.patient_id || "").trim();
      const p = patientById[pid] || null;
      return {
        threadId: t.id,
        patientId: pid,
        patientIdPublic: p?.patient_id || null,
        patientName: String(p?.name || p?.full_name || "").trim() || null,
        email: p?.email || null,
        phone: p?.phone || null,
        status: t.status || "assigned",
        assignedDoctorId: t.assigned_doctor_id || null,
        assignedAt: t.assigned_at || null,
        updatedAt: t.updated_at || null,
        createdAt: t.created_at || null,
      };
    });

    return res.json({ ok: true, items, messages: items });
  } catch (e) {
    console.error("[DOCTOR inbox]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

// GET /api/doctor/treatment-requests — incoming requests for this clinic + offer metadata
app.get("/api/doctor/treatment-requests", requireDoctorAuth, async (req, res) => {
  try {
    if (!isSupabaseEnabled()) {
      return res.json({ ok: true, requests: [] });
    }
    const clinicId = String(req.clinicId || req?.doctor?.clinic_id || "").trim();
    const rawDoctor = String(req.doctorId || req?.doctor?.id || "").trim();
    const doctorKeys = await doctorKeysForUuidFkInQuery([rawDoctor].filter(Boolean));
    const doctorKey = doctorKeys[0] || rawDoctor;
    if (!doctorKey) {
      return res.status(401).json({ ok: false, error: "Unauthorized", code: "doctor_key_missing" });
    }

    // Prefer full rows first: `*` loads every column (photos, photo_urls, attachment_urls, …).
    // Listing only base columns can succeed while omitting photo JSONB → UI never gets images.
    const trSelectVariants = [
      "*",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, photo_urls, photos, attachment_urls",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, photo_urls, photos",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, photos, attachment_urls",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, photos",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, attachment_urls",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id, photo_urls",
      "id, patient_id, description, budget, preferred_treatment, status, created_at, clinic_id",
    ];

    let list = [];
    let lastTrErr = null;
    for (const sel of trSelectVariants) {
      let trQuery = supabase
        .from("treatment_requests")
        .select(sel)
        .order("created_at", { ascending: false })
        .limit(400);
      if (clinicId && UUID_RE.test(clinicId)) {
        trQuery = trQuery.eq("clinic_id", clinicId);
      }
      const { data: trRows, error: trErr } = await trQuery;
      if (!trErr && Array.isArray(trRows)) {
        list = trRows;
        break;
      }
      lastTrErr = trErr || lastTrErr;
    }
    if (!list.length && lastTrErr) {
      console.warn("[DOCTOR treatment-requests] select failed after variants:", lastTrErr.message);
    }
    const pids = [
      ...new Set(
        list
          .map((r) => String(r.patient_id || "").trim())
          .filter((id) => UUID_RE.test(id))
      ),
    ];
    const nameById = {};
    if (pids.length > 0) {
      const { data: prow, error: pErr } = await supabase
        .from("patients")
        .select("id, name, full_name")
        .in("id", pids.slice(0, 500));
      if (!pErr && Array.isArray(prow)) {
        for (const p of prow) {
          const nid = String(p.id || "").trim();
          nameById[nid] = String(p.name || p.full_name || "Patient");
        }
      }
    }

    const requestIds = list.map((r) => r.id).filter(Boolean);
    if (!requestIds.length) {
      return res.json({ ok: true, requests: [] });
    }

    let allOffers = [];
    const offerSelectVariants = [
      "id, request_id, doctor_id, treatment_type, price_range, duration, note, created_at, clinic_id",
      "id, request_id, doctor_id, treatment_type, price_range, duration, note, created_at",
      "id, request_id, doctor_id, created_at",
    ];
    for (const osel of offerSelectVariants) {
      const { data: offerRows, error: offerErr } = await supabase
        .from("treatment_offers")
        .select(osel)
        .in("request_id", requestIds);
      if (!offerErr && Array.isArray(offerRows)) {
        allOffers = offerRows;
        break;
      }
    }

    const offersByReq = {};
    for (const o of allOffers || []) {
      const rid = o.request_id;
      if (!offersByReq[rid]) offersByReq[rid] = [];
      offersByReq[rid].push(o);
    }

    /** Match this doctor's offer — compare to any resolved UUID (not only doctorKeys[0]). */
    const doctorIdMatchSet = new Set(doctorKeys.map((k) => String(k || "").trim()).filter(Boolean));
    if (rawDoctor) doctorIdMatchSet.add(String(rawDoctor).trim());

    const mapReqStatus = (s) => {
      const x = String(s || "").toLowerCase();
      if (x === "answered") return "answered";
      if (x === "closed") return "closed";
      return "pending";
    };

    let patientFilesFallbackByReqId = {};
    try {
      patientFilesFallbackByReqId = await mapPatientFilesPhotosByTreatmentRequestId(list);
    } catch (fbErr) {
      console.warn("[DOCTOR treatment-requests] patient_files fallback:", fbErr?.message);
    }

    const requests = list.map((r) => {
      const offs = offersByReq[r.id] || [];
      const mine = offs.find((o) => doctorIdMatchSet.has(String(o.doctor_id || "").trim()));
      const pid = String(r.patient_id || "").trim();
      const patientName = (pid && nameById[pid]) || "Patient";
      let rawPhotoList = extractTreatmentRequestPhotoList(r);
      if (!rawPhotoList.length) {
        rawPhotoList = patientFilesFallbackByReqId[String(r.id)] || [];
      }
      const photosNormalized = rawPhotoList
        .map((u) => normalizeOfferAttachmentUrl(req, u) || String(u || "").trim())
        .filter(Boolean);
      const myOfferPayload =
        mine && mine.id
          ? {
              id: String(mine.id),
              treatment_type: mine.treatment_type != null ? String(mine.treatment_type) : null,
              price_range: mine.price_range != null ? String(mine.price_range) : null,
              duration: mine.duration != null ? String(mine.duration) : null,
              note: mine.note != null ? String(mine.note) : null,
              created_at: mine.created_at || null,
            }
          : null;
      return {
        id: String(r.id),
        patient_name: patientName,
        description: r.description != null ? String(r.description) : "",
        budget: r.budget != null ? String(r.budget) : null,
        preferred_treatment: r.preferred_treatment != null ? String(r.preferred_treatment) : null,
        status: mapReqStatus(r.status),
        created_at: r.created_at || new Date().toISOString(),
        offer_count: offs.length,
        my_offer_id: mine ? String(mine.id) : null,
        my_offer: myOfferPayload,
        unread_count: 0,
        is_assigned_to_me: Boolean(mine),
        photos: photosNormalized,
      };
    });

    return res.json({ ok: true, requests });
  } catch (e) {
    console.error("[DOCTOR treatment-requests GET]", e);
    return res.status(500).json({ ok: false, error: "internal_error" });
  }
});

